#[derive(Clone, Debug, PartialEq, Eq)]
pub struct IndependentCheckerJsonPath {
    pub elements: Vec<IndependentCheckerJsonPathElement>,
}

impl IndependentCheckerJsonPath {
    pub const fn root() -> Self {
        Self {
            elements: Vec::new(),
        }
    }

    pub fn field(&self, field: impl Into<String>) -> Self {
        let mut elements = self.elements.clone();
        elements.push(IndependentCheckerJsonPathElement::Field(field.into()));
        Self { elements }
    }

    pub fn index(&self, index: usize) -> Self {
        let mut elements = self.elements.clone();
        elements.push(IndependentCheckerJsonPathElement::Index(index));
        Self { elements }
    }

    pub fn artifact_local_string(&self) -> String {
        if self.elements.is_empty() {
            return "$".to_owned();
        }

        let mut out = String::new();
        for (index, element) in self.elements.iter().enumerate() {
            match element {
                IndependentCheckerJsonPathElement::Field(field) => {
                    if index > 0 {
                        out.push('.');
                    }
                    out.push_str(field);
                }
                IndependentCheckerJsonPathElement::Index(array_index) => {
                    out.push('[');
                    out.push_str(&array_index.to_string());
                    out.push(']');
                }
            }
        }
        out
    }
}

impl Default for IndependentCheckerJsonPath {
    fn default() -> Self {
        Self::root()
    }
}

#[derive(Clone, Debug, PartialEq, Eq)]
pub enum IndependentCheckerJsonPathElement {
    Field(String),
    Index(usize),
}

