#[derive(Clone, Debug, PartialEq, Eq)]
pub enum IndependentCheckerSchemaErrorReason {
    ExpectedObject {
        actual: JsonValueKind,
    },
    DuplicateField {
        field: String,
    },
    UnknownField {
        field: String,
    },
    MissingField {
        field: &'static str,
    },
    NullNotAllowed {
        field: &'static str,
    },
    WrongType {
        field: &'static str,
        expected: IndependentCheckerJsonFieldType,
        actual: JsonValueKind,
    },
    InvalidInteger {
        field: &'static str,
        raw: String,
    },
    InvalidHashFormat {
        field: &'static str,
    },
}

