#[derive(Clone, Debug, PartialEq, Eq)]
pub struct IndependentCheckerCommandError {
    pub command: IndependentCheckerCommandName,
    pub reason_code: Box<str>,
    pub field: Option<Box<str>>,
    pub expected_hash: Option<Box<Hash>>,
    pub actual_hash: Option<Box<Hash>>,
    pub expected_value: Option<Box<str>>,
    pub actual_value: Option<Box<str>>,
    pub diagnostics: Vec<String>,
}

impl IndependentCheckerCommandError {
    pub fn new(command: IndependentCheckerCommandName, reason_code: impl Into<String>) -> Self {
        Self {
            command,
            reason_code: reason_code.into().into_boxed_str(),
            field: None,
            expected_hash: None,
            actual_hash: None,
            expected_value: None,
            actual_value: None,
            diagnostics: Vec::new(),
        }
    }

    pub fn canonical_json(&self) -> String {
        let mut pairs = vec![
            (
                "command".to_owned(),
                independent_checker_json_string_literal(self.command.as_str()),
            ),
            (
                "reason_code".to_owned(),
                independent_checker_json_string_literal(&self.reason_code),
            ),
            (
                "schema".to_owned(),
                independent_checker_json_string_literal(INDEPENDENT_CHECKER_COMMAND_ERROR_SCHEMA),
            ),
        ];
        push_optional_string_pair(&mut pairs, "field", self.field.as_deref());
        push_optional_hash_pair(
            &mut pairs,
            "expected_hash",
            self.expected_hash.as_deref().copied(),
        );
        push_optional_hash_pair(
            &mut pairs,
            "actual_hash",
            self.actual_hash.as_deref().copied(),
        );
        push_optional_string_pair(&mut pairs, "expected_value", self.expected_value.as_deref());
        push_optional_string_pair(&mut pairs, "actual_value", self.actual_value.as_deref());
        if !self.diagnostics.is_empty() {
            pairs.push((
                "diagnostics".to_owned(),
                independent_checker_json_string_array(&self.diagnostics),
            ));
        }
        canonical_json_object_from_pairs(pairs)
    }
}

