/// Runner policy for Phase 8 checker audit automation.
///
/// The policy owns checker selection, runner-owned dynamic arguments, budgets,
/// import-lock paths, and axiom-policy paths. It must not be treated as a
/// checker verdict, and AI requests for additional profiles are ignored unless
/// the policy explicitly includes the profile as required or optional.
#[derive(Clone, Debug, PartialEq, Eq)]
pub struct IndependentCheckerRunnerPolicy {
    pub id: String,
    pub version: u64,
    pub trust_mode: IndependentCheckerTrustMode,
    pub required_checker_profiles: Vec<String>,
    pub optional_checker_profiles: Vec<String>,
    pub checker_allowlist: Vec<IndependentCheckerAllowlistEntry>,
    pub checker_identity_manifest: Option<IndependentCheckerIdentityManifestReference>,
    pub import_policy: IndependentCheckerRunnerImportPolicy,
    pub axiom_policy: IndependentCheckerRunnerAxiomPolicy,
    pub budgets: BTreeMap<String, IndependentCheckerRunnerBudget>,
}

impl IndependentCheckerRunnerPolicy {
    pub fn canonical_json(&self) -> String {
        let mut pairs = vec![
            (
                "axiom_policy".to_owned(),
                self.axiom_policy.canonical_json(),
            ),
            (
                "budgets".to_owned(),
                canonical_json_object_from_pairs(
                    self.budgets
                        .iter()
                        .map(|(profile, budget)| (profile.clone(), budget.canonical_json()))
                        .collect(),
                ),
            ),
            (
                "checker_allowlist".to_owned(),
                canonical_json_array(
                    self.checker_allowlist
                        .iter()
                        .map(IndependentCheckerAllowlistEntry::canonical_json)
                        .collect(),
                ),
            ),
            (
                "id".to_owned(),
                independent_checker_json_string_literal(&self.id),
            ),
            (
                "import_policy".to_owned(),
                self.import_policy.canonical_json(),
            ),
            (
                "on_missing_required_checker".to_owned(),
                independent_checker_json_string_literal("fail"),
            ),
            (
                "on_profile_requested_by_ai".to_owned(),
                independent_checker_json_string_literal("ignore_unless_policy_allows"),
            ),
            (
                "on_resource_exhausted".to_owned(),
                independent_checker_json_string_literal("fail"),
            ),
            (
                "optional_checker_profiles".to_owned(),
                independent_checker_json_string_array(&self.optional_checker_profiles),
            ),
            (
                "required_checker_profiles".to_owned(),
                independent_checker_json_string_array(&self.required_checker_profiles),
            ),
            (
                "schema".to_owned(),
                independent_checker_json_string_literal(INDEPENDENT_CHECKER_RUNNER_POLICY_SCHEMA),
            ),
            (
                "trust_mode".to_owned(),
                independent_checker_json_string_literal(self.trust_mode.as_str()),
            ),
            ("version".to_owned(), self.version.to_string()),
        ];
        if let Some(reference) = &self.checker_identity_manifest {
            pairs.push((
                "checker_identity_manifest".to_owned(),
                reference.canonical_json(),
            ));
        }
        canonical_json_object_from_pairs(pairs)
    }

    pub fn policy_hash(&self) -> Hash {
        independent_checker_sha256(self.canonical_json().as_bytes())
    }

    pub fn selected_checker_policy(
        &self,
        profile: &str,
    ) -> Option<&IndependentCheckerAllowlistEntry> {
        self.checker_allowlist
            .iter()
            .find(|entry| entry.profile == profile)
    }
}

