/// Certificate-only request handed to an independent checker runner.
///
/// This request intentionally carries paths and hashes for canonical
/// certificate bytes and import locks, but no `.npa` source, tactic script, AI
/// trace, theorem-search index, or audit sidecar content. Those artifacts may
/// explain failures outside the trust boundary, but they are not checker input.
#[derive(Clone, Debug, PartialEq, Eq)]
pub struct IndependentCheckerMachineCheckRequest {
    pub request_id: String,
    pub module: String,
    pub policy: IndependentCheckerMachineCheckRequestPolicy,
    pub certificate: IndependentCheckerMachineCheckRequestCertificate,
    pub imports: IndependentCheckerMachineCheckRequestImports,
    pub checker_profile: String,
    pub trust_mode: IndependentCheckerTrustMode,
    pub axiom_policy: String,
    pub budget: IndependentCheckerRunnerBudget,
}

impl IndependentCheckerMachineCheckRequest {
    pub fn request_hash(&self) -> Hash {
        independent_checker_sha256(self.hash_input_canonical_json().as_bytes())
    }

    pub fn hash_input_canonical_json(&self) -> String {
        canonical_json_object_from_pairs(self.semantic_canonical_json_pairs())
    }

    pub fn canonical_json(&self) -> String {
        let mut pairs = self.semantic_canonical_json_pairs();
        pairs.push((
            "request_hash".to_owned(),
            independent_checker_hash_json_literal(&self.request_hash()),
        ));
        pairs.push((
            "request_id".to_owned(),
            independent_checker_json_string_literal(&self.request_id),
        ));
        canonical_json_object_from_pairs(pairs)
    }

    fn semantic_canonical_json_pairs(&self) -> Vec<(String, String)> {
        vec![
            (
                "axiom_policy".to_owned(),
                independent_checker_json_string_literal(&self.axiom_policy),
            ),
            ("budget".to_owned(), self.budget.canonical_json()),
            ("certificate".to_owned(), self.certificate.canonical_json()),
            (
                "checker_profile".to_owned(),
                independent_checker_json_string_literal(&self.checker_profile),
            ),
            ("imports".to_owned(), self.imports.canonical_json()),
            (
                "module".to_owned(),
                independent_checker_json_string_literal(&self.module),
            ),
            ("policy".to_owned(), self.policy.canonical_json()),
            (
                "schema".to_owned(),
                independent_checker_json_string_literal(
                    INDEPENDENT_CHECKER_MACHINE_CHECK_REQUEST_SCHEMA,
                ),
            ),
            (
                "trust_mode".to_owned(),
                independent_checker_json_string_literal(self.trust_mode.as_str()),
            ),
        ]
    }
}

