#[derive(Clone, Debug, PartialEq, Eq)]
pub struct IndependentCheckerChallengeGenerationRequest {
    pub request_id: String,
    pub challenge_id: String,
    pub policy_hash: Hash,
    pub module: String,
    pub statement_core_hash: Hash,
    pub allowed_axioms: Vec<String>,
    pub imports: IndependentCheckerChallengeImports,
    pub base_certificate: IndependentCheckerChallengeBaseCertificate,
    pub mutation: IndependentCheckerChallengeMutation,
    pub output: IndependentCheckerChallengeGenerationOutput,
    pub generated_by: IndependentCheckerChallengeGeneratedBy,
}

impl IndependentCheckerChallengeGenerationRequest {
    pub fn request_hash(&self) -> Hash {
        independent_checker_sha256(self.hash_input_canonical_json().as_bytes())
    }

    pub fn hash_input_canonical_json(&self) -> String {
        canonical_json_object_from_pairs(self.canonical_json_pairs_without_request_identity())
    }

    pub fn canonical_json(&self) -> String {
        let mut pairs = self.canonical_json_pairs_without_request_identity();
        pairs.push((
            "request_hash".to_owned(),
            independent_checker_hash_json_literal(&self.request_hash()),
        ));
        pairs.push((
            "request_id".to_owned(),
            independent_checker_json_string_literal(&self.request_id),
        ));
        canonical_json_object_from_pairs(pairs)
    }

    fn canonical_json_pairs_without_request_identity(&self) -> Vec<(String, String)> {
        vec![
            (
                "allowed_axioms".to_owned(),
                independent_checker_json_string_array(&self.allowed_axioms),
            ),
            (
                "base_certificate".to_owned(),
                self.base_certificate.canonical_json(),
            ),
            (
                "challenge_id".to_owned(),
                independent_checker_json_string_literal(&self.challenge_id),
            ),
            (
                "generated_by".to_owned(),
                self.generated_by.canonical_json(),
            ),
            ("imports".to_owned(), self.imports.canonical_json()),
            (
                "module".to_owned(),
                independent_checker_json_string_literal(&self.module),
            ),
            ("mutation".to_owned(), self.mutation.canonical_json()),
            ("output".to_owned(), self.output.canonical_json()),
            (
                "policy_hash".to_owned(),
                independent_checker_hash_json_literal(&self.policy_hash),
            ),
            (
                "schema".to_owned(),
                independent_checker_json_string_literal(
                    INDEPENDENT_CHECKER_CHALLENGE_GENERATION_REQUEST_SCHEMA,
                ),
            ),
            (
                "statement_core_hash".to_owned(),
                independent_checker_hash_json_literal(&self.statement_core_hash),
            ),
        ]
    }
}

