#[derive(Clone, Debug, PartialEq, Eq)]
pub struct IndependentCheckerCompareValidationResult {
    pub status: IndependentCheckerCompareValidationStatus,
    pub normalized_result_hash: Option<Hash>,
    pub policy_hash: Option<Hash>,
    pub embedded_comparison_status: Option<IndependentCheckerNormalizedComparisonStatus>,
    pub recomputed_comparison_status: Option<IndependentCheckerNormalizedComparisonStatus>,
    pub error: Option<IndependentCheckerCompareValidationError>,
}

impl IndependentCheckerCompareValidationResult {
    fn valid(
        normalized_result_hash: Hash,
        policy_hash: Hash,
        comparison_status: IndependentCheckerNormalizedComparisonStatus,
    ) -> Self {
        Self {
            status: IndependentCheckerCompareValidationStatus::Valid,
            normalized_result_hash: Some(normalized_result_hash),
            policy_hash: Some(policy_hash),
            embedded_comparison_status: Some(comparison_status),
            recomputed_comparison_status: Some(comparison_status),
            error: None,
        }
    }

    fn comparison_mismatch(
        normalized_result_hash: Hash,
        policy_hash: Hash,
        embedded_status: IndependentCheckerNormalizedComparisonStatus,
        recomputed_status: IndependentCheckerNormalizedComparisonStatus,
        expected_hash: Hash,
        actual_hash: Hash,
    ) -> Self {
        Self {
            status: IndependentCheckerCompareValidationStatus::Failed,
            normalized_result_hash: Some(normalized_result_hash),
            policy_hash: Some(policy_hash),
            embedded_comparison_status: Some(embedded_status),
            recomputed_comparison_status: Some(recomputed_status),
            error: Some(
                IndependentCheckerCompareValidationError::comparison_mismatch(
                    expected_hash,
                    actual_hash,
                ),
            ),
        }
    }

    pub fn canonical_json(&self) -> String {
        let mut pairs = vec![
            (
                "schema".to_owned(),
                independent_checker_json_string_literal(
                    INDEPENDENT_CHECKER_COMPARE_VALIDATION_RESULT_SCHEMA,
                ),
            ),
            (
                "status".to_owned(),
                independent_checker_json_string_literal(self.status.as_str()),
            ),
        ];
        if let Some(error) = &self.error {
            pairs.push(("error".to_owned(), error.canonical_json()));
        }
        push_optional_hash_pair(
            &mut pairs,
            "normalized_result_hash",
            self.normalized_result_hash,
        );
        push_optional_hash_pair(&mut pairs, "policy_hash", self.policy_hash);
        if let Some(status) = self.embedded_comparison_status {
            pairs.push((
                "embedded_comparison_status".to_owned(),
                independent_checker_json_string_literal(status.as_str()),
            ));
        }
        if let Some(status) = self.recomputed_comparison_status {
            pairs.push((
                "recomputed_comparison_status".to_owned(),
                independent_checker_json_string_literal(status.as_str()),
            ));
        }
        canonical_json_object_from_pairs(pairs)
    }
}

