/// AI-written audit note bound to an existing machine result or normalized
/// comparison.
///
/// Sidecars are untrusted explanatory metadata. They may be schema-checked,
/// cross-artifact checked, and used for diagnostics or training, but their text,
/// classification, and suggested actions are never a checker verdict.
#[derive(Clone, Debug, PartialEq, Eq)]
pub struct IndependentCheckerAiAuditSidecar {
    pub source: IndependentCheckerAiAuditSidecarSource,
    pub input_policy: IndependentCheckerAiAuditSidecarInputPolicy,
    pub ai: IndependentCheckerAiAuditSidecarAi,
    pub status: IndependentCheckerAiAuditSidecarStatus,
    pub classification: Option<IndependentCheckerAiAuditSidecarClassification>,
    pub summary: String,
    pub suggested_next_actions: Option<Vec<String>>,
    policy_gated_fields: BTreeMap<String, IndependentCheckerAiAuditPolicyGatedFieldValue>,
}

impl IndependentCheckerAiAuditSidecar {
    pub fn canonical_json(&self) -> String {
        let mut pairs = vec![
            ("ai".to_owned(), self.ai.canonical_json()),
            (
                "input_policy".to_owned(),
                self.input_policy.canonical_json(),
            ),
            (
                "schema".to_owned(),
                independent_checker_json_string_literal(
                    INDEPENDENT_CHECKER_AI_AUDIT_SIDECAR_SCHEMA,
                ),
            ),
            ("source".to_owned(), self.source.canonical_json()),
            (
                "status".to_owned(),
                independent_checker_json_string_literal(self.status.as_str()),
            ),
            (
                "summary".to_owned(),
                independent_checker_json_string_literal(&self.summary),
            ),
        ];
        if let Some(classification) = &self.classification {
            pairs.push(("classification".to_owned(), classification.canonical_json()));
        }
        if let Some(actions) = &self.suggested_next_actions {
            pairs.push((
                "suggested_next_actions".to_owned(),
                independent_checker_json_string_array(actions),
            ));
        }
        for (field, value) in &self.policy_gated_fields {
            pairs.push((field.clone(), value.canonical_json()));
        }
        canonical_json_object_from_pairs(pairs)
    }
}

