#[derive(Clone, Debug, PartialEq, Eq)]
pub enum IndependentCheckerRequiredAiSidecarDiagnosticTarget {
    MachineResult {
        result_index: usize,
        normalized_result_hash: Hash,
        checker_profile: String,
        request_hash: Hash,
        result_hash: Hash,
        policy_hash: Hash,
    },
    NormalizedComparison {
        normalized_result_hash: Hash,
    },
}

impl IndependentCheckerRequiredAiSidecarDiagnosticTarget {
    pub const fn kind(&self) -> IndependentCheckerRequiredAiSidecarDiagnosticTargetKind {
        match self {
            Self::MachineResult { .. } => {
                IndependentCheckerRequiredAiSidecarDiagnosticTargetKind::MachineResult
            }
            Self::NormalizedComparison { .. } => {
                IndependentCheckerRequiredAiSidecarDiagnosticTargetKind::NormalizedComparison
            }
        }
    }

    pub const fn normalized_result_hash(&self) -> Hash {
        match self {
            Self::MachineResult {
                normalized_result_hash,
                ..
            }
            | Self::NormalizedComparison {
                normalized_result_hash,
            } => *normalized_result_hash,
        }
    }
}

