pub struct IndependentCheckerNormalizationWriteStore {
    pub path: String,
    pub manifest_hash: Hash,
}

impl IndependentCheckerNormalizationWriteStore {
    fn canonical_json(&self) -> String {
        canonical_json_object_from_pairs(vec![
            (
                "kind".to_owned(),
                independent_checker_json_string_literal("manifest"),
            ),
            (
                "manifest_hash".to_owned(),
                independent_checker_hash_json_literal(&self.manifest_hash),
            ),
            (
                "path".to_owned(),
                independent_checker_json_string_literal(&self.path),
            ),
        ])
    }
}

#[derive(Clone, Debug, PartialEq, Eq)]
pub struct IndependentCheckerNormalizationWriteResult {
    pub normalized_result_hash: Hash,
    pub artifact_hash: Hash,
    pub output_path: String,
    pub output_file_hash: Hash,
    pub normalized_store: Option<IndependentCheckerNormalizationWriteStore>,
}

impl IndependentCheckerNormalizationWriteResult {
    pub fn canonical_json(&self) -> String {
        let mut pairs = vec![
            (
                "artifact_hash".to_owned(),
                independent_checker_hash_json_literal(&self.artifact_hash),
            ),
            (
                "normalized_result_hash".to_owned(),
                independent_checker_hash_json_literal(&self.normalized_result_hash),
            ),
            (
                "output_file_hash".to_owned(),
                independent_checker_hash_json_literal(&self.output_file_hash),
            ),
            (
                "output_path".to_owned(),
                independent_checker_json_string_literal(&self.output_path),
            ),
            (
                "schema".to_owned(),
                independent_checker_json_string_literal(
                    INDEPENDENT_CHECKER_NORMALIZATION_WRITE_RESULT_SCHEMA,
                ),
            ),
            (
                "status".to_owned(),
                independent_checker_json_string_literal("written"),
            ),
        ];
        if let Some(store) = &self.normalized_store {
            pairs.push(("normalized_store".to_owned(), store.canonical_json()));
        }
        canonical_json_object_from_pairs(pairs)
    }
}

