pub fn independent_checker_resolve_checker_executable(
    registry: &IndependentCheckerBinaryRegistry,
    selected: &IndependentCheckerAllowlistEntry,
    actual_binary_hash: Hash,
) -> Result<IndependentCheckerResolvedCheckerExecutable, IndependentCheckerPolicyFailure> {
    let Some(entry) = registry
        .entries
        .iter()
        .find(|entry| entry.binary_id == selected.binary_id)
    else {
        return Err(IndependentCheckerPolicyFailure::value_failure(
            IndependentCheckerPolicyFailureReasonCode::CheckerBinaryFileUnreadable,
            "checker.binary_id",
            "readable_executable",
            "binary_id_not_found",
        ));
    };

    if actual_binary_hash != selected.binary_hash {
        return Err(IndependentCheckerPolicyFailure::hash_failure(
            IndependentCheckerPolicyFailureReasonCode::CheckerBinaryHashMismatch,
            "checker.binary_hash",
            selected.binary_hash,
            actual_binary_hash,
        ));
    }

    Ok(IndependentCheckerResolvedCheckerExecutable {
        binary_id: entry.binary_id.clone(),
        path: entry.path.clone(),
        binary_hash: actual_binary_hash,
    })
}

pub fn independent_checker_validate_selected_checker_identity_manifest(
    selected: &IndependentCheckerAllowlistEntry,
    manifest: &IndependentCheckerIdentityManifest,
) -> Result<(), IndependentCheckerPolicyFailure> {
    let Some(entry) = manifest
        .checkers
        .iter()
        .find(|entry| entry.profile == selected.profile)
    else {
        return Err(IndependentCheckerPolicyFailure::value_failure(
            IndependentCheckerPolicyFailureReasonCode::CheckerIdentityMissing,
            "checker_identity_manifest.checkers[]",
            "selected_checker_profile",
            "missing",
        ));
    };

    if entry.checker_id != selected.checker_id {
        return Err(IndependentCheckerPolicyFailure::value_failure(
            IndependentCheckerPolicyFailureReasonCode::CheckerIdentityMismatch,
            "checker_identity_manifest.checkers[].checker_id",
            &selected.checker_id,
            &entry.checker_id,
        ));
    }
    if entry.binary_id != selected.binary_id {
        return Err(IndependentCheckerPolicyFailure::value_failure(
            IndependentCheckerPolicyFailureReasonCode::CheckerIdentityMismatch,
            "checker_identity_manifest.checkers[].binary_id",
            &selected.binary_id,
            &entry.binary_id,
        ));
    }
    if entry.binary_hash != selected.binary_hash {
        return Err(IndependentCheckerPolicyFailure::hash_failure(
            IndependentCheckerPolicyFailureReasonCode::CheckerBinaryHashMismatch,
            "checker_identity_manifest.checkers[].binary_hash",
            selected.binary_hash,
            entry.binary_hash,
        ));
    }
    if entry.build_hash != selected.build_hash {
        return Err(IndependentCheckerPolicyFailure::hash_failure(
            IndependentCheckerPolicyFailureReasonCode::CheckerBuildHashMismatch,
            "checker_identity_manifest.checkers[].build_hash",
            selected.build_hash,
            entry.build_hash,
        ));
    }

    Ok(())
}

pub fn independent_checker_argv(
    executable_path: &str,
    selected: &IndependentCheckerAllowlistEntry,
    dynamic: &IndependentCheckerRunnerDynamicArgs,
) -> Vec<String> {
    let mut argv = Vec::new();
    argv.push(executable_path.to_owned());
    argv.extend(selected.allowed_args.iter().cloned());
    argv.push("--cert".to_owned());
    argv.push(dynamic.certificate_path.clone());
    argv.push("--imports".to_owned());
    argv.push(dynamic.imports_manifest.clone());
    argv.push("--imports-hash".to_owned());
    argv.push(format_hash_string(&dynamic.imports_manifest_hash));
    argv.push("--policy".to_owned());
    argv.push(dynamic.policy_path.clone());
    argv.push("--policy-hash".to_owned());
    argv.push(format_hash_string(&dynamic.policy_hash));
    argv.push("--output".to_owned());
    argv.push("json".to_owned());
    argv
}

pub fn independent_checker_npa_checker_ext_argv(
    executable_path: &str,
    dynamic: &IndependentCheckerNpaCheckerExtDynamicArgs,
) -> Vec<String> {
    vec![
        executable_path.to_owned(),
        "--cert".to_owned(),
        dynamic.certificate_path.clone(),
        "--import-dir".to_owned(),
        dynamic.import_dir.clone(),
        "--policy".to_owned(),
        dynamic.policy_path.clone(),
        "--output".to_owned(),
        "json".to_owned(),
    ]
}

pub fn independent_checker_npa_checker_ext_launch_plan(
    resolved: &IndependentCheckerResolvedCheckerExecutable,
    request: &IndependentCheckerMachineCheckRequest,
    import_dir: impl Into<String>,
) -> IndependentCheckerRunnerLaunchPlan {
    let dynamic = IndependentCheckerNpaCheckerExtDynamicArgs {
        certificate_path: request.certificate.path.clone(),
        import_dir: import_dir.into(),
        policy_path: request.axiom_policy.clone(),
    };
    IndependentCheckerRunnerLaunchPlan {
        argv: independent_checker_npa_checker_ext_argv(&resolved.path, &dynamic),
        environment: independent_checker_runner_fixed_environment(),
        sandbox: independent_checker_runner_sandbox_policy(),
        budget: request.budget.clone(),
    }
}

pub fn independent_checker_runner_fixed_environment() -> Vec<(String, String)> {
    INDEPENDENT_CHECKER_RUNNER_FIXED_ENVIRONMENT
        .iter()
        .map(|(key, value)| ((*key).to_owned(), (*value).to_owned()))
        .collect()
}

pub fn independent_checker_runner_sandbox_policy() -> IndependentCheckerRunnerSandboxPolicy {
    IndependentCheckerRunnerSandboxPolicy {
        network: "forbidden".to_owned(),
        certificate_mount: "read_only".to_owned(),
        import_mount: "read_only".to_owned(),
        source_mount: "forbidden".to_owned(),
        plugin_loading: "forbidden".to_owned(),
        cwd: "runner_owned".to_owned(),
        environment: independent_checker_runner_fixed_environment(),
    }
}

