pub fn independent_checker_raw_certificate_claims(
    certificate_bytes: &[u8],
) -> Result<IndependentCheckerRawCertificateClaims, IndependentCheckerRawCertificateClaimError> {
    let module = independent_checker_raw_certificate_header_module(certificate_bytes)?;
    let certificate_hash = independent_checker_raw_claimed_certificate_hash(certificate_bytes)?;
    Ok(IndependentCheckerRawCertificateClaims {
        module,
        certificate_hash,
    })
}

pub fn independent_checker_raw_claimed_certificate_hash(
    certificate_bytes: &[u8],
) -> Result<Hash, IndependentCheckerRawCertificateClaimError> {
    let Some(hash_bytes) = certificate_bytes.get(certificate_bytes.len().saturating_sub(32)..)
    else {
        return Err(IndependentCheckerRawCertificateClaimError::DecodeFailed);
    };
    if certificate_bytes.len() < 32 {
        return Err(IndependentCheckerRawCertificateClaimError::DecodeFailed);
    }
    let mut hash = [0; 32];
    hash.copy_from_slice(hash_bytes);
    Ok(hash)
}

#[allow(clippy::too_many_arguments)]
pub fn independent_checker_request_materialize(
    policy: &IndependentCheckerRunnerPolicy,
    module: impl Into<String>,
    certificate_path: impl Into<String>,
    certificate_bytes: &[u8],
    imports_manifest_path: impl Into<String>,
    imports_manifest_bytes: &[u8],
    expected_imports_manifest_hash: Hash,
    checker_profile: impl Into<String>,
    request_id: impl Into<String>,
    output_request_path: impl Into<String>,
    existing_store: Option<&IndependentCheckerRequestStoreManifest>,
) -> Result<IndependentCheckerRequestMaterialization, IndependentCheckerCommandError> {
    let module = module.into();
    let certificate_path = certificate_path.into();
    let imports_manifest_path = imports_manifest_path.into();
    let checker_profile = checker_profile.into();
    let request_id = request_id.into();
    let output_request_path = output_request_path.into();

    validate_request_materialize_input_shape(
        &module,
        &checker_profile,
        &request_id,
        &certificate_path,
        &imports_manifest_path,
        &output_request_path,
    )?;

    let actual_imports_manifest_hash = independent_checker_file_hash(imports_manifest_bytes);
    if actual_imports_manifest_hash != expected_imports_manifest_hash {
        return Err(independent_checker_command_hash_error(
            IndependentCheckerCommandName::RequestMaterialize,
            "input_hash_mismatch",
            "imports.manifest_hash",
            expected_imports_manifest_hash,
            actual_imports_manifest_hash,
        ));
    }
    let import_lock_source = std::str::from_utf8(imports_manifest_bytes).map_err(|_| {
        independent_checker_command_value_error(
            IndependentCheckerCommandName::RequestMaterialize,
            "input_json_invalid",
            "imports.manifest",
            "valid_json",
            "invalid_json",
        )
    })?;
    parse_independent_checker_import_lock_manifest(import_lock_source).map_err(|error| {
        let field = error.field.to_string();
        independent_checker_command_error_from_request_validation(
            IndependentCheckerCommandName::RequestMaterialize,
            "input_schema_invalid",
            field,
            error,
        )
    })?;

    let selected_budget = policy.budgets.get(&checker_profile);
    if policy.selected_checker_policy(&checker_profile).is_none() || selected_budget.is_none() {
        return Err(independent_checker_command_value_error(
            IndependentCheckerCommandName::RequestMaterialize,
            "request_materialization_failed",
            "checker_profile",
            "required_or_optional_checker_profile",
            checker_profile,
        ));
    }

    let claims = independent_checker_raw_certificate_claims(certificate_bytes).map_err(|_| {
        independent_checker_command_value_error(
            IndependentCheckerCommandName::RequestMaterialize,
            "request_materialization_failed",
            "certificate.expected_certificate_hash",
            "raw_claimed_certificate_hash",
            "decode_failed",
        )
    })?;
    if claims.module != module {
        return Err(independent_checker_command_value_error(
            IndependentCheckerCommandName::RequestMaterialize,
            "request_materialization_failed",
            "module",
            module,
            claims.module,
        ));
    }

    let request = IndependentCheckerMachineCheckRequest {
        request_id,
        module,
        policy: IndependentCheckerMachineCheckRequestPolicy {
            id: policy.id.clone(),
            version: policy.version,
            hash: policy.policy_hash(),
        },
        certificate: IndependentCheckerMachineCheckRequestCertificate {
            path: certificate_path,
            file_hash: independent_checker_file_hash(certificate_bytes),
            expected_certificate_hash: claims.certificate_hash,
        },
        imports: IndependentCheckerMachineCheckRequestImports {
            mode: policy.import_policy.mode.clone(),
            manifest: imports_manifest_path,
            manifest_hash: expected_imports_manifest_hash,
        },
        checker_profile: checker_profile.clone(),
        trust_mode: policy.trust_mode,
        axiom_policy: policy.axiom_policy.path.clone(),
        budget: selected_budget
            .expect("selected budget checked above")
            .clone(),
    };
    let request_file_hash = independent_checker_file_hash(request.canonical_json().as_bytes());
    let generated_entry = IndependentCheckerRequestStoreEntry {
        request_hash: request.request_hash(),
        path: output_request_path,
        file_hash: request_file_hash,
    };
    let store_update =
        independent_checker_request_store_with_materialized_entry(existing_store, generated_entry)?;
    let request_store_file_hash = store_update.manifest.file_hash();

    Ok(IndependentCheckerRequestMaterialization {
        request,
        request_file_hash,
        request_store: store_update.manifest,
        request_store_file_hash,
        request_store_rewrite_required: store_update.rewrite_required,
    })
}

pub fn independent_checker_request_store_with_materialized_entry(
    existing_store: Option<&IndependentCheckerRequestStoreManifest>,
    generated_entry: IndependentCheckerRequestStoreEntry,
) -> Result<IndependentCheckerRequestStoreUpdate, IndependentCheckerCommandError> {
    independent_checker_request_store_with_materialized_entries(
        IndependentCheckerCommandName::RequestMaterialize,
        existing_store,
        std::slice::from_ref(&generated_entry),
    )
}

fn independent_checker_request_store_with_materialized_entries(
    command: IndependentCheckerCommandName,
    existing_store: Option<&IndependentCheckerRequestStoreManifest>,
    generated_entries: &[IndependentCheckerRequestStoreEntry],
) -> Result<IndependentCheckerRequestStoreUpdate, IndependentCheckerCommandError> {
    let mut manifest = existing_store
        .cloned()
        .unwrap_or(IndependentCheckerRequestStoreManifest {
            requests: Vec::new(),
        });
    let mut rewrite_required = false;

    for generated_entry in generated_entries {
        let mut exact_existing = false;
        for existing in &manifest.requests {
            let same_request_hash = existing.request_hash == generated_entry.request_hash;
            let same_path = existing.path == generated_entry.path;
            let same_file_hash = existing.file_hash == generated_entry.file_hash;
            if same_request_hash && same_path && same_file_hash {
                exact_existing = true;
                break;
            }
            if same_request_hash || same_path {
                return Err(independent_checker_command_value_error(
                    command,
                    "request_store_entry_conflict",
                    "request_store.requests[]",
                    generated_entry.canonical_json(),
                    existing.canonical_json(),
                ));
            }
        }
        if exact_existing {
            continue;
        }
        manifest.requests.push(generated_entry.clone());
        rewrite_required = true;
    }

    manifest.requests.sort_by_key(|entry| entry.request_hash);
    Ok(IndependentCheckerRequestStoreUpdate {
        manifest,
        rewrite_required,
    })
}

#[allow(clippy::too_many_arguments)]
pub fn independent_checker_challenge_generate(
    request: &IndependentCheckerChallengeGenerationRequest,
    policy: &IndependentCheckerRunnerPolicy,
    base_certificate_bytes: &[u8],
    imports_manifest_bytes: &[u8],
    existing_store: Option<&IndependentCheckerChallengeOutputStoreManifest>,
) -> Result<IndependentCheckerChallengeGeneration, IndependentCheckerCommandError> {
    validate_independent_checker_challenge_generation_request_domain(request).map_err(|error| {
        independent_checker_command_error_from_request_validation(
            IndependentCheckerCommandName::ChallengeGenerate,
            "generation_request_schema_invalid",
            error.field.to_string(),
            error,
        )
    })?;
    let request_hash = request.request_hash();
    let policy_hash = policy.policy_hash();
    if request.policy_hash != policy_hash {
        return Err(independent_checker_command_hash_error(
            IndependentCheckerCommandName::ChallengeGenerate,
            "policy_hash_mismatch",
            "policy_hash",
            policy_hash,
            request.policy_hash,
        ));
    }
    if request.imports.mode != policy.import_policy.mode {
        return Err(independent_checker_command_value_error(
            IndependentCheckerCommandName::ChallengeGenerate,
            "import_mode_mismatch",
            "imports.mode",
            &policy.import_policy.mode,
            &request.imports.mode,
        ));
    }
    let actual_import_hash = independent_checker_file_hash(imports_manifest_bytes);
    if actual_import_hash != request.imports.manifest_hash {
        return Err(independent_checker_command_hash_error(
            IndependentCheckerCommandName::ChallengeGenerate,
            "import_manifest_hash_mismatch",
            "imports.manifest_hash",
            request.imports.manifest_hash,
            actual_import_hash,
        ));
    }
    let imports_source = std::str::from_utf8(imports_manifest_bytes).map_err(|_| {
        independent_checker_command_value_error(
            IndependentCheckerCommandName::ChallengeGenerate,
            "import_manifest_file_unreadable",
            "imports.manifest",
            "valid_utf8_file",
            "unreadable",
        )
    })?;
    parse_independent_checker_import_lock_manifest(imports_source).map_err(|error| {
        let field = error.field.to_string();
        independent_checker_command_error_from_request_validation(
            IndependentCheckerCommandName::ChallengeGenerate,
            "generation_request_schema_invalid",
            field,
            error,
        )
    })?;

    let actual_base_file_hash = independent_checker_file_hash(base_certificate_bytes);
    if actual_base_file_hash != request.base_certificate.file_hash {
        return Err(independent_checker_command_hash_error(
            IndependentCheckerCommandName::ChallengeGenerate,
            "base_certificate_file_hash_mismatch",
            "base_certificate.file_hash",
            request.base_certificate.file_hash,
            actual_base_file_hash,
        ));
    }
    let actual_claimed_hash =
        independent_checker_raw_claimed_certificate_hash(base_certificate_bytes).map_err(|_| {
            independent_checker_command_value_error(
                IndependentCheckerCommandName::ChallengeGenerate,
                "base_certificate_claimed_hash_decode_failed",
                "base_certificate.claimed_certificate_hash",
                "raw_claimed_certificate_hash",
                "decode_failed",
            )
        })?;
    if actual_claimed_hash != request.base_certificate.claimed_certificate_hash {
        return Err(independent_checker_command_hash_error(
            IndependentCheckerCommandName::ChallengeGenerate,
            "base_certificate_claimed_hash_mismatch",
            "base_certificate.claimed_certificate_hash",
            request.base_certificate.claimed_certificate_hash,
            actual_claimed_hash,
        ));
    }

    let mutated_certificate_bytes =
        independent_checker_mutate_challenge_certificate_bytes(request, base_certificate_bytes)?;
    let mutated_file_hash = independent_checker_file_hash(&mutated_certificate_bytes);
    let mutated_claimed_certificate_hash =
        independent_checker_raw_claimed_certificate_hash(&mutated_certificate_bytes).ok();
    let known_kind = request
        .mutation
        .known_kind()
        .expect("generation request domain checked known mutation kind");
    let manifest = IndependentCheckerChallengeManifest {
        challenge_id: request.challenge_id.clone(),
        policy_hash: request.policy_hash,
        module: request.module.clone(),
        statement_core_hash: request.statement_core_hash,
        allowed_axioms: request.allowed_axioms.clone(),
        imports: request.imports.clone(),
        base_certificate: request.base_certificate.clone(),
        mutated_certificate: IndependentCheckerChallengeMutatedCertificate {
            path: request.output.mutated_certificate_path.clone(),
            file_hash: mutated_file_hash,
            claimed_certificate_hash: mutated_claimed_certificate_hash,
        },
        mutation: request.mutation.clone(),
        outcome_hint: IndependentCheckerChallengeOutcomeHint {
            status: "should_fail".to_owned(),
            error_kinds: known_kind.outcome_error_kinds(),
        },
        replay: IndependentCheckerChallengeReplayMetadata {
            generator: "npa-check challenge generate".to_owned(),
            generator_version: env!("CARGO_PKG_VERSION").to_owned(),
            generator_build_hash: independent_checker_sha256(
                INDEPENDENT_CHECKER_CHALLENGE_MANIFEST_SCHEMA.as_bytes(),
            ),
            args_hash: request_hash,
        },
        generated_by: request.generated_by.clone(),
    };
    let generated_entry = IndependentCheckerChallengeOutputStoreEntry {
        challenge_id: manifest.challenge_id.clone(),
        manifest_path: request.output.manifest_path.clone(),
        manifest_hash: manifest.manifest_hash(),
    };
    let store_update =
        independent_checker_challenge_output_store_with_entry(existing_store, generated_entry)?;
    let result = IndependentCheckerChallengeGenerationResult {
        status: "written".to_owned(),
        challenge_id: request.challenge_id.clone(),
        request_hash,
        policy_hash: request.policy_hash,
        challenge_manifest: IndependentCheckerChallengeManifestReference {
            path: request.output.manifest_path.clone(),
            manifest_hash: manifest.manifest_hash(),
        },
        mutated_certificate: IndependentCheckerChallengeGeneratedCertificate {
            path: request.output.mutated_certificate_path.clone(),
            file_hash: mutated_file_hash,
            claimed_certificate_hash: mutated_claimed_certificate_hash,
        },
        challenge_store: IndependentCheckerChallengeOutputStoreReference {
            path: request.output.store_manifest_path.clone(),
            manifest_hash: store_update.manifest.file_hash(),
        },
    };
    Ok(IndependentCheckerChallengeGeneration {
        result,
        manifest,
        mutated_certificate_bytes,
        challenge_store: store_update.manifest,
        challenge_store_rewrite_required: store_update.rewrite_required,
    })
}

pub fn independent_checker_challenge_manifest_expected_certificate_hash(
    manifest: &IndependentCheckerChallengeManifest,
) -> Hash {
    manifest
        .mutated_certificate
        .claimed_certificate_hash
        .unwrap_or(manifest.base_certificate.claimed_certificate_hash)
}

pub fn independent_checker_challenge_manifest_is_rejection_required(
    manifest: &IndependentCheckerChallengeManifest,
) -> bool {
    manifest
        .mutation
        .known_kind()
        .is_some_and(IndependentCheckerChallengeMutationKind::is_rejection_required)
}

fn independent_checker_policy_profiles_in_replay_order(
    policy: &IndependentCheckerRunnerPolicy,
) -> Vec<String> {
    let mut profiles = policy.required_checker_profiles.clone();
    profiles.extend(policy.optional_checker_profiles.iter().cloned());
    profiles
}

fn independent_checker_join_workspace_path(parent: &str, leaf: &str) -> String {
    let parent = parent.trim_end_matches('/');
    if parent.is_empty() {
        leaf.to_owned()
    } else {
        format!("{parent}/{leaf}")
    }
}

pub fn independent_checker_challenge_output_store_with_entry(
    existing_store: Option<&IndependentCheckerChallengeOutputStoreManifest>,
    generated_entry: IndependentCheckerChallengeOutputStoreEntry,
) -> Result<IndependentCheckerChallengeOutputStoreUpdate, IndependentCheckerCommandError> {
    let mut manifest =
        existing_store
            .cloned()
            .unwrap_or(IndependentCheckerChallengeOutputStoreManifest {
                entries: Vec::new(),
            });
    for existing in &manifest.entries {
        let same_challenge_id = existing.challenge_id == generated_entry.challenge_id;
        let same_manifest_path = existing.manifest_path == generated_entry.manifest_path;
        let exact = same_challenge_id
            && same_manifest_path
            && existing.manifest_hash == generated_entry.manifest_hash;
        if exact {
            return Ok(IndependentCheckerChallengeOutputStoreUpdate {
                manifest,
                rewrite_required: false,
            });
        }
        if same_challenge_id {
            return Err(independent_checker_command_value_error(
                IndependentCheckerCommandName::ChallengeGenerate,
                "challenge_id_conflict",
                "challenge_id",
                "unique_challenge_id",
                &generated_entry.challenge_id,
            ));
        }
        if same_manifest_path {
            return Err(independent_checker_command_value_error(
                IndependentCheckerCommandName::ChallengeGenerate,
                "challenge_output_store_entry_conflict",
                "challenge_output_store.entries[]",
                generated_entry.canonical_json(),
                existing.canonical_json(),
            ));
        }
    }
    manifest.entries.push(generated_entry);
    manifest
        .entries
        .sort_by_key(|entry| entry.challenge_id.clone());
    Ok(IndependentCheckerChallengeOutputStoreUpdate {
        manifest,
        rewrite_required: true,
    })
}

pub fn independent_checker_challenge_materialize_requests(
    manifest: &IndependentCheckerChallengeManifest,
    manifest_hash: Hash,
    policy: &IndependentCheckerRunnerPolicy,
    request_output_dir: impl Into<String>,
    request_store_output_path: impl Into<String>,
    existing_store: Option<&IndependentCheckerRequestStoreManifest>,
) -> Result<IndependentCheckerChallengeRequestMaterialization, IndependentCheckerCommandError> {
    let request_output_dir = request_output_dir.into();
    let request_store_output_path = request_store_output_path.into();
    validate_challenge_materialize_output_paths(&request_output_dir, &request_store_output_path)?;
    let policy_hash = policy.policy_hash();
    if manifest.policy_hash != policy_hash {
        return Err(independent_checker_command_hash_error(
            IndependentCheckerCommandName::ChallengeMaterializeRequests,
            "policy_hash_mismatch",
            "challenge_manifest.policy_hash",
            policy_hash,
            manifest.policy_hash,
        ));
    }
    if manifest.imports.mode != policy.import_policy.mode {
        return Err(independent_checker_command_value_error(
            IndependentCheckerCommandName::ChallengeMaterializeRequests,
            "import_mode_mismatch",
            "challenge_manifest.imports.mode",
            &policy.import_policy.mode,
            &manifest.imports.mode,
        ));
    }
    let mut generated_requests = Vec::new();
    let mut generated_entries = Vec::new();
    let mut result_entries = Vec::new();
    let expected_certificate_hash =
        independent_checker_challenge_manifest_expected_certificate_hash(manifest);
    let profiles = independent_checker_policy_profiles_in_replay_order(policy);
    for profile in profiles {
        let Some(selected_budget) = policy.budgets.get(&profile) else {
            return Err(independent_checker_command_value_error(
                IndependentCheckerCommandName::ChallengeMaterializeRequests,
                "policy_reference_invalid",
                "policy.budgets",
                "budget_for_checker_profile",
                profile,
            ));
        };
        let request_path = independent_checker_join_workspace_path(
            &request_output_dir,
            &format!("{profile}.json"),
        );
        if request_path == request_store_output_path {
            return Err(independent_checker_command_value_error(
                IndependentCheckerCommandName::ChallengeMaterializeRequests,
                "request_output_path_conflict",
                "request_store_output_path",
                "distinct_request_and_store_paths",
                "overlap",
            ));
        }
        let request = IndependentCheckerMachineCheckRequest {
            request_id: format!("chreq:{}:{profile}", manifest.challenge_id),
            module: manifest.module.clone(),
            policy: IndependentCheckerMachineCheckRequestPolicy {
                id: policy.id.clone(),
                version: policy.version,
                hash: policy_hash,
            },
            certificate: IndependentCheckerMachineCheckRequestCertificate {
                path: manifest.mutated_certificate.path.clone(),
                file_hash: manifest.mutated_certificate.file_hash,
                expected_certificate_hash,
            },
            imports: IndependentCheckerMachineCheckRequestImports {
                mode: manifest.imports.mode.clone(),
                manifest: manifest.imports.manifest.clone(),
                manifest_hash: manifest.imports.manifest_hash,
            },
            checker_profile: profile.clone(),
            trust_mode: policy.trust_mode,
            axiom_policy: policy.axiom_policy.path.clone(),
            budget: selected_budget.clone(),
        };
        let file_hash = independent_checker_file_hash(request.canonical_json().as_bytes());
        let request_hash = request.request_hash();
        generated_entries.push(IndependentCheckerRequestStoreEntry {
            request_hash,
            path: request_path.clone(),
            file_hash,
        });
        result_entries.push(IndependentCheckerChallengeMaterializedRequestEntry {
            checker_profile: profile,
            request_hash,
            path: request_path,
            file_hash,
        });
        generated_requests.push(request);
    }
    let store_update = independent_checker_request_store_with_materialized_entries(
        IndependentCheckerCommandName::ChallengeMaterializeRequests,
        existing_store,
        &generated_entries,
    )?;
    let result = IndependentCheckerChallengeRequestMaterializationResult {
        status: "written".to_owned(),
        challenge_id: manifest.challenge_id.clone(),
        manifest_hash,
        policy_hash,
        request_store: IndependentCheckerRequestStoreReference {
            path: request_store_output_path,
            manifest_hash: store_update.manifest.file_hash(),
        },
        requests: result_entries,
    };
    Ok(IndependentCheckerChallengeRequestMaterialization {
        result,
        requests: generated_requests,
        request_store: store_update.manifest,
        request_store_rewrite_required: store_update.rewrite_required,
    })
}

pub fn independent_checker_challenge_replay_store_entry_for_result(
    result: &IndependentCheckerChallengeReplayResult,
    path: impl Into<String>,
) -> Result<IndependentCheckerChallengeReplayStoreEntry, IndependentCheckerCommandError> {
    let path = path.into();
    if !independent_checker_valid_workspace_relative_path(&path) {
        return Err(independent_checker_command_value_error(
            IndependentCheckerCommandName::ChallengeReplay,
            "input_reference_invalid",
            "replay_result.path",
            "workspace_relative_path",
            "invalid_path",
        ));
    }
    let bytes = result.canonical_json();
    Ok(IndependentCheckerChallengeReplayStoreEntry {
        challenge_id: result.challenge_id.clone(),
        manifest_hash: result.manifest_hash,
        result_hash: result.result_hash(),
        artifact_hash: result.artifact_hash,
        path,
        file_hash: independent_checker_file_hash(bytes.as_bytes()),
    })
}

pub fn independent_checker_challenge_replay_store_with_entry(
    existing_store: Option<&IndependentCheckerChallengeReplayStoreManifest>,
    generated_entry: IndependentCheckerChallengeReplayStoreEntry,
) -> Result<IndependentCheckerChallengeReplayStoreUpdate, IndependentCheckerCommandError> {
    let mut manifest =
        existing_store
            .cloned()
            .unwrap_or(IndependentCheckerChallengeReplayStoreManifest {
                results: Vec::new(),
            });
    for existing in &manifest.results {
        let same_result_hash = existing.result_hash == generated_entry.result_hash;
        let same_path = existing.path == generated_entry.path;
        let same_challenge_manifest = existing.challenge_id == generated_entry.challenge_id
            && existing.manifest_hash == generated_entry.manifest_hash;
        let exact = same_result_hash
            && same_path
            && same_challenge_manifest
            && existing.artifact_hash == generated_entry.artifact_hash
            && existing.file_hash == generated_entry.file_hash;
        if exact {
            return Ok(IndependentCheckerChallengeReplayStoreUpdate {
                manifest,
                rewrite_required: false,
            });
        }
        if same_result_hash || same_path || same_challenge_manifest {
            return Err(independent_checker_command_value_error(
                IndependentCheckerCommandName::ChallengeReplay,
                "replay_store_entry_conflict",
                "replay_store.results[]",
                generated_entry.canonical_json(),
                existing.canonical_json(),
            ));
        }
    }
    manifest.results.push(generated_entry);
    manifest.results.sort_by_key(|entry| entry.result_hash);
    Ok(IndependentCheckerChallengeReplayStoreUpdate {
        manifest,
        rewrite_required: true,
    })
}

#[allow(clippy::too_many_arguments)]
pub fn independent_checker_challenge_replay_aggregate(
    result_id: impl Into<String>,
    manifest: &IndependentCheckerChallengeManifest,
    manifest_hash: Hash,
    policy: &IndependentCheckerRunnerPolicy,
    request_store: &IndependentCheckerRequestStoreManifest,
    stored_requests: &[IndependentCheckerStoredMachineCheckRequest],
    result_store: &IndependentCheckerMachineResultStoreManifest,
    machine_results: &[IndependentCheckerMachineCheckResult],
    normalized_store: Option<&IndependentCheckerNormalizedResultStoreManifest>,
    normalized_results: &[IndependentCheckerNormalizedCheckResult],
    coverage_required: bool,
    replay_output_path: impl Into<String>,
    existing_replay_store: Option<&IndependentCheckerChallengeReplayStoreManifest>,
) -> Result<IndependentCheckerChallengeReplayAggregation, IndependentCheckerCommandError> {
    let result_id = result_id.into();
    if !independent_checker_valid_request_id(&result_id) {
        return Err(independent_checker_command_value_error(
            IndependentCheckerCommandName::ChallengeReplay,
            "input_reference_invalid",
            "result_id",
            "result_id",
            if result_id.is_empty() {
                "empty_string"
            } else {
                "invalid_string_format"
            },
        ));
    }
    let replay_output_path = replay_output_path.into();
    if !independent_checker_valid_workspace_relative_path(&replay_output_path) {
        return Err(independent_checker_command_value_error(
            IndependentCheckerCommandName::ChallengeReplay,
            "input_reference_invalid",
            "replay_output_path",
            "workspace_relative_path",
            "invalid_path",
        ));
    }
    if manifest.manifest_hash() != manifest_hash {
        return Err(independent_checker_command_hash_error(
            IndependentCheckerCommandName::ChallengeReplay,
            "manifest_hash_mismatch",
            "challenge_manifest.manifest_hash",
            manifest.manifest_hash(),
            manifest_hash,
        ));
    }
    let policy_hash = policy.policy_hash();
    if manifest.policy_hash != policy_hash {
        return Err(independent_checker_command_hash_error(
            IndependentCheckerCommandName::ChallengeReplay,
            "policy_hash_mismatch",
            "challenge_manifest.policy_hash",
            policy_hash,
            manifest.policy_hash,
        ));
    }
    validate_request_store_domain(&request_store.requests, "request_store").map_err(|error| {
        independent_checker_command_error_from_request_validation(
            IndependentCheckerCommandName::ChallengeReplay,
            "request_store_manifest_invalid",
            error.field.to_string(),
            error,
        )
    })?;
    validate_machine_result_store_domain(&result_store.results, "result_store").map_err(
        |error| {
            independent_checker_command_error_from_request_validation(
                IndependentCheckerCommandName::ChallengeReplay,
                "result_store_manifest_invalid",
                error.field.to_string(),
                error,
            )
        },
    )?;
    if let Some(store) = normalized_store {
        validate_normalized_result_store_domain(&store.results, "normalized_store").map_err(
            |error| {
                independent_checker_command_error_from_request_validation(
                    IndependentCheckerCommandName::ChallengeReplay,
                    "normalized_store_manifest_invalid",
                    error.field.to_string(),
                    error,
                )
            },
        )?;
    } else if coverage_required {
        return Err(independent_checker_command_value_error(
            IndependentCheckerCommandName::ChallengeReplay,
            "normalized_store_required",
            "normalized_store",
            "explicit_normalized_store",
            "missing",
        ));
    }

    let expected_requests =
        independent_checker_expected_challenge_replay_requests(manifest, manifest_hash, policy)?;
    let baseline_request = expected_requests.first().ok_or_else(|| {
        independent_checker_command_value_error(
            IndependentCheckerCommandName::ChallengeReplay,
            "policy_reference_invalid",
            "policy.required_checker_profiles",
            "one_or_more_checker_profiles",
            "empty",
        )
    })?;
    let artifact_hash =
        IndependentCheckerNormalizedArtifact::from_request(baseline_request, policy)
            .artifact_hash();

    let mut checker_results = Vec::new();
    let mut included_machine_results = Vec::new();
    let mut missing_checker_profiles = Vec::new();
    for expected_request in &expected_requests {
        let profile = &expected_request.checker_profile;
        let required = policy.required_checker_profiles.contains(profile);
        let request_hash = expected_request.request_hash();
        let request_present = independent_checker_validate_challenge_replay_request_binding(
            request_store,
            stored_requests,
            expected_request,
        )?;
        if !request_present {
            if required {
                missing_checker_profiles.push(profile.clone());
            }
            continue;
        }
        let candidates = result_store
            .results
            .iter()
            .filter(|entry| entry.request_hash == request_hash && entry.checker_profile == *profile)
            .collect::<Vec<_>>();
        if candidates.len() > 1 {
            return Err(independent_checker_command_value_error(
                IndependentCheckerCommandName::ChallengeReplay,
                "result_attempt_ambiguous",
                "result_store.results[]",
                "at_most_one_result_per_request_profile",
                profile,
            ));
        }
        let Some(entry) = candidates.first().copied() else {
            if required {
                missing_checker_profiles.push(profile.clone());
            }
            continue;
        };
        let machine_result =
            independent_checker_resolve_replay_machine_result(entry, machine_results, policy_hash)?;
        checker_results.push(IndependentCheckerChallengeReplayCheckerResult {
            result_id: machine_result.result_id.clone(),
            result_hash: machine_result.result_hash(),
            run_artifact_hash: machine_result.run_artifact_hash(),
            checker_profile: machine_result.checker.profile.clone(),
        });
        included_machine_results.push(machine_result);
    }

    let mut observed_error_kinds = included_machine_results
        .iter()
        .filter_map(|result| result.error.as_ref().map(|error| error.kind.clone()))
        .collect::<Vec<_>>();
    observed_error_kinds.sort();
    observed_error_kinds.dedup();

    let normalized = independent_checker_resolve_challenge_replay_normalized_result(
        policy_hash,
        artifact_hash,
        &checker_results,
        normalized_store,
        normalized_results,
        coverage_required,
    )?;
    let (normalized_result_hash, comparison_status, artifact_hash) = match normalized {
        Some(result) => (
            Some(result.normalized_result_hash()),
            Some(result.comparison.status),
            result.artifact_hash(),
        ),
        None => (None, None, artifact_hash),
    };

    let result = IndependentCheckerChallengeReplayResult {
        result_id,
        challenge_id: manifest.challenge_id.clone(),
        manifest_hash,
        mutated_file_hash: manifest.mutated_certificate.file_hash,
        mutated_claimed_certificate_hash: manifest.mutated_certificate.claimed_certificate_hash,
        checker_results,
        missing_checker_profiles,
        normalized_result_hash,
        policy_hash,
        artifact_hash,
        comparison_status,
        observed_error_kinds,
    };
    let entry =
        independent_checker_challenge_replay_store_entry_for_result(&result, replay_output_path)?;
    let store_update =
        independent_checker_challenge_replay_store_with_entry(existing_replay_store, entry)?;
    Ok(IndependentCheckerChallengeReplayAggregation {
        result,
        replay_store: store_update.manifest,
        replay_store_rewrite_required: store_update.rewrite_required,
    })
}

#[allow(clippy::too_many_arguments)]
pub fn independent_checker_challenge_coverage_summary(
    policy: &IndependentCheckerRunnerPolicy,
    target_normalized_result: &IndependentCheckerNormalizedCheckResult,
    challenge_store: &IndependentCheckerChallengeOutputStoreManifest,
    challenge_manifests: &[IndependentCheckerChallengeManifest],
    replay_store: &IndependentCheckerChallengeReplayStoreManifest,
    replay_results: &[IndependentCheckerChallengeReplayResult],
    result_store: &IndependentCheckerMachineResultStoreManifest,
    machine_results: &[IndependentCheckerMachineCheckResult],
) -> Result<IndependentCheckerChallengeCoverageSummary, IndependentCheckerCommandError> {
    validate_challenge_output_store_domain(&challenge_store.entries, "challenge_store").map_err(
        |error| {
            independent_checker_command_error_from_request_validation(
                IndependentCheckerCommandName::ChallengeCoverageSummary,
                "challenge_store_manifest_invalid",
                error.field.to_string(),
                error,
            )
        },
    )?;
    validate_challenge_replay_store_domain(&replay_store.results, "replay_store").map_err(
        |error| {
            independent_checker_command_error_from_request_validation(
                IndependentCheckerCommandName::ChallengeCoverageSummary,
                "replay_store_manifest_invalid",
                error.field.to_string(),
                error,
            )
        },
    )?;
    validate_machine_result_store_domain(&result_store.results, "result_store").map_err(
        |error| {
            independent_checker_command_error_from_request_validation(
                IndependentCheckerCommandName::ChallengeCoverageSummary,
                "result_store_manifest_invalid",
                error.field.to_string(),
                error,
            )
        },
    )?;
    independent_checker_reject_duplicate_challenge_manifest_hashes(challenge_store)?;

    let policy_hash = policy.policy_hash();
    let target_artifact_hash = target_normalized_result.artifact_hash();
    let target_normalized_result_hash = target_normalized_result.normalized_result_hash();
    let mut entries = Vec::new();
    let mut unexpected_acceptances = 0_u64;

    for challenge_entry in &challenge_store.entries {
        let manifest = independent_checker_find_challenge_manifest(
            challenge_manifests,
            &challenge_entry.challenge_id,
            challenge_entry.manifest_hash,
        )?;
        independent_checker_validate_coverage_manifest_binding(
            manifest,
            challenge_entry,
            policy_hash,
            target_normalized_result,
        )?;
        let Some(replay_entry) = replay_store.results.iter().find(|entry| {
            entry.challenge_id == challenge_entry.challenge_id
                && entry.manifest_hash == challenge_entry.manifest_hash
        }) else {
            continue;
        };
        let replay_result =
            independent_checker_find_replay_result(replay_results, replay_entry.result_hash)?;
        independent_checker_validate_coverage_replay_binding(
            replay_result,
            replay_entry,
            manifest,
            policy_hash,
        )?;
        if replay_result.normalized_result_hash.is_none() {
            if replay_result.comparison_status.is_some() {
                return Err(independent_checker_command_value_error(
                    IndependentCheckerCommandName::ChallengeCoverageSummary,
                    "coverage_summary_generation_failed",
                    "replay_store.results[].comparison_status",
                    "absent_without_normalized_result_hash",
                    "present",
                ));
            }
            return Err(independent_checker_command_value_error(
                IndependentCheckerCommandName::ChallengeCoverageSummary,
                "coverage_summary_generation_failed",
                "replay_store.results[].normalized_result_hash",
                "required_for_coverage_summary",
                "missing",
            ));
        }
        let Some(comparison_status) = replay_result.comparison_status else {
            return Err(independent_checker_command_value_error(
                IndependentCheckerCommandName::ChallengeCoverageSummary,
                "coverage_summary_generation_failed",
                "replay_store.results[].comparison_status",
                "NormalizedCheckResult.comparison.status",
                "missing",
            ));
        };
        let required_checker_acceptance =
            independent_checker_replay_has_required_checker_acceptance(
                policy,
                replay_result,
                result_store,
                machine_results,
            )?;
        if comparison_status == IndependentCheckerNormalizedComparisonStatus::AllAgreeChecked
            || required_checker_acceptance
        {
            unexpected_acceptances += 1;
        }
        entries.push(IndependentCheckerChallengeCoverageEntry {
            challenge_id: challenge_entry.challenge_id.clone(),
            manifest_hash: challenge_entry.manifest_hash,
            replay_result_hash: replay_result.result_hash(),
            comparison_status,
        });
    }
    entries.sort_by(|left, right| {
        left.challenge_id
            .cmp(&right.challenge_id)
            .then_with(|| left.manifest_hash.cmp(&right.manifest_hash))
    });

    Ok(IndependentCheckerChallengeCoverageSummary::new(
        policy_hash,
        target_artifact_hash,
        target_normalized_result_hash,
        challenge_store.file_hash(),
        result_store.file_hash(),
        challenge_store.entries.len() as u64,
        unexpected_acceptances,
        entries,
    ))
}

fn independent_checker_challenge_coverage_summary_id(summary_hash: Hash) -> String {
    let wire = format_hash_string(&summary_hash);
    format!(
        "chcov_{}",
        wire.strip_prefix("sha256:")
            .expect("format_hash_string always prefixes sha256")
    )
}

pub fn independent_checker_performance_benchmark_summary(
    runner_policy: &IndependentCheckerRunnerPolicy,
    artifact_hash: Hash,
    target_normalized_result_hash: Hash,
    benchmark_class: IndependentCheckerPerformanceBenchmarkClass,
    machine_results: &[IndependentCheckerMachineCheckResult],
) -> Result<IndependentCheckerPerformanceBenchmarkSummary, IndependentCheckerPolicyValidationError>
{
    let mut rows = Vec::new();
    for result in machine_results {
        if !independent_checker_performance_benchmark_class_matches_profile(
            benchmark_class,
            &result.checker.profile,
        ) {
            continue;
        }
        let Some(budget) = runner_policy.budgets.get(&result.checker.profile) else {
            return Err(IndependentCheckerPolicyValidationError::new(
                format_budget_key_path(&result.checker.profile),
                "runner_budget_for_benchmark_profile",
                "missing",
            ));
        };
        rows.push(IndependentCheckerPerformanceBenchmarkRow::from_machine_result(result, budget));
    }

    Ok(IndependentCheckerPerformanceBenchmarkSummary::new(
        benchmark_class,
        runner_policy.policy_hash(),
        artifact_hash,
        target_normalized_result_hash,
        rows,
    ))
}

pub fn independent_checker_performance_benchmark_summary_hash(
    source: &str,
) -> Result<Hash, IndependentCheckerRequestValidationError> {
    Ok(parse_independent_checker_performance_benchmark_summary(source)?.summary_hash)
}

fn independent_checker_performance_benchmark_class_matches_profile(
    benchmark_class: IndependentCheckerPerformanceBenchmarkClass,
    profile: &str,
) -> bool {
    match benchmark_class {
        IndependentCheckerPerformanceBenchmarkClass::FastKernel => profile == "fast-kernel",
        IndependentCheckerPerformanceBenchmarkClass::ReferenceChecker => {
            matches!(profile, "reference" | "high-trust-reference")
        }
        IndependentCheckerPerformanceBenchmarkClass::ExternalChecker => {
            profile == NPA_CHECKER_EXT_PROFILE
        }
        IndependentCheckerPerformanceBenchmarkClass::MachineApi
        | IndependentCheckerPerformanceBenchmarkClass::TheoremIndexBuild
        | IndependentCheckerPerformanceBenchmarkClass::AiBenchmark => false,
    }
}

fn independent_checker_performance_benchmark_summary_id(summary_hash: Hash) -> String {
    let wire = format_hash_string(&summary_hash);
    format!(
        "bench_{}",
        wire.strip_prefix("sha256:")
            .expect("format_hash_string always prefixes sha256")
    )
}

fn independent_checker_performance_benchmark_row_cmp(
    left: &IndependentCheckerPerformanceBenchmarkRow,
    right: &IndependentCheckerPerformanceBenchmarkRow,
) -> Ordering {
    left.module
        .cmp(&right.module)
        .then_with(|| left.checker_profile.cmp(&right.checker_profile))
        .then_with(|| left.result_hash.cmp(&right.result_hash))
        .then_with(|| left.run_artifact_hash.cmp(&right.run_artifact_hash))
}

#[allow(clippy::too_many_arguments)]
fn canonical_json_coverage_summary_pairs(
    policy_hash: Hash,
    artifact_hash: Hash,
    target_normalized_result_hash: Hash,
    challenge_store_manifest_hash: Hash,
    result_store_manifest_hash: Hash,
    total_challenges: u64,
    replayed_challenges: u64,
    unexpected_acceptances: u64,
    entries: &[IndependentCheckerChallengeCoverageEntry],
) -> Vec<(String, String)> {
    vec![
        (
            "artifact_hash".to_owned(),
            independent_checker_hash_json_literal(&artifact_hash),
        ),
        (
            "challenge_store_manifest_hash".to_owned(),
            independent_checker_hash_json_literal(&challenge_store_manifest_hash),
        ),
        (
            "entries".to_owned(),
            canonical_json_array(
                entries
                    .iter()
                    .map(IndependentCheckerChallengeCoverageEntry::canonical_json)
                    .collect(),
            ),
        ),
        (
            "policy_hash".to_owned(),
            independent_checker_hash_json_literal(&policy_hash),
        ),
        (
            "replayed_challenges".to_owned(),
            replayed_challenges.to_string(),
        ),
        (
            "result_store_manifest_hash".to_owned(),
            independent_checker_hash_json_literal(&result_store_manifest_hash),
        ),
        (
            "schema".to_owned(),
            independent_checker_json_string_literal(
                INDEPENDENT_CHECKER_CHALLENGE_COVERAGE_SUMMARY_SCHEMA,
            ),
        ),
        (
            "target_normalized_result_hash".to_owned(),
            independent_checker_hash_json_literal(&target_normalized_result_hash),
        ),
        ("total_challenges".to_owned(), total_challenges.to_string()),
        (
            "unexpected_acceptances".to_owned(),
            unexpected_acceptances.to_string(),
        ),
    ]
}

fn independent_checker_expected_challenge_replay_requests(
    manifest: &IndependentCheckerChallengeManifest,
    manifest_hash: Hash,
    policy: &IndependentCheckerRunnerPolicy,
) -> Result<Vec<IndependentCheckerMachineCheckRequest>, IndependentCheckerCommandError> {
    Ok(independent_checker_challenge_materialize_requests(
        manifest,
        manifest_hash,
        policy,
        "build/challenge-replay-requests",
        "build/challenge-replay-requests/manifest.json",
        None,
    )?
    .requests)
}

fn independent_checker_validate_challenge_replay_request_binding(
    request_store: &IndependentCheckerRequestStoreManifest,
    stored_requests: &[IndependentCheckerStoredMachineCheckRequest],
    expected_request: &IndependentCheckerMachineCheckRequest,
) -> Result<bool, IndependentCheckerCommandError> {
    let request_hash = expected_request.request_hash();
    let Some(entry) = request_store
        .requests
        .iter()
        .find(|entry| entry.request_hash == request_hash)
    else {
        return Ok(false);
    };
    let Some(stored) = stored_requests
        .iter()
        .find(|stored| stored.request.request_hash() == request_hash)
    else {
        return Err(independent_checker_command_value_error(
            IndependentCheckerCommandName::ChallengeReplay,
            "request_store_entry_unreadable",
            "request_store.requests[].path",
            "readable",
            "unreadable",
        ));
    };
    if stored.path != entry.path {
        return Err(independent_checker_command_value_error(
            IndependentCheckerCommandName::ChallengeReplay,
            "request_store_entry_mismatch",
            "request_store.requests[].path",
            &entry.path,
            &stored.path,
        ));
    }
    if stored.file_hash != entry.file_hash {
        return Err(independent_checker_command_hash_error(
            IndependentCheckerCommandName::ChallengeReplay,
            "request_file_hash_mismatch",
            "request_store.requests[].file_hash",
            entry.file_hash,
            stored.file_hash,
        ));
    }
    let canonical_file_hash =
        independent_checker_file_hash(stored.request.canonical_json().as_bytes());
    if canonical_file_hash != stored.file_hash {
        return Err(independent_checker_command_hash_error(
            IndependentCheckerCommandName::ChallengeReplay,
            "request_file_hash_mismatch",
            "request_store.requests[].file_hash",
            canonical_file_hash,
            stored.file_hash,
        ));
    }
    if stored.request.request_hash() != expected_request.request_hash() {
        return Err(independent_checker_command_hash_error(
            IndependentCheckerCommandName::ChallengeReplay,
            "request_hash_mismatch",
            "request_hash",
            expected_request.request_hash(),
            stored.request.request_hash(),
        ));
    }
    Ok(true)
}

fn independent_checker_resolve_replay_machine_result<'a>(
    entry: &IndependentCheckerMachineResultStoreEntry,
    machine_results: &'a [IndependentCheckerMachineCheckResult],
    policy_hash: Hash,
) -> Result<&'a IndependentCheckerMachineCheckResult, IndependentCheckerCommandError> {
    let Some(result) = machine_results
        .iter()
        .find(|result| result.run_artifact_hash() == entry.run_artifact_hash)
    else {
        return Err(independent_checker_command_value_error(
            IndependentCheckerCommandName::ChallengeReplay,
            "machine_result_not_found",
            "result_store.results[].run_artifact_hash",
            "loaded_machine_result",
            "missing",
        ));
    };
    if let Err((field, expected, actual)) =
        independent_checker_validate_machine_result_for_normalization(result)
    {
        return Err(independent_checker_command_value_error(
            IndependentCheckerCommandName::ChallengeReplay,
            "machine_result_schema_invalid",
            field,
            expected,
            actual,
        ));
    }
    if result.result_hash() != entry.result_hash {
        return Err(independent_checker_command_hash_error(
            IndependentCheckerCommandName::ChallengeReplay,
            "machine_result_hash_mismatch",
            "result_store.results[].result_hash",
            entry.result_hash,
            result.result_hash(),
        ));
    }
    if result.request_hash != entry.request_hash {
        return Err(independent_checker_command_hash_error(
            IndependentCheckerCommandName::ChallengeReplay,
            "machine_result_request_hash_mismatch",
            "result_store.results[].request_hash",
            entry.request_hash,
            result.request_hash,
        ));
    }
    if result.checker.profile != entry.checker_profile {
        return Err(independent_checker_command_value_error(
            IndependentCheckerCommandName::ChallengeReplay,
            "machine_result_checker_profile_mismatch",
            "result_store.results[].checker_profile",
            &entry.checker_profile,
            &result.checker.profile,
        ));
    }
    if result.policy.hash != policy_hash {
        return Err(independent_checker_command_hash_error(
            IndependentCheckerCommandName::ChallengeReplay,
            "machine_result_policy_hash_mismatch",
            "machine_results[].policy.hash",
            policy_hash,
            result.policy.hash,
        ));
    }
    let canonical_file_hash = independent_checker_file_hash(result.canonical_json().as_bytes());
    if canonical_file_hash != entry.file_hash {
        return Err(independent_checker_command_hash_error(
            IndependentCheckerCommandName::ChallengeReplay,
            "machine_result_file_hash_mismatch",
            "result_store.results[].file_hash",
            entry.file_hash,
            canonical_file_hash,
        ));
    }
    Ok(result)
}

fn independent_checker_resolve_challenge_replay_normalized_result<'a>(
    policy_hash: Hash,
    artifact_hash: Hash,
    checker_results: &[IndependentCheckerChallengeReplayCheckerResult],
    normalized_store: Option<&IndependentCheckerNormalizedResultStoreManifest>,
    normalized_results: &'a [IndependentCheckerNormalizedCheckResult],
    coverage_required: bool,
) -> Result<Option<&'a IndependentCheckerNormalizedCheckResult>, IndependentCheckerCommandError> {
    let Some(store) = normalized_store else {
        return Ok(None);
    };
    let mut expected_hashes = checker_results
        .iter()
        .map(|result| result.result_hash)
        .collect::<Vec<_>>();
    expected_hashes.sort();
    expected_hashes.dedup();
    let mut matches = Vec::new();
    for normalized in normalized_results {
        let normalized_hash = normalized.normalized_result_hash();
        let Some(entry) = store
            .results
            .iter()
            .find(|entry| entry.normalized_result_hash == normalized_hash)
        else {
            continue;
        };
        if normalized.artifact_hash() != entry.artifact_hash {
            return Err(independent_checker_command_hash_error(
                IndependentCheckerCommandName::ChallengeReplay,
                "normalized_store_entry_artifact_hash_mismatch",
                "normalized_store.results[].artifact_hash",
                entry.artifact_hash,
                normalized.artifact_hash(),
            ));
        }
        let canonical_file_hash =
            independent_checker_file_hash(normalized.canonical_json().as_bytes());
        if canonical_file_hash != entry.file_hash {
            return Err(independent_checker_command_hash_error(
                IndependentCheckerCommandName::ChallengeReplay,
                "normalized_store_entry_file_hash_mismatch",
                "normalized_store.results[].file_hash",
                entry.file_hash,
                canonical_file_hash,
            ));
        }
        if normalized.policy.hash != policy_hash || normalized.artifact_hash() != artifact_hash {
            continue;
        }
        let mut actual_hashes = normalized
            .results
            .iter()
            .map(|entry| entry.result_hash)
            .collect::<Vec<_>>();
        actual_hashes.sort();
        actual_hashes.dedup();
        if actual_hashes == expected_hashes {
            matches.push(normalized);
        }
    }
    match matches.len() {
        0 if coverage_required => Err(independent_checker_command_value_error(
            IndependentCheckerCommandName::ChallengeReplay,
            "normalized_result_not_found",
            "normalized_store.results[]",
            "matching_normalized_result",
            "missing",
        )),
        0 => Ok(None),
        1 => Ok(Some(matches[0])),
        _ => Err(independent_checker_command_value_error(
            IndependentCheckerCommandName::ChallengeReplay,
            "normalized_result_ambiguous",
            "normalized_store.results[]",
            "unique_matching_normalized_result",
            "ambiguous",
        )),
    }
}

fn independent_checker_reject_duplicate_challenge_manifest_hashes(
    challenge_store: &IndependentCheckerChallengeOutputStoreManifest,
) -> Result<(), IndependentCheckerCommandError> {
    let mut seen = BTreeSet::new();
    for (index, entry) in challenge_store.entries.iter().enumerate() {
        if !seen.insert(entry.manifest_hash) {
            return Err(independent_checker_command_value_error(
                IndependentCheckerCommandName::ChallengeCoverageSummary,
                "coverage_summary_generation_failed",
                format!("challenge_store.entries[{index}].manifest_hash"),
                "unique_manifest_hashes",
                "duplicate_manifest_hash",
            ));
        }
    }
    Ok(())
}

fn independent_checker_find_challenge_manifest<'a>(
    manifests: &'a [IndependentCheckerChallengeManifest],
    challenge_id: &str,
    manifest_hash: Hash,
) -> Result<&'a IndependentCheckerChallengeManifest, IndependentCheckerCommandError> {
    let matches = manifests
        .iter()
        .filter(|manifest| {
            manifest.challenge_id == challenge_id && manifest.manifest_hash() == manifest_hash
        })
        .collect::<Vec<_>>();
    match matches.len() {
        1 => Ok(matches[0]),
        0 => Err(independent_checker_command_value_error(
            IndependentCheckerCommandName::ChallengeCoverageSummary,
            "coverage_summary_generation_failed",
            "challenge_store.entries[].manifest_hash",
            "loaded_challenge_manifest",
            "missing",
        )),
        _ => Err(independent_checker_command_value_error(
            IndependentCheckerCommandName::ChallengeCoverageSummary,
            "coverage_summary_generation_failed",
            "challenge_store.entries[].manifest_hash",
            "unique_loaded_challenge_manifest",
            "ambiguous",
        )),
    }
}

fn independent_checker_validate_coverage_manifest_binding(
    manifest: &IndependentCheckerChallengeManifest,
    challenge_entry: &IndependentCheckerChallengeOutputStoreEntry,
    policy_hash: Hash,
    target_normalized_result: &IndependentCheckerNormalizedCheckResult,
) -> Result<(), IndependentCheckerCommandError> {
    if manifest.challenge_id != challenge_entry.challenge_id {
        return Err(independent_checker_command_value_error(
            IndependentCheckerCommandName::ChallengeCoverageSummary,
            "coverage_summary_generation_failed",
            "challenge_store.entries[].challenge_id",
            &manifest.challenge_id,
            &challenge_entry.challenge_id,
        ));
    }
    if manifest.policy_hash != policy_hash {
        return Err(independent_checker_command_hash_error(
            IndependentCheckerCommandName::ChallengeCoverageSummary,
            "coverage_summary_generation_failed",
            "challenge_manifest.policy_hash",
            policy_hash,
            manifest.policy_hash,
        ));
    }
    if !independent_checker_challenge_manifest_is_rejection_required(manifest) {
        return Err(independent_checker_command_value_error(
            IndependentCheckerCommandName::ChallengeCoverageSummary,
            "coverage_summary_generation_failed",
            "challenge_manifest.mutation.kind",
            "rejection_required_challenge",
            &manifest.mutation.kind,
        ));
    }
    if manifest.base_certificate.file_hash != target_normalized_result.artifact.input_file_hash {
        return Err(independent_checker_command_hash_error(
            IndependentCheckerCommandName::ChallengeCoverageSummary,
            "coverage_summary_generation_failed",
            "challenge_manifest.base_certificate.file_hash",
            target_normalized_result.artifact.input_file_hash,
            manifest.base_certificate.file_hash,
        ));
    }
    if manifest.base_certificate.claimed_certificate_hash
        != target_normalized_result.artifact.expected_certificate_hash
    {
        return Err(independent_checker_command_hash_error(
            IndependentCheckerCommandName::ChallengeCoverageSummary,
            "coverage_summary_generation_failed",
            "challenge_manifest.base_certificate.claimed_certificate_hash",
            target_normalized_result.artifact.expected_certificate_hash,
            manifest.base_certificate.claimed_certificate_hash,
        ));
    }
    Ok(())
}

fn independent_checker_find_replay_result(
    replay_results: &[IndependentCheckerChallengeReplayResult],
    result_hash: Hash,
) -> Result<&IndependentCheckerChallengeReplayResult, IndependentCheckerCommandError> {
    let matches = replay_results
        .iter()
        .filter(|result| result.result_hash() == result_hash)
        .collect::<Vec<_>>();
    match matches.len() {
        1 => Ok(matches[0]),
        0 => Err(independent_checker_command_value_error(
            IndependentCheckerCommandName::ChallengeCoverageSummary,
            "coverage_summary_generation_failed",
            "replay_store.results[].result_hash",
            "loaded_challenge_replay_result",
            "missing",
        )),
        _ => Err(independent_checker_command_value_error(
            IndependentCheckerCommandName::ChallengeCoverageSummary,
            "coverage_summary_generation_failed",
            "replay_store.results[].result_hash",
            "unique_loaded_challenge_replay_result",
            "ambiguous",
        )),
    }
}

fn independent_checker_validate_coverage_replay_binding(
    replay_result: &IndependentCheckerChallengeReplayResult,
    replay_entry: &IndependentCheckerChallengeReplayStoreEntry,
    manifest: &IndependentCheckerChallengeManifest,
    policy_hash: Hash,
) -> Result<(), IndependentCheckerCommandError> {
    if replay_result.challenge_id != replay_entry.challenge_id {
        return Err(independent_checker_command_value_error(
            IndependentCheckerCommandName::ChallengeCoverageSummary,
            "coverage_summary_generation_failed",
            "replay_store.results[].challenge_id",
            &replay_entry.challenge_id,
            &replay_result.challenge_id,
        ));
    }
    if replay_result.manifest_hash != replay_entry.manifest_hash {
        return Err(independent_checker_command_hash_error(
            IndependentCheckerCommandName::ChallengeCoverageSummary,
            "coverage_summary_generation_failed",
            "replay_store.results[].manifest_hash",
            replay_entry.manifest_hash,
            replay_result.manifest_hash,
        ));
    }
    if replay_result.artifact_hash != replay_entry.artifact_hash {
        return Err(independent_checker_command_hash_error(
            IndependentCheckerCommandName::ChallengeCoverageSummary,
            "coverage_summary_generation_failed",
            "replay_store.results[].artifact_hash",
            replay_entry.artifact_hash,
            replay_result.artifact_hash,
        ));
    }
    let canonical_file_hash =
        independent_checker_file_hash(replay_result.canonical_json().as_bytes());
    if canonical_file_hash != replay_entry.file_hash {
        return Err(independent_checker_command_hash_error(
            IndependentCheckerCommandName::ChallengeCoverageSummary,
            "coverage_summary_generation_failed",
            "replay_store.results[].file_hash",
            replay_entry.file_hash,
            canonical_file_hash,
        ));
    }
    if replay_result.policy_hash != policy_hash {
        return Err(independent_checker_command_hash_error(
            IndependentCheckerCommandName::ChallengeCoverageSummary,
            "coverage_summary_generation_failed",
            "replay_result.policy_hash",
            policy_hash,
            replay_result.policy_hash,
        ));
    }
    if replay_result.mutated_file_hash != manifest.mutated_certificate.file_hash {
        return Err(independent_checker_command_hash_error(
            IndependentCheckerCommandName::ChallengeCoverageSummary,
            "coverage_summary_generation_failed",
            "replay_result.mutated_file_hash",
            manifest.mutated_certificate.file_hash,
            replay_result.mutated_file_hash,
        ));
    }
    match (
        manifest.mutated_certificate.claimed_certificate_hash,
        replay_result.mutated_claimed_certificate_hash,
    ) {
        (Some(expected), Some(actual)) if expected != actual => {
            Err(independent_checker_command_hash_error(
                IndependentCheckerCommandName::ChallengeCoverageSummary,
                "coverage_summary_generation_failed",
                "replay_result.mutated_claimed_certificate_hash",
                expected,
                actual,
            ))
        }
        (Some(_), None) => Err(independent_checker_command_value_error(
            IndependentCheckerCommandName::ChallengeCoverageSummary,
            "coverage_summary_generation_failed",
            "replay_result.mutated_claimed_certificate_hash",
            "sha256:<lower-hex>",
            "missing",
        )),
        (None, Some(_)) => Err(independent_checker_command_value_error(
            IndependentCheckerCommandName::ChallengeCoverageSummary,
            "coverage_summary_generation_failed",
            "replay_result.mutated_claimed_certificate_hash",
            "absent_when_manifest_omits_mutated_claimed_certificate_hash",
            "present",
        )),
        _ => Ok(()),
    }
}

fn independent_checker_replay_has_required_checker_acceptance(
    policy: &IndependentCheckerRunnerPolicy,
    replay_result: &IndependentCheckerChallengeReplayResult,
    result_store: &IndependentCheckerMachineResultStoreManifest,
    machine_results: &[IndependentCheckerMachineCheckResult],
) -> Result<bool, IndependentCheckerCommandError> {
    for checker_result in &replay_result.checker_results {
        if !policy
            .required_checker_profiles
            .contains(&checker_result.checker_profile)
        {
            continue;
        }
        let Some(store_entry) = result_store.results.iter().find(|entry| {
            entry.run_artifact_hash == checker_result.run_artifact_hash
                && entry.result_hash == checker_result.result_hash
                && entry.checker_profile == checker_result.checker_profile
        }) else {
            return Err(independent_checker_command_value_error(
                IndependentCheckerCommandName::ChallengeCoverageSummary,
                "coverage_summary_generation_failed",
                "result_store.results[].run_artifact_hash",
                "matching_machine_result_store_entry",
                "missing",
            ));
        };
        let Some(machine_result) = machine_results
            .iter()
            .find(|result| result.run_artifact_hash() == store_entry.run_artifact_hash)
        else {
            return Err(independent_checker_command_value_error(
                IndependentCheckerCommandName::ChallengeCoverageSummary,
                "coverage_summary_generation_failed",
                "machine_results[].run_artifact_hash",
                "loaded_machine_result",
                "missing",
            ));
        };
        if machine_result.result_hash() != checker_result.result_hash
            || machine_result.checker.profile != checker_result.checker_profile
        {
            return Err(independent_checker_command_value_error(
                IndependentCheckerCommandName::ChallengeCoverageSummary,
                "coverage_summary_generation_failed",
                "machine_results[]",
                "matching_replay_checker_result",
                "mismatch",
            ));
        }
        if machine_result.request_hash != store_entry.request_hash {
            return Err(independent_checker_command_hash_error(
                IndependentCheckerCommandName::ChallengeCoverageSummary,
                "coverage_summary_generation_failed",
                "result_store.results[].request_hash",
                store_entry.request_hash,
                machine_result.request_hash,
            ));
        }
        let canonical_file_hash =
            independent_checker_file_hash(machine_result.canonical_json().as_bytes());
        if canonical_file_hash != store_entry.file_hash {
            return Err(independent_checker_command_hash_error(
                IndependentCheckerCommandName::ChallengeCoverageSummary,
                "coverage_summary_generation_failed",
                "result_store.results[].file_hash",
                store_entry.file_hash,
                canonical_file_hash,
            ));
        }
        if machine_result.status == IndependentCheckerMachineCheckStatus::Checked {
            return Ok(true);
        }
    }
    Ok(false)
}

