pub fn independent_checker_machine_result_store_entry_for_result(
    result: &IndependentCheckerMachineCheckResult,
    path: impl Into<String>,
) -> Result<IndependentCheckerMachineResultStoreEntry, IndependentCheckerCommandError> {
    let path = path.into();
    if !independent_checker_valid_workspace_relative_path(&path) {
        return Err(independent_checker_command_value_error(
            IndependentCheckerCommandName::Run,
            "input_reference_invalid",
            "result.path",
            "workspace_relative_path",
            "invalid_path",
        ));
    }
    let bytes = result.canonical_json();
    Ok(IndependentCheckerMachineResultStoreEntry {
        result_hash: result.result_hash(),
        request_hash: result.request_hash,
        run_artifact_hash: result.run_artifact_hash(),
        checker_profile: result.checker.profile.clone(),
        path,
        file_hash: independent_checker_file_hash(bytes.as_bytes()),
    })
}

pub fn independent_checker_machine_result_store_with_entry(
    existing_store: Option<&IndependentCheckerMachineResultStoreManifest>,
    generated_entry: IndependentCheckerMachineResultStoreEntry,
) -> Result<IndependentCheckerMachineResultStoreUpdate, IndependentCheckerCommandError> {
    let mut manifest =
        existing_store
            .cloned()
            .unwrap_or(IndependentCheckerMachineResultStoreManifest {
                results: Vec::new(),
            });

    for existing in &manifest.results {
        let same_run_artifact_hash =
            existing.run_artifact_hash == generated_entry.run_artifact_hash;
        let same_path = existing.path == generated_entry.path;
        let exact = same_run_artifact_hash
            && same_path
            && existing.file_hash == generated_entry.file_hash
            && existing.result_hash == generated_entry.result_hash
            && existing.request_hash == generated_entry.request_hash
            && existing.checker_profile == generated_entry.checker_profile;
        if exact {
            return Ok(IndependentCheckerMachineResultStoreUpdate {
                manifest,
                rewrite_required: false,
            });
        }
        if same_run_artifact_hash || same_path {
            return Err(independent_checker_command_value_error(
                IndependentCheckerCommandName::Run,
                "result_store_entry_conflict",
                "result_store.results[]",
                generated_entry.canonical_json(),
                existing.canonical_json(),
            ));
        }
    }

    manifest.results.push(generated_entry);
    manifest
        .results
        .sort_by_key(|entry| entry.run_artifact_hash);
    Ok(IndependentCheckerMachineResultStoreUpdate {
        manifest,
        rewrite_required: true,
    })
}

