pub fn independent_checker_normalize_results(
    normalized_result_id: impl Into<String>,
    normalize_error_result_id: impl Into<String>,
    policy: &IndependentCheckerRunnerPolicy,
    request_store_manifest: &IndependentCheckerRequestStoreManifest,
    stored_requests: &[IndependentCheckerStoredMachineCheckRequest],
    machine_results: &[IndependentCheckerMachineCheckResult],
    selector: Option<IndependentCheckerArtifactSelector>,
) -> Result<IndependentCheckerNormalizedCheckResult, IndependentCheckerNormalizeErrorResult> {
    let normalized_result_id = normalized_result_id.into();
    let normalize_error_result_id = normalize_error_result_id.into();
    let policy_hash = policy.policy_hash();

    if !independent_checker_valid_request_id(&normalized_result_id) {
        return Err(independent_checker_normalize_value_error(
            normalize_error_result_id,
            policy_hash,
            IndependentCheckerNormalizeErrorReasonCode::SelectorSchemaInvalid,
            "normalized_result_id",
            "normalized_result_id",
            if normalized_result_id.is_empty() {
                "empty_string"
            } else {
                "invalid_string_format"
            },
        ));
    }

    if machine_results.is_empty() {
        return Err(independent_checker_normalize_value_error(
            normalize_error_result_id,
            policy_hash,
            IndependentCheckerNormalizeErrorReasonCode::SelectorAmbiguous,
            "machine_results",
            "one_or_more_machine_results",
            "empty",
        ));
    }

    if let Some(selector) = &selector {
        if !independent_checker_valid_dotted_name(&selector.module) {
            return Err(independent_checker_normalize_value_error(
                normalize_error_result_id,
                policy_hash,
                IndependentCheckerNormalizeErrorReasonCode::SelectorSchemaInvalid,
                "artifact_selector.module",
                "module_name",
                "invalid_name_format",
            ));
        }
    }

    if let Err(error) =
        validate_request_store_domain(&request_store_manifest.requests, "request_store")
    {
        return Err(independent_checker_normalize_request_validation_error(
            normalize_error_result_id,
            policy_hash,
            IndependentCheckerNormalizeErrorReasonCode::RequestStoreManifestInvalid,
            error,
        ));
    }

    let mut seen_profiles = BTreeSet::new();
    for result in machine_results {
        if !seen_profiles.insert(result.checker.profile.clone()) {
            return Err(independent_checker_normalize_value_error(
                normalize_error_result_id,
                policy_hash,
                IndependentCheckerNormalizeErrorReasonCode::DuplicateCheckerProfileResult,
                "machine_results[].checker.profile",
                "unique_checker_profile",
                &result.checker.profile,
            ));
        }
        if let Err((field, expected, actual)) =
            independent_checker_validate_machine_result_for_normalization(result)
        {
            return Err(independent_checker_normalize_value_error(
                normalize_error_result_id,
                policy_hash,
                IndependentCheckerNormalizeErrorReasonCode::MachineResultSchemaInvalid,
                field,
                expected,
                actual,
            ));
        }
    }

    let ordered_results =
        independent_checker_order_machine_results_for_normalization(policy, machine_results);
    let baseline_request_hash = if let Some(selector) = selector.as_ref() {
        selector.request_hash
    } else {
        let Some(required_baseline_profile) = policy.required_checker_profiles.first() else {
            return Err(independent_checker_normalize_value_error(
                normalize_error_result_id,
                policy_hash,
                IndependentCheckerNormalizeErrorReasonCode::SelectorAmbiguous,
                "artifact_selector",
                "baseline_required_checker_profile",
                "missing",
            ));
        };
        let Some(result) = machine_results
            .iter()
            .find(|result| &result.checker.profile == required_baseline_profile)
        else {
            return Err(independent_checker_normalize_value_error(
                normalize_error_result_id,
                policy_hash,
                IndependentCheckerNormalizeErrorReasonCode::SelectorAmbiguous,
                "artifact_selector",
                "single_baseline_result",
                "missing",
            ));
        };
        result.request_hash
    };

    let baseline_request = independent_checker_lookup_stored_request(
        request_store_manifest,
        stored_requests,
        baseline_request_hash,
        "artifact_selector.request_hash",
        normalize_error_result_id.clone(),
        policy_hash,
    )?;
    if let Some(selector) = selector.as_ref() {
        if selector.module != baseline_request.request.module {
            return Err(independent_checker_normalize_value_error(
                normalize_error_result_id,
                policy_hash,
                IndependentCheckerNormalizeErrorReasonCode::SelectorModuleMismatch,
                "artifact_selector.module",
                &baseline_request.request.module,
                &selector.module,
            ));
        }
    }

    let artifact =
        IndependentCheckerNormalizedArtifact::from_request(&baseline_request.request, policy);
    let mut entries = Vec::new();
    for result in ordered_results {
        let request = independent_checker_lookup_stored_request(
            request_store_manifest,
            stored_requests,
            result.request_hash,
            "machine_results[].request_hash",
            normalize_error_result_id.clone(),
            policy_hash,
        )?;
        let entry_artifact =
            IndependentCheckerNormalizedArtifact::from_request(&request.request, policy)
                .artifact_hash();
        let entry =
            independent_checker_normalized_entry_from_machine_result(result, entry_artifact);
        independent_checker_assert_normalized_entry_source_copy(&entry, result);
        entries.push(entry);
    }

    let normalized_policy = IndependentCheckerMachineCheckRequestPolicy {
        id: policy.id.clone(),
        version: policy.version,
        hash: policy_hash,
    };
    let comparison = independent_checker_build_normalized_comparison_parts(
        policy,
        normalized_policy.hash,
        artifact.artifact_hash(),
        &entries,
    );
    Ok(IndependentCheckerNormalizedCheckResult {
        normalized_result_id,
        artifact,
        policy: normalized_policy,
        results: entries,
        comparison,
    })
}

pub fn independent_checker_build_normalized_comparison(
    policy: &IndependentCheckerRunnerPolicy,
    normalized_result: &IndependentCheckerNormalizedCheckResult,
) -> IndependentCheckerNormalizedComparison {
    independent_checker_build_normalized_comparison_parts(
        policy,
        normalized_result.policy.hash,
        normalized_result.artifact_hash(),
        &normalized_result.results,
    )
}

pub fn independent_checker_compare_normalized_result(
    policy: &IndependentCheckerRunnerPolicy,
    normalized_result: &IndependentCheckerNormalizedCheckResult,
) -> IndependentCheckerCompareValidationResult {
    let policy_hash = policy.policy_hash();
    let recomputed = independent_checker_build_normalized_comparison(policy, normalized_result);
    let embedded_json = normalized_result.comparison.canonical_json();
    let recomputed_json = recomputed.canonical_json();
    if embedded_json == recomputed_json {
        IndependentCheckerCompareValidationResult::valid(
            normalized_result.normalized_result_hash(),
            policy_hash,
            normalized_result.comparison.status,
        )
    } else {
        IndependentCheckerCompareValidationResult::comparison_mismatch(
            normalized_result.normalized_result_hash(),
            policy_hash,
            normalized_result.comparison.status,
            recomputed.status,
            independent_checker_sha256(recomputed_json.as_bytes()),
            independent_checker_sha256(embedded_json.as_bytes()),
        )
    }
}

pub fn independent_checker_normalized_result_passes_ci_gate(
    policy: &IndependentCheckerRunnerPolicy,
    normalized_result: &IndependentCheckerNormalizedCheckResult,
    machine_results: &[IndependentCheckerMachineCheckResult],
) -> bool {
    let validation = independent_checker_compare_normalized_result(policy, normalized_result);
    if validation.status != IndependentCheckerCompareValidationStatus::Valid
        || validation.recomputed_comparison_status
            != Some(IndependentCheckerNormalizedComparisonStatus::AllAgreeChecked)
    {
        return false;
    }
    normalized_result.results.iter().all(|entry| {
        machine_results
            .iter()
            .filter(|result| {
                independent_checker_normalized_entry_matches_machine_result(entry, result)
            })
            .count()
            == 1
    })
}

pub fn independent_checker_normalized_disagreement_reports(
    normalized_result: &IndependentCheckerNormalizedCheckResult,
) -> Vec<IndependentCheckerNormalizedDisagreementReport> {
    let normalized_result_hash = normalized_result.normalized_result_hash();
    normalized_result
        .comparison
        .disagreements
        .iter()
        .map(|disagreement| {
            let actual_entry = normalized_result
                .results
                .iter()
                .find(|entry| entry.checker_profile == disagreement.checker_profile);
            let baseline_entry =
                disagreement
                    .baseline_checker_profile
                    .as_ref()
                    .and_then(|profile| {
                        normalized_result
                            .results
                            .iter()
                            .find(|entry| &entry.checker_profile == profile)
                    });
            IndependentCheckerNormalizedDisagreementReport {
                normalized_result_hash,
                module: normalized_result.artifact.module.clone(),
                declaration: actual_entry
                    .and_then(independent_checker_normalized_entry_declaration)
                    .or_else(|| {
                        baseline_entry.and_then(independent_checker_normalized_entry_declaration)
                    }),
                field: disagreement.field.clone(),
                checker_profile: disagreement.checker_profile.clone(),
                baseline_checker_profile: disagreement.baseline_checker_profile.clone(),
                certificate_hash: actual_entry
                    .and_then(|entry| entry.certificate_hash)
                    .or_else(|| baseline_entry.and_then(|entry| entry.certificate_hash))
                    .unwrap_or(normalized_result.artifact.expected_certificate_hash),
                comparison_status: normalized_result.comparison.status,
            }
        })
        .collect()
}

pub fn checker_disagreement_record_from_normalized_result(
    candidate_identity_hash: Hash,
    normalized_result: &IndependentCheckerNormalizedCheckResult,
) -> Result<CheckerDisagreementRecord, CheckerDisagreementRecordError> {
    if normalized_result.comparison.status
        != IndependentCheckerNormalizedComparisonStatus::Disagreement
    {
        return Err(
            CheckerDisagreementRecordError::NormalizedResultIsNotDisagreement {
                status: normalized_result.comparison.status,
            },
        );
    }

    let normalized_result_hash = normalized_result.normalized_result_hash();
    let mut compared_fields = normalized_result
        .comparison
        .disagreements
        .iter()
        .map(|disagreement| CheckerDisagreementComparedField {
            field: disagreement.field.clone(),
            expected_checker_profile: disagreement.baseline_checker_profile.clone(),
            actual_checker_profile: disagreement.checker_profile.clone(),
            expected_hash: disagreement.baseline_hash,
            actual_hash: disagreement.actual_hash,
            expected_value: disagreement.baseline_value.clone(),
            actual_value: disagreement.actual_value.clone(),
        })
        .collect::<Vec<_>>();
    checker_disagreement_sort_compared_fields(&mut compared_fields);
    if compared_fields.is_empty() {
        return Err(CheckerDisagreementRecordError::MissingComparedFields);
    }

    let mut checker_identities = normalized_result
        .results
        .iter()
        .map(|entry| CheckerDisagreementCheckerIdentity {
            checker_profile: entry.checker_profile.clone(),
            checker_id: entry.checker_id.clone(),
            checker_binary_id: entry.checker_binary_id.clone(),
            checker_binary_hash: entry.checker_binary_hash,
            checker_build_hash: entry.checker_build_hash,
            request_hash: entry.request_hash,
            result_hash: entry.result_hash,
        })
        .collect::<Vec<_>>();
    checker_disagreement_sort_checker_identities(&mut checker_identities);

    let mut import_hashes = vec![CheckerDisagreementImportHash {
        kind: CheckerDisagreementImportHashKind::ImportLock,
        hash: normalized_result.artifact.import_lock_hash,
    }];
    import_hashes.sort_by(|left, right| {
        left.kind
            .cmp(&right.kind)
            .then_with(|| left.hash.cmp(&right.hash))
    });

    let frozen_input_artifact_hashes = vec![
        CheckerDisagreementFrozenInputArtifact {
            kind: CheckerDisagreementFrozenInputKind::CandidateIdentity,
            hash: candidate_identity_hash,
        },
        CheckerDisagreementFrozenInputArtifact {
            kind: CheckerDisagreementFrozenInputKind::Certificate,
            hash: normalized_result.artifact.expected_certificate_hash,
        },
        CheckerDisagreementFrozenInputArtifact {
            kind: CheckerDisagreementFrozenInputKind::CertificateFile,
            hash: normalized_result.artifact.input_file_hash,
        },
        CheckerDisagreementFrozenInputArtifact {
            kind: CheckerDisagreementFrozenInputKind::ImportLock,
            hash: normalized_result.artifact.import_lock_hash,
        },
        CheckerDisagreementFrozenInputArtifact {
            kind: CheckerDisagreementFrozenInputKind::AxiomPolicy,
            hash: normalized_result.artifact.axiom_policy_hash,
        },
        CheckerDisagreementFrozenInputArtifact {
            kind: CheckerDisagreementFrozenInputKind::RunnerPolicy,
            hash: normalized_result.policy.hash,
        },
        CheckerDisagreementFrozenInputArtifact {
            kind: CheckerDisagreementFrozenInputKind::NormalizedResult,
            hash: normalized_result_hash,
        },
    ];

    Ok(CheckerDisagreementRecord {
        candidate_identity_hash,
        certificate_hash: normalized_result.artifact.expected_certificate_hash,
        import_hashes,
        policy_hash: normalized_result.policy.hash,
        checker_identities,
        compared_fields,
        frozen_input_artifact_hashes,
        normalized_result_hash,
        comparison_status: normalized_result.comparison.status,
        cache_invalidation_advisory: true,
        rerun_required_for_acceptance: true,
    })
}

fn checker_disagreement_sort_checker_identities(
    identities: &mut [CheckerDisagreementCheckerIdentity],
) {
    identities.sort_by(|left, right| {
        left.checker_profile
            .cmp(&right.checker_profile)
            .then_with(|| left.request_hash.cmp(&right.request_hash))
            .then_with(|| left.result_hash.cmp(&right.result_hash))
            .then_with(|| left.checker_id.cmp(&right.checker_id))
            .then_with(|| left.checker_binary_id.cmp(&right.checker_binary_id))
            .then_with(|| left.checker_binary_hash.cmp(&right.checker_binary_hash))
            .then_with(|| left.checker_build_hash.cmp(&right.checker_build_hash))
    });
}

fn checker_disagreement_sort_compared_fields(fields: &mut [CheckerDisagreementComparedField]) {
    fields.sort_by(|left, right| {
        left.field
            .cmp(&right.field)
            .then_with(|| {
                left.actual_checker_profile
                    .cmp(&right.actual_checker_profile)
            })
            .then_with(|| {
                left.expected_checker_profile
                    .cmp(&right.expected_checker_profile)
            })
            .then_with(|| left.expected_hash.cmp(&right.expected_hash))
            .then_with(|| left.actual_hash.cmp(&right.actual_hash))
            .then_with(|| left.expected_value.cmp(&right.expected_value))
            .then_with(|| left.actual_value.cmp(&right.actual_value))
    });
}

pub fn parse_independent_checker_release_policy(
    source: &str,
) -> Result<IndependentCheckerReleasePolicy, IndependentCheckerPolicyValidationError> {
    let document = JsonDocument::parse(source).map_err(|_| {
        IndependentCheckerPolicyValidationError::new("$", "valid_json", "invalid_json")
    })?;
    parse_independent_checker_release_policy_value(document.root())
}

pub fn independent_checker_release_policy_hash(
    source: &str,
) -> Result<Hash, IndependentCheckerPolicyValidationError> {
    Ok(parse_independent_checker_release_policy(source)?.policy_hash())
}

pub fn independent_checker_validate_release_policy_runner_trust(
    policy: &IndependentCheckerReleasePolicy,
    runner_policy: &IndependentCheckerRunnerPolicy,
    challenge_runner_policy: &IndependentCheckerRunnerPolicy,
) -> Result<(), IndependentCheckerPolicyValidationError> {
    let expected = policy.mode.trust_mode();
    if runner_policy.trust_mode != expected {
        return Err(IndependentCheckerPolicyValidationError::new(
            "runner_policy_hash",
            format!("RunnerPolicy.trust_mode:{}", policy.mode.as_str()),
            format!(
                "RunnerPolicy.trust_mode:{}",
                runner_policy.trust_mode.as_str()
            ),
        ));
    }
    if challenge_runner_policy.trust_mode != expected {
        return Err(IndependentCheckerPolicyValidationError::new(
            "challenge_runner_policy_hash",
            format!("RunnerPolicy.trust_mode:{}", policy.mode.as_str()),
            format!(
                "RunnerPolicy.trust_mode:{}",
                challenge_runner_policy.trust_mode.as_str()
            ),
        ));
    }
    Ok(())
}

pub fn parse_independent_checker_release_bundle_staging_plan(
    source: &str,
) -> Result<IndependentCheckerReleaseBundleStagingPlan, IndependentCheckerCommandError> {
    let document = JsonDocument::parse(source).map_err(|_| {
        independent_checker_release_stage_value_error(
            "input_json_invalid",
            "plan.path",
            "valid_json",
            "invalid_json",
        )
    })?;
    parse_independent_checker_release_bundle_staging_plan_value(document.root())
}

pub fn independent_checker_release_stage_bundle_inputs(
    phase: IndependentCheckerReleaseBundleStagingPhase,
    bundle_root: impl Into<String>,
    plan_path: impl Into<String>,
    plan_hash: Hash,
    plan_source: &str,
    workspace_files: &BTreeMap<String, Vec<u8>>,
    existing_bundle_files: Option<&BTreeMap<String, Vec<u8>>>,
) -> Result<IndependentCheckerReleaseBundleStaging, IndependentCheckerCommandError> {
    let bundle_root = bundle_root.into();
    let plan_path = plan_path.into();
    if !independent_checker_valid_workspace_relative_path(&plan_path) {
        return Err(independent_checker_release_stage_value_error(
            "input_reference_invalid",
            "plan.path",
            "workspace_relative_path",
            "invalid_path",
        ));
    }
    if !independent_checker_valid_workspace_relative_path(&bundle_root) {
        return Err(independent_checker_release_stage_value_error(
            "input_reference_invalid",
            "bundle_root",
            "workspace_relative_path",
            "invalid_path",
        ));
    }

    let actual_plan_hash = independent_checker_file_hash(plan_source.as_bytes());
    if actual_plan_hash != plan_hash {
        return Err(independent_checker_release_stage_hash_error(
            "input_hash_mismatch",
            "plan_hash",
            plan_hash,
            actual_plan_hash,
        ));
    }

    let plan = parse_independent_checker_release_bundle_staging_plan(plan_source)?;
    if plan.phase != phase {
        return Err(independent_checker_release_stage_value_error(
            "input_schema_invalid",
            "phase",
            format!("--phase:{}", phase.as_str()),
            format!("plan.phase:{}", plan.phase.as_str()),
        ));
    }
    if plan.bundle_root != bundle_root {
        return Err(independent_checker_release_stage_value_error(
            "input_schema_invalid",
            "bundle_root",
            format!("--bundle-root:{bundle_root}"),
            format!("plan.bundle_root:{}", plan.bundle_root),
        ));
    }

    let mut staged_files = BTreeMap::<String, Vec<u8>>::new();
    let mut staged_artifacts = Vec::<IndependentCheckerReleaseBundleStagedArtifact>::new();
    let mut request_entries = BTreeMap::<Hash, IndependentCheckerRequestStoreEntry>::new();
    let mut machine_entries = BTreeMap::<Hash, IndependentCheckerMachineResultStoreEntry>::new();
    let mut normalized_entries =
        BTreeMap::<Hash, IndependentCheckerNormalizedResultStoreEntry>::new();

    for (index, input) in plan.inputs.iter().enumerate() {
        let source_bytes = workspace_files.get(&input.path).ok_or_else(|| {
            independent_checker_release_stage_value_error(
                "input_file_unreadable",
                format!("inputs[{index}].path"),
                "readable_file",
                "missing",
            )
        })?;
        let actual_file_hash = independent_checker_file_hash(source_bytes);
        if actual_file_hash != input.file_hash {
            return Err(independent_checker_release_stage_hash_error(
                "input_hash_mismatch",
                format!("inputs[{index}].file_hash"),
                input.file_hash,
                actual_file_hash,
            ));
        }
        if input.kind.is_binary_certificate_artifact() {
            independent_checker_release_validate_direct_certificate_artifact(
                input,
                index,
                source_bytes,
            )?;
            independent_checker_release_stage_file(
                input.kind,
                input.file_hash,
                source_bytes,
                existing_bundle_files,
                &mut staged_files,
                &mut staged_artifacts,
            )?;
            continue;
        }
        let input_json_reason = if input.kind.is_store_source_manifest()
            || input.kind
                == IndependentCheckerReleaseBundleArtifactKind::ChallengeOutputStoreManifest
        {
            "input_store_manifest_invalid"
        } else {
            "input_json_invalid"
        };
        let source = independent_checker_release_stage_utf8(
            source_bytes,
            input_json_reason,
            format!("inputs[{index}].path"),
        )?;

        if input.kind.is_store_source_manifest() {
            independent_checker_release_validate_planned_hash(
                input,
                index,
                "manifest_hash",
                input.file_hash,
            )?;
            match input.kind {
                IndependentCheckerReleaseBundleArtifactKind::RequestStoreManifest => {
                    let manifest = parse_independent_checker_request_store_manifest(source)
                        .map_err(|error| {
                            independent_checker_release_stage_store_manifest_error(
                                index, input.kind, error,
                            )
                        })?;
                    independent_checker_release_stage_request_manifest_entries(
                        index,
                        &manifest,
                        workspace_files,
                        existing_bundle_files,
                        &mut staged_files,
                        &mut staged_artifacts,
                        &mut request_entries,
                    )?;
                }
                IndependentCheckerReleaseBundleArtifactKind::MachineResultStoreManifest => {
                    let manifest = parse_independent_checker_machine_result_store_manifest(source)
                        .map_err(|error| {
                            independent_checker_release_stage_store_manifest_error(
                                index, input.kind, error,
                            )
                        })?;
                    independent_checker_release_stage_machine_manifest_entries(
                        index,
                        &manifest,
                        workspace_files,
                        existing_bundle_files,
                        &mut staged_files,
                        &mut staged_artifacts,
                        &mut machine_entries,
                    )?;
                }
                IndependentCheckerReleaseBundleArtifactKind::NormalizedResultStoreManifest => {
                    let manifest =
                        parse_independent_checker_normalized_result_store_manifest(source)
                            .map_err(|error| {
                                independent_checker_release_stage_store_manifest_error(
                                    index, input.kind, error,
                                )
                            })?;
                    independent_checker_release_stage_normalized_manifest_entries(
                        index,
                        &manifest,
                        workspace_files,
                        existing_bundle_files,
                        &mut staged_files,
                        &mut staged_artifacts,
                        &mut normalized_entries,
                    )?;
                }
                _ => unreachable!("store source manifest predicate is exhaustive"),
            }
            continue;
        }

        independent_checker_release_validate_direct_artifact(input, index, source)?;
        independent_checker_release_stage_file(
            input.kind,
            input.file_hash,
            source_bytes,
            existing_bundle_files,
            &mut staged_files,
            &mut staged_artifacts,
        )?;
    }

    let mut store_manifests = Vec::new();
    if phase == IndependentCheckerReleaseBundleStagingPhase::Store {
        let request_manifest = IndependentCheckerRequestStoreManifest {
            requests: request_entries.into_values().collect(),
        };
        let machine_manifest = IndependentCheckerMachineResultStoreManifest {
            results: machine_entries.into_values().collect(),
        };
        let normalized_manifest = IndependentCheckerNormalizedResultStoreManifest {
            results: normalized_entries.into_values().collect(),
        };
        independent_checker_release_stage_generated_store_manifest(
            IndependentCheckerReleaseBundleArtifactKind::RequestStoreManifest,
            request_manifest.canonical_json(),
            existing_bundle_files,
            &mut staged_files,
            &mut store_manifests,
        )?;
        independent_checker_release_stage_generated_store_manifest(
            IndependentCheckerReleaseBundleArtifactKind::MachineResultStoreManifest,
            machine_manifest.canonical_json(),
            existing_bundle_files,
            &mut staged_files,
            &mut store_manifests,
        )?;
        independent_checker_release_stage_generated_store_manifest(
            IndependentCheckerReleaseBundleArtifactKind::NormalizedResultStoreManifest,
            normalized_manifest.canonical_json(),
            existing_bundle_files,
            &mut staged_files,
            &mut store_manifests,
        )?;
    }

    staged_artifacts.sort_by(|left, right| {
        (left.kind.as_str(), left.path.as_str(), left.file_hash).cmp(&(
            right.kind.as_str(),
            right.path.as_str(),
            right.file_hash,
        ))
    });
    store_manifests.sort_by(|left, right| {
        (left.kind.as_str(), left.path.as_str(), left.manifest_hash).cmp(&(
            right.kind.as_str(),
            right.path.as_str(),
            right.manifest_hash,
        ))
    });

    let files = staged_files
        .into_iter()
        .map(|(path, bytes)| IndependentCheckerReleaseBundleStagedFile { path, bytes })
        .collect();
    Ok(IndependentCheckerReleaseBundleStaging {
        result: IndependentCheckerReleaseBundleStagingResult {
            phase,
            bundle_root,
            staged_artifacts,
            store_manifests,
        },
        files,
    })
}

pub fn parse_independent_checker_release_audit_bundle_manifest(
    source: &str,
) -> Result<IndependentCheckerReleaseAuditBundleManifest, IndependentCheckerCommandError> {
    let manifest = parse_independent_checker_release_audit_bundle_manifest_unchecked(source)?;
    independent_checker_validate_release_audit_bundle_manifest_identity(&manifest).map_err(
        |error| {
            independent_checker_release_validate_bundle_audit_error_to_command(
                "input_schema_invalid",
                error,
            )
        },
    )?;
    independent_checker_validate_release_audit_bundle_artifact_order(&manifest.artifacts).map_err(
        |error| {
            independent_checker_release_validate_bundle_audit_error_to_command(
                "input_schema_invalid",
                error,
            )
        },
    )?;
    Ok(manifest)
}

pub fn independent_checker_release_bundle(
    bundle_root: impl Into<String>,
    out_path: impl Into<String>,
    artifact_hash: Hash,
    inputs: &[IndependentCheckerReleaseAuditBundleArtifact],
    bundle_files: &BTreeMap<String, Vec<u8>>,
    existing_out: Option<&[u8]>,
) -> Result<IndependentCheckerReleaseBundleGeneration, IndependentCheckerCommandError> {
    let bundle_root = bundle_root.into();
    let out_path = out_path.into();
    if !independent_checker_valid_workspace_relative_path(&bundle_root) {
        return Err(independent_checker_release_bundle_value_error(
            "input_reference_invalid",
            "bundle_root",
            "workspace_relative_path",
            "invalid_path",
        ));
    }
    if !independent_checker_valid_workspace_relative_path(&out_path) {
        return Err(independent_checker_release_bundle_value_error(
            "input_reference_invalid",
            "out",
            "workspace_relative_path",
            "invalid_path",
        ));
    }
    let expected_out_path = format!("{bundle_root}/manifest.json");
    if out_path != expected_out_path {
        return Err(independent_checker_release_bundle_value_error(
            "input_reference_invalid",
            "out",
            expected_out_path,
            out_path,
        ));
    }

    let mut artifacts = inputs.to_vec();
    artifacts.sort_by(|left, right| {
        (left.kind.as_str(), left.path.as_str()).cmp(&(right.kind.as_str(), right.path.as_str()))
    });
    independent_checker_validate_release_audit_bundle_artifact_order(&artifacts).map_err(
        |error| {
            independent_checker_release_bundle_audit_error_to_command(
                "release_bundle_generation_failed",
                error,
            )
        },
    )?;
    independent_checker_validate_release_audit_bundle_artifact_files(&artifacts, bundle_files)
        .map_err(|error| {
            independent_checker_release_bundle_audit_error_to_command(
                "release_bundle_generation_failed",
                error,
            )
        })?;

    let policy_hash =
        independent_checker_release_audit_bundle_policy_hash_from_inputs(&artifacts, bundle_files)?;
    let manifest =
        IndependentCheckerReleaseAuditBundleManifest::new(policy_hash, artifact_hash, artifacts);
    independent_checker_validate_release_audit_bundle_closed_set(&manifest, bundle_files).map_err(
        |error| {
            independent_checker_release_bundle_audit_error_to_command(
                "release_bundle_generation_failed",
                error,
            )
        },
    )?;

    let bytes = manifest.canonical_json().into_bytes();
    let out_rewrite_required = match existing_out {
        Some(existing) if existing == bytes.as_slice() => false,
        Some(_) => {
            return Err(independent_checker_release_bundle_value_error(
                "output_path_conflict",
                "out",
                "absent_or_exact_match",
                "different_bytes",
            ))
        }
        None => true,
    };
    Ok(IndependentCheckerReleaseBundleGeneration {
        manifest,
        bytes,
        out_rewrite_required,
    })
}

pub fn independent_checker_release_validate_bundle(
    manifest_path: impl Into<String>,
    manifest_hash: Hash,
    manifest_source: &str,
    bundle_files: &BTreeMap<String, Vec<u8>>,
    existing_out: Option<&[u8]>,
) -> Result<IndependentCheckerReleaseBundleValidation, IndependentCheckerCommandError> {
    let manifest_path = manifest_path.into();
    if !independent_checker_valid_workspace_relative_path(&manifest_path) {
        return Err(independent_checker_release_validate_bundle_value_error(
            "input_reference_invalid",
            "manifest.path",
            "workspace_relative_path",
            "invalid_path",
        ));
    }
    let actual_manifest_hash = independent_checker_file_hash(manifest_source.as_bytes());
    if actual_manifest_hash != manifest_hash {
        return Err(independent_checker_release_validate_bundle_hash_error(
            "input_hash_mismatch",
            "manifest_hash",
            manifest_hash,
            actual_manifest_hash,
        ));
    }

    let manifest =
        parse_independent_checker_release_audit_bundle_manifest_unchecked(manifest_source)?;
    let validation = independent_checker_validate_release_audit_bundle_manifest_identity(&manifest)
        .and_then(|_| {
            independent_checker_validate_release_audit_bundle_artifact_order(&manifest.artifacts)
        })
        .and_then(|_| {
            independent_checker_validate_release_audit_bundle_artifact_files(
                &manifest.artifacts,
                bundle_files,
            )
        })
        .and_then(|_| {
            independent_checker_validate_release_audit_bundle_closed_set(&manifest, bundle_files)
        });

    let result = match validation {
        Ok(()) => IndependentCheckerAuxiliaryResult::passed(
            independent_checker_release_audit_bundle_auxiliary_result_id(manifest.bundle_hash),
            IndependentCheckerAuxiliaryResultKind::AuditBundle,
            manifest.policy_hash,
            manifest.bundle_hash,
            None,
        ),
        Err(error) => IndependentCheckerAuxiliaryResult::failed(
            independent_checker_release_audit_bundle_auxiliary_result_id(manifest.bundle_hash),
            IndependentCheckerAuxiliaryResultKind::AuditBundle,
            manifest.policy_hash,
            manifest.bundle_hash,
            None,
            error.into_auxiliary_error(),
        ),
    };
    let result_bytes = result.canonical_json().into_bytes();
    let out_rewrite_required = match existing_out {
        Some(existing) if existing == result_bytes.as_slice() => false,
        Some(_) => {
            return Err(independent_checker_release_validate_bundle_value_error(
                "output_path_conflict",
                "out",
                "absent_or_exact_match",
                "different_bytes",
            ))
        }
        None => true,
    };
    Ok(IndependentCheckerReleaseBundleValidation {
        result,
        out_rewrite_required,
    })
}

#[allow(clippy::too_many_arguments)]
pub fn independent_checker_training_export(
    normalized_store_path: impl Into<String>,
    normalized_store_manifest_hash: Hash,
    normalized_store_source: &str,
    result_store_path: impl Into<String>,
    result_store_manifest_hash: Hash,
    result_store_source: &str,
    workspace_files: &BTreeMap<String, Vec<u8>>,
    out_path: impl Into<String>,
    manifest_out_path: impl Into<String>,
    existing_out: Option<&[u8]>,
    existing_manifest_out: Option<&[u8]>,
) -> Result<IndependentCheckerTrainingExport, IndependentCheckerCommandError> {
    let normalized_store_path = normalized_store_path.into();
    let result_store_path = result_store_path.into();
    let out_path = out_path.into();
    let manifest_out_path = manifest_out_path.into();
    independent_checker_training_export_validate_path(
        "normalized_store.path",
        &normalized_store_path,
    )?;
    independent_checker_training_export_validate_path("result_store.path", &result_store_path)?;
    independent_checker_training_export_validate_path("out.path", &out_path)?;
    independent_checker_training_export_validate_path("manifest_out.path", &manifest_out_path)?;

    let actual_normalized_store_hash =
        independent_checker_file_hash(normalized_store_source.as_bytes());
    if actual_normalized_store_hash != normalized_store_manifest_hash {
        return Err(independent_checker_training_export_hash_error(
            "input_hash_mismatch",
            "normalized_store.manifest_hash",
            normalized_store_manifest_hash,
            actual_normalized_store_hash,
        ));
    }
    let actual_result_store_hash = independent_checker_file_hash(result_store_source.as_bytes());
    if actual_result_store_hash != result_store_manifest_hash {
        return Err(independent_checker_training_export_hash_error(
            "input_hash_mismatch",
            "result_store.manifest_hash",
            result_store_manifest_hash,
            actual_result_store_hash,
        ));
    }

    let normalized_store =
        match parse_independent_checker_normalized_result_store_manifest(normalized_store_source) {
            Ok(store) => store,
            Err(error) => {
                return Err(independent_checker_training_export_store_manifest_error(
                    "normalized_store",
                    error,
                ));
            }
        };
    let result_store = parse_independent_checker_machine_result_store_manifest(result_store_source)
        .map_err(|error| {
            independent_checker_training_export_store_manifest_error("result_store", error)
        })?;

    let normalized_results =
        independent_checker_training_export_normalized_results(&normalized_store, workspace_files)?;
    let machine_results = independent_checker_training_export_machine_results(
        &result_store,
        workspace_files,
        &normalized_results,
    )?;
    let examples =
        independent_checker_training_export_examples(&normalized_results, &machine_results)?;
    let jsonl_bytes = independent_checker_training_export_jsonl_bytes(&examples);
    let file_hash = independent_checker_file_hash(&jsonl_bytes);
    let manifest = IndependentCheckerTrainingExportManifest::new(
        file_hash,
        examples.len() as u64,
        IndependentCheckerTrainingExportSources {
            result_store_manifest_hash,
            normalized_store_manifest_hash,
        },
    );
    let manifest_bytes = manifest.canonical_json().into_bytes();
    let out_rewrite_required = independent_checker_training_export_validate_existing_output(
        "out.path",
        &jsonl_bytes,
        existing_out,
    )?;
    let manifest_out_rewrite_required =
        independent_checker_training_export_validate_existing_output(
            "manifest_out.path",
            &manifest_bytes,
            existing_manifest_out,
        )?;

    Ok(IndependentCheckerTrainingExport {
        manifest,
        jsonl_bytes,
        manifest_bytes,
        out_rewrite_required,
        manifest_out_rewrite_required,
    })
}

