pub fn independent_checker_auxiliary_result_store_entry_for_result(
    result: &IndependentCheckerAuxiliaryResult,
    path: impl Into<String>,
) -> Result<IndependentCheckerAuxiliaryResultStoreEntry, IndependentCheckerCommandError> {
    let path = path.into();
    if !independent_checker_valid_workspace_relative_path(&path) {
        return Err(independent_checker_command_value_error(
            independent_checker_command_for_auxiliary_kind(result.kind),
            "input_reference_invalid",
            "auxiliary_result.path",
            "workspace_relative_path",
            "invalid_path",
        ));
    }
    let bytes = result.canonical_json();
    Ok(IndependentCheckerAuxiliaryResultStoreEntry {
        result_hash: result.result_hash(),
        kind: result.kind,
        policy_hash: result.policy_hash,
        artifact_hash: result.artifact_hash,
        path,
        file_hash: independent_checker_file_hash(bytes.as_bytes()),
    })
}

pub fn independent_checker_auxiliary_result_store_with_entry(
    existing_store: Option<&IndependentCheckerAuxiliaryResultStoreManifest>,
    generated_entry: IndependentCheckerAuxiliaryResultStoreEntry,
) -> Result<IndependentCheckerAuxiliaryResultStoreUpdate, IndependentCheckerCommandError> {
    let mut manifest =
        existing_store
            .cloned()
            .unwrap_or(IndependentCheckerAuxiliaryResultStoreManifest {
                results: Vec::new(),
            });

    for existing in &manifest.results {
        let same_result_hash = existing.result_hash == generated_entry.result_hash;
        let same_path = existing.path == generated_entry.path;
        let exact = same_result_hash
            && same_path
            && existing.kind == generated_entry.kind
            && existing.policy_hash == generated_entry.policy_hash
            && existing.artifact_hash == generated_entry.artifact_hash
            && existing.file_hash == generated_entry.file_hash;
        if exact {
            return Ok(IndependentCheckerAuxiliaryResultStoreUpdate {
                manifest,
                rewrite_required: false,
            });
        }
        if same_result_hash || same_path {
            return Err(independent_checker_command_value_error(
                independent_checker_command_for_auxiliary_kind(generated_entry.kind),
                "auxiliary_store_entry_conflict",
                "auxiliary_result_store.results[]",
                generated_entry.canonical_json(),
                existing.canonical_json(),
            ));
        }
    }

    manifest.results.push(generated_entry);
    manifest.results.sort_by(|left, right| {
        left.result_hash
            .cmp(&right.result_hash)
            .then_with(|| left.kind.as_str().cmp(right.kind.as_str()))
            .then_with(|| left.policy_hash.cmp(&right.policy_hash))
            .then_with(|| left.artifact_hash.cmp(&right.artifact_hash))
    });
    Ok(IndependentCheckerAuxiliaryResultStoreUpdate {
        manifest,
        rewrite_required: true,
    })
}

pub fn independent_checker_auxiliary_axiom_policy_result(
    result_id: impl Into<String>,
    policy: &IndependentCheckerRunnerPolicy,
    axiom_policy: &IndependentCheckerAxiomPolicy,
    normalized_result: &IndependentCheckerNormalizedCheckResult,
    axiom_report: &IndependentCheckerAxiomReport,
) -> Result<IndependentCheckerAuxiliaryResult, IndependentCheckerCommandError> {
    let Some(checker_profile) = policy.required_checker_profiles.first() else {
        return Err(independent_checker_command_value_error(
            IndependentCheckerCommandName::AuxiliaryAxiomPolicy,
            "policy_reference_invalid",
            "policy.required_checker_profiles",
            "baseline_required_checker_profile",
            "missing",
        ));
    };
    let selected = normalized_result
        .results
        .iter()
        .find(|entry| &entry.checker_profile == checker_profile);
    let selector = selected.map(|entry| IndependentCheckerAuxiliarySelector::AxiomPolicy {
        normalized_result_hash: normalized_result.normalized_result_hash(),
        checker_profile: checker_profile.clone(),
        result_hash: entry.result_hash,
        axiom_report_hash: entry.axiom_report_hash.unwrap_or([0; 32]),
    });
    independent_checker_auxiliary_axiom_policy_result_with_selector(
        result_id,
        policy,
        axiom_policy,
        normalized_result,
        axiom_report,
        selector,
    )
}

pub fn independent_checker_auxiliary_axiom_policy_result_with_selector(
    result_id: impl Into<String>,
    policy: &IndependentCheckerRunnerPolicy,
    axiom_policy: &IndependentCheckerAxiomPolicy,
    normalized_result: &IndependentCheckerNormalizedCheckResult,
    axiom_report: &IndependentCheckerAxiomReport,
    selector: Option<IndependentCheckerAuxiliarySelector>,
) -> Result<IndependentCheckerAuxiliaryResult, IndependentCheckerCommandError> {
    let result_id = result_id.into();
    validate_auxiliary_result_id(
        &result_id,
        IndependentCheckerCommandName::AuxiliaryAxiomPolicy,
    )?;
    let policy_hash = policy.policy_hash();
    let artifact_hash = normalized_result.artifact_hash();
    let selector = match selector {
        Some(IndependentCheckerAuxiliarySelector::AxiomPolicy { .. }) => selector,
        Some(_) | None => {
            return Ok(IndependentCheckerAuxiliaryResult::inconclusive(
                result_id,
                IndependentCheckerAuxiliaryResultKind::AxiomPolicy,
                policy_hash,
                artifact_hash,
                selector,
                IndependentCheckerAuxiliaryError::value(
                    IndependentCheckerAuxiliaryReasonCode::AxiomPolicyInconclusive,
                    "selector",
                    "axiom_policy_selector",
                    "missing",
                ),
            ))
        }
    };
    let IndependentCheckerAuxiliarySelector::AxiomPolicy {
        normalized_result_hash,
        checker_profile,
        result_hash,
        axiom_report_hash,
    } = selector
        .clone()
        .expect("selector is Some and checked as axiom_policy")
    else {
        unreachable!("selector kind checked above")
    };
    let actual_normalized_hash = normalized_result.normalized_result_hash();
    if normalized_result_hash != actual_normalized_hash {
        return Ok(IndependentCheckerAuxiliaryResult::inconclusive(
            result_id,
            IndependentCheckerAuxiliaryResultKind::AxiomPolicy,
            policy_hash,
            artifact_hash,
            selector,
            IndependentCheckerAuxiliaryError::hash(
                IndependentCheckerAuxiliaryReasonCode::AxiomPolicyInconclusive,
                "selector.normalized_result_hash",
                actual_normalized_hash,
                normalized_result_hash,
            ),
        ));
    }
    let selected = normalized_result
        .results
        .iter()
        .find(|entry| entry.checker_profile == checker_profile);
    let Some(selected) = selected else {
        return Ok(IndependentCheckerAuxiliaryResult::inconclusive(
            result_id,
            IndependentCheckerAuxiliaryResultKind::AxiomPolicy,
            policy_hash,
            artifact_hash,
            selector,
            IndependentCheckerAuxiliaryError::value(
                IndependentCheckerAuxiliaryReasonCode::AxiomPolicyInconclusive,
                "selector.checker_profile",
                "checked_normalized_result_entry",
                "missing",
            ),
        ));
    };
    if selected.status != IndependentCheckerMachineCheckStatus::Checked {
        return Ok(IndependentCheckerAuxiliaryResult::inconclusive(
            result_id,
            IndependentCheckerAuxiliaryResultKind::AxiomPolicy,
            policy_hash,
            artifact_hash,
            selector,
            IndependentCheckerAuxiliaryError::value(
                IndependentCheckerAuxiliaryReasonCode::AxiomPolicyInconclusive,
                "selector.checker_profile",
                "checked_normalized_result_entry",
                "not_checked",
            ),
        ));
    }
    if selected.result_hash != result_hash {
        return Ok(IndependentCheckerAuxiliaryResult::inconclusive(
            result_id,
            IndependentCheckerAuxiliaryResultKind::AxiomPolicy,
            policy_hash,
            artifact_hash,
            selector,
            IndependentCheckerAuxiliaryError::hash(
                IndependentCheckerAuxiliaryReasonCode::AxiomPolicyInconclusive,
                "selector.result_hash",
                selected.result_hash,
                result_hash,
            ),
        ));
    }
    let Some(selected_axiom_report_hash) = selected.axiom_report_hash else {
        return Ok(IndependentCheckerAuxiliaryResult::inconclusive(
            result_id,
            IndependentCheckerAuxiliaryResultKind::AxiomPolicy,
            policy_hash,
            artifact_hash,
            selector,
            IndependentCheckerAuxiliaryError::value(
                IndependentCheckerAuxiliaryReasonCode::AxiomPolicyInconclusive,
                "selector.checker_profile",
                "checked_normalized_result_entry",
                "missing_axiom_report_hash",
            ),
        ));
    };
    if selected_axiom_report_hash != axiom_report_hash {
        return Ok(IndependentCheckerAuxiliaryResult::inconclusive(
            result_id,
            IndependentCheckerAuxiliaryResultKind::AxiomPolicy,
            policy_hash,
            artifact_hash,
            selector,
            IndependentCheckerAuxiliaryError::hash(
                IndependentCheckerAuxiliaryReasonCode::AxiomPolicyInconclusive,
                "selector.axiom_report_hash",
                selected_axiom_report_hash,
                axiom_report_hash,
            ),
        ));
    }
    let parsed_report_hash = axiom_report.axiom_report_hash();
    if parsed_report_hash != axiom_report_hash {
        return Ok(IndependentCheckerAuxiliaryResult::failed(
            result_id,
            IndependentCheckerAuxiliaryResultKind::AxiomPolicy,
            policy_hash,
            artifact_hash,
            selector,
            IndependentCheckerAuxiliaryError::hash(
                IndependentCheckerAuxiliaryReasonCode::AxiomPolicyFailed,
                "selector.axiom_report_hash",
                axiom_report_hash,
                parsed_report_hash,
            ),
        ));
    }
    if axiom_report.module != normalized_result.artifact.module {
        return Ok(IndependentCheckerAuxiliaryResult::inconclusive(
            result_id,
            IndependentCheckerAuxiliaryResultKind::AxiomPolicy,
            policy_hash,
            artifact_hash,
            selector,
            IndependentCheckerAuxiliaryError::value(
                IndependentCheckerAuxiliaryReasonCode::AxiomPolicyInconclusive,
                "axiom_report.module",
                &normalized_result.artifact.module,
                &axiom_report.module,
            ),
        ));
    }
    match selected.certificate_hash {
        Some(certificate_hash) if certificate_hash == axiom_report.certificate_hash => {}
        Some(certificate_hash) => {
            return Ok(IndependentCheckerAuxiliaryResult::inconclusive(
                result_id,
                IndependentCheckerAuxiliaryResultKind::AxiomPolicy,
                policy_hash,
                artifact_hash,
                selector,
                IndependentCheckerAuxiliaryError::hash(
                    IndependentCheckerAuxiliaryReasonCode::AxiomPolicyInconclusive,
                    "axiom_report.certificate_hash",
                    certificate_hash,
                    axiom_report.certificate_hash,
                ),
            ))
        }
        None => {
            return Ok(IndependentCheckerAuxiliaryResult::inconclusive(
                result_id,
                IndependentCheckerAuxiliaryResultKind::AxiomPolicy,
                policy_hash,
                artifact_hash,
                selector,
                IndependentCheckerAuxiliaryError::value(
                    IndependentCheckerAuxiliaryReasonCode::AxiomPolicyInconclusive,
                    "axiom_report.certificate_hash",
                    "present",
                    "missing",
                ),
            ))
        }
    }
    for (index, axiom) in axiom_report.axioms.iter().enumerate() {
        if !axiom_policy.allows(&axiom.name) {
            return Ok(IndependentCheckerAuxiliaryResult::failed(
                result_id,
                IndependentCheckerAuxiliaryResultKind::AxiomPolicy,
                policy_hash,
                artifact_hash,
                selector,
                IndependentCheckerAuxiliaryError::value(
                    IndependentCheckerAuxiliaryReasonCode::AxiomPolicyFailed,
                    format!("axiom_report.axioms[{index}].name"),
                    "allowed_axiom",
                    &axiom.name,
                ),
            ));
        }
    }
    Ok(IndependentCheckerAuxiliaryResult::passed(
        result_id,
        IndependentCheckerAuxiliaryResultKind::AxiomPolicy,
        policy_hash,
        artifact_hash,
        selector,
    ))
}

pub fn independent_checker_auxiliary_reproducibility_result(
    result_id: impl Into<String>,
    policy: &IndependentCheckerRunnerPolicy,
    artifact_hash: Hash,
    baseline: &IndependentCheckerMachineCheckResult,
    repeated: &IndependentCheckerMachineCheckResult,
) -> Result<IndependentCheckerAuxiliaryResult, IndependentCheckerCommandError> {
    let selector = IndependentCheckerAuxiliarySelector::Reproducibility {
        request_hash: baseline.request_hash,
        checker_profile: baseline.checker.profile.clone(),
        baseline_run_artifact_hash: baseline.run_artifact_hash(),
        repeated_run_artifact_hash: repeated.run_artifact_hash(),
    };
    independent_checker_auxiliary_reproducibility_result_with_selector(
        result_id,
        policy,
        artifact_hash,
        baseline,
        repeated,
        selector,
    )
}

pub fn independent_checker_auxiliary_reproducibility_result_with_selector(
    result_id: impl Into<String>,
    policy: &IndependentCheckerRunnerPolicy,
    artifact_hash: Hash,
    baseline: &IndependentCheckerMachineCheckResult,
    repeated: &IndependentCheckerMachineCheckResult,
    selector: IndependentCheckerAuxiliarySelector,
) -> Result<IndependentCheckerAuxiliaryResult, IndependentCheckerCommandError> {
    let result_id = result_id.into();
    validate_auxiliary_result_id(
        &result_id,
        IndependentCheckerCommandName::AuxiliaryReproducibility,
    )?;
    let policy_hash = policy.policy_hash();
    let IndependentCheckerAuxiliarySelector::Reproducibility {
        request_hash,
        checker_profile,
        baseline_run_artifact_hash,
        repeated_run_artifact_hash,
    } = selector.clone()
    else {
        return Ok(IndependentCheckerAuxiliaryResult::inconclusive(
            result_id,
            IndependentCheckerAuxiliaryResultKind::Reproducibility,
            policy_hash,
            artifact_hash,
            Some(selector),
            IndependentCheckerAuxiliaryError::value(
                IndependentCheckerAuxiliaryReasonCode::ReproducibilityInconclusive,
                "selector",
                "reproducibility_selector",
                "wrong_type",
            ),
        ));
    };
    if baseline_run_artifact_hash == repeated_run_artifact_hash {
        return Err(independent_checker_command_value_error(
            IndependentCheckerCommandName::AuxiliaryReproducibility,
            "input_reference_invalid",
            "selector.repeated_run_artifact_hash",
            "distinct_run_artifact_hash",
            "duplicate",
        ));
    }
    let selector = Some(selector);
    for (label, result, expected_run_hash) in [
        ("baseline", baseline, baseline_run_artifact_hash),
        ("repeated", repeated, repeated_run_artifact_hash),
    ] {
        if result.run_artifact_hash() != expected_run_hash {
            return Ok(IndependentCheckerAuxiliaryResult::inconclusive(
                result_id,
                IndependentCheckerAuxiliaryResultKind::Reproducibility,
                policy_hash,
                artifact_hash,
                selector,
                IndependentCheckerAuxiliaryError::hash(
                    IndependentCheckerAuxiliaryReasonCode::ReproducibilityInconclusive,
                    format!("selector.{label}_run_artifact_hash"),
                    expected_run_hash,
                    result.run_artifact_hash(),
                ),
            ));
        }
    }
    if let Some(error) = independent_checker_reproducibility_comparability_mismatch(
        policy,
        request_hash,
        &checker_profile,
        baseline,
        repeated,
    ) {
        return Ok(IndependentCheckerAuxiliaryResult::inconclusive(
            result_id,
            IndependentCheckerAuxiliaryResultKind::Reproducibility,
            policy_hash,
            artifact_hash,
            selector,
            error,
        ));
    }
    if let Some(error) = independent_checker_reproducibility_identity_mismatch(baseline, repeated) {
        return Ok(IndependentCheckerAuxiliaryResult::failed(
            result_id,
            IndependentCheckerAuxiliaryResultKind::Reproducibility,
            policy_hash,
            artifact_hash,
            selector,
            error,
        ));
    }
    Ok(IndependentCheckerAuxiliaryResult::passed(
        result_id,
        IndependentCheckerAuxiliaryResultKind::Reproducibility,
        policy_hash,
        artifact_hash,
        selector,
    ))
}

pub fn independent_checker_auxiliary_import_certificate_hash_result(
    result_id: impl Into<String>,
    release_policy: &IndependentCheckerReleasePolicy,
    import_lock_manifest_hash: Hash,
    import_lock: &IndependentCheckerImportLockManifest,
    certificate_files: &BTreeMap<String, Vec<u8>>,
) -> Result<IndependentCheckerAuxiliaryResult, IndependentCheckerCommandError> {
    let result_id = result_id.into();
    validate_auxiliary_result_id(
        &result_id,
        IndependentCheckerCommandName::AuxiliaryImportCertificateHash,
    )?;
    if release_policy.mode != IndependentCheckerReleaseMode::HighTrust {
        return Err(independent_checker_command_value_error(
            IndependentCheckerCommandName::AuxiliaryImportCertificateHash,
            "policy_reference_invalid",
            "release_policy.mode",
            "high-trust",
            release_policy.mode.as_str(),
        ));
    }
    let policy_hash = release_policy.policy_hash();
    for (index, import) in import_lock.imports.iter().enumerate() {
        let Some(bytes) = certificate_files.get(&import.certificate.path) else {
            return Ok(IndependentCheckerAuxiliaryResult::inconclusive(
                result_id,
                IndependentCheckerAuxiliaryResultKind::ImportCertificateHash,
                policy_hash,
                import_lock_manifest_hash,
                None,
                IndependentCheckerAuxiliaryError::value(
                    IndependentCheckerAuxiliaryReasonCode::ImportCertificateHashInconclusive,
                    format!("import_lock.imports[{index}].certificate.path"),
                    "readable_file",
                    "missing",
                ),
            ));
        };
        let actual_file_hash = independent_checker_file_hash(bytes);
        if actual_file_hash != import.certificate.file_hash {
            return Ok(IndependentCheckerAuxiliaryResult::failed(
                result_id,
                IndependentCheckerAuxiliaryResultKind::ImportCertificateHash,
                policy_hash,
                import_lock_manifest_hash,
                None,
                IndependentCheckerAuxiliaryError::hash(
                    IndependentCheckerAuxiliaryReasonCode::ImportCertificateHashMismatch,
                    format!("import_lock.imports[{index}].certificate.file_hash"),
                    import.certificate.file_hash,
                    actual_file_hash,
                ),
            ));
        }
        let actual_certificate_hash = match independent_checker_raw_claimed_certificate_hash(bytes)
        {
            Ok(hash) => hash,
            Err(_) => {
                return Ok(IndependentCheckerAuxiliaryResult::failed(
                    result_id,
                    IndependentCheckerAuxiliaryResultKind::ImportCertificateHash,
                    policy_hash,
                    import_lock_manifest_hash,
                    None,
                    IndependentCheckerAuxiliaryError::value(
                        IndependentCheckerAuxiliaryReasonCode::ImportCertificateHashMismatch,
                        format!("import_lock.imports[{index}].certificate.path"),
                        "canonical_certificate",
                        "invalid_certificate_encoding",
                    ),
                ))
            }
        };
        if actual_certificate_hash != import.certificate.certificate_hash {
            return Ok(IndependentCheckerAuxiliaryResult::failed(
                result_id,
                IndependentCheckerAuxiliaryResultKind::ImportCertificateHash,
                policy_hash,
                import_lock_manifest_hash,
                None,
                IndependentCheckerAuxiliaryError::hash(
                    IndependentCheckerAuxiliaryReasonCode::ImportCertificateHashMismatch,
                    format!("import_lock.imports[{index}].certificate.certificate_hash"),
                    import.certificate.certificate_hash,
                    actual_certificate_hash,
                ),
            ));
        }
    }
    Ok(IndependentCheckerAuxiliaryResult::passed(
        result_id,
        IndependentCheckerAuxiliaryResultKind::ImportCertificateHash,
        policy_hash,
        import_lock_manifest_hash,
        None,
    ))
}

pub fn independent_checker_auxiliary_command_exit_success(
    result: &Result<IndependentCheckerAuxiliaryResult, IndependentCheckerCommandError>,
) -> bool {
    result.is_ok()
}

pub fn independent_checker_auxiliary_result_passes_release_condition(
    result: &IndependentCheckerAuxiliaryResult,
) -> bool {
    result.status == IndependentCheckerAuxiliaryStatus::Passed
}

pub fn independent_checker_auxiliary_results_all_passed(
    results: &[IndependentCheckerAuxiliaryResult],
) -> bool {
    results
        .iter()
        .all(independent_checker_auxiliary_result_passes_release_condition)
}

