pub fn parse_independent_checker_ai_audit_sidecar(
    source: &str,
) -> Result<IndependentCheckerAiAuditSidecar, IndependentCheckerAuditSidecarValidationError> {
    let document = JsonDocument::parse(source).map_err(|_| {
        IndependentCheckerAuditSidecarValidationError::actual_value(
            IndependentCheckerAuditSidecarValidationReasonCode::SidecarJsonInvalid,
            "sidecar.path",
            "invalid_json",
        )
    })?;
    independent_checker_parse_ai_audit_sidecar_value(document.root())
}

pub fn independent_checker_validate_ai_audit_sidecar_schema_only(
    sidecar_source: &str,
) -> IndependentCheckerAuditSidecarValidationResult {
    let sidecar_file_hash = independent_checker_file_hash(sidecar_source.as_bytes());
    let mode = IndependentCheckerAuditSidecarValidationMode::SchemaOnly;
    let document = match JsonDocument::parse(sidecar_source) {
        Ok(document) => document,
        Err(_) => {
            return IndependentCheckerAuditSidecarValidationResult::failed(
                mode,
                Some(sidecar_file_hash),
                None,
                None,
                IndependentCheckerAuditSidecarValidationError::actual_value(
                    IndependentCheckerAuditSidecarValidationReasonCode::SidecarJsonInvalid,
                    "sidecar.path",
                    "invalid_json",
                ),
            )
        }
    };
    match independent_checker_parse_ai_audit_sidecar_value(document.root()) {
        Ok(_) => IndependentCheckerAuditSidecarValidationResult::valid(
            mode,
            sidecar_file_hash,
            None,
            None,
        ),
        Err(error) => IndependentCheckerAuditSidecarValidationResult::failed(
            mode,
            Some(sidecar_file_hash),
            None,
            None,
            error,
        ),
    }
}

pub fn independent_checker_validate_ai_audit_sidecar_cross_artifact(
    sidecar_source: &str,
    input_policy_source: &str,
    input_policy_reference_hash: Hash,
    machine_results: &[IndependentCheckerMachineCheckResult],
    normalized_results: &[IndependentCheckerNormalizedCheckResult],
) -> IndependentCheckerAuditSidecarValidationResult {
    let sidecar_file_hash = independent_checker_file_hash(sidecar_source.as_bytes());
    let mode = IndependentCheckerAuditSidecarValidationMode::CrossArtifact;
    let document = match JsonDocument::parse(sidecar_source) {
        Ok(document) => document,
        Err(_) => {
            return IndependentCheckerAuditSidecarValidationResult::failed(
                mode,
                Some(sidecar_file_hash),
                None,
                None,
                IndependentCheckerAuditSidecarValidationError::actual_value(
                    IndependentCheckerAuditSidecarValidationReasonCode::SidecarJsonInvalid,
                    "sidecar.path",
                    "invalid_json",
                ),
            )
        }
    };
    let sidecar = match independent_checker_parse_ai_audit_sidecar_value(document.root()) {
        Ok(sidecar) => sidecar,
        Err(error) => {
            return IndependentCheckerAuditSidecarValidationResult::failed(
                mode,
                Some(sidecar_file_hash),
                None,
                None,
                error,
            )
        }
    };

    let policy_document = match JsonDocument::parse(input_policy_source) {
        Ok(document) => document,
        Err(_) => {
            return IndependentCheckerAuditSidecarValidationResult::failed(
                mode,
                Some(sidecar_file_hash),
                Some(input_policy_reference_hash),
                Some(&sidecar),
                IndependentCheckerAuditSidecarValidationError::value(
                    IndependentCheckerAuditSidecarValidationReasonCode::InputPolicyJsonInvalid,
                    "input_policy.path",
                    "valid_json",
                    "invalid_json",
                ),
            )
        }
    };
    let input_policy =
        match independent_checker_parse_ai_audit_input_policy_value(policy_document.root()) {
            Ok(policy) => policy,
            Err(error) => {
                return IndependentCheckerAuditSidecarValidationResult::failed(
                    mode,
                    Some(sidecar_file_hash),
                    Some(input_policy_reference_hash),
                    Some(&sidecar),
                    error,
                )
            }
        };
    let input_policy_hash = input_policy.input_policy_hash();
    if sidecar.input_policy.hash != input_policy_reference_hash {
        return IndependentCheckerAuditSidecarValidationResult::failed(
            mode,
            Some(sidecar_file_hash),
            Some(input_policy_reference_hash),
            Some(&sidecar),
            IndependentCheckerAuditSidecarValidationError::hash(
                IndependentCheckerAuditSidecarValidationReasonCode::InputPolicyHashMismatch,
                "input_policy.hash",
                input_policy_reference_hash,
                sidecar.input_policy.hash,
            ),
        );
    }
    if input_policy_hash != input_policy_reference_hash {
        return IndependentCheckerAuditSidecarValidationResult::failed(
            mode,
            Some(sidecar_file_hash),
            Some(input_policy_reference_hash),
            Some(&sidecar),
            IndependentCheckerAuditSidecarValidationError::hash(
                IndependentCheckerAuditSidecarValidationReasonCode::InputPolicyHashMismatch,
                "input_policy.hash",
                input_policy_reference_hash,
                input_policy_hash,
            ),
        );
    }

    if let Some(error) =
        independent_checker_ai_audit_copied_policy_mismatch(&sidecar, &input_policy)
    {
        return IndependentCheckerAuditSidecarValidationResult::failed(
            mode,
            Some(sidecar_file_hash),
            Some(input_policy_reference_hash),
            Some(&sidecar),
            error,
        );
    }
    if let Some(error) =
        independent_checker_ai_audit_policy_gated_field_error(&sidecar, &input_policy)
    {
        return IndependentCheckerAuditSidecarValidationResult::failed(
            mode,
            Some(sidecar_file_hash),
            Some(input_policy_reference_hash),
            Some(&sidecar),
            error,
        );
    }

    let source = match independent_checker_resolve_ai_audit_sidecar_source(
        &sidecar,
        machine_results,
        normalized_results,
    ) {
        Ok(source) => source,
        Err(error) => {
            return IndependentCheckerAuditSidecarValidationResult::failed(
                mode,
                Some(sidecar_file_hash),
                Some(input_policy_reference_hash),
                Some(&sidecar),
                error,
            )
        }
    };
    if let Some(error) =
        independent_checker_validate_ai_audit_source_dependent_fields(&sidecar, &source)
    {
        return IndependentCheckerAuditSidecarValidationResult::failed(
            mode,
            Some(sidecar_file_hash),
            Some(input_policy_reference_hash),
            Some(&sidecar),
            error,
        );
    }
    let prompt_input = independent_checker_ai_audit_prompt_input(&sidecar, &input_policy, &source);
    let expected_prompt_hash = prompt_input.prompt_hash();
    if expected_prompt_hash != sidecar.ai.prompt_hash {
        return IndependentCheckerAuditSidecarValidationResult::failed(
            mode,
            Some(sidecar_file_hash),
            Some(input_policy_reference_hash),
            Some(&sidecar),
            IndependentCheckerAuditSidecarValidationError::hash(
                IndependentCheckerAuditSidecarValidationReasonCode::PromptHashMismatch,
                "ai.prompt_hash",
                expected_prompt_hash,
                sidecar.ai.prompt_hash,
            ),
        );
    }
    IndependentCheckerAuditSidecarValidationResult::valid(
        mode,
        sidecar_file_hash,
        Some(input_policy_reference_hash),
        Some(&sidecar),
    )
}

pub fn independent_checker_ai_audit_prompt_input_for_sidecar(
    sidecar: &IndependentCheckerAiAuditSidecar,
    input_policy: &IndependentCheckerAiAuditInputPolicy,
    machine_result: Option<&IndependentCheckerMachineCheckResult>,
    normalized_result: Option<&IndependentCheckerNormalizedCheckResult>,
) -> Option<IndependentCheckerAiAuditPromptInput> {
    let source = match sidecar.source.kind {
        IndependentCheckerAiAuditSidecarSourceKind::MachineResult => {
            IndependentCheckerResolvedAiAuditSource::MachineResult {
                machine_result: machine_result?,
                normalized_result: if sidecar.source.normalized_result_hash.is_some() {
                    Some(normalized_result?)
                } else {
                    normalized_result
                },
            }
        }
        IndependentCheckerAiAuditSidecarSourceKind::NormalizedComparison => {
            IndependentCheckerResolvedAiAuditSource::NormalizedComparison {
                normalized_result: normalized_result?,
            }
        }
    };
    Some(independent_checker_ai_audit_prompt_input(
        sidecar,
        input_policy,
        &source,
    ))
}

pub fn independent_checker_ai_sidecar_diagnostic_targets_from_normalized_result(
    normalized_result: &IndependentCheckerNormalizedCheckResult,
) -> Vec<IndependentCheckerRequiredAiSidecarDiagnosticTarget> {
    let normalized_result_hash = normalized_result.normalized_result_hash();
    let mut targets = Vec::new();
    for (index, entry) in normalized_result.results.iter().enumerate() {
        if entry.status == IndependentCheckerMachineCheckStatus::Failed {
            targets.push(
                IndependentCheckerRequiredAiSidecarDiagnosticTarget::MachineResult {
                    result_index: index,
                    normalized_result_hash,
                    checker_profile: entry.checker_profile.clone(),
                    request_hash: entry.request_hash,
                    result_hash: entry.result_hash,
                    policy_hash: entry.policy_hash,
                },
            );
        }
    }
    if independent_checker_normalized_comparison_requires_ai_diagnostic(
        normalized_result.comparison.status,
    ) {
        targets.push(
            IndependentCheckerRequiredAiSidecarDiagnosticTarget::NormalizedComparison {
                normalized_result_hash,
            },
        );
    }
    targets
}

pub fn independent_checker_required_ai_sidecar_diagnostic_targets(
    release_policy: &IndependentCheckerReleasePolicy,
    normalized_result: &IndependentCheckerNormalizedCheckResult,
) -> Vec<IndependentCheckerRequiredAiSidecarDiagnosticTarget> {
    if independent_checker_release_policy_required_ai_diagnostic_input_policy_hash(release_policy)
        .is_none()
    {
        return Vec::new();
    }
    independent_checker_ai_sidecar_diagnostic_targets_from_normalized_result(normalized_result)
}

pub fn independent_checker_release_target_has_required_ai_sidecar_diagnostic_targets(
    release_policy: &IndependentCheckerReleasePolicy,
    normalized_result: &IndependentCheckerNormalizedCheckResult,
) -> bool {
    !independent_checker_required_ai_sidecar_diagnostic_targets(release_policy, normalized_result)
        .is_empty()
}

pub fn evaluate_required_ai_sidecar_diagnostics(
    release_policy: &IndependentCheckerReleasePolicy,
    ci_diagnostic_targets: &[IndependentCheckerCiDiagnosticTargetContext],
    ai_sidecars: &[IndependentCheckerResolvedAiAuditSidecarEntry],
    audit_sidecar_validation_results: &[IndependentCheckerResolvedAuditSidecarValidationEntry],
    ai_sidecar_diagnostic_results: &[IndependentCheckerResolvedAiSidecarDiagnosticResultEntry],
) -> Result<
    IndependentCheckerRequiredAiSidecarDiagnosticEvaluation,
    IndependentCheckerAiSidecarDiagnosticEvaluationFailure,
> {
    let Some(input_policy_hash) =
        independent_checker_release_policy_required_ai_diagnostic_input_policy_hash(release_policy)
    else {
        return Ok(IndependentCheckerRequiredAiSidecarDiagnosticEvaluation {
            recomputed_results: Vec::new(),
            pass_failure: None,
        });
    };

    independent_checker_validate_required_ai_sidecar_diagnostic_entry_metadata(
        ai_sidecars,
        audit_sidecar_validation_results,
        ai_sidecar_diagnostic_results,
    )?;
    independent_checker_validate_ci_diagnostic_target_uniqueness(ci_diagnostic_targets)?;

    let policy_hash = release_policy.policy_hash();
    let target_sets = ci_diagnostic_targets
        .iter()
        .map(|target| {
            independent_checker_ai_sidecar_diagnostic_targets_from_normalized_result(
                &target.artifact,
            )
        })
        .collect::<Vec<_>>();
    independent_checker_validate_saved_ai_sidecar_diagnostic_target_counts(
        policy_hash,
        input_policy_hash,
        ci_diagnostic_targets,
        &target_sets,
        ai_sidecar_diagnostic_results,
    )?;

    let mut recomputed_results = Vec::new();
    for (context_index, context) in ci_diagnostic_targets.iter().enumerate() {
        let normalized_result_hash = context.artifact.normalized_result_hash();
        let targets = &target_sets[context_index];
        let target_count = targets.len() as u64;
        let error = independent_checker_first_required_ai_sidecar_diagnostic_error(
            context,
            targets,
            input_policy_hash,
            ai_sidecars,
            audit_sidecar_validation_results,
        );
        let result = match error {
            Some(error) => IndependentCheckerAiSidecarDiagnosticResult::failed(
                policy_hash,
                input_policy_hash,
                normalized_result_hash,
                target_count,
                error,
            ),
            None => IndependentCheckerAiSidecarDiagnosticResult::passed(
                policy_hash,
                input_policy_hash,
                normalized_result_hash,
                target_count,
            ),
        };
        recomputed_results.push(result);
    }

    let pass_failure = independent_checker_first_required_ai_sidecar_diagnostic_pass_failure(
        policy_hash,
        input_policy_hash,
        ci_diagnostic_targets,
        &target_sets,
        &recomputed_results,
        ai_sidecar_diagnostic_results,
    );
    Ok(IndependentCheckerRequiredAiSidecarDiagnosticEvaluation {
        recomputed_results,
        pass_failure,
    })
}

fn independent_checker_release_policy_required_ai_diagnostic_input_policy_hash(
    release_policy: &IndependentCheckerReleasePolicy,
) -> Option<Hash> {
    (release_policy.ai_triage.enabled && release_policy.ai_triage.required)
        .then_some(release_policy.ai_triage.input_policy_hash)
        .flatten()
}

const fn independent_checker_normalized_comparison_requires_ai_diagnostic(
    status: IndependentCheckerNormalizedComparisonStatus,
) -> bool {
    matches!(
        status,
        IndependentCheckerNormalizedComparisonStatus::Disagreement
            | IndependentCheckerNormalizedComparisonStatus::MissingCheckerResult
            | IndependentCheckerNormalizedComparisonStatus::PolicyFailure
            | IndependentCheckerNormalizedComparisonStatus::Inconclusive
    )
}

fn independent_checker_validate_required_ai_sidecar_diagnostic_entry_metadata(
    ai_sidecars: &[IndependentCheckerResolvedAiAuditSidecarEntry],
    audit_sidecar_validation_results: &[IndependentCheckerResolvedAuditSidecarValidationEntry],
    ai_sidecar_diagnostic_results: &[IndependentCheckerResolvedAiSidecarDiagnosticResultEntry],
) -> Result<(), IndependentCheckerAiSidecarDiagnosticEvaluationFailure> {
    for (index, entry) in ai_sidecars.iter().enumerate() {
        if !independent_checker_valid_workspace_relative_path(&entry.path) {
            return Err(IndependentCheckerAiSidecarDiagnosticEvaluationFailure::value(
                IndependentCheckerAiSidecarDiagnosticEvaluationFailureReasonCode::AiSidecarInputSchemaInvalid,
                format!("ai_sidecars[{index}].path"),
                "workspace_relative_path",
                "invalid_path",
            ));
        }
    }
    for (index, entry) in audit_sidecar_validation_results.iter().enumerate() {
        if !independent_checker_valid_workspace_relative_path(&entry.path) {
            return Err(IndependentCheckerAiSidecarDiagnosticEvaluationFailure::value(
                IndependentCheckerAiSidecarDiagnosticEvaluationFailureReasonCode::AuditSidecarValidationInputSchemaInvalid,
                format!("audit_sidecar_validation_results[{index}].path"),
                "workspace_relative_path",
                "invalid_path",
            ));
        }
    }
    for (index, entry) in ai_sidecar_diagnostic_results.iter().enumerate() {
        if !independent_checker_valid_workspace_relative_path(&entry.path) {
            return Err(IndependentCheckerAiSidecarDiagnosticEvaluationFailure::value(
                IndependentCheckerAiSidecarDiagnosticEvaluationFailureReasonCode::AiSidecarDiagnosticInputSchemaInvalid,
                format!("ai_sidecar_diagnostic_results[{index}].path"),
                "workspace_relative_path",
                "invalid_path",
            ));
        }
    }
    Ok(())
}

fn independent_checker_validate_ci_diagnostic_target_uniqueness(
    ci_diagnostic_targets: &[IndependentCheckerCiDiagnosticTargetContext],
) -> Result<(), IndependentCheckerAiSidecarDiagnosticEvaluationFailure> {
    let mut artifact_hashes = BTreeMap::<Hash, usize>::new();
    let mut normalized_result_hashes = BTreeMap::<Hash, usize>::new();
    for (index, target) in ci_diagnostic_targets.iter().enumerate() {
        let artifact_hash = target.artifact.artifact_hash();
        if artifact_hashes.insert(artifact_hash, index).is_some() {
            return Err(IndependentCheckerAiSidecarDiagnosticEvaluationFailure::value(
                IndependentCheckerAiSidecarDiagnosticEvaluationFailureReasonCode::CiDiagnosticTargetDuplicate,
                format!("ci_diagnostic_targets[{index}].artifact_hash"),
                "unique_artifact_hash",
                "duplicate",
            ));
        }
        let normalized_result_hash = target.artifact.normalized_result_hash();
        if normalized_result_hashes
            .insert(normalized_result_hash, index)
            .is_some()
        {
            return Err(IndependentCheckerAiSidecarDiagnosticEvaluationFailure::value(
                IndependentCheckerAiSidecarDiagnosticEvaluationFailureReasonCode::CiDiagnosticTargetDuplicate,
                format!("ci_diagnostic_targets[{index}].normalized_result_hash"),
                "unique_normalized_result_hash",
                "duplicate",
            ));
        }
    }
    Ok(())
}

fn independent_checker_validate_saved_ai_sidecar_diagnostic_target_counts(
    policy_hash: Hash,
    input_policy_hash: Hash,
    ci_diagnostic_targets: &[IndependentCheckerCiDiagnosticTargetContext],
    target_sets: &[Vec<IndependentCheckerRequiredAiSidecarDiagnosticTarget>],
    ai_sidecar_diagnostic_results: &[IndependentCheckerResolvedAiSidecarDiagnosticResultEntry],
) -> Result<(), IndependentCheckerAiSidecarDiagnosticEvaluationFailure> {
    for (diagnostic_index, diagnostic) in ai_sidecar_diagnostic_results.iter().enumerate() {
        for (context_index, context) in ci_diagnostic_targets.iter().enumerate() {
            let target_count = target_sets[context_index].len() as u64;
            if target_count == 0 {
                continue;
            }
            let artifact = &diagnostic.artifact;
            if artifact.policy_hash == policy_hash
                && artifact.input_policy_hash == input_policy_hash
                && artifact.normalized_result_hash == context.artifact.normalized_result_hash()
                && artifact.target_count != target_count
            {
                return Err(IndependentCheckerAiSidecarDiagnosticEvaluationFailure::value(
                    IndependentCheckerAiSidecarDiagnosticEvaluationFailureReasonCode::AiSidecarDiagnosticTargetCountMismatch,
                    format!("ai_sidecar_diagnostic[{diagnostic_index}].artifact.target_count"),
                    target_count.to_string(),
                    artifact.target_count.to_string(),
                ));
            }
        }
    }
    Ok(())
}

fn independent_checker_first_required_ai_sidecar_diagnostic_error(
    context: &IndependentCheckerCiDiagnosticTargetContext,
    targets: &[IndependentCheckerRequiredAiSidecarDiagnosticTarget],
    input_policy_hash: Hash,
    ai_sidecars: &[IndependentCheckerResolvedAiAuditSidecarEntry],
    audit_sidecar_validation_results: &[IndependentCheckerResolvedAuditSidecarValidationEntry],
) -> Option<IndependentCheckerAiSidecarDiagnosticError> {
    for (target_index, target) in targets.iter().enumerate() {
        let error = match target {
            IndependentCheckerRequiredAiSidecarDiagnosticTarget::MachineResult { .. } => {
                independent_checker_required_machine_result_ai_sidecar_diagnostic_error(
                    target_index,
                    target,
                    context,
                    input_policy_hash,
                    ai_sidecars,
                    audit_sidecar_validation_results,
                )
            }
            IndependentCheckerRequiredAiSidecarDiagnosticTarget::NormalizedComparison {
                normalized_result_hash,
            } => independent_checker_required_normalized_comparison_ai_sidecar_diagnostic_error(
                target_index,
                *normalized_result_hash,
                input_policy_hash,
                ai_sidecars,
                audit_sidecar_validation_results,
            ),
        };
        if error.is_some() {
            return error;
        }
    }
    None
}

fn independent_checker_required_machine_result_ai_sidecar_diagnostic_error(
    target_index: usize,
    target: &IndependentCheckerRequiredAiSidecarDiagnosticTarget,
    context: &IndependentCheckerCiDiagnosticTargetContext,
    input_policy_hash: Hash,
    ai_sidecars: &[IndependentCheckerResolvedAiAuditSidecarEntry],
    audit_sidecar_validation_results: &[IndependentCheckerResolvedAuditSidecarValidationEntry],
) -> Option<IndependentCheckerAiSidecarDiagnosticError> {
    let IndependentCheckerRequiredAiSidecarDiagnosticTarget::MachineResult {
        checker_profile,
        request_hash,
        result_hash,
        policy_hash,
        ..
    } = target
    else {
        return None;
    };
    let selected_raw_results = context
        .normalizer_machine_results
        .iter()
        .filter(|result| {
            result.checker.profile == *checker_profile
                && result.request_hash == *request_hash
                && result.result_hash() == *result_hash
                && result.policy.hash == *policy_hash
        })
        .collect::<Vec<_>>();
    let selected_raw_result =
        match selected_raw_results.as_slice() {
            [] => {
                return Some(IndependentCheckerAiSidecarDiagnosticError::value(
                    IndependentCheckerAiSidecarDiagnosticFailureReasonCode::RequiredAiSidecarSelectedRawMissing,
                    format!("required_ai_sidecar_targets[{target_index}].selected_raw_result"),
                    "exactly_one_selected_raw_machine_check_result",
                    "missing",
                ))
            }
            [selected] => *selected,
            _ => return Some(IndependentCheckerAiSidecarDiagnosticError::value(
                IndependentCheckerAiSidecarDiagnosticFailureReasonCode::RequiredAiSidecarSelectedRawDuplicate,
                format!("required_ai_sidecar_targets[{target_index}].selected_raw_result"),
                "exactly_one_selected_raw_machine_check_result",
                "duplicate",
            )),
        };
    let normalized_result_hash = context.artifact.normalized_result_hash();
    let candidates = ai_sidecars
        .iter()
        .enumerate()
        .filter(|(_, sidecar)| {
            independent_checker_machine_result_diagnostic_sidecar_matches(
                &sidecar.artifact,
                selected_raw_result,
                normalized_result_hash,
            )
        })
        .collect::<Vec<_>>();
    let (sidecar_index, sidecar) =
        match candidates.as_slice() {
            [] => return Some(IndependentCheckerAiSidecarDiagnosticError::value(
                IndependentCheckerAiSidecarDiagnosticFailureReasonCode::RequiredAiSidecarMissing,
                format!("required_ai_sidecar_targets[{target_index}].ai_sidecar"),
                "exactly_one_ai_sidecar",
                "missing",
            )),
            [(index, sidecar)] => (*index, *sidecar),
            _ => return Some(IndependentCheckerAiSidecarDiagnosticError::value(
                IndependentCheckerAiSidecarDiagnosticFailureReasonCode::RequiredAiSidecarDuplicate,
                format!("required_ai_sidecar_targets[{target_index}].ai_sidecar"),
                "exactly_one_ai_sidecar",
                "duplicate",
            )),
        };
    independent_checker_required_ai_sidecar_candidate_error(
        sidecar_index,
        sidecar,
        Some(selected_raw_result.run_artifact_hash()),
        input_policy_hash,
        audit_sidecar_validation_results,
    )
}

fn independent_checker_required_normalized_comparison_ai_sidecar_diagnostic_error(
    target_index: usize,
    normalized_result_hash: Hash,
    input_policy_hash: Hash,
    ai_sidecars: &[IndependentCheckerResolvedAiAuditSidecarEntry],
    audit_sidecar_validation_results: &[IndependentCheckerResolvedAuditSidecarValidationEntry],
) -> Option<IndependentCheckerAiSidecarDiagnosticError> {
    let candidates = ai_sidecars
        .iter()
        .enumerate()
        .filter(|(_, sidecar)| {
            sidecar.artifact.source.kind
                == IndependentCheckerAiAuditSidecarSourceKind::NormalizedComparison
                && sidecar.artifact.source.normalized_result_hash == Some(normalized_result_hash)
        })
        .collect::<Vec<_>>();
    let (sidecar_index, sidecar) =
        match candidates.as_slice() {
            [] => return Some(IndependentCheckerAiSidecarDiagnosticError::value(
                IndependentCheckerAiSidecarDiagnosticFailureReasonCode::RequiredAiSidecarMissing,
                format!("required_ai_sidecar_targets[{target_index}].ai_sidecar"),
                "exactly_one_ai_sidecar",
                "missing",
            )),
            [(index, sidecar)] => (*index, *sidecar),
            _ => return Some(IndependentCheckerAiSidecarDiagnosticError::value(
                IndependentCheckerAiSidecarDiagnosticFailureReasonCode::RequiredAiSidecarDuplicate,
                format!("required_ai_sidecar_targets[{target_index}].ai_sidecar"),
                "exactly_one_ai_sidecar",
                "duplicate",
            )),
        };
    independent_checker_required_ai_sidecar_candidate_error(
        sidecar_index,
        sidecar,
        None,
        input_policy_hash,
        audit_sidecar_validation_results,
    )
}

fn independent_checker_machine_result_diagnostic_sidecar_matches(
    sidecar: &IndependentCheckerAiAuditSidecar,
    selected_raw_result: &IndependentCheckerMachineCheckResult,
    normalized_result_hash: Hash,
) -> bool {
    sidecar.source.kind == IndependentCheckerAiAuditSidecarSourceKind::MachineResult
        && sidecar.source.request_hash == Some(selected_raw_result.request_hash)
        && sidecar.source.result_hash == Some(selected_raw_result.result_hash())
        && sidecar
            .source
            .normalized_result_hash
            .is_none_or(|hash| hash == normalized_result_hash)
}

fn independent_checker_required_ai_sidecar_candidate_error(
    sidecar_index: usize,
    sidecar: &IndependentCheckerResolvedAiAuditSidecarEntry,
    selected_raw_run_artifact_hash: Option<Hash>,
    input_policy_hash: Hash,
    audit_sidecar_validation_results: &[IndependentCheckerResolvedAuditSidecarValidationEntry],
) -> Option<IndependentCheckerAiSidecarDiagnosticError> {
    if sidecar.artifact.input_policy.hash != input_policy_hash {
        return Some(IndependentCheckerAiSidecarDiagnosticError::hash(
            IndependentCheckerAiSidecarDiagnosticFailureReasonCode::RequiredAiSidecarInputPolicyMismatch,
            format!("ai_sidecar[{sidecar_index}].artifact.input_policy.hash"),
            input_policy_hash,
            sidecar.artifact.input_policy.hash,
        ));
    }
    let validation_candidates = audit_sidecar_validation_results
        .iter()
        .enumerate()
        .filter(|(_, validation)| validation.artifact.sidecar_file_hash == Some(sidecar.file_hash))
        .collect::<Vec<_>>();
    let (validation_index, validation) =
        match validation_candidates.as_slice() {
            [] => {
                return Some(IndependentCheckerAiSidecarDiagnosticError::value(
                    IndependentCheckerAiSidecarDiagnosticFailureReasonCode::RequiredAiSidecarValidationMissing,
                    format!("ai_sidecar[{sidecar_index}].validation_response"),
                    "exactly_one_audit_sidecar_validation_result",
                    "missing",
                ))
            }
            [(index, validation)] => (*index, *validation),
            _ => return Some(IndependentCheckerAiSidecarDiagnosticError::value(
                IndependentCheckerAiSidecarDiagnosticFailureReasonCode::RequiredAiSidecarValidationDuplicate,
                format!("ai_sidecar[{sidecar_index}].validation_response"),
                "exactly_one_audit_sidecar_validation_result",
                "duplicate",
            )),
        };
    if validation.artifact.mode != IndependentCheckerAuditSidecarValidationMode::CrossArtifact {
        return Some(IndependentCheckerAiSidecarDiagnosticError::value(
            IndependentCheckerAiSidecarDiagnosticFailureReasonCode::RequiredAiSidecarValidationModeMismatch,
            format!("audit_sidecar_validation[{validation_index}].artifact.mode"),
            IndependentCheckerAuditSidecarValidationMode::CrossArtifact.as_str(),
            validation.artifact.mode.as_str(),
        ));
    }
    if validation.artifact.status != IndependentCheckerAuditSidecarValidationStatus::Valid {
        return Some(IndependentCheckerAiSidecarDiagnosticError::value(
            IndependentCheckerAiSidecarDiagnosticFailureReasonCode::RequiredAiSidecarValidationFailed,
            format!("audit_sidecar_validation[{validation_index}].artifact.status"),
            IndependentCheckerAuditSidecarValidationStatus::Valid.as_str(),
            validation.artifact.status.as_str(),
        ));
    }
    if validation.artifact.input_policy_hash != Some(input_policy_hash) {
        return Some(independent_checker_diagnostic_expected_hash_actual_optional_hash_error(
            IndependentCheckerAiSidecarDiagnosticFailureReasonCode::RequiredAiSidecarValidationInputPolicyMismatch,
            format!("audit_sidecar_validation[{validation_index}].artifact.input_policy_hash"),
            input_policy_hash,
            validation.artifact.input_policy_hash,
        ));
    }
    if !independent_checker_audit_sidecar_validation_source_matches_sidecar(
        &validation.artifact,
        &sidecar.artifact,
    ) {
        return Some(IndependentCheckerAiSidecarDiagnosticError::value(
            IndependentCheckerAiSidecarDiagnosticFailureReasonCode::RequiredAiSidecarValidationSourceMismatch,
            format!("audit_sidecar_validation[{validation_index}].artifact"),
            "source_kind_specific_matching_key",
            "source_key_mismatch",
        ));
    }
    if let Some(expected_run_artifact_hash) = selected_raw_run_artifact_hash {
        let actual_run_artifact_hash = sidecar
            .artifact
            .source
            .run_artifact_hash
            .expect("machine-result AI sidecar source is schema-valid");
        if actual_run_artifact_hash != expected_run_artifact_hash {
            return Some(IndependentCheckerAiSidecarDiagnosticError::hash(
                IndependentCheckerAiSidecarDiagnosticFailureReasonCode::RequiredAiSidecarSourceMismatch,
                format!("ai_sidecar[{sidecar_index}].artifact.source.run_artifact_hash"),
                expected_run_artifact_hash,
                actual_run_artifact_hash,
            ));
        }
    }
    None
}

fn independent_checker_diagnostic_expected_hash_actual_optional_hash_error(
    reason_code: IndependentCheckerAiSidecarDiagnosticFailureReasonCode,
    field: impl Into<String>,
    expected_hash: Hash,
    actual_hash: Option<Hash>,
) -> IndependentCheckerAiSidecarDiagnosticError {
    match actual_hash {
        Some(actual_hash) => IndependentCheckerAiSidecarDiagnosticError::hash(
            reason_code,
            field,
            expected_hash,
            actual_hash,
        ),
        None => IndependentCheckerAiSidecarDiagnosticError {
            reason_code,
            field: field.into(),
            expected_hash: Some(expected_hash),
            actual_hash: None,
            expected_value: None,
            actual_value: Some("missing".to_owned()),
        },
    }
}

fn independent_checker_audit_sidecar_validation_source_matches_sidecar(
    validation: &IndependentCheckerAuditSidecarValidationResult,
    sidecar: &IndependentCheckerAiAuditSidecar,
) -> bool {
    if validation.source_kind != Some(sidecar.source.kind) {
        return false;
    }
    match sidecar.source.kind {
        IndependentCheckerAiAuditSidecarSourceKind::MachineResult => {
            validation.source_result_hash == sidecar.source.result_hash
                && match sidecar.source.normalized_result_hash {
                    Some(hash) => validation.source_normalized_result_hash == Some(hash),
                    None => validation.source_normalized_result_hash.is_none(),
                }
        }
        IndependentCheckerAiAuditSidecarSourceKind::NormalizedComparison => {
            validation.source_result_hash.is_none()
                && validation.source_normalized_result_hash == sidecar.source.normalized_result_hash
        }
    }
}

fn independent_checker_first_required_ai_sidecar_diagnostic_pass_failure(
    policy_hash: Hash,
    input_policy_hash: Hash,
    ci_diagnostic_targets: &[IndependentCheckerCiDiagnosticTargetContext],
    target_sets: &[Vec<IndependentCheckerRequiredAiSidecarDiagnosticTarget>],
    recomputed_results: &[IndependentCheckerAiSidecarDiagnosticResult],
    saved_results: &[IndependentCheckerResolvedAiSidecarDiagnosticResultEntry],
) -> Option<IndependentCheckerAiSidecarDiagnosticPassFailure> {
    for (context_index, context) in ci_diagnostic_targets.iter().enumerate() {
        if target_sets[context_index].is_empty() {
            continue;
        }
        let normalized_result_hash = context.artifact.normalized_result_hash();
        let candidates = saved_results
            .iter()
            .enumerate()
            .filter(|(_, saved)| {
                let artifact = &saved.artifact;
                artifact.policy_hash == policy_hash
                    && artifact.input_policy_hash == input_policy_hash
                    && artifact.normalized_result_hash == normalized_result_hash
            })
            .collect::<Vec<_>>();
        let (saved_index, saved) = match candidates.as_slice() {
            [] => {
                return Some(IndependentCheckerAiSidecarDiagnosticPassFailure::value(
                    IndependentCheckerAiSidecarDiagnosticPassFailureReasonCode::RequiredAiSidecarDiagnosticMissing,
                    format!("ci_diagnostic_targets[{context_index}].ai_sidecar_diagnostic_result"),
                    "exactly_one_saved_ai_sidecar_diagnostic_result",
                    "missing",
                ))
            }
            [(index, saved)] => (*index, *saved),
            _ => {
                return Some(IndependentCheckerAiSidecarDiagnosticPassFailure::value(
                    IndependentCheckerAiSidecarDiagnosticPassFailureReasonCode::RequiredAiSidecarDiagnosticDuplicate,
                    format!("ci_diagnostic_targets[{context_index}].ai_sidecar_diagnostic_result"),
                    "exactly_one_saved_ai_sidecar_diagnostic_result",
                    "duplicate",
                ))
            }
        };
        if saved.artifact.status != IndependentCheckerAiSidecarDiagnosticStatus::Passed {
            return Some(IndependentCheckerAiSidecarDiagnosticPassFailure::value(
                IndependentCheckerAiSidecarDiagnosticPassFailureReasonCode::RequiredAiSidecarDiagnosticNotPassed,
                format!("ai_sidecar_diagnostic[{saved_index}].artifact.status"),
                IndependentCheckerAiSidecarDiagnosticStatus::Passed.as_str(),
                saved.artifact.status.as_str(),
            ));
        }
        let expected_json = recomputed_results[context_index].canonical_json();
        let actual_json = saved.artifact.canonical_json();
        if expected_json != actual_json {
            return Some(IndependentCheckerAiSidecarDiagnosticPassFailure::hash(
                IndependentCheckerAiSidecarDiagnosticPassFailureReasonCode::RequiredAiSidecarDiagnosticCanonicalMismatch,
                format!("ai_sidecar_diagnostic[{saved_index}].artifact"),
                independent_checker_sha256(expected_json.as_bytes()),
                independent_checker_sha256(actual_json.as_bytes()),
            ));
        }
    }
    None
}

pub fn parse_independent_checker_normalized_result_store_manifest(
    source: &str,
) -> Result<IndependentCheckerNormalizedResultStoreManifest, IndependentCheckerRequestValidationError>
{
    let document = JsonDocument::parse(source).map_err(|_| {
        IndependentCheckerRequestValidationError::value_failure(
            "normalized_store",
            "valid_json",
            "invalid_json",
        )
    })?;
    parse_independent_checker_normalized_result_store_manifest_value(
        document.root(),
        "normalized_store",
    )
}

pub fn independent_checker_normalized_result_store_entry_for_result(
    result: &IndependentCheckerNormalizedCheckResult,
    path: impl Into<String>,
) -> Result<IndependentCheckerNormalizedResultStoreEntry, IndependentCheckerCommandError> {
    let path = path.into();
    if !independent_checker_valid_workspace_relative_path(&path) {
        return Err(independent_checker_command_value_error(
            IndependentCheckerCommandName::NormalizeResults,
            "input_reference_invalid",
            "normalized_result.path",
            "workspace_relative_path",
            "invalid_path",
        ));
    }
    let bytes = result.canonical_json();
    Ok(IndependentCheckerNormalizedResultStoreEntry {
        normalized_result_hash: result.normalized_result_hash(),
        artifact_hash: result.artifact_hash(),
        path,
        file_hash: independent_checker_file_hash(bytes.as_bytes()),
    })
}

pub fn independent_checker_normalized_result_store_with_entry(
    existing_store: Option<&IndependentCheckerNormalizedResultStoreManifest>,
    generated_entry: IndependentCheckerNormalizedResultStoreEntry,
) -> Result<IndependentCheckerNormalizedResultStoreUpdate, IndependentCheckerCommandError> {
    let mut manifest =
        existing_store
            .cloned()
            .unwrap_or(IndependentCheckerNormalizedResultStoreManifest {
                results: Vec::new(),
            });

    for existing in &manifest.results {
        let same_normalized_result_hash =
            existing.normalized_result_hash == generated_entry.normalized_result_hash;
        let same_path = existing.path == generated_entry.path;
        let exact = same_normalized_result_hash
            && same_path
            && existing.artifact_hash == generated_entry.artifact_hash
            && existing.file_hash == generated_entry.file_hash;
        if exact {
            return Ok(IndependentCheckerNormalizedResultStoreUpdate {
                manifest,
                rewrite_required: false,
            });
        }
        if same_normalized_result_hash || same_path {
            return Err(independent_checker_command_value_error(
                IndependentCheckerCommandName::NormalizeResults,
                "normalized_store_entry_conflict",
                "normalized_store.results[]",
                generated_entry.canonical_json(),
                existing.canonical_json(),
            ));
        }
    }

    manifest.results.push(generated_entry);
    manifest.results.sort_by(|left, right| {
        left.normalized_result_hash
            .cmp(&right.normalized_result_hash)
    });
    Ok(IndependentCheckerNormalizedResultStoreUpdate {
        manifest,
        rewrite_required: true,
    })
}

pub fn independent_checker_normalization_write_result(
    normalized_result: &IndependentCheckerNormalizedCheckResult,
    output_path: impl Into<String>,
    normalized_store: Option<IndependentCheckerNormalizationWriteStore>,
) -> Result<IndependentCheckerNormalizationWriteResult, IndependentCheckerCommandError> {
    let output_path = output_path.into();
    if !independent_checker_valid_workspace_relative_path(&output_path) {
        return Err(independent_checker_command_value_error(
            IndependentCheckerCommandName::NormalizeResults,
            "input_reference_invalid",
            "output_path",
            "workspace_relative_path",
            "invalid_path",
        ));
    }
    if let Some(store) = &normalized_store {
        if !independent_checker_valid_workspace_relative_path(&store.path) {
            return Err(independent_checker_command_value_error(
                IndependentCheckerCommandName::NormalizeResults,
                "input_reference_invalid",
                "normalized_store.path",
                "workspace_relative_path",
                "invalid_path",
            ));
        }
    }
    let bytes = normalized_result.canonical_json();
    Ok(IndependentCheckerNormalizationWriteResult {
        normalized_result_hash: normalized_result.normalized_result_hash(),
        artifact_hash: normalized_result.artifact_hash(),
        output_path,
        output_file_hash: independent_checker_file_hash(bytes.as_bytes()),
        normalized_store,
    })
}

impl IndependentCheckerRawResultSchemaError {
    fn new(
        field: impl Into<String>,
        expected_value: impl Into<String>,
        actual_value: impl Into<String>,
    ) -> Self {
        Self {
            field: field.into(),
            expected_value: expected_value.into(),
            actual_value: actual_value.into(),
        }
    }
}

fn independent_checker_budget_mismatch_error(
    expected: &IndependentCheckerRunnerBudget,
    actual: &IndependentCheckerRunnerBudget,
) -> IndependentCheckerMachineCheckError {
    let (field, expected_value, actual_value) = if expected.max_steps != actual.max_steps {
        (
            "budget.max_steps",
            expected.max_steps.to_string(),
            actual.max_steps.to_string(),
        )
    } else if expected.max_memory_mb != actual.max_memory_mb {
        (
            "budget.max_memory_mb",
            expected.max_memory_mb.to_string(),
            actual.max_memory_mb.to_string(),
        )
    } else {
        (
            "budget.timeout_ms",
            expected.timeout_ms.to_string(),
            actual.timeout_ms.to_string(),
        )
    };
    IndependentCheckerMachineCheckError::new("policy_failure")
        .with_reason_code("request_budget_mismatch")
        .with_value_payload(field, expected_value, actual_value)
}

fn independent_checker_normalize_value_error(
    result_id: impl Into<String>,
    policy_hash: Hash,
    reason_code: IndependentCheckerNormalizeErrorReasonCode,
    field: impl Into<String>,
    expected_value: impl Into<String>,
    actual_value: impl Into<String>,
) -> IndependentCheckerNormalizeErrorResult {
    IndependentCheckerNormalizeErrorResult::normalize_failure(result_id, reason_code, field)
        .with_policy_hash(policy_hash)
        .with_error_expected_value(expected_value)
        .with_error_actual_value(actual_value)
}

fn independent_checker_normalize_hash_error(
    result_id: impl Into<String>,
    policy_hash: Hash,
    reason_code: IndependentCheckerNormalizeErrorReasonCode,
    field: impl Into<String>,
    expected_hash: Hash,
    actual_hash: Hash,
) -> IndependentCheckerNormalizeErrorResult {
    IndependentCheckerNormalizeErrorResult::normalize_failure(result_id, reason_code, field)
        .with_policy_hash(policy_hash)
        .with_error_expected_hash(expected_hash)
        .with_error_actual_hash(actual_hash)
}

fn independent_checker_normalize_actual_hash_error(
    result_id: impl Into<String>,
    policy_hash: Hash,
    reason_code: IndependentCheckerNormalizeErrorReasonCode,
    field: impl Into<String>,
    actual_hash: Hash,
) -> IndependentCheckerNormalizeErrorResult {
    IndependentCheckerNormalizeErrorResult::normalize_failure(result_id, reason_code, field)
        .with_policy_hash(policy_hash)
        .with_error_actual_hash(actual_hash)
}

fn independent_checker_normalize_request_validation_error(
    result_id: impl Into<String>,
    policy_hash: Hash,
    reason_code: IndependentCheckerNormalizeErrorReasonCode,
    error: IndependentCheckerRequestValidationError,
) -> IndependentCheckerNormalizeErrorResult {
    let mut out = IndependentCheckerNormalizeErrorResult::normalize_failure(
        result_id,
        reason_code,
        error.field,
    )
    .with_policy_hash(policy_hash);
    if let Some(expected_value) = error.expected_value {
        out = out.with_error_expected_value(expected_value);
    }
    if let Some(actual_value) = error.actual_value {
        out = out.with_error_actual_value(actual_value);
    }
    if let Some(expected_hash) = error.expected_hash {
        out = out.with_error_expected_hash(*expected_hash);
    }
    if let Some(actual_hash) = error.actual_hash {
        out = out.with_error_actual_hash(*actual_hash);
    }
    out
}

fn independent_checker_validate_machine_result_for_normalization(
    result: &IndependentCheckerMachineCheckResult,
) -> Result<(), (&'static str, &'static str, &'static str)> {
    if !independent_checker_valid_request_id(&result.result_id) {
        return Err((
            "machine_results[].result_id",
            "result_id",
            if result.result_id.is_empty() {
                "empty_string"
            } else {
                "invalid_string_format"
            },
        ));
    }
    if !independent_checker_valid_checker_profile_name(&result.checker.profile) {
        return Err((
            "machine_results[].checker.profile",
            "checker_profile_name",
            "invalid_name_format",
        ));
    }
    if result.process.launched {
        if result.checker.binary_id.is_none() {
            return Err((
                "machine_results[].checker.binary_id",
                "checker_binary_id",
                "missing",
            ));
        }
        if result.checker.binary_hash.is_none() {
            return Err((
                "machine_results[].checker.binary_hash",
                "sha256:<lower-hex>",
                "missing",
            ));
        }
    }
    match result.status {
        IndependentCheckerMachineCheckStatus::Checked => {
            if result.certificate_hash.is_none() {
                return Err((
                    "machine_results[].certificate_hash",
                    "sha256:<lower-hex>",
                    "missing",
                ));
            }
            if result.export_hash.is_none() {
                return Err((
                    "machine_results[].export_hash",
                    "sha256:<lower-hex>",
                    "missing",
                ));
            }
            if result.axiom_report_hash.is_none() {
                return Err((
                    "machine_results[].axiom_report_hash",
                    "sha256:<lower-hex>",
                    "missing",
                ));
            }
            if result.error.is_some() {
                return Err((
                    "machine_results[].error",
                    "absent_for_status",
                    "forbidden_field",
                ));
            }
        }
        IndependentCheckerMachineCheckStatus::Failed => {
            if result.error.is_none() {
                return Err((
                    "machine_results[].error",
                    "MachineCheckResult.error",
                    "missing",
                ));
            }
        }
    }
    Ok(())
}

fn independent_checker_order_machine_results_for_normalization<'a>(
    policy: &IndependentCheckerRunnerPolicy,
    machine_results: &'a [IndependentCheckerMachineCheckResult],
) -> Vec<&'a IndependentCheckerMachineCheckResult> {
    let mut out = Vec::new();
    for profile in &policy.required_checker_profiles {
        if let Some(result) = machine_results
            .iter()
            .find(|result| &result.checker.profile == profile)
        {
            out.push(result);
        }
    }
    for profile in &policy.optional_checker_profiles {
        if let Some(result) = machine_results
            .iter()
            .find(|result| &result.checker.profile == profile)
        {
            out.push(result);
        }
    }
    let known = policy
        .required_checker_profiles
        .iter()
        .chain(policy.optional_checker_profiles.iter())
        .collect::<BTreeSet<_>>();
    let mut outside_policy = machine_results
        .iter()
        .filter(|result| !known.contains(&result.checker.profile))
        .collect::<Vec<_>>();
    outside_policy.sort_by_key(|result| result.checker.profile.clone());
    out.extend(outside_policy);
    out
}

fn independent_checker_lookup_stored_request<'a>(
    manifest: &IndependentCheckerRequestStoreManifest,
    stored_requests: &'a [IndependentCheckerStoredMachineCheckRequest],
    request_hash: Hash,
    field: &'static str,
    result_id: String,
    policy_hash: Hash,
) -> Result<&'a IndependentCheckerStoredMachineCheckRequest, IndependentCheckerNormalizeErrorResult>
{
    let Some(entry) = manifest
        .requests
        .iter()
        .find(|entry| entry.request_hash == request_hash)
    else {
        return Err(independent_checker_normalize_actual_hash_error(
            result_id,
            policy_hash,
            IndependentCheckerNormalizeErrorReasonCode::RequestHashNotFound,
            field,
            request_hash,
        ));
    };
    let Some(stored) = stored_requests
        .iter()
        .find(|request| request.request.request_hash() == request_hash)
    else {
        return Err(independent_checker_normalize_value_error(
            result_id,
            policy_hash,
            IndependentCheckerNormalizeErrorReasonCode::RequestFileUnreadable,
            "request_store.requests[].path",
            "readable",
            "unreadable",
        ));
    };
    if stored.path != entry.path {
        return Err(independent_checker_normalize_value_error(
            result_id,
            policy_hash,
            IndependentCheckerNormalizeErrorReasonCode::RequestStoreManifestInvalid,
            "request_store.requests[].path",
            &entry.path,
            &stored.path,
        ));
    }
    if stored.file_hash != entry.file_hash {
        return Err(independent_checker_normalize_hash_error(
            result_id,
            policy_hash,
            IndependentCheckerNormalizeErrorReasonCode::RequestFileHashMismatch,
            "request_store.requests[].file_hash",
            entry.file_hash,
            stored.file_hash,
        ));
    }
    Ok(stored)
}

fn independent_checker_normalized_entry_from_machine_result(
    result: &IndependentCheckerMachineCheckResult,
    artifact_hash: Hash,
) -> IndependentCheckerNormalizedCheckResultEntry {
    let failure_key = result
        .error
        .as_ref()
        .map(IndependentCheckerNormalizedFailureKey::from_error);
    IndependentCheckerNormalizedCheckResultEntry {
        result_id: result.result_id.clone(),
        result_hash: result.result_hash(),
        request_hash: result.request_hash,
        policy_hash: result.policy.hash,
        artifact_hash,
        checker_profile: result.checker.profile.clone(),
        process_launched: result.process.launched,
        status: result.status,
        checker_binary_id: result
            .process
            .launched
            .then(|| result.checker.binary_id.clone())
            .flatten(),
        checker_binary_hash: result
            .process
            .launched
            .then_some(result.checker.binary_hash)
            .flatten(),
        checker_id: result
            .process
            .launched
            .then(|| result.checker.id.clone())
            .flatten(),
        checker_build_hash: result
            .process
            .launched
            .then_some(result.checker.build_hash)
            .flatten(),
        certificate_hash: result.certificate_hash,
        export_hash: result.export_hash,
        axiom_report_hash: result.axiom_report_hash,
        error: result.error.clone(),
        failure_key,
    }
}

fn independent_checker_normalized_entry_matches_machine_result(
    entry: &IndependentCheckerNormalizedCheckResultEntry,
    result: &IndependentCheckerMachineCheckResult,
) -> bool {
    let expected =
        independent_checker_normalized_entry_from_machine_result(result, entry.artifact_hash);
    entry == &expected
}

fn independent_checker_normalized_entry_declaration(
    entry: &IndependentCheckerNormalizedCheckResultEntry,
) -> Option<String> {
    entry
        .failure_key
        .as_ref()
        .and_then(|failure_key| failure_key.declaration.clone())
        .or_else(|| {
            entry
                .error
                .as_ref()
                .and_then(|error| error.declaration.clone())
        })
}

fn independent_checker_assert_normalized_entry_source_copy(
    entry: &IndependentCheckerNormalizedCheckResultEntry,
    result: &IndependentCheckerMachineCheckResult,
) {
    debug_assert_eq!(entry.result_id, result.result_id);
    debug_assert_eq!(entry.result_hash, result.result_hash());
    debug_assert_eq!(entry.request_hash, result.request_hash);
    debug_assert_eq!(entry.policy_hash, result.policy.hash);
    debug_assert_eq!(entry.checker_profile, result.checker.profile);
    debug_assert_eq!(entry.process_launched, result.process.launched);
    debug_assert_eq!(entry.status, result.status);
    if result.process.launched {
        debug_assert_eq!(entry.checker_binary_id, result.checker.binary_id);
        debug_assert_eq!(entry.checker_binary_hash, result.checker.binary_hash);
        debug_assert_eq!(entry.checker_id, result.checker.id);
        debug_assert_eq!(entry.checker_build_hash, result.checker.build_hash);
    } else {
        debug_assert_eq!(entry.checker_binary_id, None);
        debug_assert_eq!(entry.checker_binary_hash, None);
        debug_assert_eq!(entry.checker_id, None);
        debug_assert_eq!(entry.checker_build_hash, None);
    }
    debug_assert_eq!(entry.certificate_hash, result.certificate_hash);
    debug_assert_eq!(entry.export_hash, result.export_hash);
    debug_assert_eq!(entry.axiom_report_hash, result.axiom_report_hash);
    debug_assert_eq!(entry.error, result.error);
}

fn independent_checker_build_normalized_comparison_parts(
    policy: &IndependentCheckerRunnerPolicy,
    normalized_policy_hash: Hash,
    artifact_hash: Hash,
    entries: &[IndependentCheckerNormalizedCheckResultEntry],
) -> IndependentCheckerNormalizedComparison {
    let participating_entries = entries
        .iter()
        .filter(|entry| {
            independent_checker_policy_has_checker_profile(policy, &entry.checker_profile)
        })
        .collect::<Vec<_>>();

    let policy_reasons = independent_checker_normalized_comparison_policy_reasons(
        policy,
        normalized_policy_hash,
        entries,
    );
    if !policy_reasons.is_empty() {
        return independent_checker_normalized_comparison_with_reasons(
            IndependentCheckerNormalizedComparisonStatus::PolicyFailure,
            policy_reasons,
        );
    }

    let copied_policy_reasons = entries
        .iter()
        .filter(|entry| !independent_checker_malformed_process_state(entry))
        .filter_map(|entry| {
            let error = entry.error.as_ref()?;
            (error.kind == "policy_failure")
                .then(|| independent_checker_status_reason_from_error(entry, "policy_failure"))
        })
        .collect::<Vec<_>>();
    if !copied_policy_reasons.is_empty() {
        return independent_checker_normalized_comparison_with_reasons(
            IndependentCheckerNormalizedComparisonStatus::PolicyFailure,
            copied_policy_reasons,
        );
    }

    let identity_reasons =
        independent_checker_normalized_comparison_identity_reasons(policy, &participating_entries);
    if !identity_reasons.is_empty() {
        return independent_checker_normalized_comparison_with_reasons(
            IndependentCheckerNormalizedComparisonStatus::PolicyFailure,
            identity_reasons,
        );
    }

    let malformed_reasons = participating_entries
        .iter()
        .copied()
        .filter(|entry| independent_checker_malformed_process_state(entry))
        .map(independent_checker_malformed_process_state_reason)
        .collect::<Vec<_>>();
    if !malformed_reasons.is_empty() {
        return independent_checker_normalized_comparison_with_reasons(
            IndependentCheckerNormalizedComparisonStatus::Inconclusive,
            malformed_reasons,
        );
    }

    let present_profiles = entries
        .iter()
        .map(|entry| entry.checker_profile.as_str())
        .collect::<BTreeSet<_>>();
    let missing_checker_profiles = policy
        .required_checker_profiles
        .iter()
        .filter(|profile| !present_profiles.contains(profile.as_str()))
        .cloned()
        .collect::<Vec<_>>();
    if !missing_checker_profiles.is_empty() {
        return IndependentCheckerNormalizedComparison {
            status: IndependentCheckerNormalizedComparisonStatus::MissingCheckerResult,
            matching_fields: Vec::new(),
            missing_checker_profiles,
            disagreements: Vec::new(),
            status_reasons: Vec::new(),
        };
    }

    let mut disagreements = Vec::new();
    for entry in &participating_entries {
        if entry.artifact_hash != artifact_hash {
            disagreements.push(IndependentCheckerNormalizedDisagreement {
                field: "artifact_hash".to_owned(),
                baseline_checker_profile: None,
                baseline_hash: Some(artifact_hash),
                baseline_value: None,
                checker_profile: entry.checker_profile.clone(),
                actual_hash: Some(entry.artifact_hash),
                actual_value: None,
            });
        }
    }
    if !disagreements.is_empty() {
        independent_checker_sort_normalized_disagreements(&mut disagreements);
        return IndependentCheckerNormalizedComparison {
            status: IndependentCheckerNormalizedComparisonStatus::Disagreement,
            matching_fields: Vec::new(),
            missing_checker_profiles: Vec::new(),
            disagreements,
            status_reasons: Vec::new(),
        };
    }

    let inconclusive_reasons = participating_entries
        .iter()
        .copied()
        .filter(|entry| independent_checker_inconclusive_comparison_source(entry))
        .map(|entry| independent_checker_status_reason_from_error(entry, "inconclusive"))
        .collect::<Vec<_>>();
    if !inconclusive_reasons.is_empty() {
        return independent_checker_normalized_comparison_with_reasons(
            IndependentCheckerNormalizedComparisonStatus::Inconclusive,
            inconclusive_reasons,
        );
    }

    let Some(baseline) = participating_entries.first().copied() else {
        return IndependentCheckerNormalizedComparison {
            status: IndependentCheckerNormalizedComparisonStatus::Inconclusive,
            matching_fields: Vec::new(),
            missing_checker_profiles: Vec::new(),
            disagreements: Vec::new(),
            status_reasons: Vec::new(),
        };
    };

    if participating_entries
        .iter()
        .all(|entry| entry.status == IndependentCheckerMachineCheckStatus::Checked)
    {
        for entry in participating_entries.iter().skip(1).copied() {
            independent_checker_push_hash_disagreement(
                &mut disagreements,
                "certificate_hash",
                baseline,
                entry,
                baseline.certificate_hash,
                entry.certificate_hash,
            );
            independent_checker_push_hash_disagreement(
                &mut disagreements,
                "export_hash",
                baseline,
                entry,
                baseline.export_hash,
                entry.export_hash,
            );
            independent_checker_push_hash_disagreement(
                &mut disagreements,
                "axiom_report_hash",
                baseline,
                entry,
                baseline.axiom_report_hash,
                entry.axiom_report_hash,
            );
        }
        if disagreements.is_empty() {
            return IndependentCheckerNormalizedComparison {
                status: IndependentCheckerNormalizedComparisonStatus::AllAgreeChecked,
                matching_fields: vec![
                    "certificate_hash".to_owned(),
                    "export_hash".to_owned(),
                    "axiom_report_hash".to_owned(),
                ],
                missing_checker_profiles: Vec::new(),
                disagreements,
                status_reasons: Vec::new(),
            };
        }
    } else if participating_entries
        .iter()
        .all(|entry| entry.status == IndependentCheckerMachineCheckStatus::Failed)
    {
        let baseline_hash = baseline
            .failure_key
            .as_ref()
            .map(IndependentCheckerNormalizedFailureKey::failure_key_hash);
        for entry in participating_entries.iter().skip(1).copied() {
            let actual_hash = entry
                .failure_key
                .as_ref()
                .map(IndependentCheckerNormalizedFailureKey::failure_key_hash);
            independent_checker_push_hash_disagreement(
                &mut disagreements,
                "failure_key",
                baseline,
                entry,
                baseline_hash,
                actual_hash,
            );
        }
        if disagreements.is_empty() {
            return IndependentCheckerNormalizedComparison {
                status: IndependentCheckerNormalizedComparisonStatus::AllAgreeFailed,
                matching_fields: vec!["failure_key".to_owned()],
                missing_checker_profiles: Vec::new(),
                disagreements,
                status_reasons: Vec::new(),
            };
        }
    } else {
        independent_checker_push_status_disagreements(
            &mut disagreements,
            baseline,
            &participating_entries,
        );
        for entry in participating_entries.iter().skip(1).copied() {
            if baseline.status != entry.status {
                continue;
            }
            match baseline.status {
                IndependentCheckerMachineCheckStatus::Checked => {
                    independent_checker_push_hash_disagreement(
                        &mut disagreements,
                        "certificate_hash",
                        baseline,
                        entry,
                        baseline.certificate_hash,
                        entry.certificate_hash,
                    );
                    independent_checker_push_hash_disagreement(
                        &mut disagreements,
                        "export_hash",
                        baseline,
                        entry,
                        baseline.export_hash,
                        entry.export_hash,
                    );
                    independent_checker_push_hash_disagreement(
                        &mut disagreements,
                        "axiom_report_hash",
                        baseline,
                        entry,
                        baseline.axiom_report_hash,
                        entry.axiom_report_hash,
                    );
                }
                IndependentCheckerMachineCheckStatus::Failed => {
                    let baseline_hash = baseline
                        .failure_key
                        .as_ref()
                        .map(IndependentCheckerNormalizedFailureKey::failure_key_hash);
                    let actual_hash = entry
                        .failure_key
                        .as_ref()
                        .map(IndependentCheckerNormalizedFailureKey::failure_key_hash);
                    independent_checker_push_hash_disagreement(
                        &mut disagreements,
                        "failure_key",
                        baseline,
                        entry,
                        baseline_hash,
                        actual_hash,
                    );
                }
            }
        }
    }

    independent_checker_sort_normalized_disagreements(&mut disagreements);
    IndependentCheckerNormalizedComparison {
        status: IndependentCheckerNormalizedComparisonStatus::Disagreement,
        matching_fields: Vec::new(),
        missing_checker_profiles: Vec::new(),
        disagreements,
        status_reasons: Vec::new(),
    }
}

fn independent_checker_normalized_comparison_with_reasons(
    status: IndependentCheckerNormalizedComparisonStatus,
    mut status_reasons: Vec<IndependentCheckerNormalizedStatusReason>,
) -> IndependentCheckerNormalizedComparison {
    independent_checker_sort_normalized_status_reasons(&mut status_reasons);
    IndependentCheckerNormalizedComparison {
        status,
        matching_fields: Vec::new(),
        missing_checker_profiles: Vec::new(),
        disagreements: Vec::new(),
        status_reasons,
    }
}

fn independent_checker_policy_has_checker_profile(
    policy: &IndependentCheckerRunnerPolicy,
    profile: &str,
) -> bool {
    policy
        .required_checker_profiles
        .iter()
        .chain(policy.optional_checker_profiles.iter())
        .any(|allowed| allowed == profile)
}

fn independent_checker_normalized_comparison_policy_reasons(
    policy: &IndependentCheckerRunnerPolicy,
    normalized_policy_hash: Hash,
    entries: &[IndependentCheckerNormalizedCheckResultEntry],
) -> Vec<IndependentCheckerNormalizedStatusReason> {
    let expected_policy_hash = policy.policy_hash();
    let mut reasons = Vec::new();
    if normalized_policy_hash != expected_policy_hash {
        reasons.push(independent_checker_global_hash_status_reason(
            "policy_failure",
            "policy_failure",
            "policy_hash_mismatch",
            "policy.hash",
            expected_policy_hash,
            normalized_policy_hash,
        ));
    }
    for entry in entries {
        if entry.policy_hash != normalized_policy_hash {
            reasons.push(independent_checker_entry_hash_status_reason(
                entry,
                "policy_failure",
                "policy_failure",
                "result_policy_hash_mismatch",
                "results[].policy_hash",
                normalized_policy_hash,
                entry.policy_hash,
            ));
        }
        if !independent_checker_policy_has_checker_profile(policy, &entry.checker_profile) {
            reasons.push(independent_checker_entry_value_status_reason(
                entry,
                "policy_failure",
                "policy_failure",
                "checker_profile_not_allowed",
                "results[].checker_profile",
                "required_or_optional_checker_profile",
                &entry.checker_profile,
            ));
        }
    }
    reasons
}

fn independent_checker_normalized_comparison_identity_reasons(
    policy: &IndependentCheckerRunnerPolicy,
    entries: &[&IndependentCheckerNormalizedCheckResultEntry],
) -> Vec<IndependentCheckerNormalizedStatusReason> {
    let mut reasons = Vec::new();
    for entry in entries {
        if !entry.process_launched {
            continue;
        }
        let Some(selected) = policy.selected_checker_policy(&entry.checker_profile) else {
            continue;
        };
        if let Some(binary_id) = entry.checker_binary_id.as_deref() {
            if binary_id != selected.binary_id {
                reasons.push(independent_checker_entry_value_status_reason(
                    entry,
                    "policy_failure",
                    "policy_failure",
                    "checker_binary_id_mismatch",
                    "results[].checker_binary_id",
                    &selected.binary_id,
                    binary_id,
                ));
            }
        }
        if let Some(binary_hash) = entry.checker_binary_hash {
            if binary_hash != selected.binary_hash {
                reasons.push(independent_checker_entry_hash_status_reason(
                    entry,
                    "policy_failure",
                    "policy_failure",
                    "checker_binary_hash_mismatch",
                    "results[].checker_binary_hash",
                    selected.binary_hash,
                    binary_hash,
                ));
            }
        }
        if let Some(checker_id) = entry.checker_id.as_deref() {
            if checker_id != selected.checker_id {
                reasons.push(independent_checker_entry_value_status_reason(
                    entry,
                    "policy_failure",
                    "policy_failure",
                    "checker_identity_mismatch",
                    "results[].checker_id",
                    &selected.checker_id,
                    checker_id,
                ));
            }
        }
        if let Some(build_hash) = entry.checker_build_hash {
            if build_hash != selected.build_hash {
                reasons.push(independent_checker_entry_hash_status_reason(
                    entry,
                    "policy_failure",
                    "policy_failure",
                    "checker_build_hash_mismatch",
                    "results[].checker_build_hash",
                    selected.build_hash,
                    build_hash,
                ));
            }
        }
        if !independent_checker_identity_missing_exempt(entry) {
            if entry.checker_id.is_none() {
                reasons.push(independent_checker_entry_value_status_reason(
                    entry,
                    "policy_failure",
                    "policy_failure",
                    "checker_identity_missing",
                    "results[].checker_id",
                    "required_for_launched_non_inconclusive_result",
                    "missing",
                ));
            }
            if entry.checker_build_hash.is_none() {
                reasons.push(independent_checker_entry_value_status_reason(
                    entry,
                    "policy_failure",
                    "policy_failure",
                    "checker_identity_missing",
                    "results[].checker_build_hash",
                    "required_for_launched_non_inconclusive_result",
                    "missing",
                ));
            }
        }
    }
    reasons
}

fn independent_checker_identity_missing_exempt(
    entry: &IndependentCheckerNormalizedCheckResultEntry,
) -> bool {
    matches!(
        entry.error.as_ref().map(|error| error.kind.as_str()),
        Some("checker_internal_error" | "resource_exhausted" | "timeout")
    )
}

fn independent_checker_malformed_process_state(
    entry: &IndependentCheckerNormalizedCheckResultEntry,
) -> bool {
    if !entry.process_launched && entry.status == IndependentCheckerMachineCheckStatus::Checked {
        return true;
    }
    let error_kind = entry.error.as_ref().map(|error| error.kind.as_str());
    let reason_code = entry
        .error
        .as_ref()
        .and_then(|error| error.reason_code.as_deref());
    if !entry.process_launched
        && !matches!(
            error_kind,
            Some("policy_failure" | "timeout" | "resource_exhausted")
        )
    {
        return true;
    }
    if entry.process_launched
        && matches!(
            reason_code,
            Some("launch_timeout" | "launch_resource_exhausted")
        )
    {
        return true;
    }
    !entry.process_launched
        && matches!(
            reason_code,
            Some("checker_timeout" | "checker_resource_exhausted" | "process_exit_failure")
        )
}

fn independent_checker_malformed_process_state_reason(
    entry: &IndependentCheckerNormalizedCheckResultEntry,
) -> IndependentCheckerNormalizedStatusReason {
    independent_checker_entry_value_status_reason(
        entry,
        "inconclusive",
        "checker_internal_error",
        "malformed_process_state",
        "results[].process_launched",
        "process_state_consistent_with_error_kind",
        "malformed_process_state",
    )
}

fn independent_checker_inconclusive_comparison_source(
    entry: &IndependentCheckerNormalizedCheckResultEntry,
) -> bool {
    let Some(error) = entry.error.as_ref() else {
        return false;
    };
    matches!(
        (
            entry.process_launched,
            error.kind.as_str(),
            error.reason_code.as_deref(),
        ),
        (false, "timeout", Some("launch_timeout"))
            | (
                false,
                "resource_exhausted",
                Some("launch_resource_exhausted")
            )
            | (true, "timeout", Some("checker_timeout"))
            | (
                true,
                "resource_exhausted",
                Some("checker_resource_exhausted")
            )
            | (
                true,
                "checker_internal_error",
                Some(
                    "checker_reported_internal_error"
                        | "malformed_success_output"
                        | "success_exit_status_mismatch"
                        | "missing_rejection_error"
                        | "malformed_rejection_output"
                        | "malformed_internal_error_output"
                        | "checker_module_mismatch"
                        | "process_exit_failure",
                ),
            )
    )
}

fn independent_checker_status_reason_from_error(
    entry: &IndependentCheckerNormalizedCheckResultEntry,
    kind: &str,
) -> IndependentCheckerNormalizedStatusReason {
    let error = entry
        .error
        .as_ref()
        .expect("status reason copied from an entry error");
    IndependentCheckerNormalizedStatusReason {
        kind: kind.to_owned(),
        error_kind: error.kind.clone(),
        reason_code: error
            .reason_code
            .clone()
            .unwrap_or_else(|| error.kind.clone()),
        checker_profile: Some(entry.checker_profile.clone()),
        result_hash: Some(entry.result_hash),
        field: error.field.clone(),
        expected_hash: error.expected_hash,
        actual_hash: error.actual_hash,
        expected_value: error.expected_value.clone(),
        actual_value: error.actual_value.clone(),
    }
}

fn independent_checker_global_hash_status_reason(
    kind: &str,
    error_kind: &str,
    reason_code: &str,
    field: &str,
    expected_hash: Hash,
    actual_hash: Hash,
) -> IndependentCheckerNormalizedStatusReason {
    IndependentCheckerNormalizedStatusReason {
        kind: kind.to_owned(),
        error_kind: error_kind.to_owned(),
        reason_code: reason_code.to_owned(),
        checker_profile: None,
        result_hash: None,
        field: Some(field.to_owned()),
        expected_hash: Some(expected_hash),
        actual_hash: Some(actual_hash),
        expected_value: None,
        actual_value: None,
    }
}

fn independent_checker_entry_hash_status_reason(
    entry: &IndependentCheckerNormalizedCheckResultEntry,
    kind: &str,
    error_kind: &str,
    reason_code: &str,
    field: &str,
    expected_hash: Hash,
    actual_hash: Hash,
) -> IndependentCheckerNormalizedStatusReason {
    IndependentCheckerNormalizedStatusReason {
        kind: kind.to_owned(),
        error_kind: error_kind.to_owned(),
        reason_code: reason_code.to_owned(),
        checker_profile: Some(entry.checker_profile.clone()),
        result_hash: Some(entry.result_hash),
        field: Some(field.to_owned()),
        expected_hash: Some(expected_hash),
        actual_hash: Some(actual_hash),
        expected_value: None,
        actual_value: None,
    }
}

fn independent_checker_entry_value_status_reason(
    entry: &IndependentCheckerNormalizedCheckResultEntry,
    kind: &str,
    error_kind: &str,
    reason_code: &str,
    field: &str,
    expected_value: impl Into<String>,
    actual_value: impl Into<String>,
) -> IndependentCheckerNormalizedStatusReason {
    IndependentCheckerNormalizedStatusReason {
        kind: kind.to_owned(),
        error_kind: error_kind.to_owned(),
        reason_code: reason_code.to_owned(),
        checker_profile: Some(entry.checker_profile.clone()),
        result_hash: Some(entry.result_hash),
        field: Some(field.to_owned()),
        expected_hash: None,
        actual_hash: None,
        expected_value: Some(expected_value.into()),
        actual_value: Some(actual_value.into()),
    }
}

fn independent_checker_push_status_disagreements(
    disagreements: &mut Vec<IndependentCheckerNormalizedDisagreement>,
    baseline: &IndependentCheckerNormalizedCheckResultEntry,
    entries: &[&IndependentCheckerNormalizedCheckResultEntry],
) {
    for entry in entries.iter().skip(1).copied() {
        if entry.status != baseline.status {
            disagreements.push(IndependentCheckerNormalizedDisagreement {
                field: "status".to_owned(),
                baseline_checker_profile: Some(baseline.checker_profile.clone()),
                baseline_hash: None,
                baseline_value: Some(baseline.status.as_str().to_owned()),
                checker_profile: entry.checker_profile.clone(),
                actual_hash: None,
                actual_value: Some(entry.status.as_str().to_owned()),
            });
        }
    }
}

fn independent_checker_sort_normalized_disagreements(
    disagreements: &mut [IndependentCheckerNormalizedDisagreement],
) {
    disagreements.sort_by(|left, right| {
        left.field
            .cmp(&right.field)
            .then_with(|| left.checker_profile.cmp(&right.checker_profile))
            .then_with(|| {
                left.baseline_checker_profile
                    .cmp(&right.baseline_checker_profile)
            })
            .then_with(|| {
                left.baseline_hash
                    .map(|hash| format_hash_string(&hash))
                    .cmp(&right.baseline_hash.map(|hash| format_hash_string(&hash)))
            })
            .then_with(|| {
                left.actual_hash
                    .map(|hash| format_hash_string(&hash))
                    .cmp(&right.actual_hash.map(|hash| format_hash_string(&hash)))
            })
            .then_with(|| left.baseline_value.cmp(&right.baseline_value))
            .then_with(|| left.actual_value.cmp(&right.actual_value))
    });
}

fn independent_checker_sort_normalized_status_reasons(
    reasons: &mut [IndependentCheckerNormalizedStatusReason],
) {
    reasons.sort_by(|left, right| {
        independent_checker_status_reason_sort_key(left)
            .cmp(&independent_checker_status_reason_sort_key(right))
    });
}

fn independent_checker_status_reason_sort_key(
    reason: &IndependentCheckerNormalizedStatusReason,
) -> Vec<String> {
    vec![
        reason.kind.clone(),
        reason.checker_profile.clone().unwrap_or_default(),
        reason.field.clone().unwrap_or_default(),
        reason.reason_code.clone(),
        reason
            .result_hash
            .map(|hash| format_hash_string(&hash))
            .unwrap_or_default(),
        reason.error_kind.clone(),
        independent_checker_status_reason_payload_rank(reason).to_string(),
        reason
            .expected_hash
            .map(|hash| format_hash_string(&hash))
            .unwrap_or_default(),
        reason
            .actual_hash
            .map(|hash| format_hash_string(&hash))
            .unwrap_or_default(),
        reason
            .expected_value
            .as_deref()
            .map(independent_checker_json_string_literal)
            .unwrap_or_default(),
        reason
            .actual_value
            .as_deref()
            .map(independent_checker_json_string_literal)
            .unwrap_or_default(),
    ]
}

fn independent_checker_status_reason_payload_rank(
    reason: &IndependentCheckerNormalizedStatusReason,
) -> u8 {
    if reason.expected_hash.is_some() || reason.actual_hash.is_some() {
        1
    } else if reason.expected_value.is_some() {
        2
    } else if reason.actual_value.is_some() {
        3
    } else {
        0
    }
}

fn independent_checker_push_hash_disagreement(
    disagreements: &mut Vec<IndependentCheckerNormalizedDisagreement>,
    field: &str,
    baseline: &IndependentCheckerNormalizedCheckResultEntry,
    actual: &IndependentCheckerNormalizedCheckResultEntry,
    baseline_hash: Option<Hash>,
    actual_hash: Option<Hash>,
) {
    if baseline_hash != actual_hash {
        disagreements.push(IndependentCheckerNormalizedDisagreement {
            field: field.to_owned(),
            baseline_checker_profile: Some(baseline.checker_profile.clone()),
            baseline_hash,
            baseline_value: None,
            checker_profile: actual.checker_profile.clone(),
            actual_hash,
            actual_value: None,
        });
    }
}

enum IndependentCheckerResolvedAiAuditSource<'a> {
    MachineResult {
        machine_result: &'a IndependentCheckerMachineCheckResult,
        normalized_result: Option<&'a IndependentCheckerNormalizedCheckResult>,
    },
    NormalizedComparison {
        normalized_result: &'a IndependentCheckerNormalizedCheckResult,
    },
}

fn independent_checker_parse_ai_audit_input_policy_value(
    value: &JsonValue<'_>,
) -> Result<IndependentCheckerAiAuditInputPolicy, IndependentCheckerAuditSidecarValidationError> {
    let members = independent_checker_ai_object_members(
        value,
        "input_policy",
        "object",
        IndependentCheckerAuditSidecarValidationReasonCode::InputPolicySchemaInvalid,
    )?;
    independent_checker_ai_required_fixed_string(
        members,
        "schema",
        "input_policy.schema",
        INDEPENDENT_CHECKER_AI_AUDIT_INPUT_POLICY_SCHEMA,
        IndependentCheckerAuditSidecarValidationReasonCode::InputPolicySchemaInvalid,
    )?;
    let id = independent_checker_ai_required_string(
        members,
        "id",
        "input_policy.id",
        "independent_checker_policy_id",
        IndependentCheckerAuditSidecarValidationReasonCode::InputPolicySchemaInvalid,
    )?;
    if id.is_empty() {
        return Err(IndependentCheckerAuditSidecarValidationError::value(
            IndependentCheckerAuditSidecarValidationReasonCode::InputPolicySchemaInvalid,
            "input_policy.id",
            "independent_checker_policy_id",
            "empty_string",
        ));
    }
    if !independent_checker_valid_runner_policy_id(&id) {
        return Err(IndependentCheckerAuditSidecarValidationError::value(
            IndependentCheckerAuditSidecarValidationReasonCode::InputPolicySchemaInvalid,
            "input_policy.id",
            "independent_checker_policy_id",
            "invalid_name_format",
        ));
    }
    let version = independent_checker_ai_required_positive_i64(
        members,
        "version",
        "input_policy.version",
        IndependentCheckerAuditSidecarValidationReasonCode::InputPolicySchemaInvalid,
    )?;
    let included_fields = independent_checker_ai_required_included_fields(
        members,
        "included_fields",
        "input_policy.included_fields",
        IndependentCheckerAuditSidecarValidationReasonCode::InputPolicySchemaInvalid,
    )?;
    let redaction = independent_checker_ai_required_string(
        members,
        "redaction",
        "input_policy.redaction",
        "AiAuditInputPolicy.redaction",
        IndependentCheckerAuditSidecarValidationReasonCode::InputPolicySchemaInvalid,
    )?;
    if !independent_checker_ai_audit_redaction_allowed(&redaction) {
        return Err(IndependentCheckerAuditSidecarValidationError::value(
            IndependentCheckerAuditSidecarValidationReasonCode::InputPolicySchemaInvalid,
            "input_policy.redaction",
            "AiAuditInputPolicy.redaction",
            "invalid_enum",
        ));
    }
    let allow_source_text = independent_checker_ai_required_bool(
        members,
        "allow_source_text",
        "input_policy.allow_source_text",
        IndependentCheckerAuditSidecarValidationReasonCode::InputPolicySchemaInvalid,
    )?;
    let allow_tactic_trace = independent_checker_ai_required_bool(
        members,
        "allow_tactic_trace",
        "input_policy.allow_tactic_trace",
        IndependentCheckerAuditSidecarValidationReasonCode::InputPolicySchemaInvalid,
    )?;
    independent_checker_ai_reject_unknown_fields(
        members,
        &[
            "schema",
            "id",
            "version",
            "included_fields",
            "redaction",
            "allow_source_text",
            "allow_tactic_trace",
        ],
        "input_policy",
        IndependentCheckerAuditSidecarValidationReasonCode::InputPolicySchemaInvalid,
    )?;
    Ok(IndependentCheckerAiAuditInputPolicy {
        id,
        version,
        included_fields,
        redaction,
        allow_source_text,
        allow_tactic_trace,
    })
}

fn independent_checker_parse_ai_audit_sidecar_value(
    value: &JsonValue<'_>,
) -> Result<IndependentCheckerAiAuditSidecar, IndependentCheckerAuditSidecarValidationError> {
    let members = independent_checker_ai_object_members(
        value,
        "$",
        "object",
        IndependentCheckerAuditSidecarValidationReasonCode::SidecarSchemaInvalid,
    )?;
    independent_checker_ai_required_fixed_string(
        members,
        "schema",
        "schema",
        INDEPENDENT_CHECKER_AI_AUDIT_SIDECAR_SCHEMA,
        IndependentCheckerAuditSidecarValidationReasonCode::SidecarSchemaInvalid,
    )?;
    if let Some(field) = independent_checker_find_static_forbidden_sidecar_field(value, "$") {
        return Err(IndependentCheckerAuditSidecarValidationError::actual_value(
            IndependentCheckerAuditSidecarValidationReasonCode::ForbiddenSidecarField,
            field,
            "present",
        ));
    }

    let source_value = independent_checker_ai_required_value(
        members,
        "source",
        "source",
        "object",
        IndependentCheckerAuditSidecarValidationReasonCode::SidecarSchemaInvalid,
    )?;
    let source = independent_checker_parse_ai_audit_sidecar_source(source_value)?;
    let input_policy_value = independent_checker_ai_required_value(
        members,
        "input_policy",
        "input_policy",
        "object",
        IndependentCheckerAuditSidecarValidationReasonCode::SidecarSchemaInvalid,
    )?;
    let input_policy = independent_checker_parse_ai_audit_sidecar_input_policy(input_policy_value)?;
    if source.kind == IndependentCheckerAiAuditSidecarSourceKind::MachineResult
        && source.normalized_result_hash.is_none()
        && input_policy.included_fields.iter().any(|field| {
            matches!(
                field.as_str(),
                "input_file_hash" | "expected_certificate_hash"
            )
        })
    {
        return Err(IndependentCheckerAuditSidecarValidationError::value(
            IndependentCheckerAuditSidecarValidationReasonCode::SidecarSchemaInvalid,
            "source.normalized_result_hash",
            "required_for_input_field",
            "missing",
        ));
    }
    let ai_value = independent_checker_ai_required_value(
        members,
        "ai",
        "ai",
        "object",
        IndependentCheckerAuditSidecarValidationReasonCode::SidecarSchemaInvalid,
    )?;
    let ai = independent_checker_parse_ai_audit_sidecar_ai(ai_value)?;
    let status = independent_checker_parse_ai_audit_sidecar_status(
        &independent_checker_ai_required_string(
            members,
            "status",
            "status",
            "AiAuditSidecar.status",
            IndependentCheckerAuditSidecarValidationReasonCode::SidecarSchemaInvalid,
        )?,
        "status",
    )?;

    let classification_value = independent_checker_ai_optional_value(
        members,
        "classification",
        "classification",
        IndependentCheckerAuditSidecarValidationReasonCode::SidecarSchemaInvalid,
    )?;
    if source.kind == IndependentCheckerAiAuditSidecarSourceKind::NormalizedComparison
        && classification_value
            .and_then(JsonValue::object_members)
            .is_some_and(|members| {
                members
                    .iter()
                    .any(|member| member.key() == "checker_error_kind")
            })
    {
        return Err(IndependentCheckerAuditSidecarValidationError::actual_value(
            IndependentCheckerAuditSidecarValidationReasonCode::ForbiddenSidecarField,
            "classification.checker_error_kind",
            "present",
        ));
    }
    let classification = match classification_value {
        Some(value) => Some(independent_checker_parse_ai_audit_sidecar_classification(
            value,
        )?),
        None if status.requires_classification() => {
            return Err(IndependentCheckerAuditSidecarValidationError::value(
                IndependentCheckerAuditSidecarValidationReasonCode::SidecarSchemaInvalid,
                "classification",
                format!("required_for_status:{}", status.as_str()),
                "missing",
            ))
        }
        None => None,
    };

    let summary = independent_checker_ai_required_text_string(members, "summary", "summary")?;
    let suggested_next_actions =
        independent_checker_parse_ai_audit_suggested_next_actions(members, status)?;
    let policy_gated_fields = independent_checker_parse_ai_audit_policy_gated_fields(members)?;

    let mut allowed = vec![
        "schema",
        "source",
        "input_policy",
        "ai",
        "status",
        "classification",
        "summary",
        "suggested_next_actions",
    ];
    allowed.extend(
        INDEPENDENT_CHECKER_AI_AUDIT_POLICY_GATED_FIELDS
            .iter()
            .copied(),
    );
    independent_checker_ai_reject_unknown_fields(
        members,
        &allowed,
        "$",
        IndependentCheckerAuditSidecarValidationReasonCode::SidecarSchemaInvalid,
    )?;

    Ok(IndependentCheckerAiAuditSidecar {
        source,
        input_policy,
        ai,
        status,
        classification,
        summary,
        suggested_next_actions,
        policy_gated_fields,
    })
}

fn independent_checker_parse_ai_audit_sidecar_source(
    value: &JsonValue<'_>,
) -> Result<IndependentCheckerAiAuditSidecarSource, IndependentCheckerAuditSidecarValidationError> {
    let members = independent_checker_ai_object_members(
        value,
        "source",
        "object",
        IndependentCheckerAuditSidecarValidationReasonCode::SidecarSchemaInvalid,
    )?;
    let kind_raw = independent_checker_ai_required_string(
        members,
        "kind",
        "source.kind",
        "AiAuditSidecar.source.kind",
        IndependentCheckerAuditSidecarValidationReasonCode::SidecarSchemaInvalid,
    )?;
    let kind = match kind_raw.as_str() {
        "machine_result" => IndependentCheckerAiAuditSidecarSourceKind::MachineResult,
        "normalized_comparison" => IndependentCheckerAiAuditSidecarSourceKind::NormalizedComparison,
        _ => {
            return Err(IndependentCheckerAuditSidecarValidationError::value(
                IndependentCheckerAuditSidecarValidationReasonCode::SidecarSchemaInvalid,
                "source.kind",
                "AiAuditSidecar.source.kind",
                "invalid_enum",
            ))
        }
    };
    let result_hash = match kind {
        IndependentCheckerAiAuditSidecarSourceKind::MachineResult => {
            Some(independent_checker_ai_required_hash(
                members,
                "result_hash",
                "source.result_hash",
                IndependentCheckerAuditSidecarValidationReasonCode::SidecarSchemaInvalid,
            )?)
        }
        IndependentCheckerAiAuditSidecarSourceKind::NormalizedComparison => None,
    };
    let request_hash = match kind {
        IndependentCheckerAiAuditSidecarSourceKind::MachineResult => {
            Some(independent_checker_ai_required_hash(
                members,
                "request_hash",
                "source.request_hash",
                IndependentCheckerAuditSidecarValidationReasonCode::SidecarSchemaInvalid,
            )?)
        }
        IndependentCheckerAiAuditSidecarSourceKind::NormalizedComparison => None,
    };
    let run_artifact_hash = match kind {
        IndependentCheckerAiAuditSidecarSourceKind::MachineResult => {
            Some(independent_checker_ai_required_hash(
                members,
                "run_artifact_hash",
                "source.run_artifact_hash",
                IndependentCheckerAuditSidecarValidationReasonCode::SidecarSchemaInvalid,
            )?)
        }
        IndependentCheckerAiAuditSidecarSourceKind::NormalizedComparison => None,
    };
    let normalized_result_hash = match kind {
        IndependentCheckerAiAuditSidecarSourceKind::MachineResult => {
            independent_checker_ai_optional_hash(
                members,
                "normalized_result_hash",
                "source.normalized_result_hash",
                IndependentCheckerAuditSidecarValidationReasonCode::SidecarSchemaInvalid,
            )?
        }
        IndependentCheckerAiAuditSidecarSourceKind::NormalizedComparison => {
            Some(independent_checker_ai_required_hash(
                members,
                "normalized_result_hash",
                "source.normalized_result_hash",
                IndependentCheckerAuditSidecarValidationReasonCode::SidecarSchemaInvalid,
            )?)
        }
    };
    let result_id = match kind {
        IndependentCheckerAiAuditSidecarSourceKind::MachineResult => {
            independent_checker_ai_optional_visible_ascii(
                members,
                "result_id",
                "source.result_id",
                "result_id",
            )?
        }
        IndependentCheckerAiAuditSidecarSourceKind::NormalizedComparison => None,
    };
    let normalized_result_id = independent_checker_ai_optional_visible_ascii(
        members,
        "normalized_result_id",
        "source.normalized_result_id",
        "normalized_result_id",
    )?;

    if kind == IndependentCheckerAiAuditSidecarSourceKind::NormalizedComparison {
        for field in [
            "result_hash",
            "request_hash",
            "run_artifact_hash",
            "result_id",
        ] {
            if members.iter().any(|member| member.key() == field) {
                return Err(IndependentCheckerAuditSidecarValidationError::actual_value(
                    IndependentCheckerAuditSidecarValidationReasonCode::ForbiddenSidecarField,
                    format!("source.{field}"),
                    "present",
                ));
            }
        }
    }
    if kind == IndependentCheckerAiAuditSidecarSourceKind::MachineResult
        && normalized_result_id.is_some()
        && normalized_result_hash.is_none()
    {
        return Err(IndependentCheckerAuditSidecarValidationError::value(
            IndependentCheckerAuditSidecarValidationReasonCode::SidecarSchemaInvalid,
            "source.normalized_result_hash",
            "required_with_source.normalized_result_id",
            "missing",
        ));
    }

    independent_checker_ai_reject_unknown_fields(
        members,
        &[
            "kind",
            "result_hash",
            "request_hash",
            "run_artifact_hash",
            "normalized_result_hash",
            "result_id",
            "normalized_result_id",
        ],
        "source",
        IndependentCheckerAuditSidecarValidationReasonCode::SidecarSchemaInvalid,
    )?;

    Ok(IndependentCheckerAiAuditSidecarSource {
        kind,
        result_hash,
        request_hash,
        run_artifact_hash,
        normalized_result_hash,
        result_id,
        normalized_result_id,
    })
}

fn independent_checker_parse_ai_audit_sidecar_input_policy(
    value: &JsonValue<'_>,
) -> Result<
    IndependentCheckerAiAuditSidecarInputPolicy,
    IndependentCheckerAuditSidecarValidationError,
> {
    let members = independent_checker_ai_object_members(
        value,
        "input_policy",
        "object",
        IndependentCheckerAuditSidecarValidationReasonCode::SidecarSchemaInvalid,
    )?;
    let id = independent_checker_ai_required_string(
        members,
        "id",
        "input_policy.id",
        "independent_checker_policy_id",
        IndependentCheckerAuditSidecarValidationReasonCode::SidecarSchemaInvalid,
    )?;
    if id.is_empty() || !independent_checker_valid_runner_policy_id(&id) {
        return Err(IndependentCheckerAuditSidecarValidationError::value(
            IndependentCheckerAuditSidecarValidationReasonCode::SidecarSchemaInvalid,
            "input_policy.id",
            "independent_checker_policy_id",
            if id.is_empty() {
                "empty_string"
            } else {
                "invalid_name_format"
            },
        ));
    }
    let version = independent_checker_ai_required_positive_i64(
        members,
        "version",
        "input_policy.version",
        IndependentCheckerAuditSidecarValidationReasonCode::SidecarSchemaInvalid,
    )?;
    let hash = independent_checker_ai_required_hash(
        members,
        "hash",
        "input_policy.hash",
        IndependentCheckerAuditSidecarValidationReasonCode::SidecarSchemaInvalid,
    )?;
    let included_fields = independent_checker_ai_required_included_fields(
        members,
        "included_fields",
        "input_policy.included_fields",
        IndependentCheckerAuditSidecarValidationReasonCode::SidecarSchemaInvalid,
    )?;
    let redaction = independent_checker_ai_required_string(
        members,
        "redaction",
        "input_policy.redaction",
        "AiAuditInputPolicy.redaction",
        IndependentCheckerAuditSidecarValidationReasonCode::SidecarSchemaInvalid,
    )?;
    if !independent_checker_ai_audit_redaction_allowed(&redaction) {
        return Err(IndependentCheckerAuditSidecarValidationError::value(
            IndependentCheckerAuditSidecarValidationReasonCode::SidecarSchemaInvalid,
            "input_policy.redaction",
            "AiAuditInputPolicy.redaction",
            "invalid_enum",
        ));
    }
    independent_checker_ai_reject_unknown_fields(
        members,
        &["id", "version", "hash", "included_fields", "redaction"],
        "input_policy",
        IndependentCheckerAuditSidecarValidationReasonCode::SidecarSchemaInvalid,
    )?;
    Ok(IndependentCheckerAiAuditSidecarInputPolicy {
        id,
        version,
        hash,
        included_fields,
        redaction,
    })
}

fn independent_checker_parse_ai_audit_sidecar_ai(
    value: &JsonValue<'_>,
) -> Result<IndependentCheckerAiAuditSidecarAi, IndependentCheckerAuditSidecarValidationError> {
    let members = independent_checker_ai_object_members(
        value,
        "ai",
        "object",
        IndependentCheckerAuditSidecarValidationReasonCode::SidecarSchemaInvalid,
    )?;
    let agent = independent_checker_ai_required_visible_ascii(
        members,
        "agent",
        "ai.agent",
        "non_empty_visible_ascii_string",
    )?;
    let model = independent_checker_ai_required_visible_ascii(
        members,
        "model",
        "ai.model",
        "non_empty_visible_ascii_string",
    )?;
    let prompt_hash = independent_checker_ai_required_hash(
        members,
        "prompt_hash",
        "ai.prompt_hash",
        IndependentCheckerAuditSidecarValidationReasonCode::SidecarSchemaInvalid,
    )?;
    independent_checker_ai_reject_unknown_fields(
        members,
        &["agent", "model", "prompt_hash"],
        "ai",
        IndependentCheckerAuditSidecarValidationReasonCode::SidecarSchemaInvalid,
    )?;
    Ok(IndependentCheckerAiAuditSidecarAi {
        agent,
        model,
        prompt_hash,
    })
}

fn independent_checker_parse_ai_audit_sidecar_classification(
    value: &JsonValue<'_>,
) -> Result<
    IndependentCheckerAiAuditSidecarClassification,
    IndependentCheckerAuditSidecarValidationError,
> {
    let members = independent_checker_ai_object_members(
        value,
        "classification",
        "object",
        IndependentCheckerAuditSidecarValidationReasonCode::SidecarSchemaInvalid,
    )?;
    let category = independent_checker_ai_required_string(
        members,
        "category",
        "classification.category",
        "AiAuditSidecar.classification.category",
        IndependentCheckerAuditSidecarValidationReasonCode::SidecarSchemaInvalid,
    )?;
    if !independent_checker_ai_audit_classification_category_allowed(&category) {
        return Err(IndependentCheckerAuditSidecarValidationError::value(
            IndependentCheckerAuditSidecarValidationReasonCode::SidecarSchemaInvalid,
            "classification.category",
            "AiAuditSidecar.classification.category",
            "invalid_enum",
        ));
    }
    let confidence = independent_checker_ai_required_string(
        members,
        "confidence",
        "classification.confidence",
        "AiAuditSidecar.classification.confidence",
        IndependentCheckerAuditSidecarValidationReasonCode::SidecarSchemaInvalid,
    )?;
    if !matches!(confidence.as_str(), "low" | "medium" | "high" | "unknown") {
        return Err(IndependentCheckerAuditSidecarValidationError::value(
            IndependentCheckerAuditSidecarValidationReasonCode::SidecarSchemaInvalid,
            "classification.confidence",
            "AiAuditSidecar.classification.confidence",
            "invalid_enum",
        ));
    }
    let checker_error_kind = independent_checker_ai_optional_string(
        members,
        "checker_error_kind",
        "classification.checker_error_kind",
        "MachineCheckResult.error.kind",
        IndependentCheckerAuditSidecarValidationReasonCode::SidecarSchemaInvalid,
    )?;
    if let Some(kind) = checker_error_kind.as_deref() {
        if !independent_checker_raw_checker_error_kind_allowed(kind)
            && !matches!(
                kind,
                "policy_failure" | "timeout" | "resource_exhausted" | "checker_internal_error"
            )
        {
            return Err(IndependentCheckerAuditSidecarValidationError::value(
                IndependentCheckerAuditSidecarValidationReasonCode::SidecarSchemaInvalid,
                "classification.checker_error_kind",
                "MachineCheckResult.error.kind",
                "invalid_enum",
            ));
        }
    }
    independent_checker_ai_reject_unknown_fields(
        members,
        &["category", "confidence", "checker_error_kind"],
        "classification",
        IndependentCheckerAuditSidecarValidationReasonCode::SidecarSchemaInvalid,
    )?;
    Ok(IndependentCheckerAiAuditSidecarClassification {
        category,
        confidence,
        checker_error_kind,
    })
}

fn independent_checker_parse_ai_audit_suggested_next_actions(
    members: &[JsonMember<'_>],
    status: IndependentCheckerAiAuditSidecarStatus,
) -> Result<Option<Vec<String>>, IndependentCheckerAuditSidecarValidationError> {
    let Some(value) = independent_checker_ai_optional_value(
        members,
        "suggested_next_actions",
        "suggested_next_actions",
        IndependentCheckerAuditSidecarValidationReasonCode::SidecarSchemaInvalid,
    )?
    else {
        if status.requires_next_actions() {
            return Err(IndependentCheckerAuditSidecarValidationError::value(
                IndependentCheckerAuditSidecarValidationReasonCode::SidecarSchemaInvalid,
                "suggested_next_actions",
                format!("non_empty_array_for_status:{}", status.as_str()),
                "missing",
            ));
        }
        return Ok(None);
    };
    let Some(elements) = value.array_elements() else {
        return Err(IndependentCheckerAuditSidecarValidationError::value(
            IndependentCheckerAuditSidecarValidationReasonCode::SidecarSchemaInvalid,
            "suggested_next_actions",
            if status.requires_next_actions() {
                format!("non_empty_array_for_status:{}", status.as_str())
            } else {
                "array".to_owned()
            },
            if value.kind() == JsonValueKind::Null {
                "null_not_allowed"
            } else {
                "wrong_type"
            },
        ));
    };
    if elements.is_empty() && status.requires_next_actions() {
        return Err(IndependentCheckerAuditSidecarValidationError::value(
            IndependentCheckerAuditSidecarValidationReasonCode::SidecarSchemaInvalid,
            "suggested_next_actions",
            format!("non_empty_array_for_status:{}", status.as_str()),
            "empty_array",
        ));
    }
    let mut actions = Vec::new();
    for (index, element) in elements.iter().enumerate() {
        let path = format!("suggested_next_actions[{index}]");
        let Some(action) = element.string_value() else {
            return Err(IndependentCheckerAuditSidecarValidationError::value(
                IndependentCheckerAuditSidecarValidationReasonCode::SidecarSchemaInvalid,
                path,
                "non_empty_text_string",
                if element.kind() == JsonValueKind::Null {
                    "null_not_allowed"
                } else {
                    "wrong_type"
                },
            ));
        };
        independent_checker_validate_ai_text(action, &path)?;
        actions.push(action.to_owned());
    }
    Ok(Some(actions))
}

fn independent_checker_parse_ai_audit_policy_gated_fields(
    members: &[JsonMember<'_>],
) -> Result<
    BTreeMap<String, IndependentCheckerAiAuditPolicyGatedFieldValue>,
    IndependentCheckerAuditSidecarValidationError,
> {
    let mut fields = BTreeMap::new();
    for member in members {
        if !independent_checker_ai_policy_gated_field_name(member.key()) {
            continue;
        }
        let value = member.value();
        if let Some(text) = value.string_value() {
            fields.insert(
                member.key().to_owned(),
                IndependentCheckerAiAuditPolicyGatedFieldValue::String(text.to_owned()),
            );
            continue;
        }
        let Some(elements) = value.array_elements() else {
            return Err(IndependentCheckerAuditSidecarValidationError::value(
                IndependentCheckerAuditSidecarValidationReasonCode::SidecarSchemaInvalid,
                member.key(),
                "string_or_string_array",
                if value.kind() == JsonValueKind::Null {
                    "null_not_allowed"
                } else {
                    "wrong_type"
                },
            ));
        };
        let mut strings = Vec::new();
        for (index, element) in elements.iter().enumerate() {
            let Some(text) = element.string_value() else {
                return Err(IndependentCheckerAuditSidecarValidationError::value(
                    IndependentCheckerAuditSidecarValidationReasonCode::SidecarSchemaInvalid,
                    format!("{}[{index}]", member.key()),
                    "string",
                    if element.kind() == JsonValueKind::Null {
                        "null_not_allowed"
                    } else {
                        "wrong_type"
                    },
                ));
            };
            strings.push(text.to_owned());
        }
        fields.insert(
            member.key().to_owned(),
            IndependentCheckerAiAuditPolicyGatedFieldValue::Strings(strings),
        );
    }
    Ok(fields)
}

fn independent_checker_ai_audit_copied_policy_mismatch(
    sidecar: &IndependentCheckerAiAuditSidecar,
    policy: &IndependentCheckerAiAuditInputPolicy,
) -> Option<IndependentCheckerAuditSidecarValidationError> {
    if sidecar.input_policy.id != policy.id {
        return Some(IndependentCheckerAuditSidecarValidationError::value(
            IndependentCheckerAuditSidecarValidationReasonCode::InputPolicyFieldMismatch,
            "input_policy.id",
            &policy.id,
            &sidecar.input_policy.id,
        ));
    }
    if sidecar.input_policy.version != policy.version {
        return Some(IndependentCheckerAuditSidecarValidationError::value(
            IndependentCheckerAuditSidecarValidationReasonCode::InputPolicyFieldMismatch,
            "input_policy.version",
            policy.version.to_string(),
            sidecar.input_policy.version.to_string(),
        ));
    }
    if sidecar.input_policy.included_fields != policy.included_fields {
        return Some(IndependentCheckerAuditSidecarValidationError::value(
            IndependentCheckerAuditSidecarValidationReasonCode::InputPolicyFieldMismatch,
            "input_policy.included_fields",
            independent_checker_json_string_array(&policy.included_fields),
            independent_checker_json_string_array(&sidecar.input_policy.included_fields),
        ));
    }
    if sidecar.input_policy.redaction != policy.redaction {
        return Some(IndependentCheckerAuditSidecarValidationError::value(
            IndependentCheckerAuditSidecarValidationReasonCode::InputPolicyFieldMismatch,
            "input_policy.redaction",
            &policy.redaction,
            &sidecar.input_policy.redaction,
        ));
    }
    None
}

fn independent_checker_ai_audit_policy_gated_field_error(
    sidecar: &IndependentCheckerAiAuditSidecar,
    policy: &IndependentCheckerAiAuditInputPolicy,
) -> Option<IndependentCheckerAuditSidecarValidationError> {
    for field in [
        "source_text",
        "source_excerpt",
        "theorem_statement",
        "proof_script",
    ] {
        if !policy.allow_source_text && sidecar.policy_gated_fields.contains_key(field) {
            return Some(IndependentCheckerAuditSidecarValidationError::actual_value(
                IndependentCheckerAuditSidecarValidationReasonCode::ForbiddenSidecarField,
                field,
                "present",
            ));
        }
    }
    for field in [
        "tactic_trace",
        "tactic_script",
        "elaboration_trace",
        "ai_search_trace",
    ] {
        if !policy.allow_tactic_trace && sidecar.policy_gated_fields.contains_key(field) {
            return Some(IndependentCheckerAuditSidecarValidationError::actual_value(
                IndependentCheckerAuditSidecarValidationReasonCode::ForbiddenSidecarField,
                field,
                "present",
            ));
        }
    }
    None
}

fn independent_checker_resolve_ai_audit_sidecar_source<'a>(
    sidecar: &IndependentCheckerAiAuditSidecar,
    machine_results: &'a [IndependentCheckerMachineCheckResult],
    normalized_results: &'a [IndependentCheckerNormalizedCheckResult],
) -> Result<
    IndependentCheckerResolvedAiAuditSource<'a>,
    IndependentCheckerAuditSidecarValidationError,
> {
    match sidecar.source.kind {
        IndependentCheckerAiAuditSidecarSourceKind::MachineResult => {
            let run_artifact_hash = sidecar
                .source
                .run_artifact_hash
                .expect("machine result source run hash is schema-valid");
            let Some(machine_result) = machine_results
                .iter()
                .find(|result| result.run_artifact_hash() == run_artifact_hash)
            else {
                return Err(
                    IndependentCheckerAuditSidecarValidationError::expected_hash(
                        IndependentCheckerAuditSidecarValidationReasonCode::SourceResultNotFound,
                        "source.run_artifact_hash",
                        run_artifact_hash,
                    ),
                );
            };
            let source_result_hash = sidecar
                .source
                .result_hash
                .expect("machine result source result hash is schema-valid");
            if source_result_hash != machine_result.result_hash() {
                return Err(IndependentCheckerAuditSidecarValidationError::hash(
                    IndependentCheckerAuditSidecarValidationReasonCode::SourceHashMismatch,
                    "source.result_hash",
                    source_result_hash,
                    machine_result.result_hash(),
                ));
            }
            let source_request_hash = sidecar
                .source
                .request_hash
                .expect("machine result source request hash is schema-valid");
            if source_request_hash != machine_result.request_hash {
                return Err(IndependentCheckerAuditSidecarValidationError::hash(
                    IndependentCheckerAuditSidecarValidationReasonCode::SourceHashMismatch,
                    "source.request_hash",
                    source_request_hash,
                    machine_result.request_hash,
                ));
            }
            if let Some(result_id) = &sidecar.source.result_id {
                if result_id != &machine_result.result_id {
                    return Err(IndependentCheckerAuditSidecarValidationError::value(
                        IndependentCheckerAuditSidecarValidationReasonCode::SourceIdMismatch,
                        "source.result_id",
                        result_id,
                        &machine_result.result_id,
                    ));
                }
            }
            let normalized_result = if let Some(normalized_hash) =
                sidecar.source.normalized_result_hash
            {
                let Some(normalized) = normalized_results
                    .iter()
                    .find(|result| result.normalized_result_hash() == normalized_hash)
                else {
                    return Err(IndependentCheckerAuditSidecarValidationError::expected_hash(
                            IndependentCheckerAuditSidecarValidationReasonCode::SourceNormalizedResultNotFound,
                            "source.normalized_result_hash",
                            normalized_hash,
                        ));
                };
                if !normalized
                    .results
                    .iter()
                    .any(|entry| entry.result_hash == source_result_hash)
                {
                    return Err(IndependentCheckerAuditSidecarValidationError::expected_hash(
                            IndependentCheckerAuditSidecarValidationReasonCode::NormalizedResultMissingSource,
                            "normalized_result.results[].result_hash",
                            source_result_hash,
                        ));
                }
                if let Some(normalized_id) = &sidecar.source.normalized_result_id {
                    if normalized_id != &normalized.normalized_result_id {
                        return Err(IndependentCheckerAuditSidecarValidationError::value(
                            IndependentCheckerAuditSidecarValidationReasonCode::SourceIdMismatch,
                            "source.normalized_result_id",
                            normalized_id,
                            &normalized.normalized_result_id,
                        ));
                    }
                }
                Some(normalized)
            } else {
                None
            };
            Ok(IndependentCheckerResolvedAiAuditSource::MachineResult {
                machine_result,
                normalized_result,
            })
        }
        IndependentCheckerAiAuditSidecarSourceKind::NormalizedComparison => {
            let normalized_hash = sidecar
                .source
                .normalized_result_hash
                .expect("normalized comparison source hash is schema-valid");
            let Some(normalized_result) = normalized_results
                .iter()
                .find(|result| result.normalized_result_hash() == normalized_hash)
            else {
                return Err(IndependentCheckerAuditSidecarValidationError::expected_hash(
                    IndependentCheckerAuditSidecarValidationReasonCode::SourceNormalizedResultNotFound,
                    "source.normalized_result_hash",
                    normalized_hash,
                ));
            };
            if let Some(normalized_id) = &sidecar.source.normalized_result_id {
                if normalized_id != &normalized_result.normalized_result_id {
                    return Err(IndependentCheckerAuditSidecarValidationError::value(
                        IndependentCheckerAuditSidecarValidationReasonCode::SourceIdMismatch,
                        "source.normalized_result_id",
                        normalized_id,
                        &normalized_result.normalized_result_id,
                    ));
                }
            }
            Ok(IndependentCheckerResolvedAiAuditSource::NormalizedComparison { normalized_result })
        }
    }
}

fn independent_checker_validate_ai_audit_source_dependent_fields(
    sidecar: &IndependentCheckerAiAuditSidecar,
    source: &IndependentCheckerResolvedAiAuditSource<'_>,
) -> Option<IndependentCheckerAuditSidecarValidationError> {
    match source {
        IndependentCheckerResolvedAiAuditSource::MachineResult { machine_result, .. } => {
            if machine_result.status == IndependentCheckerMachineCheckStatus::Failed {
                if let Some(classification) = &sidecar.classification {
                    let expected = machine_result
                        .error
                        .as_ref()
                        .map(|error| error.kind.as_str())
                        .unwrap_or("missing");
                    match classification.checker_error_kind.as_deref() {
                        Some(actual) if actual == expected => {}
                        Some(actual) => return Some(IndependentCheckerAuditSidecarValidationError::value(
                            IndependentCheckerAuditSidecarValidationReasonCode::ReferencedArtifactValueMismatch,
                            "classification.checker_error_kind",
                            expected,
                            actual,
                        )),
                        None => return Some(IndependentCheckerAuditSidecarValidationError::value(
                            IndependentCheckerAuditSidecarValidationReasonCode::ReferencedArtifactValueMismatch,
                            "classification.checker_error_kind",
                            expected,
                            "missing",
                        )),
                    }
                }
            } else if let Some(actual) = sidecar
                .classification
                .as_ref()
                .and_then(|classification| classification.checker_error_kind.as_ref())
            {
                return Some(IndependentCheckerAuditSidecarValidationError::value(
                    IndependentCheckerAuditSidecarValidationReasonCode::ReferencedArtifactValueMismatch,
                    "classification.checker_error_kind",
                    "absent",
                    actual,
                ));
            }
            if machine_result.status == IndependentCheckerMachineCheckStatus::Checked
                && sidecar.status != IndependentCheckerAiAuditSidecarStatus::Summarized
            {
                return Some(IndependentCheckerAuditSidecarValidationError::value(
                    IndependentCheckerAuditSidecarValidationReasonCode::ReferencedArtifactValueMismatch,
                    "status",
                    "sidecar_status:summarized_only",
                    sidecar.status.as_str(),
                ));
            }
        }
        IndependentCheckerResolvedAiAuditSource::NormalizedComparison { normalized_result } => {
            if matches!(
                normalized_result.comparison.status,
                IndependentCheckerNormalizedComparisonStatus::AllAgreeChecked
                    | IndependentCheckerNormalizedComparisonStatus::AllAgreeFailed
            ) && sidecar.status != IndependentCheckerAiAuditSidecarStatus::Summarized
            {
                return Some(IndependentCheckerAuditSidecarValidationError::value(
                    IndependentCheckerAuditSidecarValidationReasonCode::ReferencedArtifactValueMismatch,
                    "status",
                    "sidecar_status:summarized_only",
                    sidecar.status.as_str(),
                ));
            }
        }
    }
    None
}

fn independent_checker_ai_audit_prompt_input(
    sidecar: &IndependentCheckerAiAuditSidecar,
    input_policy: &IndependentCheckerAiAuditInputPolicy,
    source: &IndependentCheckerResolvedAiAuditSource<'_>,
) -> IndependentCheckerAiAuditPromptInput {
    let source_hash = match sidecar.source.kind {
        IndependentCheckerAiAuditSidecarSourceKind::MachineResult => sidecar
            .source
            .result_hash
            .expect("machine result source hash is schema-valid"),
        IndependentCheckerAiAuditSidecarSourceKind::NormalizedComparison => sidecar
            .source
            .normalized_result_hash
            .expect("normalized comparison source hash is schema-valid"),
    };
    let mut fields = Vec::new();
    for field in &input_policy.included_fields {
        if let Some(value) = independent_checker_ai_audit_resolve_prompt_field(field, source) {
            fields.push((field.clone(), value));
        }
    }
    fields.sort_by(|left, right| independent_checker_rfc8785_object_key_cmp(&left.0, &right.0));
    IndependentCheckerAiAuditPromptInput {
        agent: sidecar.ai.agent.clone(),
        model: sidecar.ai.model.clone(),
        source_kind: sidecar.source.kind,
        source_hash,
        source_run_artifact_hash: (sidecar.source.kind
            == IndependentCheckerAiAuditSidecarSourceKind::MachineResult)
            .then_some(
                sidecar
                    .source
                    .run_artifact_hash
                    .expect("machine result source run hash is schema-valid"),
            ),
        source_membership_hash: (sidecar.source.kind
            == IndependentCheckerAiAuditSidecarSourceKind::MachineResult)
            .then_some(sidecar.source.normalized_result_hash)
            .flatten(),
        input_policy: IndependentCheckerAiAuditSidecarInputPolicy::from_policy(input_policy),
        fields,
    }
}

fn independent_checker_ai_audit_resolve_prompt_field(
    field: &str,
    source: &IndependentCheckerResolvedAiAuditSource<'_>,
) -> Option<String> {
    match source {
        IndependentCheckerResolvedAiAuditSource::MachineResult {
            machine_result,
            normalized_result,
        } => independent_checker_ai_audit_machine_result_field(
            field,
            machine_result,
            *normalized_result,
        ),
        IndependentCheckerResolvedAiAuditSource::NormalizedComparison { normalized_result } => {
            independent_checker_ai_audit_normalized_comparison_field(field, normalized_result)
        }
    }
}

fn independent_checker_ai_audit_machine_result_field(
    field: &str,
    result: &IndependentCheckerMachineCheckResult,
    normalized_result: Option<&IndependentCheckerNormalizedCheckResult>,
) -> Option<String> {
    match field {
        "module" => Some(independent_checker_json_string_literal(&result.module)),
        "status" => Some(independent_checker_json_string_literal(
            result.status.as_str(),
        )),
        "certificate_hash" => result
            .certificate_hash
            .map(|hash| independent_checker_hash_json_literal(&hash)),
        "checker_binary_hash" => result
            .checker
            .binary_hash
            .map(|hash| independent_checker_hash_json_literal(&hash)),
        "checker_binary_id" => result
            .checker
            .binary_id
            .as_deref()
            .map(independent_checker_json_string_literal),
        "checker_build_hash" => result
            .checker
            .build_hash
            .map(|hash| independent_checker_hash_json_literal(&hash)),
        "checker_id" => result
            .checker
            .id
            .as_deref()
            .map(independent_checker_json_string_literal),
        "checker_profile" => Some(independent_checker_json_string_literal(
            &result.checker.profile,
        )),
        "checker_version" => result
            .checker
            .version
            .as_deref()
            .map(independent_checker_json_string_literal),
        "error.actual_hash" => result
            .error
            .as_ref()
            .and_then(|error| error.actual_hash)
            .map(|hash| independent_checker_hash_json_literal(&hash)),
        "error.core_path" => result
            .error
            .as_ref()
            .and_then(|error| error.core_path.as_ref())
            .map(|path| independent_checker_json_string_array(path)),
        "error.declaration" => result
            .error
            .as_ref()
            .and_then(|error| error.declaration.as_deref())
            .map(independent_checker_json_string_literal),
        "error.expected_hash" => result
            .error
            .as_ref()
            .and_then(|error| error.expected_hash)
            .map(|hash| independent_checker_hash_json_literal(&hash)),
        "error.kind" => result
            .error
            .as_ref()
            .map(|error| independent_checker_json_string_literal(&error.kind)),
        "error.reason_code" => result
            .error
            .as_ref()
            .and_then(|error| error.reason_code.as_deref())
            .map(independent_checker_json_string_literal),
        "policy.hash" => Some(independent_checker_hash_json_literal(&result.policy.hash)),
        "policy.id" => Some(independent_checker_json_string_literal(&result.policy.id)),
        "policy.version" => Some(result.policy.version.to_string()),
        "input_file_hash" => normalized_result.map(|normalized| {
            independent_checker_hash_json_literal(&normalized.artifact.input_file_hash)
        }),
        "expected_certificate_hash" => normalized_result.map(|normalized| {
            independent_checker_hash_json_literal(&normalized.artifact.expected_certificate_hash)
        }),
        _ => None,
    }
}

fn independent_checker_ai_audit_normalized_comparison_field(
    field: &str,
    result: &IndependentCheckerNormalizedCheckResult,
) -> Option<String> {
    match field {
        "module" => Some(independent_checker_json_string_literal(
            &result.artifact.module,
        )),
        "input_file_hash" => Some(independent_checker_hash_json_literal(
            &result.artifact.input_file_hash,
        )),
        "expected_certificate_hash" => Some(independent_checker_hash_json_literal(
            &result.artifact.expected_certificate_hash,
        )),
        "artifact_hash" => Some(independent_checker_hash_json_literal(
            &result.artifact_hash(),
        )),
        "policy.hash" => Some(independent_checker_hash_json_literal(&result.policy.hash)),
        "policy.id" => Some(independent_checker_json_string_literal(&result.policy.id)),
        "policy.version" => Some(result.policy.version.to_string()),
        "comparison.status" => Some(independent_checker_json_string_literal(
            result.comparison.status.as_str(),
        )),
        "comparison.disagreements" => Some(canonical_json_array(
            result
                .comparison
                .disagreements
                .iter()
                .map(IndependentCheckerNormalizedDisagreement::canonical_json)
                .collect(),
        )),
        "comparison.matching_fields" => Some(independent_checker_json_string_array(
            &result.comparison.matching_fields,
        )),
        "comparison.missing_checker_profiles" => Some(independent_checker_json_string_array(
            &result.comparison.missing_checker_profiles,
        )),
        "comparison.status_reasons" => Some(canonical_json_array(
            result
                .comparison
                .status_reasons
                .iter()
                .map(IndependentCheckerNormalizedStatusReason::canonical_json)
                .collect(),
        )),
        _ => None,
    }
}

const INDEPENDENT_CHECKER_AI_AUDIT_POLICY_GATED_FIELDS: &[&str] = &[
    "source_text",
    "source_excerpt",
    "theorem_statement",
    "proof_script",
    "tactic_trace",
    "tactic_script",
    "elaboration_trace",
    "ai_search_trace",
];

const INDEPENDENT_CHECKER_AI_AUDIT_MACHINE_FIELDS: &[&str] = &[
    "certificate_hash",
    "checker_binary_hash",
    "checker_binary_id",
    "checker_build_hash",
    "checker_id",
    "checker_profile",
    "checker_version",
    "error.actual_hash",
    "error.core_path",
    "error.declaration",
    "error.expected_hash",
    "error.kind",
    "error.reason_code",
    "expected_certificate_hash",
    "input_file_hash",
    "module",
    "policy.hash",
    "policy.id",
    "policy.version",
    "status",
];

const INDEPENDENT_CHECKER_AI_AUDIT_NORMALIZED_COMPARISON_FIELDS: &[&str] = &[
    "artifact_hash",
    "comparison.disagreements",
    "comparison.matching_fields",
    "comparison.missing_checker_profiles",
    "comparison.status",
    "comparison.status_reasons",
    "expected_certificate_hash",
    "input_file_hash",
    "module",
    "policy.hash",
    "policy.id",
    "policy.version",
];

fn independent_checker_ai_included_field_allowed(field: &str) -> bool {
    INDEPENDENT_CHECKER_AI_AUDIT_MACHINE_FIELDS.contains(&field)
        || INDEPENDENT_CHECKER_AI_AUDIT_NORMALIZED_COMPARISON_FIELDS.contains(&field)
}

fn independent_checker_ai_policy_gated_field_name(field: &str) -> bool {
    INDEPENDENT_CHECKER_AI_AUDIT_POLICY_GATED_FIELDS.contains(&field)
}

fn independent_checker_ai_audit_redaction_allowed(value: &str) -> bool {
    matches!(value, "default" | "strict" | "release")
}

fn independent_checker_ai_audit_classification_category_allowed(value: &str) -> bool {
    matches!(
        value,
        "certificate_encoding_bug"
            | "import_resolution_bug"
            | "certificate_generator_bug"
            | "kernel_checker_disagreement"
            | "axiom_policy_violation"
            | "source_to_certificate_staleness"
            | "unsupported_feature"
            | "checker_resource_limit"
            | "checker_internal_bug"
            | "unknown"
    )
}

fn independent_checker_parse_ai_audit_sidecar_status(
    value: &str,
    field: &str,
) -> Result<IndependentCheckerAiAuditSidecarStatus, IndependentCheckerAuditSidecarValidationError> {
    match value {
        "summarized" => Ok(IndependentCheckerAiAuditSidecarStatus::Summarized),
        "triaged" => Ok(IndependentCheckerAiAuditSidecarStatus::Triaged),
        "suggested_fix" => Ok(IndependentCheckerAiAuditSidecarStatus::SuggestedFix),
        "suggested_challenge" => Ok(IndependentCheckerAiAuditSidecarStatus::SuggestedChallenge),
        "inconclusive" => Ok(IndependentCheckerAiAuditSidecarStatus::Inconclusive),
        _ => Err(IndependentCheckerAuditSidecarValidationError::value(
            IndependentCheckerAuditSidecarValidationReasonCode::SidecarSchemaInvalid,
            field,
            "AiAuditSidecar.status",
            "invalid_enum",
        )),
    }
}

fn independent_checker_find_static_forbidden_sidecar_field(
    value: &JsonValue<'_>,
    path: &str,
) -> Option<String> {
    if let Some(members) = value.object_members() {
        for member in members {
            let key = member.key();
            let field_path = independent_checker_ai_join_path(path, key);
            if independent_checker_ai_reserved_forbidden_field_name(key)
                || independent_checker_ai_secret_forbidden_field_name(key)
                || (independent_checker_ai_policy_gated_field_name(key) && path != "$")
            {
                return Some(field_path);
            }
            if let Some(nested) =
                independent_checker_find_static_forbidden_sidecar_field(member.value(), &field_path)
            {
                return Some(nested);
            }
        }
        return None;
    }
    if let Some(elements) = value.array_elements() {
        for (index, element) in elements.iter().enumerate() {
            if let Some(nested) = independent_checker_find_static_forbidden_sidecar_field(
                element,
                &format!("{path}[{index}]"),
            ) {
                return Some(nested);
            }
        }
    }
    None
}

fn independent_checker_ai_reserved_forbidden_field_name(value: &str) -> bool {
    matches!(
        value,
        "verdict"
            | "accepted"
            | "checked"
            | "verified"
            | "checker_status"
            | "certificate_valid"
            | "proof_valid"
            | "generated_certificate"
            | "generated_certificate_bytes"
            | "certificate_bytes"
            | "proof_term"
            | "raw_certificate"
            | "raw_proof"
    )
}

fn independent_checker_ai_secret_forbidden_field_name(value: &str) -> bool {
    matches!(
        value,
        "secret"
            | "token"
            | "access_token"
            | "refresh_token"
            | "api_key"
            | "password"
            | "authorization"
            | "private_key"
    )
}

fn independent_checker_ai_object_members<'value, 'src>(
    value: &'value JsonValue<'src>,
    field: &str,
    expected: &str,
    reason_code: IndependentCheckerAuditSidecarValidationReasonCode,
) -> Result<&'value [JsonMember<'src>], IndependentCheckerAuditSidecarValidationError> {
    value.object_members().ok_or_else(|| {
        IndependentCheckerAuditSidecarValidationError::value(
            reason_code,
            field,
            expected,
            if value.kind() == JsonValueKind::Null {
                "null_not_allowed"
            } else {
                "wrong_type"
            },
        )
    })
}

fn independent_checker_ai_required_value<'value, 'src>(
    members: &'value [JsonMember<'src>],
    name: &str,
    field: &str,
    expected: &str,
    reason_code: IndependentCheckerAuditSidecarValidationReasonCode,
) -> Result<&'value JsonValue<'src>, IndependentCheckerAuditSidecarValidationError> {
    if duplicate_member(members, name) {
        return Err(IndependentCheckerAuditSidecarValidationError::value(
            reason_code,
            field,
            "unique_object_keys",
            "duplicate_field",
        ));
    }
    let Some(member) = members.iter().find(|member| member.key() == name) else {
        return Err(IndependentCheckerAuditSidecarValidationError::value(
            reason_code,
            field,
            expected,
            "missing",
        ));
    };
    if member.value().kind() == JsonValueKind::Null {
        return Err(IndependentCheckerAuditSidecarValidationError::value(
            reason_code,
            field,
            expected,
            "null_not_allowed",
        ));
    }
    Ok(member.value())
}

fn independent_checker_ai_optional_value<'value, 'src>(
    members: &'value [JsonMember<'src>],
    name: &str,
    field: &str,
    reason_code: IndependentCheckerAuditSidecarValidationReasonCode,
) -> Result<Option<&'value JsonValue<'src>>, IndependentCheckerAuditSidecarValidationError> {
    if duplicate_member(members, name) {
        return Err(IndependentCheckerAuditSidecarValidationError::value(
            reason_code,
            field,
            "unique_object_keys",
            "duplicate_field",
        ));
    }
    Ok(members
        .iter()
        .find(|member| member.key() == name)
        .map(JsonMember::value))
}

fn independent_checker_ai_required_fixed_string(
    members: &[JsonMember<'_>],
    name: &str,
    field: &str,
    fixed: &str,
    reason_code: IndependentCheckerAuditSidecarValidationReasonCode,
) -> Result<(), IndependentCheckerAuditSidecarValidationError> {
    let value = independent_checker_ai_required_string(members, name, field, fixed, reason_code)?;
    if value != fixed {
        return Err(IndependentCheckerAuditSidecarValidationError::value(
            reason_code,
            field,
            fixed,
            "invalid_enum",
        ));
    }
    Ok(())
}

fn independent_checker_ai_required_string(
    members: &[JsonMember<'_>],
    name: &str,
    field: &str,
    expected: &str,
    reason_code: IndependentCheckerAuditSidecarValidationReasonCode,
) -> Result<String, IndependentCheckerAuditSidecarValidationError> {
    let value = independent_checker_ai_required_value(members, name, field, expected, reason_code)?;
    value.string_value().map(ToOwned::to_owned).ok_or_else(|| {
        IndependentCheckerAuditSidecarValidationError::value(
            reason_code,
            field,
            expected,
            if value.kind() == JsonValueKind::Null {
                "null_not_allowed"
            } else {
                "wrong_type"
            },
        )
    })
}

fn independent_checker_ai_optional_string(
    members: &[JsonMember<'_>],
    name: &str,
    field: &str,
    expected: &str,
    reason_code: IndependentCheckerAuditSidecarValidationReasonCode,
) -> Result<Option<String>, IndependentCheckerAuditSidecarValidationError> {
    let Some(value) = independent_checker_ai_optional_value(members, name, field, reason_code)?
    else {
        return Ok(None);
    };
    if value.kind() == JsonValueKind::Null {
        return Err(IndependentCheckerAuditSidecarValidationError::value(
            reason_code,
            field,
            expected,
            "null_not_allowed",
        ));
    }
    value
        .string_value()
        .map(|value| Some(value.to_owned()))
        .ok_or_else(|| {
            IndependentCheckerAuditSidecarValidationError::value(
                reason_code,
                field,
                expected,
                "wrong_type",
            )
        })
}

fn independent_checker_ai_required_hash(
    members: &[JsonMember<'_>],
    name: &str,
    field: &str,
    reason_code: IndependentCheckerAuditSidecarValidationReasonCode,
) -> Result<Hash, IndependentCheckerAuditSidecarValidationError> {
    let value = independent_checker_ai_required_string(
        members,
        name,
        field,
        "sha256:<lower-hex>",
        reason_code,
    )?;
    parse_hash_string(&value).map_err(|_| {
        IndependentCheckerAuditSidecarValidationError::value(
            reason_code,
            field,
            "sha256:<lower-hex>",
            "invalid_hash_format",
        )
    })
}

fn independent_checker_ai_optional_hash(
    members: &[JsonMember<'_>],
    name: &str,
    field: &str,
    reason_code: IndependentCheckerAuditSidecarValidationReasonCode,
) -> Result<Option<Hash>, IndependentCheckerAuditSidecarValidationError> {
    let Some(value) = independent_checker_ai_optional_string(
        members,
        name,
        field,
        "sha256:<lower-hex>",
        reason_code,
    )?
    else {
        return Ok(None);
    };
    parse_hash_string(&value).map(Some).map_err(|_| {
        IndependentCheckerAuditSidecarValidationError::value(
            reason_code,
            field,
            "sha256:<lower-hex>",
            "invalid_hash_format",
        )
    })
}

fn independent_checker_ai_required_bool(
    members: &[JsonMember<'_>],
    name: &str,
    field: &str,
    reason_code: IndependentCheckerAuditSidecarValidationReasonCode,
) -> Result<bool, IndependentCheckerAuditSidecarValidationError> {
    let value = independent_checker_ai_required_value(members, name, field, "bool", reason_code)?;
    value.bool_value().ok_or_else(|| {
        IndependentCheckerAuditSidecarValidationError::value(
            reason_code,
            field,
            "bool",
            if value.kind() == JsonValueKind::Null {
                "null_not_allowed"
            } else {
                "wrong_type"
            },
        )
    })
}

fn independent_checker_ai_required_positive_i64(
    members: &[JsonMember<'_>],
    name: &str,
    field: &str,
    reason_code: IndependentCheckerAuditSidecarValidationReasonCode,
) -> Result<u64, IndependentCheckerAuditSidecarValidationError> {
    let value =
        independent_checker_ai_required_value(members, name, field, "positive_i64", reason_code)?;
    let Some(raw) = value.number_raw() else {
        return Err(IndependentCheckerAuditSidecarValidationError::value(
            reason_code,
            field,
            "positive_i64",
            "wrong_type",
        ));
    };
    if raw.contains('.') || raw.contains('e') || raw.contains('E') {
        return Err(IndependentCheckerAuditSidecarValidationError::value(
            reason_code,
            field,
            "positive_i64",
            "wrong_type",
        ));
    }
    let value = raw.parse::<u64>().map_err(|_| {
        IndependentCheckerAuditSidecarValidationError::value(
            reason_code,
            field,
            "positive_i64",
            "integer_out_of_range",
        )
    })?;
    if value == 0 {
        return Err(IndependentCheckerAuditSidecarValidationError::value(
            reason_code,
            field,
            "positive_i64",
            "non_positive_integer",
        ));
    }
    if value > i64::MAX as u64 {
        return Err(IndependentCheckerAuditSidecarValidationError::value(
            reason_code,
            field,
            "positive_i64",
            "integer_out_of_range",
        ));
    }
    Ok(value)
}

fn independent_checker_ai_required_visible_ascii(
    members: &[JsonMember<'_>],
    name: &str,
    field: &str,
    expected: &str,
) -> Result<String, IndependentCheckerAuditSidecarValidationError> {
    let value = independent_checker_ai_required_string(
        members,
        name,
        field,
        expected,
        IndependentCheckerAuditSidecarValidationReasonCode::SidecarSchemaInvalid,
    )?;
    independent_checker_validate_visible_ascii(&value, field, expected)?;
    Ok(value)
}

fn independent_checker_ai_optional_visible_ascii(
    members: &[JsonMember<'_>],
    name: &str,
    field: &str,
    expected: &str,
) -> Result<Option<String>, IndependentCheckerAuditSidecarValidationError> {
    let Some(value) = independent_checker_ai_optional_string(
        members,
        name,
        field,
        expected,
        IndependentCheckerAuditSidecarValidationReasonCode::SidecarSchemaInvalid,
    )?
    else {
        return Ok(None);
    };
    independent_checker_validate_visible_ascii(&value, field, expected)?;
    Ok(Some(value))
}

fn independent_checker_ai_required_text_string(
    members: &[JsonMember<'_>],
    name: &str,
    field: &str,
) -> Result<String, IndependentCheckerAuditSidecarValidationError> {
    let value = independent_checker_ai_required_string(
        members,
        name,
        field,
        "non_empty_text_string",
        IndependentCheckerAuditSidecarValidationReasonCode::SidecarSchemaInvalid,
    )?;
    independent_checker_validate_ai_text(&value, field)?;
    Ok(value)
}

fn independent_checker_ai_required_included_fields(
    members: &[JsonMember<'_>],
    name: &str,
    field: &str,
    reason_code: IndependentCheckerAuditSidecarValidationReasonCode,
) -> Result<Vec<String>, IndependentCheckerAuditSidecarValidationError> {
    let value = independent_checker_ai_required_value(members, name, field, "array", reason_code)?;
    let Some(elements) = value.array_elements() else {
        return Err(IndependentCheckerAuditSidecarValidationError::value(
            reason_code,
            field,
            "array",
            "wrong_type",
        ));
    };
    let mut fields = Vec::new();
    for (index, element) in elements.iter().enumerate() {
        let path = format!("{field}[{index}]");
        let Some(field_path) = element.string_value() else {
            return Err(IndependentCheckerAuditSidecarValidationError::value(
                reason_code,
                path,
                "field_path_string",
                if element.kind() == JsonValueKind::Null {
                    "null_not_allowed"
                } else {
                    "wrong_type"
                },
            ));
        };
        fields.push(field_path.to_owned());
    }
    for (index, field_path) in fields.iter().enumerate() {
        if !independent_checker_ai_included_field_allowed(field_path) {
            return Err(IndependentCheckerAuditSidecarValidationError::value(
                reason_code,
                format!("{field}[{index}]"),
                "allowed_input_policy_field",
                "unknown_field",
            ));
        }
    }
    for index in 1..fields.len() {
        if fields[index - 1] > fields[index] {
            return Err(IndependentCheckerAuditSidecarValidationError::value(
                reason_code,
                format!("{field}[{index}]"),
                "field_path_bytewise_ascending",
                "order_violation",
            ));
        }
    }
    let mut seen = BTreeSet::new();
    for (index, field_path) in fields.iter().enumerate() {
        if !seen.insert(field_path) {
            return Err(IndependentCheckerAuditSidecarValidationError::value(
                reason_code,
                format!("{field}[{index}]"),
                "unique_included_fields",
                "duplicate_field",
            ));
        }
    }
    Ok(fields)
}

fn independent_checker_ai_reject_unknown_fields(
    members: &[JsonMember<'_>],
    allowed: &[&str],
    container_path: &str,
    reason_code: IndependentCheckerAuditSidecarValidationReasonCode,
) -> Result<(), IndependentCheckerAuditSidecarValidationError> {
    let mut counts = BTreeMap::<String, usize>::new();
    for member in members {
        *counts.entry(member.key().to_owned()).or_default() += 1;
    }
    let mut duplicates = counts
        .iter()
        .filter_map(|(field, count)| (*count > 1).then_some(field.as_str()))
        .collect::<Vec<_>>();
    duplicates.sort_by(|left, right| independent_checker_rfc8785_object_key_cmp(left, right));
    if let Some(field) = duplicates.first() {
        return Err(IndependentCheckerAuditSidecarValidationError::value(
            reason_code,
            independent_checker_ai_join_path(container_path, field),
            "unique_object_keys",
            "duplicate_field",
        ));
    }
    let mut unknown = counts
        .keys()
        .filter(|field| !allowed.contains(&field.as_str()))
        .map(String::as_str)
        .collect::<Vec<_>>();
    unknown.sort_by(|left, right| independent_checker_rfc8785_object_key_cmp(left, right));
    if let Some(field) = unknown.first() {
        return Err(IndependentCheckerAuditSidecarValidationError::value(
            reason_code,
            independent_checker_ai_join_path(container_path, field),
            "absent",
            "unknown_field",
        ));
    }
    Ok(())
}

fn independent_checker_validate_visible_ascii(
    value: &str,
    field: &str,
    expected: &str,
) -> Result<(), IndependentCheckerAuditSidecarValidationError> {
    if value.is_empty() {
        return Err(IndependentCheckerAuditSidecarValidationError::value(
            IndependentCheckerAuditSidecarValidationReasonCode::SidecarSchemaInvalid,
            field,
            expected,
            "empty_string",
        ));
    }
    if !value.bytes().all(|byte| (0x21..=0x7e).contains(&byte)) {
        return Err(IndependentCheckerAuditSidecarValidationError::value(
            IndependentCheckerAuditSidecarValidationReasonCode::SidecarSchemaInvalid,
            field,
            expected,
            "invalid_string_format",
        ));
    }
    Ok(())
}

fn independent_checker_validate_ai_text(
    value: &str,
    field: &str,
) -> Result<(), IndependentCheckerAuditSidecarValidationError> {
    if value.is_empty() {
        return Err(IndependentCheckerAuditSidecarValidationError::value(
            IndependentCheckerAuditSidecarValidationReasonCode::SidecarSchemaInvalid,
            field,
            "non_empty_text_string",
            "empty_string",
        ));
    }
    if value
        .chars()
        .any(|ch| matches!(ch, '\u{0000}'..='\u{001f}' | '\u{007f}'))
    {
        return Err(IndependentCheckerAuditSidecarValidationError::value(
            IndependentCheckerAuditSidecarValidationReasonCode::SidecarSchemaInvalid,
            field,
            "non_empty_text_string",
            "invalid_string_format",
        ));
    }
    Ok(())
}

fn independent_checker_ai_join_path(container: &str, field: &str) -> String {
    if container == "$" {
        field.to_owned()
    } else {
        format!("{container}.{field}")
    }
}

fn independent_checker_adopt_checker_observation(
    request: &IndependentCheckerMachineCheckRequest,
    policy: &IndependentCheckerRunnerPolicy,
    selected_checker: &IndependentCheckerAllowlistEntry,
    observation: IndependentCheckerRunObservation,
) -> IndependentCheckerMachineCheckResult {
    if let Some(reason) = observation.process.termination_reason.as_deref() {
        return match reason {
            "timeout" => independent_checker_infrastructure_failure_result(
                request,
                policy,
                selected_checker,
                &observation,
                "timeout",
                "checker_timeout",
            ),
            "resource_exhausted" => independent_checker_infrastructure_failure_result(
                request,
                policy,
                selected_checker,
                &observation,
                "resource_exhausted",
                "checker_resource_exhausted",
            ),
            "killed_without_exit_status" => {
                let error = IndependentCheckerMachineCheckError::new("checker_internal_error")
                    .with_reason_code("process_exit_failure")
                    .with_value_payload(
                        "process.termination_reason",
                        "process_exit_status",
                        "killed_without_exit_status",
                    );
                independent_checker_machine_check_result_base(
                    request,
                    policy,
                    Some(selected_checker),
                    &observation,
                    IndependentCheckerMachineCheckStatus::Failed,
                    Some(error),
                )
            }
            _ => independent_checker_infrastructure_failure_result(
                request,
                policy,
                selected_checker,
                &observation,
                "checker_internal_error",
                "process_exit_failure",
            ),
        };
    }

    let Some(exit_code) = observation.process.exit_code else {
        let error = IndependentCheckerMachineCheckError::new("checker_internal_error")
            .with_reason_code("process_exit_failure");
        return independent_checker_machine_check_result_base(
            request,
            policy,
            Some(selected_checker),
            &observation,
            IndependentCheckerMachineCheckStatus::Failed,
            Some(error),
        );
    };

    if exit_code >= 3 {
        let error = IndependentCheckerMachineCheckError::new("checker_internal_error")
            .with_reason_code("process_exit_failure");
        let mut result = independent_checker_machine_check_result_base(
            request,
            policy,
            Some(selected_checker),
            &observation,
            IndependentCheckerMachineCheckStatus::Failed,
            Some(error),
        );
        result.diagnostics.clear();
        return result;
    }

    let stdout = std::str::from_utf8(&observation.stdout);
    let raw = stdout
        .ok()
        .and_then(|source| parse_independent_checker_raw_result(source).ok());
    let raw_error = match stdout {
        Ok(source) => parse_independent_checker_raw_result(source).err(),
        Err(_) => Some(IndependentCheckerRawResultSchemaError::new(
            "checker_raw",
            "valid_json",
            "invalid_json",
        )),
    };
    let Some(raw) = raw else {
        let reason_code = match exit_code {
            0 => "malformed_success_output",
            1 => "malformed_rejection_output",
            2 => "malformed_internal_error_output",
            _ => unreachable!("exit_code >= 3 handled above"),
        };
        let mut error = IndependentCheckerMachineCheckError::new("checker_internal_error")
            .with_reason_code(reason_code);
        if let Some(raw_error) = raw_error {
            error = error.with_value_payload(
                raw_error.field,
                raw_error.expected_value,
                raw_error.actual_value,
            );
        }
        let mut result = independent_checker_machine_check_result_base(
            request,
            policy,
            Some(selected_checker),
            &observation,
            IndependentCheckerMachineCheckStatus::Failed,
            Some(error),
        );
        if !observation.stdout.is_empty() {
            result
                .diagnostics
                .push("checker_process:stdout_present".to_owned());
        }
        independent_checker_push_stderr_diagnostic(&mut result, &observation);
        return result;
    };

    let mut checker =
        independent_checker_machine_check_checker_for_request(request, Some(selected_checker));
    checker.id = raw.checker_id.clone();
    checker.build_hash = raw.checker_build_hash;
    checker.version = raw.checker_version.clone();

    if exit_code == 0 && raw.status != IndependentCheckerMachineCheckStatus::Checked {
        let error = IndependentCheckerMachineCheckError::new("checker_internal_error")
            .with_reason_code("success_exit_status_mismatch");
        let mut result = independent_checker_machine_check_result_base(
            request,
            policy,
            Some(selected_checker),
            &observation,
            IndependentCheckerMachineCheckStatus::Failed,
            Some(error),
        );
        result.checker = checker;
        independent_checker_push_stderr_diagnostic(&mut result, &observation);
        return result;
    }
    if exit_code == 1
        && (raw.status != IndependentCheckerMachineCheckStatus::Failed || raw.error.is_none())
    {
        let error = IndependentCheckerMachineCheckError::new("checker_internal_error")
            .with_reason_code("missing_rejection_error");
        let mut result = independent_checker_machine_check_result_base(
            request,
            policy,
            Some(selected_checker),
            &observation,
            IndependentCheckerMachineCheckStatus::Failed,
            Some(error),
        );
        result.checker = checker;
        independent_checker_push_stderr_diagnostic(&mut result, &observation);
        return result;
    }
    if exit_code == 1
        && raw
            .error
            .as_ref()
            .map(|error| error.kind.as_str() == "checker_internal_error")
            .unwrap_or(false)
    {
        let error = IndependentCheckerMachineCheckError::new("checker_internal_error")
            .with_reason_code("malformed_rejection_output");
        let mut result = independent_checker_machine_check_result_base(
            request,
            policy,
            Some(selected_checker),
            &observation,
            IndependentCheckerMachineCheckStatus::Failed,
            Some(error),
        );
        result.checker = checker;
        independent_checker_push_stderr_diagnostic(&mut result, &observation);
        return result;
    }
    if exit_code == 2
        && raw
            .error
            .as_ref()
            .map(|error| error.kind.as_str() != "checker_internal_error")
            .unwrap_or(true)
    {
        let error = IndependentCheckerMachineCheckError::new("checker_internal_error")
            .with_reason_code("malformed_internal_error_output");
        let mut result = independent_checker_machine_check_result_base(
            request,
            policy,
            Some(selected_checker),
            &observation,
            IndependentCheckerMachineCheckStatus::Failed,
            Some(error),
        );
        result.checker = checker;
        independent_checker_push_stderr_diagnostic(&mut result, &observation);
        return result;
    }

    if raw.checker_id.as_deref() != Some(selected_checker.checker_id.as_str()) {
        let actual = raw.checker_id.as_deref().unwrap_or("missing");
        let error = IndependentCheckerMachineCheckError::new("policy_failure")
            .with_reason_code(if raw.checker_id.is_some() {
                "checker_identity_mismatch"
            } else {
                "checker_identity_missing"
            })
            .with_value_payload("checker.id", &selected_checker.checker_id, actual);
        let mut result = independent_checker_machine_check_result_base(
            request,
            policy,
            Some(selected_checker),
            &observation,
            IndependentCheckerMachineCheckStatus::Failed,
            Some(error),
        );
        result.checker = checker;
        independent_checker_push_stderr_diagnostic(&mut result, &observation);
        return result;
    }
    if raw.checker_build_hash != Some(selected_checker.build_hash) {
        let mut error = IndependentCheckerMachineCheckError::new("policy_failure")
            .with_reason_code(if raw.checker_build_hash.is_some() {
                "checker_build_hash_mismatch"
            } else {
                "checker_identity_missing"
            });
        error.field = Some("checker.build_hash".to_owned());
        error.expected_hash = Some(selected_checker.build_hash);
        error.actual_hash = raw.checker_build_hash;
        let mut result = independent_checker_machine_check_result_base(
            request,
            policy,
            Some(selected_checker),
            &observation,
            IndependentCheckerMachineCheckStatus::Failed,
            Some(error),
        );
        result.checker = checker;
        independent_checker_push_stderr_diagnostic(&mut result, &observation);
        return result;
    }

    if let Some(raw_module) = raw.module.as_deref() {
        if raw_module != request.module {
            let error = IndependentCheckerMachineCheckError::new("checker_internal_error")
                .with_reason_code("checker_module_mismatch")
                .with_value_payload("module", &request.module, raw_module);
            let mut result = independent_checker_machine_check_result_base(
                request,
                policy,
                Some(selected_checker),
                &observation,
                IndependentCheckerMachineCheckStatus::Failed,
                Some(error),
            );
            result.checker = checker;
            independent_checker_push_stderr_diagnostic(&mut result, &observation);
            return result;
        }
    }

    if raw.status == IndependentCheckerMachineCheckStatus::Checked
        || raw
            .error
            .as_ref()
            .map(independent_checker_error_requires_certificate_hash)
            .unwrap_or(false)
    {
        if let Some(certificate_hash) = raw.certificate_hash {
            if certificate_hash != request.certificate.expected_certificate_hash {
                let error = IndependentCheckerMachineCheckError::new("certificate_hash_mismatch")
                    .with_hash_payload(
                        "certificate_hash",
                        request.certificate.expected_certificate_hash,
                        certificate_hash,
                    );
                let mut result = independent_checker_machine_check_result_base(
                    request,
                    policy,
                    Some(selected_checker),
                    &observation,
                    IndependentCheckerMachineCheckStatus::Failed,
                    Some(error),
                );
                result.checker = checker;
                result.certificate_hash = Some(certificate_hash);
                independent_checker_push_stderr_diagnostic(&mut result, &observation);
                return result;
            }
        }
    }

    match exit_code {
        0 => {
            let mut result = independent_checker_machine_check_result_base(
                request,
                policy,
                Some(selected_checker),
                &observation,
                IndependentCheckerMachineCheckStatus::Checked,
                None,
            );
            result.checker = checker;
            result.certificate_hash = raw.certificate_hash;
            result.export_hash = raw.export_hash;
            result.axiom_report_hash = raw.axiom_report_hash;
            independent_checker_push_stderr_diagnostic(&mut result, &observation);
            result
        }
        1 => {
            let mut result = independent_checker_machine_check_result_base(
                request,
                policy,
                Some(selected_checker),
                &observation,
                IndependentCheckerMachineCheckStatus::Failed,
                raw.error,
            );
            result.checker = checker;
            result.certificate_hash = raw.certificate_hash;
            result.export_hash = raw.export_hash;
            result.axiom_report_hash = raw.axiom_report_hash;
            independent_checker_push_stderr_diagnostic(&mut result, &observation);
            result
        }
        2 => {
            let error = raw.error.unwrap_or_else(|| {
                IndependentCheckerMachineCheckError::new("checker_internal_error")
                    .with_reason_code("checker_reported_internal_error")
            });
            let mut result = independent_checker_machine_check_result_base(
                request,
                policy,
                Some(selected_checker),
                &observation,
                IndependentCheckerMachineCheckStatus::Failed,
                Some(error),
            );
            result.checker = checker;
            result.certificate_hash = raw.certificate_hash;
            result.export_hash = raw.export_hash;
            result.axiom_report_hash = raw.axiom_report_hash;
            independent_checker_push_stderr_diagnostic(&mut result, &observation);
            result
        }
        _ => unreachable!("exit_code >= 3 handled above"),
    }
}

fn independent_checker_policy_failure_result(
    request: &IndependentCheckerMachineCheckRequest,
    policy: &IndependentCheckerRunnerPolicy,
    observation: &IndependentCheckerRunObservation,
    _reason_code: &str,
    error: IndependentCheckerMachineCheckError,
) -> IndependentCheckerMachineCheckResult {
    let mut result = independent_checker_machine_check_result_base(
        request,
        policy,
        None,
        observation,
        IndependentCheckerMachineCheckStatus::Failed,
        Some(error),
    );
    result.process = IndependentCheckerMachineCheckProcess::not_launched();
    result.resource_usage = IndependentCheckerMachineCheckResourceUsage::zero();
    result.diagnostics.clear();
    result
}

fn independent_checker_infrastructure_failure_result(
    request: &IndependentCheckerMachineCheckRequest,
    policy: &IndependentCheckerRunnerPolicy,
    selected_checker: &IndependentCheckerAllowlistEntry,
    observation: &IndependentCheckerRunObservation,
    kind: &str,
    reason_code: &str,
) -> IndependentCheckerMachineCheckResult {
    let error = IndependentCheckerMachineCheckError::new(kind).with_reason_code(reason_code);
    independent_checker_machine_check_result_base(
        request,
        policy,
        Some(selected_checker),
        observation,
        IndependentCheckerMachineCheckStatus::Failed,
        Some(error),
    )
}

fn independent_checker_machine_check_result_base(
    request: &IndependentCheckerMachineCheckRequest,
    policy: &IndependentCheckerRunnerPolicy,
    selected_checker: Option<&IndependentCheckerAllowlistEntry>,
    observation: &IndependentCheckerRunObservation,
    status: IndependentCheckerMachineCheckStatus,
    error: Option<IndependentCheckerMachineCheckError>,
) -> IndependentCheckerMachineCheckResult {
    let mut diagnostics = Vec::new();
    if observation.process.exit_code.is_some()
        && observation.process.exit_code.unwrap_or(255) <= 2
        && !observation.stderr.is_empty()
    {
        diagnostics.push("checker_process:stderr_present".to_owned());
    }
    IndependentCheckerMachineCheckResult {
        request_id: request.request_id.clone(),
        request_hash: request.request_hash(),
        result_id: observation.result_id.clone(),
        policy: IndependentCheckerMachineCheckRequestPolicy {
            id: policy.id.clone(),
            version: policy.version,
            hash: policy.policy_hash(),
        },
        runner: observation.runner.clone(),
        checker: independent_checker_machine_check_checker_for_request(request, selected_checker),
        attempt: observation.attempt,
        status,
        module: request.module.clone(),
        process: observation.process.clone(),
        resource_usage: observation.resource_usage.clone(),
        error,
        certificate_hash: None,
        export_hash: None,
        axiom_report_hash: None,
        diagnostics,
        axioms_used: None,
        declarations_checked: None,
        raw_checker_output_hex: (!observation.stdout.is_empty())
            .then(|| independent_checker_hex_bytes(&observation.stdout)),
    }
}

fn independent_checker_machine_check_checker_for_request(
    request: &IndependentCheckerMachineCheckRequest,
    selected_checker: Option<&IndependentCheckerAllowlistEntry>,
) -> IndependentCheckerMachineCheckChecker {
    IndependentCheckerMachineCheckChecker {
        profile: request.checker_profile.clone(),
        binary_id: selected_checker.map(|checker| checker.binary_id.clone()),
        binary_hash: selected_checker.map(|checker| checker.binary_hash),
        id: None,
        build_hash: None,
        version: None,
    }
}

fn independent_checker_push_stderr_diagnostic(
    result: &mut IndependentCheckerMachineCheckResult,
    observation: &IndependentCheckerRunObservation,
) {
    if !observation.stderr.is_empty()
        && observation.process.exit_code.is_some()
        && observation.process.exit_code.unwrap_or(255) <= 2
        && !result
            .diagnostics
            .iter()
            .any(|diagnostic| diagnostic == "checker_process:stderr_present")
    {
        result
            .diagnostics
            .push("checker_process:stderr_present".to_owned());
    }
}

fn independent_checker_error_requires_certificate_hash(
    error: &IndependentCheckerMachineCheckError,
) -> bool {
    matches!(
        error.kind.as_str(),
        "import_not_found"
            | "import_hash_mismatch"
            | "certificate_hash_mismatch"
            | "axiom_report_mismatch"
            | "export_hash_mismatch"
            | "type_mismatch"
            | "conversion_failure"
            | "universe_inconsistency"
            | "inductive_invalid"
            | "positivity_failure"
            | "declaration_hash_mismatch"
            | "dependency_hash_mismatch"
            | "forbidden_axiom"
    )
}

fn parse_independent_checker_raw_result_value(
    value: &JsonValue<'_>,
) -> Result<IndependentCheckerRawResult, IndependentCheckerRawResultSchemaError> {
    let members = value.object_members().ok_or_else(|| {
        IndependentCheckerRawResultSchemaError::new("checker_raw", "object", "wrong_type")
    })?;
    raw_required_fixed_string(
        members,
        "schema",
        "checker_raw.schema",
        INDEPENDENT_CHECKER_CHECKER_RAW_RESULT_SCHEMA,
    )?;
    let status_raw = raw_required_string(
        members,
        "status",
        "checker_raw.status",
        "CheckerRawResult.status",
    )?;
    let status = match status_raw.as_str() {
        "checked" => IndependentCheckerMachineCheckStatus::Checked,
        "failed" => IndependentCheckerMachineCheckStatus::Failed,
        _ => {
            return Err(IndependentCheckerRawResultSchemaError::new(
                "checker_raw.status",
                "CheckerRawResult.status",
                "invalid_enum",
            ))
        }
    };
    let checker_id = raw_optional_identity_string(
        members,
        "checker_id",
        "checker_raw.checker_id",
        "checker_id",
    )?;
    if let Some(checker_id) = checker_id.as_deref() {
        if !independent_checker_valid_checker_id(checker_id) {
            return Err(IndependentCheckerRawResultSchemaError::new(
                "checker_raw.checker_id",
                "checker_id",
                "invalid_name_format",
            ));
        }
    }
    let checker_version = raw_optional_identity_string(
        members,
        "checker_version",
        "checker_raw.checker_version",
        "string",
    )?;
    let checker_build_hash = raw_optional_identity_hash(
        members,
        "checker_build_hash",
        "checker_raw.checker_build_hash",
    )?;

    let module = raw_optional_module(members, "module", "checker_raw.module")?;
    let certificate_hash =
        raw_optional_hash(members, "certificate_hash", "checker_raw.certificate_hash")?;
    let export_hash = raw_optional_hash(members, "export_hash", "checker_raw.export_hash")?;
    let axiom_report_hash = raw_optional_hash(
        members,
        "axiom_report_hash",
        "checker_raw.axiom_report_hash",
    )?;
    let error = raw_optional_error(members)?;

    match status {
        IndependentCheckerMachineCheckStatus::Checked => {
            if module.is_none() {
                return Err(IndependentCheckerRawResultSchemaError::new(
                    "checker_raw.module",
                    "module_name",
                    "missing",
                ));
            }
            if certificate_hash.is_none() {
                return Err(IndependentCheckerRawResultSchemaError::new(
                    "checker_raw.certificate_hash",
                    "sha256:<lower-hex>",
                    "missing",
                ));
            }
            if export_hash.is_none() {
                return Err(IndependentCheckerRawResultSchemaError::new(
                    "checker_raw.export_hash",
                    "sha256:<lower-hex>",
                    "missing",
                ));
            }
            if axiom_report_hash.is_none() {
                return Err(IndependentCheckerRawResultSchemaError::new(
                    "checker_raw.axiom_report_hash",
                    "sha256:<lower-hex>",
                    "missing",
                ));
            }
            if duplicate_member(members, "error")
                || members.iter().any(|member| member.key() == "error")
            {
                return Err(IndependentCheckerRawResultSchemaError::new(
                    "checker_raw.error",
                    "absent_for_status_kind",
                    "forbidden_field",
                ));
            }
        }
        IndependentCheckerMachineCheckStatus::Failed => {
            let Some(error) = &error else {
                return Err(IndependentCheckerRawResultSchemaError::new(
                    "checker_raw.error",
                    "object",
                    "missing",
                ));
            };
            if independent_checker_error_requires_certificate_hash(error) {
                if module.is_none() {
                    return Err(IndependentCheckerRawResultSchemaError::new(
                        "checker_raw.module",
                        "module_name",
                        "missing",
                    ));
                }
                if certificate_hash.is_none() {
                    return Err(IndependentCheckerRawResultSchemaError::new(
                        "checker_raw.certificate_hash",
                        "sha256:<lower-hex>",
                        "missing",
                    ));
                }
            }
        }
    }

    raw_reject_unknown_fields(
        members,
        &[
            "schema",
            "checker_id",
            "checker_version",
            "checker_build_hash",
            "status",
            "module",
            "certificate_hash",
            "export_hash",
            "axiom_report_hash",
            "error",
        ],
        "checker_raw",
    )?;

    Ok(IndependentCheckerRawResult {
        status,
        checker_id,
        checker_version,
        checker_build_hash,
        module,
        certificate_hash,
        export_hash,
        axiom_report_hash,
        error,
    })
}

fn raw_required_string(
    members: &[JsonMember<'_>],
    name: &str,
    field: &str,
    expected: &str,
) -> Result<String, IndependentCheckerRawResultSchemaError> {
    if duplicate_member(members, name) {
        return Err(IndependentCheckerRawResultSchemaError::new(
            field,
            "unique_object_keys",
            "duplicate_field",
        ));
    }
    let Some(value) = members
        .iter()
        .find(|member| member.key() == name)
        .map(JsonMember::value)
    else {
        return Err(IndependentCheckerRawResultSchemaError::new(
            field, expected, "missing",
        ));
    };
    if value.kind() == JsonValueKind::Null {
        return Err(IndependentCheckerRawResultSchemaError::new(
            field,
            expected,
            "null_not_allowed",
        ));
    }
    value
        .string_value()
        .map(ToOwned::to_owned)
        .ok_or_else(|| IndependentCheckerRawResultSchemaError::new(field, expected, "wrong_type"))
}

fn raw_required_fixed_string(
    members: &[JsonMember<'_>],
    name: &str,
    field: &str,
    fixed: &str,
) -> Result<(), IndependentCheckerRawResultSchemaError> {
    let value = raw_required_string(members, name, field, fixed)?;
    if value != fixed {
        return Err(IndependentCheckerRawResultSchemaError::new(
            field,
            fixed,
            "invalid_enum",
        ));
    }
    Ok(())
}

