fn parse_independent_checker_axiom_report_value(
    value: &JsonValue<'_>,
) -> Result<IndependentCheckerAxiomReport, IndependentCheckerRequestValidationError> {
    let members = object_members_or_policy_error(value, "$", "object")?;
    required_fixed_string_field(
        members,
        "schema",
        "schema",
        INDEPENDENT_CHECKER_AXIOM_REPORT_SCHEMA,
        INDEPENDENT_CHECKER_AXIOM_REPORT_SCHEMA,
    )?;
    let parsed_hash = required_hash_field(
        members,
        "axiom_report_hash",
        "axiom_report_hash",
        "sha256:<lower-hex>",
    )?;
    let module = required_string_field(members, "module", "module", "module_name")?;
    if !independent_checker_valid_dotted_name(&module) {
        return Err(IndependentCheckerRequestValidationError::value_failure(
            "module",
            "module_name",
            "invalid_name_format",
        ));
    }
    let certificate_hash = required_hash_field(
        members,
        "certificate_hash",
        "certificate_hash",
        "sha256:<lower-hex>",
    )?;
    let axioms_value = required_field_value(members, "axioms", "axioms", "array")?;
    let Some(axiom_values) = axioms_value.array_elements() else {
        return Err(wrong_type_error("axioms", "array", axioms_value.kind()).into());
    };
    let mut axioms = Vec::new();
    for (index, axiom_value) in axiom_values.iter().enumerate() {
        let path = format!("axioms[{index}]");
        let axiom_members = object_members_or_policy_error(axiom_value, &path, "object")?;
        let name = required_string_field(
            axiom_members,
            "name",
            &format!("{path}.name"),
            "certificate_name",
        )?;
        if !independent_checker_valid_dotted_name(&name) {
            return Err(IndependentCheckerRequestValidationError::value_failure(
                format!("{path}.name"),
                "certificate_name",
                "invalid_name_format",
            ));
        }
        reject_unknown_fields(axiom_members, AXIOM_REPORT_ENTRY_FIELDS, &path)?;
        axioms.push(IndependentCheckerAxiomReportEntry { name });
    }
    reject_unknown_fields(members, AXIOM_REPORT_FIELDS, "$")?;
    validate_axiom_report_domain(&axioms)?;
    let report = IndependentCheckerAxiomReport {
        module,
        certificate_hash,
        axioms,
    };
    let recomputed = report.axiom_report_hash();
    if recomputed != parsed_hash {
        return Err(IndependentCheckerRequestValidationError::hash_failure(
            "axiom_report_hash",
            recomputed,
            parsed_hash,
        ));
    }
    Ok(report)
}

