fn parse_independent_checker_machine_check_request_value(
    value: &JsonValue<'_>,
) -> Result<IndependentCheckerMachineCheckRequest, IndependentCheckerRequestValidationError> {
    let members = object_members_or_policy_error(value, "$", "object")?;
    if !members.iter().any(|member| member.key() == "request_hash") {
        return Err(IndependentCheckerRequestValidationError::value_failure(
            "request_hash",
            "sha256:<lower-hex>",
            "missing",
        ));
    }

    required_fixed_string_field(
        members,
        "schema",
        "schema",
        INDEPENDENT_CHECKER_MACHINE_CHECK_REQUEST_SCHEMA,
        INDEPENDENT_CHECKER_MACHINE_CHECK_REQUEST_SCHEMA,
    )?;
    let request_id = required_string_field(members, "request_id", "request_id", "request_id")?;
    if !independent_checker_valid_request_id(&request_id) {
        return Err(IndependentCheckerRequestValidationError::value_failure(
            "request_id",
            "request_id",
            if request_id.is_empty() {
                "empty_string"
            } else {
                "invalid_string_format"
            },
        ));
    }
    let parsed_request_hash = required_hash_field(
        members,
        "request_hash",
        "request_hash",
        "sha256:<lower-hex>",
    )?;
    let module = required_string_field(members, "module", "module", "module_name")?;
    if !independent_checker_valid_dotted_name(&module) {
        return Err(IndependentCheckerRequestValidationError::value_failure(
            "module",
            "module_name",
            "invalid_name_format",
        ));
    }
    let policy = parse_machine_check_request_policy(members)?;
    let certificate = parse_machine_check_request_certificate(members)?;
    let imports = parse_machine_check_request_imports(members)?;
    let checker_profile = required_string_field(
        members,
        "checker_profile",
        "checker_profile",
        "checker_profile_name",
    )?;
    if !independent_checker_valid_checker_profile_name(&checker_profile) {
        return Err(IndependentCheckerRequestValidationError::value_failure(
            "checker_profile",
            "checker_profile_name",
            "invalid_name_format",
        ));
    }
    let trust_mode_raw = required_string_field(members, "trust_mode", "trust_mode", "trust_mode")?;
    let trust_mode = IndependentCheckerTrustMode::parse(&trust_mode_raw).ok_or_else(|| {
        IndependentCheckerRequestValidationError::value_failure(
            "trust_mode",
            "trust_mode",
            "invalid_enum",
        )
    })?;
    let axiom_policy = required_string_field(
        members,
        "axiom_policy",
        "axiom_policy",
        "workspace_relative_path",
    )?;
    if !independent_checker_valid_workspace_relative_path(&axiom_policy) {
        return Err(IndependentCheckerRequestValidationError::value_failure(
            "axiom_policy",
            "workspace_relative_path",
            "invalid_path",
        ));
    }
    let budget = parse_machine_check_request_budget(members)?;
    reject_unknown_fields(members, MACHINE_CHECK_REQUEST_FIELDS, "$")?;

    let request = IndependentCheckerMachineCheckRequest {
        request_id,
        module,
        policy,
        certificate,
        imports,
        checker_profile,
        trust_mode,
        axiom_policy,
        budget,
    };
    let recomputed = request.request_hash();
    if recomputed != parsed_request_hash {
        return Err(IndependentCheckerRequestValidationError::hash_failure(
            "request_hash",
            recomputed,
            parsed_request_hash,
        ));
    }
    Ok(request)
}

