fn parse_independent_checker_challenge_mutation_field(
    members: &[JsonMember<'_>],
    field: &str,
    allow_informational: bool,
) -> Result<IndependentCheckerChallengeMutation, IndependentCheckerRequestValidationError> {
    let value = required_field_value(members, last_json_path_component(field), field, "object")?;
    let mutation_members = object_members_or_policy_error(value, field, "object")?;
    let kind = required_string_field(
        mutation_members,
        "kind",
        &format!("{field}.kind"),
        "challenge_mutation_kind",
    )?;
    let known_kind = IndependentCheckerChallengeMutationKind::parse(&kind);
    if known_kind.is_none() {
        if allow_informational {
            if !independent_checker_valid_informational_challenge_kind(&kind) {
                return Err(IndependentCheckerRequestValidationError::value_failure(
                    format!("{field}.kind"),
                    "challenge_mutation_kind",
                    "invalid_name_format",
                ));
            }
        } else {
            return Err(IndependentCheckerRequestValidationError::value_failure(
                format!("{field}.kind"),
                "challenge_mutation_kind",
                "invalid_enum",
            ));
        }
    }
    let target = required_string_field(
        mutation_members,
        "target",
        &format!("{field}.target"),
        "challenge_mutation_target",
    )?;
    validate_challenge_mutation_target(&target, known_kind, allow_informational).map_err(
        |actual| {
            IndependentCheckerRequestValidationError::value_failure(
                format!("{field}.target"),
                "challenge_mutation_target",
                actual,
            )
        },
    )?;
    let seed = required_hash_field(
        mutation_members,
        "seed",
        &format!("{field}.seed"),
        "sha256:<lower-hex>",
    )?;
    reject_unknown_fields(mutation_members, CHALLENGE_MUTATION_FIELDS, field)?;
    Ok(IndependentCheckerChallengeMutation { kind, target, seed })
}

