fn parse_independent_checker_release_bundle_staging_plan_value(
    value: &JsonValue<'_>,
) -> Result<IndependentCheckerReleaseBundleStagingPlan, IndependentCheckerCommandError> {
    let members = independent_checker_release_stage_object_members(value, "plan", "object")?;
    independent_checker_release_stage_required_fixed_string(
        members,
        "schema",
        "schema",
        INDEPENDENT_CHECKER_RELEASE_BUNDLE_STAGING_PLAN_SCHEMA,
        INDEPENDENT_CHECKER_RELEASE_BUNDLE_STAGING_PLAN_SCHEMA,
    )?;
    let phase_raw = independent_checker_release_stage_required_string(
        members,
        "phase",
        "phase",
        "release_bundle_staging_phase",
    )?;
    let phase =
        IndependentCheckerReleaseBundleStagingPhase::parse(&phase_raw).ok_or_else(|| {
            independent_checker_release_stage_value_error(
                "input_schema_invalid",
                "phase",
                "store|final",
                "invalid_enum",
            )
        })?;
    let bundle_root = independent_checker_release_stage_required_string(
        members,
        "bundle_root",
        "bundle_root",
        "workspace_relative_path",
    )?;
    if !independent_checker_valid_workspace_relative_path(&bundle_root) {
        return Err(independent_checker_release_stage_value_error(
            "input_schema_invalid",
            "bundle_root",
            "workspace_relative_path",
            "invalid_path",
        ));
    }
    let inputs_value =
        independent_checker_release_stage_required_value(members, "inputs", "inputs", "array")?;
    let Some(input_values) = inputs_value.array_elements() else {
        return Err(independent_checker_release_stage_value_error(
            "input_schema_invalid",
            "inputs",
            "array",
            "wrong_type",
        ));
    };
    let mut inputs = Vec::new();
    for (index, input_value) in input_values.iter().enumerate() {
        inputs.push(
            parse_independent_checker_release_bundle_staging_input_value(input_value, index)?,
        );
    }
    independent_checker_release_stage_reject_unknown_fields(
        members,
        RELEASE_BUNDLE_STAGING_PLAN_FIELDS,
        "$",
    )?;

    independent_checker_release_validate_staging_plan_inputs(phase, &inputs)?;
    Ok(IndependentCheckerReleaseBundleStagingPlan {
        phase,
        bundle_root,
        inputs,
    })
}

fn parse_independent_checker_release_bundle_staging_input_value(
    value: &JsonValue<'_>,
    index: usize,
) -> Result<IndependentCheckerReleaseBundleStagingInput, IndependentCheckerCommandError> {
    let input_path = format!("inputs[{index}]");
    let members = independent_checker_release_stage_object_members(value, &input_path, "object")?;
    let kind_raw = independent_checker_release_stage_required_string(
        members,
        "kind",
        format!("{input_path}.kind"),
        "release_bundle_artifact_kind",
    )?;
    let kind = IndependentCheckerReleaseBundleArtifactKind::parse(&kind_raw).ok_or_else(|| {
        independent_checker_release_stage_value_error(
            "input_schema_invalid",
            format!("{input_path}.kind"),
            "release_bundle_artifact_kind",
            "invalid_enum",
        )
    })?;
    let path = independent_checker_release_stage_required_string(
        members,
        "path",
        format!("{input_path}.path"),
        "workspace_relative_path",
    )?;
    if !independent_checker_valid_workspace_relative_path(&path) {
        return Err(independent_checker_release_stage_value_error(
            "input_schema_invalid",
            format!("{input_path}.path"),
            "workspace_relative_path",
            "invalid_path",
        ));
    }
    let file_hash = independent_checker_release_stage_required_hash(
        members,
        "file_hash",
        format!("{input_path}.file_hash"),
        "sha256:<lower-hex>",
    )?;
    let hashes_value = independent_checker_release_stage_required_value(
        members,
        "hashes",
        format!("{input_path}.hashes"),
        "object",
    )?;
    let hashes =
        parse_independent_checker_release_bundle_input_hashes(hashes_value, &input_path, kind)?;
    independent_checker_release_stage_reject_unknown_fields(
        members,
        RELEASE_BUNDLE_STAGING_INPUT_FIELDS,
        &input_path,
    )?;

    Ok(IndependentCheckerReleaseBundleStagingInput {
        kind,
        path,
        file_hash,
        hashes,
    })
}

fn parse_independent_checker_release_bundle_input_hashes(
    value: &JsonValue<'_>,
    input_path: &str,
    kind: IndependentCheckerReleaseBundleArtifactKind,
) -> Result<BTreeMap<String, Hash>, IndependentCheckerCommandError> {
    let hashes_path = format!("{input_path}.hashes");
    let members = independent_checker_release_stage_object_members(value, &hashes_path, "object")?;
    let required = kind.required_hash_fields();
    if required.is_empty() && !members.is_empty() {
        return Err(independent_checker_release_stage_value_error(
            "input_schema_invalid",
            &hashes_path,
            "empty_object",
            "non_empty",
        ));
    }
    let mut hashes = BTreeMap::new();
    for member in members {
        if hashes.contains_key(member.key()) {
            return Err(independent_checker_release_stage_value_error(
                "input_schema_invalid",
                format!("{hashes_path}.{}", member.key()),
                "unique_object_keys",
                "duplicate_field",
            ));
        }
        let Some(raw) = member.value().string_value() else {
            return Err(independent_checker_release_stage_value_error(
                "input_schema_invalid",
                format!("{hashes_path}.{}", member.key()),
                "sha256:<lower-hex>",
                if member.value().kind() == JsonValueKind::Null {
                    "null_not_allowed"
                } else {
                    "wrong_type"
                },
            ));
        };
        let hash = parse_hash_string(raw).map_err(|_| {
            independent_checker_release_stage_value_error(
                "input_schema_invalid",
                format!("{hashes_path}.{}", member.key()),
                "sha256:<lower-hex>",
                "invalid_hash_format",
            )
        })?;
        hashes.insert(member.key().to_owned(), hash);
    }
    for required_field in required {
        if !hashes.contains_key(*required_field) {
            return Err(independent_checker_release_stage_value_error(
                "input_schema_invalid",
                format!("{hashes_path}.{required_field}"),
                "sha256:<lower-hex>",
                "missing",
            ));
        }
    }
    for key in hashes.keys() {
        if !required.contains(&key.as_str()) {
            return Err(independent_checker_release_stage_value_error(
                "input_schema_invalid",
                format!("{hashes_path}.{key}"),
                format!("hash_field_for_kind:{}", kind.as_str()),
                "unknown_field",
            ));
        }
    }
    Ok(hashes)
}

fn independent_checker_release_validate_staging_plan_inputs(
    phase: IndependentCheckerReleaseBundleStagingPhase,
    inputs: &[IndependentCheckerReleaseBundleStagingInput],
) -> Result<(), IndependentCheckerCommandError> {
    for index in 1..inputs.len() {
        let left = (
            inputs[index].kind.as_str(),
            inputs[index].path.as_str(),
            inputs[index].file_hash,
        );
        let right = (
            inputs[index - 1].kind.as_str(),
            inputs[index - 1].path.as_str(),
            inputs[index - 1].file_hash,
        );
        if left < right {
            return Err(independent_checker_release_stage_value_error(
                "input_schema_invalid",
                format!("inputs[{index}]"),
                "inputs_sorted_by_kind_path_file_hash",
                "order_violation",
            ));
        }
    }

    let mut kind_paths = BTreeSet::new();
    let mut paths = BTreeSet::new();
    for (index, input) in inputs.iter().enumerate() {
        if !kind_paths.insert((input.kind, input.path.as_str())) {
            return Err(independent_checker_release_stage_value_error(
                "input_schema_invalid",
                format!("inputs[{index}]"),
                "unique_kind_path",
                "duplicate_entry",
            ));
        }
        if !paths.insert(input.path.as_str()) {
            return Err(independent_checker_release_stage_value_error(
                "input_schema_invalid",
                format!("inputs[{index}].path"),
                "unique_path",
                "duplicate_path",
            ));
        }
    }

    if phase == IndependentCheckerReleaseBundleStagingPhase::Store {
        independent_checker_release_require_store_input_kind(
            inputs,
            IndependentCheckerReleaseBundleArtifactKind::RequestStoreManifest,
            "one_or_more",
        )?;
        independent_checker_release_require_store_input_kind(
            inputs,
            IndependentCheckerReleaseBundleArtifactKind::MachineResultStoreManifest,
            "one_or_more",
        )?;
        independent_checker_release_require_store_input_kind(
            inputs,
            IndependentCheckerReleaseBundleArtifactKind::NormalizedResultStoreManifest,
            "one_or_more",
        )?;
        let challenge_count = inputs
            .iter()
            .filter(|input| {
                input.kind
                    == IndependentCheckerReleaseBundleArtifactKind::ChallengeOutputStoreManifest
            })
            .count();
        if challenge_count != 1 {
            return Err(independent_checker_release_stage_value_error(
                "input_schema_invalid",
                "inputs[]",
                "exactly_one:challenge_output_store_manifest",
                if challenge_count == 0 {
                    "missing:challenge_output_store_manifest".to_owned()
                } else {
                    format!("count:{challenge_count}")
                },
            ));
        }
    }
    for (index, input) in inputs.iter().enumerate() {
        if !input.kind.allowed_for_phase(phase) {
            return Err(independent_checker_release_stage_value_error(
                "input_schema_invalid",
                format!("inputs[{index}].kind"),
                format!("allowed_kind_for_phase:{}", phase.as_str()),
                input.kind.as_str(),
            ));
        }
    }
    Ok(())
}

fn independent_checker_release_require_store_input_kind(
    inputs: &[IndependentCheckerReleaseBundleStagingInput],
    kind: IndependentCheckerReleaseBundleArtifactKind,
    expected_prefix: &str,
) -> Result<(), IndependentCheckerCommandError> {
    if inputs.iter().any(|input| input.kind == kind) {
        return Ok(());
    }
    Err(independent_checker_release_stage_value_error(
        "input_schema_invalid",
        "inputs[]",
        format!("{expected_prefix}:{}", kind.as_str()),
        format!("missing:{}", kind.as_str()),
    ))
}

fn independent_checker_release_validate_direct_artifact(
    input: &IndependentCheckerReleaseBundleStagingInput,
    index: usize,
    source: &str,
) -> Result<(), IndependentCheckerCommandError> {
    let direct_json_reason = if matches!(
        input.kind,
        IndependentCheckerReleaseBundleArtifactKind::RequestStoreManifest
            | IndependentCheckerReleaseBundleArtifactKind::MachineResultStoreManifest
            | IndependentCheckerReleaseBundleArtifactKind::NormalizedResultStoreManifest
            | IndependentCheckerReleaseBundleArtifactKind::ChallengeOutputStoreManifest
    ) {
        "input_store_manifest_invalid"
    } else {
        "input_json_invalid"
    };
    JsonDocument::parse(source).map_err(|_| {
        independent_checker_release_stage_value_error(
            direct_json_reason,
            format!("inputs[{index}].path"),
            "valid_json",
            "invalid_json",
        )
    })?;
    match input.kind {
        IndependentCheckerReleaseBundleArtifactKind::ReleasePolicy => {
            let policy = parse_independent_checker_release_policy(source).map_err(|error| {
                independent_checker_release_stage_artifact_policy_error(
                    "input_schema_invalid",
                    index,
                    input.kind,
                    error,
                )
            })?;
            independent_checker_release_validate_planned_hash(
                input,
                index,
                "policy_hash",
                policy.policy_hash(),
            )
        }
        IndependentCheckerReleaseBundleArtifactKind::RunnerPolicy => {
            let policy = parse_independent_checker_runner_policy(source).map_err(|error| {
                independent_checker_release_stage_artifact_policy_error(
                    "input_schema_invalid",
                    index,
                    input.kind,
                    error,
                )
            })?;
            independent_checker_release_validate_planned_hash(
                input,
                index,
                "policy_hash",
                policy.policy_hash(),
            )
        }
        IndependentCheckerReleaseBundleArtifactKind::CheckerIdentityManifest => {
            parse_independent_checker_identity_manifest(source).map_err(|error| {
                independent_checker_release_stage_artifact_policy_error(
                    "input_schema_invalid",
                    index,
                    input.kind,
                    error,
                )
            })?;
            independent_checker_release_validate_planned_hash(
                input,
                index,
                "manifest_hash",
                input.file_hash,
            )
        }
        IndependentCheckerReleaseBundleArtifactKind::ImportLock => {
            parse_independent_checker_import_lock_manifest(source).map_err(|error| {
                independent_checker_release_stage_artifact_request_error(
                    "input_schema_invalid",
                    index,
                    input.kind,
                    error,
                )
            })?;
            independent_checker_release_validate_planned_hash(
                input,
                index,
                "manifest_hash",
                input.file_hash,
            )
        }
        IndependentCheckerReleaseBundleArtifactKind::ProofCertificate
        | IndependentCheckerReleaseBundleArtifactKind::ImportCertificate => {
            unreachable!("binary certificate artifacts are validated before JSON dispatch")
        }
        IndependentCheckerReleaseBundleArtifactKind::MachineCheckRequest => {
            let request =
                parse_independent_checker_machine_check_request(source).map_err(|error| {
                    independent_checker_release_stage_artifact_request_error(
                        "input_schema_invalid",
                        index,
                        input.kind,
                        error,
                    )
                })?;
            independent_checker_release_validate_planned_hash(
                input,
                index,
                "request_hash",
                request.request_hash(),
            )
        }
        IndependentCheckerReleaseBundleArtifactKind::MachineCheckResult => {
            let summary = parse_independent_checker_machine_check_result_summary(source, "$")
                .map_err(|error| {
                    independent_checker_release_stage_artifact_request_error(
                        "input_schema_invalid",
                        index,
                        input.kind,
                        error,
                    )
                })?;
            independent_checker_release_validate_planned_hash(
                input,
                index,
                "result_hash",
                summary.result_hash,
            )?;
            independent_checker_release_validate_planned_hash(
                input,
                index,
                "run_artifact_hash",
                summary.run_artifact_hash,
            )
        }
        IndependentCheckerReleaseBundleArtifactKind::NormalizedCheckResult => {
            let summary = parse_independent_checker_normalized_check_result_summary(source, "$")
                .map_err(|error| {
                    independent_checker_release_stage_artifact_request_error(
                        "input_schema_invalid",
                        index,
                        input.kind,
                        error,
                    )
                })?;
            independent_checker_release_validate_planned_hash(
                input,
                index,
                "artifact_hash",
                summary.artifact_hash,
            )?;
            independent_checker_release_validate_planned_hash(
                input,
                index,
                "normalized_result_hash",
                summary.normalized_result_hash,
            )
        }
        IndependentCheckerReleaseBundleArtifactKind::RequestStoreManifest => {
            parse_independent_checker_request_store_manifest(source).map_err(|error| {
                independent_checker_release_stage_artifact_request_error(
                    "input_store_manifest_invalid",
                    index,
                    input.kind,
                    error,
                )
            })?;
            independent_checker_release_validate_planned_hash(
                input,
                index,
                "manifest_hash",
                input.file_hash,
            )
        }
        IndependentCheckerReleaseBundleArtifactKind::MachineResultStoreManifest => {
            parse_independent_checker_machine_result_store_manifest(source).map_err(|error| {
                independent_checker_release_stage_artifact_request_error(
                    "input_store_manifest_invalid",
                    index,
                    input.kind,
                    error,
                )
            })?;
            independent_checker_release_validate_planned_hash(
                input,
                index,
                "manifest_hash",
                input.file_hash,
            )
        }
        IndependentCheckerReleaseBundleArtifactKind::NormalizedResultStoreManifest => {
            parse_independent_checker_normalized_result_store_manifest(source).map_err(
                |error| {
                    independent_checker_release_stage_artifact_request_error(
                        "input_store_manifest_invalid",
                        index,
                        input.kind,
                        error,
                    )
                },
            )?;
            independent_checker_release_validate_planned_hash(
                input,
                index,
                "manifest_hash",
                input.file_hash,
            )
        }
        IndependentCheckerReleaseBundleArtifactKind::ChallengeManifest => {
            parse_independent_checker_challenge_manifest(source).map_err(|error| {
                independent_checker_release_stage_artifact_request_error(
                    "input_schema_invalid",
                    index,
                    input.kind,
                    error,
                )
            })?;
            independent_checker_release_validate_planned_hash(
                input,
                index,
                "manifest_hash",
                input.file_hash,
            )
        }
        IndependentCheckerReleaseBundleArtifactKind::ChallengeOutputStoreManifest => {
            parse_independent_checker_challenge_output_store_manifest(source).map_err(|error| {
                independent_checker_release_stage_artifact_request_error(
                    "input_store_manifest_invalid",
                    index,
                    input.kind,
                    error,
                )
            })?;
            independent_checker_release_validate_planned_hash(
                input,
                index,
                "manifest_hash",
                input.file_hash,
            )
        }
        IndependentCheckerReleaseBundleArtifactKind::ChallengeReplayResult => {
            let result =
                parse_independent_checker_challenge_replay_result(source).map_err(|error| {
                    independent_checker_release_stage_artifact_request_error(
                        "input_schema_invalid",
                        index,
                        input.kind,
                        error,
                    )
                })?;
            independent_checker_release_validate_planned_hash(
                input,
                index,
                "result_hash",
                result.result_hash(),
            )
        }
        IndependentCheckerReleaseBundleArtifactKind::ChallengeCoverageSummary => {
            let summary =
                parse_independent_checker_challenge_coverage_summary(source).map_err(|error| {
                    independent_checker_release_stage_artifact_request_error(
                        "input_schema_invalid",
                        index,
                        input.kind,
                        error,
                    )
                })?;
            independent_checker_release_validate_planned_hash(
                input,
                index,
                "summary_hash",
                summary.summary_hash(),
            )
        }
        IndependentCheckerReleaseBundleArtifactKind::PerformanceBenchmarkSummary => {
            let summary = parse_independent_checker_performance_benchmark_summary(source).map_err(
                |error| {
                    independent_checker_release_stage_artifact_request_error(
                        "input_schema_invalid",
                        index,
                        input.kind,
                        error,
                    )
                },
            )?;
            independent_checker_release_validate_planned_hash(
                input,
                index,
                "summary_hash",
                summary.summary_hash,
            )
        }
        IndependentCheckerReleaseBundleArtifactKind::AuxiliaryResult => {
            let result = parse_independent_checker_auxiliary_result(source).map_err(|error| {
                independent_checker_release_stage_artifact_request_error(
                    "input_schema_invalid",
                    index,
                    input.kind,
                    error,
                )
            })?;
            independent_checker_release_validate_planned_hash(
                input,
                index,
                "result_hash",
                result.result_hash(),
            )
        }
        IndependentCheckerReleaseBundleArtifactKind::AiAuditInputPolicy => {
            let policy =
                parse_independent_checker_ai_audit_input_policy(source).map_err(|error| {
                    independent_checker_release_stage_artifact_audit_error(
                        "input_schema_invalid",
                        index,
                        input.kind,
                        error,
                    )
                })?;
            independent_checker_release_validate_planned_hash(
                input,
                index,
                "input_policy_hash",
                policy.input_policy_hash(),
            )
        }
        IndependentCheckerReleaseBundleArtifactKind::AiAuditSidecar => {
            parse_independent_checker_ai_audit_sidecar(source).map_err(|error| {
                independent_checker_release_stage_artifact_audit_error(
                    "input_schema_invalid",
                    index,
                    input.kind,
                    error,
                )
            })?;
            Ok(())
        }
        IndependentCheckerReleaseBundleArtifactKind::CompareValidationResponse => {
            validate_independent_checker_release_schema_only_artifact(
                source,
                INDEPENDENT_CHECKER_COMPARE_VALIDATION_RESULT_SCHEMA,
                COMPARE_VALIDATION_RESULT_FIELDS,
                &["valid", "failed"],
                format!("inputs[{index}].artifact"),
            )
        }
        IndependentCheckerReleaseBundleArtifactKind::AuditSidecarValidationResponse => {
            validate_independent_checker_release_schema_only_artifact(
                source,
                INDEPENDENT_CHECKER_AUDIT_SIDECAR_VALIDATION_RESULT_SCHEMA,
                AUDIT_SIDECAR_VALIDATION_RESULT_FIELDS,
                &["valid", "failed"],
                format!("inputs[{index}].artifact"),
            )
        }
    }
}

fn independent_checker_release_validate_direct_certificate_artifact(
    input: &IndependentCheckerReleaseBundleStagingInput,
    index: usize,
    bytes: &[u8],
) -> Result<(), IndependentCheckerCommandError> {
    let facts = independent_checker_certificate_artifact_facts(bytes).map_err(|_| {
        independent_checker_release_stage_value_error(
            "input_certificate_invalid",
            format!("inputs[{index}].path"),
            "canonical_npcert",
            "decode_failed",
        )
    })?;
    independent_checker_release_validate_planned_hash(
        input,
        index,
        "certificate_hash",
        facts.certificate_hash,
    )?;
    match input.kind {
        IndependentCheckerReleaseBundleArtifactKind::ProofCertificate => {
            let statement_core_hash = independent_checker_single_theorem_statement_hash(
                &facts,
                format!("inputs[{index}].statement_core_hash"),
            )
            .map_err(|error| {
                independent_checker_release_stage_value_error(
                    "input_certificate_invalid",
                    error.field,
                    error
                        .expected_value
                        .map(|value| value.into_string())
                        .unwrap_or_else(|| "exactly_one_theorem_statement".to_owned()),
                    error
                        .actual_value
                        .map(|value| value.into_string())
                        .unwrap_or_else(|| "invalid".to_owned()),
                )
            })?;
            independent_checker_release_validate_planned_hash(
                input,
                index,
                "statement_core_hash",
                statement_core_hash,
            )
        }
        IndependentCheckerReleaseBundleArtifactKind::ImportCertificate => {
            independent_checker_release_validate_planned_hash(
                input,
                index,
                "export_hash",
                facts.export_hash,
            )
        }
        _ => unreachable!("certificate artifact validation only called for certificate artifacts"),
    }
}

fn independent_checker_release_validate_planned_hash(
    input: &IndependentCheckerReleaseBundleStagingInput,
    index: usize,
    field: &str,
    actual: Hash,
) -> Result<(), IndependentCheckerCommandError> {
    let expected = *input
        .hashes
        .get(field)
        .expect("plan hash shape validates required fields");
    if expected != actual {
        return Err(independent_checker_release_stage_hash_error(
            "input_hash_mismatch",
            format!("inputs[{index}].hashes.{field}"),
            expected,
            actual,
        ));
    }
    Ok(())
}

fn validate_independent_checker_release_schema_only_artifact(
    source: &str,
    schema: &str,
    allowed_fields: &[&str],
    valid_statuses: &[&str],
    field: String,
) -> Result<(), IndependentCheckerCommandError> {
    let document = JsonDocument::parse(source).map_err(|_| {
        independent_checker_release_stage_value_error(
            "input_json_invalid",
            &field,
            "valid_json",
            "invalid_json",
        )
    })?;
    let members =
        independent_checker_release_stage_object_members(document.root(), &field, "object")?;
    independent_checker_release_stage_required_fixed_string(
        members,
        "schema",
        format!("{field}.schema"),
        schema,
        schema,
    )?;
    let status = independent_checker_release_stage_required_string(
        members,
        "status",
        format!("{field}.status"),
        "status",
    )?;
    if !valid_statuses.contains(&status.as_str()) {
        return Err(independent_checker_release_stage_value_error(
            "input_schema_invalid",
            format!("{field}.status"),
            "status",
            "invalid_enum",
        ));
    }
    independent_checker_release_stage_reject_unknown_fields(members, allowed_fields, &field)
}

fn independent_checker_release_stage_request_manifest_entries(
    input_index: usize,
    manifest: &IndependentCheckerRequestStoreManifest,
    workspace_files: &BTreeMap<String, Vec<u8>>,
    existing_bundle_files: Option<&BTreeMap<String, Vec<u8>>>,
    staged_files: &mut BTreeMap<String, Vec<u8>>,
    staged_artifacts: &mut Vec<IndependentCheckerReleaseBundleStagedArtifact>,
    merged_entries: &mut BTreeMap<Hash, IndependentCheckerRequestStoreEntry>,
) -> Result<(), IndependentCheckerCommandError> {
    for (index, entry) in manifest.requests.iter().enumerate() {
        let entry_path = format!("inputs[{input_index}].store.request_store.requests[{index}]");
        let source_bytes = independent_checker_release_store_entry_bytes(
            workspace_files,
            &entry.path,
            format!("{entry_path}.path"),
        )?;
        let actual_file_hash = independent_checker_file_hash(source_bytes);
        if actual_file_hash != entry.file_hash {
            return Err(independent_checker_release_stage_hash_error(
                "input_store_entry_invalid",
                format!("{entry_path}.file_hash"),
                entry.file_hash,
                actual_file_hash,
            ));
        }
        let source = independent_checker_release_stage_utf8(
            source_bytes,
            "input_store_entry_invalid",
            format!("{entry_path}.path"),
        )?;
        let request = parse_independent_checker_machine_check_request(source).map_err(|error| {
            independent_checker_release_stage_request_error(
                "input_store_entry_invalid",
                format!("{entry_path}.artifact"),
                error,
            )
        })?;
        if request.request_hash() != entry.request_hash {
            return Err(independent_checker_release_stage_hash_error(
                "input_store_entry_invalid",
                format!("{entry_path}.request_hash"),
                entry.request_hash,
                request.request_hash(),
            ));
        }
        let staged_path = independent_checker_release_stage_file(
            IndependentCheckerReleaseBundleArtifactKind::MachineCheckRequest,
            entry.file_hash,
            source_bytes,
            existing_bundle_files,
            staged_files,
            staged_artifacts,
        )?;
        let staged_entry = IndependentCheckerRequestStoreEntry {
            request_hash: entry.request_hash,
            path: staged_path,
            file_hash: entry.file_hash,
        };
        independent_checker_release_merge_request_entry(merged_entries, staged_entry)?;
    }
    Ok(())
}

fn independent_checker_release_stage_machine_manifest_entries(
    input_index: usize,
    manifest: &IndependentCheckerMachineResultStoreManifest,
    workspace_files: &BTreeMap<String, Vec<u8>>,
    existing_bundle_files: Option<&BTreeMap<String, Vec<u8>>>,
    staged_files: &mut BTreeMap<String, Vec<u8>>,
    staged_artifacts: &mut Vec<IndependentCheckerReleaseBundleStagedArtifact>,
    merged_entries: &mut BTreeMap<Hash, IndependentCheckerMachineResultStoreEntry>,
) -> Result<(), IndependentCheckerCommandError> {
    for (index, entry) in manifest.results.iter().enumerate() {
        let entry_path =
            format!("inputs[{input_index}].store.machine_result_store.results[{index}]");
        let source_bytes = independent_checker_release_store_entry_bytes(
            workspace_files,
            &entry.path,
            format!("{entry_path}.path"),
        )?;
        let actual_file_hash = independent_checker_file_hash(source_bytes);
        if actual_file_hash != entry.file_hash {
            return Err(independent_checker_release_stage_hash_error(
                "input_store_entry_invalid",
                format!("{entry_path}.file_hash"),
                entry.file_hash,
                actual_file_hash,
            ));
        }
        let source = independent_checker_release_stage_utf8(
            source_bytes,
            "input_store_entry_invalid",
            format!("{entry_path}.path"),
        )?;
        let summary = parse_independent_checker_machine_check_result_summary(source, "$").map_err(
            |error| {
                independent_checker_release_stage_request_error(
                    "input_store_entry_invalid",
                    format!("{entry_path}.artifact"),
                    error,
                )
            },
        )?;
        if summary.result_hash != entry.result_hash {
            return Err(independent_checker_release_stage_hash_error(
                "input_store_entry_invalid",
                format!("{entry_path}.result_hash"),
                entry.result_hash,
                summary.result_hash,
            ));
        }
        if summary.request_hash != entry.request_hash {
            return Err(independent_checker_release_stage_hash_error(
                "input_store_entry_invalid",
                format!("{entry_path}.request_hash"),
                entry.request_hash,
                summary.request_hash,
            ));
        }
        if summary.run_artifact_hash != entry.run_artifact_hash {
            return Err(independent_checker_release_stage_hash_error(
                "input_store_entry_invalid",
                format!("{entry_path}.run_artifact_hash"),
                entry.run_artifact_hash,
                summary.run_artifact_hash,
            ));
        }
        if summary.checker_profile != entry.checker_profile {
            return Err(independent_checker_release_stage_value_error(
                "input_store_entry_invalid",
                format!("{entry_path}.checker_profile"),
                &entry.checker_profile,
                &summary.checker_profile,
            ));
        }
        let staged_path = independent_checker_release_stage_file(
            IndependentCheckerReleaseBundleArtifactKind::MachineCheckResult,
            entry.file_hash,
            source_bytes,
            existing_bundle_files,
            staged_files,
            staged_artifacts,
        )?;
        let staged_entry = IndependentCheckerMachineResultStoreEntry {
            result_hash: entry.result_hash,
            request_hash: entry.request_hash,
            run_artifact_hash: entry.run_artifact_hash,
            checker_profile: entry.checker_profile.clone(),
            path: staged_path,
            file_hash: entry.file_hash,
        };
        independent_checker_release_merge_machine_entry(merged_entries, staged_entry)?;
    }
    Ok(())
}

