fn parse_independent_checker_release_audit_bundle_manifest_unchecked(
    source: &str,
) -> Result<IndependentCheckerReleaseAuditBundleManifest, IndependentCheckerCommandError> {
    let document = JsonDocument::parse(source).map_err(|_| {
        independent_checker_release_validate_bundle_value_error(
            "input_json_invalid",
            "manifest.path",
            "valid_json",
            "invalid_json",
        )
    })?;
    let members =
        independent_checker_release_validate_bundle_object_members(document.root(), "$", "object")?;
    independent_checker_release_validate_bundle_required_fixed_string(
        members,
        "schema",
        "schema",
        INDEPENDENT_CHECKER_RELEASE_AUDIT_BUNDLE_MANIFEST_SCHEMA,
        INDEPENDENT_CHECKER_RELEASE_AUDIT_BUNDLE_MANIFEST_SCHEMA,
    )?;
    let bundle_id = independent_checker_release_validate_bundle_required_string(
        members,
        "bundle_id",
        "bundle_id",
        "release_<sha256-lower-hex>",
    )?;
    let bundle_hash = independent_checker_release_validate_bundle_required_hash(
        members,
        "bundle_hash",
        "bundle_hash",
        "sha256:<lower-hex>",
    )?;
    let policy_hash = independent_checker_release_validate_bundle_required_hash(
        members,
        "policy_hash",
        "policy_hash",
        "sha256:<lower-hex>",
    )?;
    let artifact_hash = independent_checker_release_validate_bundle_required_hash(
        members,
        "artifact_hash",
        "artifact_hash",
        "sha256:<lower-hex>",
    )?;
    let artifacts_value = independent_checker_release_validate_bundle_required_value(
        members,
        "artifacts",
        "artifacts",
        "array",
    )?;
    let Some(artifact_values) = artifacts_value.array_elements() else {
        return Err(independent_checker_release_validate_bundle_value_error(
            "input_schema_invalid",
            "artifacts",
            "array",
            "wrong_type",
        ));
    };
    let mut artifacts = Vec::new();
    for (index, artifact_value) in artifact_values.iter().enumerate() {
        artifacts.push(
            parse_independent_checker_release_audit_bundle_artifact_value(artifact_value, index)?,
        );
    }
    independent_checker_release_validate_bundle_reject_unknown_fields(
        members,
        RELEASE_AUDIT_BUNDLE_MANIFEST_FIELDS,
        "$",
    )?;
    Ok(IndependentCheckerReleaseAuditBundleManifest {
        bundle_id,
        bundle_hash,
        policy_hash,
        artifact_hash,
        artifacts,
    })
}

fn parse_independent_checker_release_audit_bundle_artifact_value(
    value: &JsonValue<'_>,
    index: usize,
) -> Result<IndependentCheckerReleaseAuditBundleArtifact, IndependentCheckerCommandError> {
    let field = format!("artifacts[{index}]");
    let members =
        independent_checker_release_validate_bundle_object_members(value, &field, "object")?;
    let kind_raw = independent_checker_release_validate_bundle_required_string(
        members,
        "kind",
        format!("{field}.kind"),
        "release_bundle_artifact_kind",
    )?;
    let kind = IndependentCheckerReleaseBundleArtifactKind::parse(&kind_raw).ok_or_else(|| {
        independent_checker_release_validate_bundle_value_error(
            "input_schema_invalid",
            format!("{field}.kind"),
            "release_bundle_artifact_kind",
            "invalid_enum",
        )
    })?;
    let path = independent_checker_release_validate_bundle_required_string(
        members,
        "path",
        format!("{field}.path"),
        "bundle_local_artifact_path",
    )?;
    if !independent_checker_valid_workspace_relative_path(&path) {
        return Err(independent_checker_release_validate_bundle_value_error(
            "input_schema_invalid",
            format!("{field}.path"),
            "bundle_local_artifact_path",
            "invalid_path",
        ));
    }
    let file_hash = independent_checker_release_validate_bundle_required_hash(
        members,
        "file_hash",
        format!("{field}.file_hash"),
        "sha256:<lower-hex>",
    )?;
    let hashes_value = independent_checker_release_validate_bundle_required_value(
        members,
        "hashes",
        format!("{field}.hashes"),
        "object",
    )?;
    let hashes =
        parse_independent_checker_release_audit_bundle_hashes_value(hashes_value, &field, kind)?;
    independent_checker_release_validate_bundle_reject_unknown_fields(
        members,
        RELEASE_AUDIT_BUNDLE_ARTIFACT_FIELDS,
        &field,
    )?;
    Ok(IndependentCheckerReleaseAuditBundleArtifact {
        kind,
        path,
        file_hash,
        hashes,
    })
}

fn parse_independent_checker_release_audit_bundle_hashes_value(
    value: &JsonValue<'_>,
    artifact_path: &str,
    kind: IndependentCheckerReleaseBundleArtifactKind,
) -> Result<BTreeMap<String, Hash>, IndependentCheckerCommandError> {
    let hashes_path = format!("{artifact_path}.hashes");
    let members =
        independent_checker_release_validate_bundle_object_members(value, &hashes_path, "object")?;
    let required = kind.required_hash_fields();
    if required.is_empty() && !members.is_empty() {
        return Err(independent_checker_release_validate_bundle_value_error(
            "input_schema_invalid",
            &hashes_path,
            "empty_object",
            "non_empty",
        ));
    }
    let mut hashes = BTreeMap::new();
    for member in members {
        if hashes.contains_key(member.key()) {
            return Err(independent_checker_release_validate_bundle_value_error(
                "input_schema_invalid",
                format!("{hashes_path}.{}", member.key()),
                "unique_object_keys",
                "duplicate_field",
            ));
        }
        let Some(raw) = member.value().string_value() else {
            return Err(independent_checker_release_validate_bundle_value_error(
                "input_schema_invalid",
                format!("{hashes_path}.{}", member.key()),
                "sha256:<lower-hex>",
                if member.value().kind() == JsonValueKind::Null {
                    "null_not_allowed"
                } else {
                    "wrong_type"
                },
            ));
        };
        let hash = parse_hash_string(raw).map_err(|_| {
            independent_checker_release_validate_bundle_value_error(
                "input_schema_invalid",
                format!("{hashes_path}.{}", member.key()),
                "sha256:<lower-hex>",
                "invalid_hash_format",
            )
        })?;
        hashes.insert(member.key().to_owned(), hash);
    }
    for required_field in required {
        if !hashes.contains_key(*required_field) {
            return Err(independent_checker_release_validate_bundle_value_error(
                "input_schema_invalid",
                format!("{hashes_path}.{required_field}"),
                "sha256:<lower-hex>",
                "missing",
            ));
        }
    }
    for key in hashes.keys() {
        if !required.contains(&key.as_str()) {
            return Err(independent_checker_release_validate_bundle_value_error(
                "input_schema_invalid",
                format!("{hashes_path}.{key}"),
                format!("hash_field_for_kind:{}", kind.as_str()),
                "unknown_field",
            ));
        }
    }
    Ok(hashes)
}

fn independent_checker_validate_release_audit_bundle_manifest_identity(
    manifest: &IndependentCheckerReleaseAuditBundleManifest,
) -> Result<(), IndependentCheckerReleaseAuditBundleError> {
    let recomputed = manifest.hash_input_hash();
    if recomputed != manifest.bundle_hash {
        return Err(IndependentCheckerReleaseAuditBundleError::invalid_hash(
            "bundle_hash",
            recomputed,
            manifest.bundle_hash,
        ));
    }
    let expected_id = independent_checker_release_audit_bundle_id(manifest.bundle_hash);
    if manifest.bundle_id != expected_id {
        return Err(IndependentCheckerReleaseAuditBundleError::invalid_value(
            "bundle_id",
            expected_id,
            &manifest.bundle_id,
        ));
    }
    Ok(())
}

fn independent_checker_validate_release_audit_bundle_artifact_order(
    artifacts: &[IndependentCheckerReleaseAuditBundleArtifact],
) -> Result<(), IndependentCheckerReleaseAuditBundleError> {
    for index in 1..artifacts.len() {
        let left = (
            artifacts[index].kind.as_str(),
            artifacts[index].path.as_str(),
        );
        let right = (
            artifacts[index - 1].kind.as_str(),
            artifacts[index - 1].path.as_str(),
        );
        if left < right {
            return Err(IndependentCheckerReleaseAuditBundleError::invalid_value(
                format!("artifacts[{index}]"),
                "artifacts_sorted_by_kind_path",
                "order_violation",
            ));
        }
    }
    let mut kind_paths = BTreeSet::new();
    let mut paths = BTreeSet::new();
    for (index, artifact) in artifacts.iter().enumerate() {
        if !kind_paths.insert((artifact.kind, artifact.path.as_str())) {
            return Err(IndependentCheckerReleaseAuditBundleError::invalid_value(
                format!("artifacts[{index}]"),
                "unique_kind_path",
                "duplicate_entry",
            ));
        }
        if !paths.insert(artifact.path.as_str()) {
            return Err(IndependentCheckerReleaseAuditBundleError::invalid_value(
                format!("artifacts[{index}].path"),
                "unique_path",
                "duplicate_path",
            ));
        }
    }
    Ok(())
}

fn independent_checker_validate_release_audit_bundle_artifact_files(
    artifacts: &[IndependentCheckerReleaseAuditBundleArtifact],
    bundle_files: &BTreeMap<String, Vec<u8>>,
) -> Result<(), IndependentCheckerReleaseAuditBundleError> {
    for (index, artifact) in artifacts.iter().enumerate() {
        let expected_path =
            independent_checker_release_bundle_artifact_path(artifact.kind, artifact.file_hash);
        if artifact.path != expected_path {
            return Err(IndependentCheckerReleaseAuditBundleError::invalid_value(
                format!("artifacts[{index}].path"),
                expected_path,
                &artifact.path,
            ));
        }
        let Some(bytes) = bundle_files.get(&artifact.path) else {
            return Err(IndependentCheckerReleaseAuditBundleError::missing_value(
                format!("artifacts[{index}].path"),
                "readable_bundle_file",
                "missing",
            ));
        };
        let actual_file_hash = independent_checker_file_hash(bytes);
        if actual_file_hash != artifact.file_hash {
            return Err(IndependentCheckerReleaseAuditBundleError::invalid_hash(
                format!("artifacts[{index}].file_hash"),
                artifact.file_hash,
                actual_file_hash,
            ));
        }
        if artifact.kind.is_binary_certificate_artifact() {
            let actual_hashes = independent_checker_release_bundle_certificate_artifact_hashes(
                artifact.kind,
                bytes,
                index,
            )?;
            if actual_hashes != artifact.hashes {
                return Err(IndependentCheckerReleaseAuditBundleError::invalid_value(
                    format!("artifacts[{index}].hashes"),
                    independent_checker_hashes_canonical_json(&actual_hashes),
                    independent_checker_hashes_canonical_json(&artifact.hashes),
                ));
            }
            continue;
        }
        let source =
            independent_checker_release_bundle_utf8(bytes, format!("artifacts[{index}].path"))?;
        let actual_hashes =
            independent_checker_release_bundle_artifact_hashes(artifact.kind, source, index)?;
        if actual_hashes != artifact.hashes {
            return Err(IndependentCheckerReleaseAuditBundleError::invalid_value(
                format!("artifacts[{index}].hashes"),
                independent_checker_hashes_canonical_json(&actual_hashes),
                independent_checker_hashes_canonical_json(&artifact.hashes),
            ));
        }
    }
    Ok(())
}

fn independent_checker_release_bundle_certificate_artifact_hashes(
    kind: IndependentCheckerReleaseBundleArtifactKind,
    bytes: &[u8],
    index: usize,
) -> Result<BTreeMap<String, Hash>, IndependentCheckerReleaseAuditBundleError> {
    let facts = independent_checker_certificate_artifact_facts(bytes).map_err(|_| {
        IndependentCheckerReleaseAuditBundleError::invalid_value(
            format!("artifacts[{index}].path"),
            "canonical_npcert",
            "decode_failed",
        )
    })?;
    let mut hashes = BTreeMap::new();
    hashes.insert("certificate_hash".to_owned(), facts.certificate_hash);
    match kind {
        IndependentCheckerReleaseBundleArtifactKind::ProofCertificate => {
            hashes.insert(
                "statement_core_hash".to_owned(),
                independent_checker_single_theorem_statement_hash(
                    &facts,
                    format!("artifacts[{index}].hashes.statement_core_hash"),
                )?,
            );
        }
        IndependentCheckerReleaseBundleArtifactKind::ImportCertificate => {
            hashes.insert("export_hash".to_owned(), facts.export_hash);
        }
        _ => unreachable!("certificate hash extraction only called for certificate artifacts"),
    }
    Ok(hashes)
}

fn independent_checker_release_bundle_utf8(
    bytes: &[u8],
    field: impl Into<String>,
) -> Result<&str, IndependentCheckerReleaseAuditBundleError> {
    std::str::from_utf8(bytes).map_err(|_| {
        IndependentCheckerReleaseAuditBundleError::invalid_value(
            field,
            "valid_json",
            "invalid_json",
        )
    })
}

fn independent_checker_release_bundle_artifact_hashes(
    kind: IndependentCheckerReleaseBundleArtifactKind,
    source: &str,
    index: usize,
) -> Result<BTreeMap<String, Hash>, IndependentCheckerReleaseAuditBundleError> {
    let mut hashes = BTreeMap::new();
    match kind {
        IndependentCheckerReleaseBundleArtifactKind::ReleasePolicy => {
            let policy = parse_independent_checker_release_policy(source).map_err(|error| {
                independent_checker_release_bundle_policy_error(index, kind, error)
            })?;
            hashes.insert("policy_hash".to_owned(), policy.policy_hash());
        }
        IndependentCheckerReleaseBundleArtifactKind::RunnerPolicy => {
            let policy = parse_independent_checker_runner_policy(source).map_err(|error| {
                independent_checker_release_bundle_policy_error(index, kind, error)
            })?;
            hashes.insert("policy_hash".to_owned(), policy.policy_hash());
        }
        IndependentCheckerReleaseBundleArtifactKind::CheckerIdentityManifest => {
            parse_independent_checker_identity_manifest(source).map_err(|error| {
                independent_checker_release_bundle_policy_error(index, kind, error)
            })?;
            hashes.insert(
                "manifest_hash".to_owned(),
                independent_checker_file_hash(source.as_bytes()),
            );
        }
        IndependentCheckerReleaseBundleArtifactKind::ImportLock => {
            parse_independent_checker_import_lock_manifest(source).map_err(|error| {
                independent_checker_release_bundle_request_error(index, kind, error)
            })?;
            hashes.insert(
                "manifest_hash".to_owned(),
                independent_checker_file_hash(source.as_bytes()),
            );
        }
        IndependentCheckerReleaseBundleArtifactKind::ProofCertificate
        | IndependentCheckerReleaseBundleArtifactKind::ImportCertificate => {
            unreachable!("binary certificate artifacts are hashed before JSON dispatch")
        }
        IndependentCheckerReleaseBundleArtifactKind::MachineCheckRequest => {
            let request =
                parse_independent_checker_machine_check_request(source).map_err(|error| {
                    independent_checker_release_bundle_request_error(index, kind, error)
                })?;
            hashes.insert("request_hash".to_owned(), request.request_hash());
        }
        IndependentCheckerReleaseBundleArtifactKind::MachineCheckResult => {
            let summary = parse_independent_checker_machine_check_result_summary(source, "$")
                .map_err(|error| {
                    independent_checker_release_bundle_request_error(index, kind, error)
                })?;
            hashes.insert("result_hash".to_owned(), summary.result_hash);
            hashes.insert("run_artifact_hash".to_owned(), summary.run_artifact_hash);
        }
        IndependentCheckerReleaseBundleArtifactKind::NormalizedCheckResult => {
            let summary = parse_independent_checker_normalized_check_result_summary(source, "$")
                .map_err(|error| {
                    independent_checker_release_bundle_request_error(index, kind, error)
                })?;
            hashes.insert("artifact_hash".to_owned(), summary.artifact_hash);
            hashes.insert(
                "normalized_result_hash".to_owned(),
                summary.normalized_result_hash,
            );
        }
        IndependentCheckerReleaseBundleArtifactKind::RequestStoreManifest => {
            parse_independent_checker_request_store_manifest(source).map_err(|error| {
                independent_checker_release_bundle_request_error(index, kind, error)
            })?;
            hashes.insert(
                "manifest_hash".to_owned(),
                independent_checker_file_hash(source.as_bytes()),
            );
        }
        IndependentCheckerReleaseBundleArtifactKind::MachineResultStoreManifest => {
            parse_independent_checker_machine_result_store_manifest(source).map_err(|error| {
                independent_checker_release_bundle_request_error(index, kind, error)
            })?;
            hashes.insert(
                "manifest_hash".to_owned(),
                independent_checker_file_hash(source.as_bytes()),
            );
        }
        IndependentCheckerReleaseBundleArtifactKind::NormalizedResultStoreManifest => {
            parse_independent_checker_normalized_result_store_manifest(source).map_err(
                |error| independent_checker_release_bundle_request_error(index, kind, error),
            )?;
            hashes.insert(
                "manifest_hash".to_owned(),
                independent_checker_file_hash(source.as_bytes()),
            );
        }
        IndependentCheckerReleaseBundleArtifactKind::ChallengeManifest => {
            parse_independent_checker_challenge_manifest(source).map_err(|error| {
                independent_checker_release_bundle_request_error(index, kind, error)
            })?;
            hashes.insert(
                "manifest_hash".to_owned(),
                independent_checker_file_hash(source.as_bytes()),
            );
        }
        IndependentCheckerReleaseBundleArtifactKind::ChallengeOutputStoreManifest => {
            parse_independent_checker_challenge_output_store_manifest(source).map_err(|error| {
                independent_checker_release_bundle_request_error(index, kind, error)
            })?;
            hashes.insert(
                "manifest_hash".to_owned(),
                independent_checker_file_hash(source.as_bytes()),
            );
        }
        IndependentCheckerReleaseBundleArtifactKind::ChallengeReplayResult => {
            let result =
                parse_independent_checker_challenge_replay_result(source).map_err(|error| {
                    independent_checker_release_bundle_request_error(index, kind, error)
                })?;
            hashes.insert("result_hash".to_owned(), result.result_hash());
        }
        IndependentCheckerReleaseBundleArtifactKind::ChallengeCoverageSummary => {
            let summary =
                parse_independent_checker_challenge_coverage_summary(source).map_err(|error| {
                    independent_checker_release_bundle_request_error(index, kind, error)
                })?;
            hashes.insert("summary_hash".to_owned(), summary.summary_hash());
        }
        IndependentCheckerReleaseBundleArtifactKind::PerformanceBenchmarkSummary => {
            let summary = parse_independent_checker_performance_benchmark_summary(source).map_err(
                |error| independent_checker_release_bundle_request_error(index, kind, error),
            )?;
            hashes.insert("summary_hash".to_owned(), summary.summary_hash);
        }
        IndependentCheckerReleaseBundleArtifactKind::AuxiliaryResult => {
            let result = parse_independent_checker_auxiliary_result(source).map_err(|error| {
                independent_checker_release_bundle_request_error(index, kind, error)
            })?;
            hashes.insert("result_hash".to_owned(), result.result_hash());
        }
        IndependentCheckerReleaseBundleArtifactKind::AiAuditInputPolicy => {
            let policy =
                parse_independent_checker_ai_audit_input_policy(source).map_err(|error| {
                    independent_checker_release_bundle_audit_error(index, kind, error)
                })?;
            hashes.insert("input_policy_hash".to_owned(), policy.input_policy_hash());
        }
        IndependentCheckerReleaseBundleArtifactKind::AiAuditSidecar => {
            parse_independent_checker_ai_audit_sidecar(source).map_err(|error| {
                independent_checker_release_bundle_audit_error(index, kind, error)
            })?;
        }
        IndependentCheckerReleaseBundleArtifactKind::CompareValidationResponse => {
            independent_checker_release_bundle_schema_only_status(
                source,
                INDEPENDENT_CHECKER_COMPARE_VALIDATION_RESULT_SCHEMA,
                COMPARE_VALIDATION_RESULT_FIELDS,
                "valid",
                format!("artifacts[{index}].artifact"),
            )?;
        }
        IndependentCheckerReleaseBundleArtifactKind::AuditSidecarValidationResponse => {
            independent_checker_release_bundle_schema_only_status(
                source,
                INDEPENDENT_CHECKER_AUDIT_SIDECAR_VALIDATION_RESULT_SCHEMA,
                AUDIT_SIDECAR_VALIDATION_RESULT_FIELDS,
                "valid",
                format!("artifacts[{index}].artifact"),
            )?;
        }
    }
    Ok(hashes)
}

fn independent_checker_release_bundle_policy_error(
    index: usize,
    kind: IndependentCheckerReleaseBundleArtifactKind,
    error: IndependentCheckerPolicyValidationError,
) -> IndependentCheckerReleaseAuditBundleError {
    IndependentCheckerReleaseAuditBundleError {
        reason_code: IndependentCheckerAuxiliaryReasonCode::AuditBundleInvalid,
        field: independent_checker_release_audit_bundle_artifact_field(index, kind, &error.field)
            .into_boxed_str(),
        expected_hash: None,
        actual_hash: None,
        expected_value: Some(error.expected_value.into_boxed_str()),
        actual_value: Some(error.actual_value.into_boxed_str()),
    }
}

