fn independent_checker_release_stage_artifact_field(
    input_index: usize,
    kind: IndependentCheckerReleaseBundleArtifactKind,
    field: &str,
) -> String {
    let prefix = format!("inputs[{input_index}].artifact");
    for root in independent_checker_release_stage_artifact_virtual_roots(kind) {
        if field == *root || field == format!("{root}.$") {
            return prefix;
        }
        if let Some(suffix) = field
            .strip_prefix(*root)
            .and_then(|rest| rest.strip_prefix('.'))
        {
            return format!("{prefix}.{suffix}");
        }
    }
    independent_checker_prefixed_json_field(prefix, field)
}

fn independent_checker_release_stage_artifact_virtual_roots(
    kind: IndependentCheckerReleaseBundleArtifactKind,
) -> &'static [&'static str] {
    match kind {
        IndependentCheckerReleaseBundleArtifactKind::ReleasePolicy => &["release_policy"],
        IndependentCheckerReleaseBundleArtifactKind::AiAuditInputPolicy => &["input_policy"],
        IndependentCheckerReleaseBundleArtifactKind::CheckerIdentityManifest => {
            &["checker_identity_manifest"]
        }
        IndependentCheckerReleaseBundleArtifactKind::ImportLock => &["imports.manifest"],
        IndependentCheckerReleaseBundleArtifactKind::ChallengeManifest => &["challenge_manifest"],
        IndependentCheckerReleaseBundleArtifactKind::ChallengeOutputStoreManifest => {
            &["challenge_output_store"]
        }
        IndependentCheckerReleaseBundleArtifactKind::RequestStoreManifest => &["request_store"],
        IndependentCheckerReleaseBundleArtifactKind::MachineResultStoreManifest => {
            &["result_store"]
        }
        IndependentCheckerReleaseBundleArtifactKind::NormalizedResultStoreManifest => {
            &["normalized_store"]
        }
        _ => &[],
    }
}

fn independent_checker_prefixed_json_field(prefix: String, field: &str) -> String {
    if field == "$" {
        return prefix;
    }
    if field.starts_with('[') {
        format!("{prefix}{field}")
    } else {
        format!("{prefix}.{field}")
    }
}

fn parse_machine_check_request_policy(
    members: &[JsonMember<'_>],
) -> Result<IndependentCheckerMachineCheckRequestPolicy, IndependentCheckerRequestValidationError> {
    let value = required_field_value(members, "policy", "policy", "object")?;
    let policy_members = object_members_or_policy_error(value, "policy", "object")?;
    let id = required_string_field(policy_members, "id", "policy.id", "runner_policy_id")?;
    if !independent_checker_valid_runner_policy_id(&id) {
        return Err(IndependentCheckerRequestValidationError::value_failure(
            "policy.id",
            "runner_policy_id",
            "invalid_name_format",
        ));
    }
    let version_raw =
        required_integer_raw_field(policy_members, "version", "policy.version", "positive_i64")?;
    let version = parse_positive_i64_domain(&version_raw, "policy.version")?;
    let hash = required_hash_field(policy_members, "hash", "policy.hash", "sha256:<lower-hex>")?;
    reject_unknown_fields(
        policy_members,
        MACHINE_CHECK_REQUEST_POLICY_FIELDS,
        "policy",
    )?;
    Ok(IndependentCheckerMachineCheckRequestPolicy { id, version, hash })
}

