fn reject_unknown_fields(
    members: &[JsonMember<'_>],
    allowed: &[&str],
    container_path: &str,
) -> Result<(), IndependentCheckerPolicyValidationError> {
    let mut counts = BTreeMap::<String, usize>::new();
    for member in members {
        *counts.entry(member.key().to_owned()).or_default() += 1;
    }
    let mut unknown = counts
        .keys()
        .filter(|field| !allowed.contains(&field.as_str()))
        .map(String::as_str)
        .collect::<Vec<_>>();
    unknown.sort_by(|left, right| independent_checker_rfc8785_object_key_cmp(left, right));
    if let Some(field) = unknown.first() {
        let report_path = unknown_field_report_path(container_path, field);
        let actual = if counts.get(*field).copied().unwrap_or(0) > 1 {
            "duplicate_field"
        } else {
            "unknown_field"
        };
        let expected = if actual == "duplicate_field" {
            "unique_object_keys"
        } else {
            "absent"
        };
        return Err(IndependentCheckerPolicyValidationError::new(
            report_path,
            expected,
            actual,
        ));
    }
    Ok(())
}

fn wrong_type_error(
    field: &str,
    expected: &str,
    actual: JsonValueKind,
) -> IndependentCheckerPolicyValidationError {
    IndependentCheckerPolicyValidationError::new(
        field,
        expected,
        if actual == JsonValueKind::Null {
            "null_not_allowed"
        } else {
            "wrong_type"
        },
    )
}

fn duplicate_member(members: &[JsonMember<'_>], name: &str) -> bool {
    members
        .iter()
        .filter(|member| member.key() == name)
        .take(2)
        .count()
        > 1
}

fn parse_positive_i64_domain(
    raw: &str,
    field: &str,
) -> Result<u64, IndependentCheckerPolicyValidationError> {
    let value = raw.parse::<u64>().map_err(|_| {
        IndependentCheckerPolicyValidationError::new(field, "positive_i64", "integer_out_of_range")
    })?;
    if value == 0 {
        return Err(IndependentCheckerPolicyValidationError::new(
            field,
            "positive_i64",
            "non_positive_integer",
        ));
    }
    if value > i64::MAX as u64 {
        return Err(IndependentCheckerPolicyValidationError::new(
            field,
            "positive_i64",
            "integer_out_of_range",
        ));
    }
    Ok(value)
}

fn independent_checker_valid_runner_policy_id(value: &str) -> bool {
    independent_checker_valid_lower_profile_like(value, 64, false)
}

fn independent_checker_valid_checker_profile_name(value: &str) -> bool {
    independent_checker_valid_lower_profile_like(value, 64, false)
}

fn independent_checker_valid_lower_profile_like(
    value: &str,
    max_len: usize,
    allow_dot: bool,
) -> bool {
    let bytes = value.as_bytes();
    if bytes.is_empty() || bytes.len() > max_len || !bytes[0].is_ascii_lowercase() {
        return false;
    }
    bytes.iter().all(|byte| {
        byte.is_ascii_lowercase()
            || byte.is_ascii_digit()
            || *byte == b'-'
            || (allow_dot && *byte == b'.')
            || (allow_dot && *byte == b'_')
    })
}

fn independent_checker_valid_checker_id(value: &str) -> bool {
    let bytes = value.as_bytes();
    if bytes.is_empty() || bytes.len() > 128 || !bytes[0].is_ascii_lowercase() {
        return false;
    }
    bytes.iter().all(|byte| {
        byte.is_ascii_lowercase() || byte.is_ascii_digit() || matches!(*byte, b'.' | b'_' | b'-')
    })
}

fn independent_checker_valid_checker_reason_code(value: &str) -> bool {
    independent_checker_valid_checker_id(value)
}

fn independent_checker_visible_ascii_nonempty(value: &str) -> bool {
    !value.is_empty() && value.bytes().all(|byte| (0x21..=0x7e).contains(&byte))
}

fn independent_checker_valid_lower_hex_bytes(value: &str) -> bool {
    value.len().is_multiple_of(2)
        && value
            .bytes()
            .all(|byte| byte.is_ascii_digit() || (b'a'..=b'f').contains(&byte))
}

fn independent_checker_printable_ascii_nonempty(value: &str) -> bool {
    !value.is_empty() && value.bytes().all(|byte| (0x20..=0x7e).contains(&byte))
}

fn independent_checker_valid_request_id(value: &str) -> bool {
    independent_checker_visible_ascii_nonempty(value)
}

fn independent_checker_valid_challenge_id(value: &str) -> bool {
    let bytes = value.as_bytes();
    if bytes.is_empty() || bytes.len() > 128 || !bytes[0].is_ascii_lowercase() {
        return false;
    }
    bytes
        .iter()
        .all(|byte| byte.is_ascii_lowercase() || byte.is_ascii_digit() || *byte == b'_')
}

fn independent_checker_valid_challenge_coverage_summary_id(value: &str) -> bool {
    let Some(hex) = value.strip_prefix("chcov_") else {
        return false;
    };
    hex.len() == 64
        && hex
            .bytes()
            .all(|byte| byte.is_ascii_digit() || (b'a'..=b'f').contains(&byte))
}

fn independent_checker_valid_performance_benchmark_summary_id(value: &str) -> bool {
    let Some(hex) = value.strip_prefix("bench_") else {
        return false;
    };
    hex.len() == 64
        && hex
            .bytes()
            .all(|byte| byte.is_ascii_digit() || (b'a'..=b'f').contains(&byte))
}

fn independent_checker_valid_informational_challenge_kind(value: &str) -> bool {
    let bytes = value.as_bytes();
    if bytes.is_empty() || bytes.len() > 64 || !bytes[0].is_ascii_lowercase() {
        return false;
    }
    bytes
        .iter()
        .all(|byte| byte.is_ascii_lowercase() || byte.is_ascii_digit() || *byte == b'_')
}

fn independent_checker_valid_informational_challenge_target(value: &str) -> bool {
    !value.is_empty()
        && value.len() <= 255
        && value.bytes().all(|byte| (0x21..=0x7e).contains(&byte))
}

fn validate_challenge_mutation_target(
    target: &str,
    known_kind: Option<IndependentCheckerChallengeMutationKind>,
    allow_informational: bool,
) -> Result<(), &'static str> {
    match known_kind {
        Some(kind) if kind.requires_whole_certificate_target() => {
            if target == "$whole_certificate" {
                Ok(())
            } else {
                Err("invalid_enum")
            }
        }
        Some(_) => {
            if independent_checker_valid_dotted_name(target) {
                Ok(())
            } else {
                Err("invalid_name_format")
            }
        }
        None if allow_informational => {
            if independent_checker_valid_informational_challenge_target(target) {
                Ok(())
            } else {
                Err("invalid_name_format")
            }
        }
        None => Err("invalid_enum"),
    }
}

fn independent_checker_valid_dotted_name(value: &str) -> bool {
    parse_module_name_wire(value).is_ok()
}

fn independent_checker_dotted_name_cmp(left: &str, right: &str) -> Ordering {
    independent_checker_dotted_name_sort_key(left)
        .cmp(&independent_checker_dotted_name_sort_key(right))
}

fn independent_checker_dotted_name_sort_key(value: &str) -> Vec<u8> {
    parse_module_name_wire(value)
        .and_then(|name| machine_api_name_canonical_bytes(&name))
        .unwrap_or_else(|_| value.as_bytes().to_vec())
}

fn independent_checker_valid_workspace_relative_path(value: &str) -> bool {
    if value.is_empty()
        || value.starts_with('/')
        || value.contains('\\')
        || value.contains(':')
        || value.contains("://")
        || value.bytes().any(|byte| byte <= 0x20 || byte == 0x7f)
    {
        return false;
    }
    value
        .split('/')
        .all(|segment| !segment.is_empty() && segment != "." && segment != "..")
}

fn last_json_path_component(path: &str) -> &str {
    path.rsplit('.').next().unwrap_or(path)
}

fn independent_checker_join_json_path(root_path: &str, field: &str) -> String {
    if root_path == "$" {
        field.to_owned()
    } else {
        format!("{root_path}.{field}")
    }
}

fn format_budget_key_path(profile: &str) -> String {
    if independent_checker_budget_key_path_component(profile) {
        format!("budgets.{profile}")
    } else {
        "budgets".to_owned()
    }
}

fn independent_checker_budget_key_path_component(value: &str) -> bool {
    !value.is_empty()
        && value.len() <= 64
        && value
            .bytes()
            .all(|byte| byte.is_ascii_alphanumeric() || matches!(byte, b'_' | b'-'))
}

fn unknown_field_report_path(container: &str, field: &str) -> String {
    if independent_checker_budget_key_path_component(field) {
        if container == "$" {
            field.to_owned()
        } else {
            format!("{container}.{field}")
        }
    } else {
        container.to_owned()
    }
}

fn independent_checker_hash_json_literal(hash: &Hash) -> String {
    independent_checker_json_string_literal(&format_hash_string(hash))
}

fn canonical_json_array(values: Vec<String>) -> String {
    let mut out = String::new();
    out.push('[');
    for (index, value) in values.iter().enumerate() {
        if index > 0 {
            out.push(',');
        }
        out.push_str(value);
    }
    out.push(']');
    out
}

fn independent_checker_encode_uvar(mut value: u64) -> Vec<u8> {
    let mut out = Vec::new();
    loop {
        let mut byte = (value & 0x7f) as u8;
        value >>= 7;
        if value != 0 {
            byte |= 0x80;
        }
        out.push(byte);
        if value == 0 {
            break;
        }
    }
    out
}

pub fn independent_checker_canonical_json_string(
    source: &str,
) -> Result<String, IndependentCheckerCanonicalJsonError> {
    let bytes = independent_checker_canonical_json_bytes(source)?;
    Ok(String::from_utf8(bytes).expect("canonical JSON is UTF-8"))
}

pub fn independent_checker_canonical_json_bytes(
    source: &str,
) -> Result<Vec<u8>, IndependentCheckerCanonicalJsonError> {
    let document = JsonDocument::parse(source).map_err(|err| {
        IndependentCheckerCanonicalJsonError::JsonParse {
            offset: err.offset,
            kind: err.kind,
        }
    })?;
    independent_checker_canonical_json_value_bytes(document.root())
}

pub fn independent_checker_canonical_json_value_bytes(
    value: &JsonValue<'_>,
) -> Result<Vec<u8>, IndependentCheckerCanonicalJsonError> {
    let mut out = Vec::new();
    let root = IndependentCheckerJsonPath::root();
    write_independent_checker_canonical_json_value(value, &root, &mut out)?;
    Ok(out)
}

pub fn independent_checker_canonical_json_object_excluding_top_level_fields(
    source: &str,
    excluded_fields: &[&str],
) -> Result<Vec<u8>, IndependentCheckerCanonicalJsonError> {
    let document = JsonDocument::parse(source).map_err(|err| {
        IndependentCheckerCanonicalJsonError::JsonParse {
            offset: err.offset,
            kind: err.kind,
        }
    })?;
    let root = IndependentCheckerJsonPath::root();
    let Some(members) = document.root().object_members() else {
        return Err(IndependentCheckerCanonicalJsonError::ExpectedObject {
            path: root,
            actual: document.root().kind(),
        });
    };
    let excluded = excluded_fields.iter().copied().collect::<BTreeSet<_>>();
    let mut out = Vec::new();
    write_independent_checker_canonical_json_object_members(
        members,
        &root,
        &mut out,
        Some(&excluded),
    )?;
    Ok(out)
}

pub fn independent_checker_hash_json_object_excluding_top_level_fields(
    source: &str,
    excluded_fields: &[&str],
) -> Result<Hash, IndependentCheckerCanonicalJsonError> {
    let canonical = independent_checker_canonical_json_object_excluding_top_level_fields(
        source,
        excluded_fields,
    )?;
    Ok(independent_checker_sha256(&canonical))
}

pub fn independent_checker_json_artifact_hash_from_source(
    source: &str,
) -> Result<Hash, IndependentCheckerCanonicalJsonError> {
    let canonical = independent_checker_canonical_json_bytes(source)?;
    Ok(independent_checker_sha256(&canonical))
}

pub fn independent_checker_file_hash(bytes: &[u8]) -> Hash {
    independent_checker_sha256(bytes)
}

pub fn independent_checker_sha256(bytes: &[u8]) -> Hash {
    let digest = Sha256::digest(bytes);
    let mut hash = [0u8; 32];
    hash.copy_from_slice(&digest);
    hash
}

pub fn independent_checker_rfc8785_object_key_cmp(left: &str, right: &str) -> Ordering {
    let mut left_units = left.encode_utf16();
    let mut right_units = right.encode_utf16();
    loop {
        match (left_units.next(), right_units.next()) {
            (Some(left), Some(right)) => match left.cmp(&right) {
                Ordering::Equal => {}
                ordering => return ordering,
            },
            (Some(_), None) => return Ordering::Greater,
            (None, Some(_)) => return Ordering::Less,
            (None, None) => return Ordering::Equal,
        }
    }
}

pub fn independent_checker_forbids_verification_input_field(field: &str) -> bool {
    INDEPENDENT_CHECKER_FORBIDDEN_VERIFICATION_INPUT_FIELDS.contains(&field)
}

pub fn independent_checker_first_forbidden_verification_input_field<'value, 'src>(
    value: &'value JsonValue<'src>,
) -> Option<&'value str> {
    let members = value.object_members()?;
    let mut fields = members
        .iter()
        .map(crate::json::JsonMember::key)
        .filter(|field| independent_checker_forbids_verification_input_field(field))
        .collect::<Vec<_>>();
    fields.sort_by(|left, right| independent_checker_rfc8785_object_key_cmp(left, right));
    fields.first().copied()
}

pub fn validate_independent_checker_closed_object<'value, 'src>(
    value: &'value JsonValue<'src>,
    schema: IndependentCheckerClosedSchema<'_>,
    path: &IndependentCheckerJsonPath,
) -> Result<IndependentCheckerValidatedObject<'value, 'src>, IndependentCheckerSchemaError> {
    let Some(members) = value.object_members() else {
        return Err(IndependentCheckerSchemaError {
            path: path.clone(),
            reason: IndependentCheckerSchemaErrorReason::ExpectedObject {
                actual: value.kind(),
            },
        });
    };

    let mut counts = BTreeMap::<String, usize>::new();
    for member in members {
        *counts.entry(member.key().to_owned()).or_insert(0) += 1;
    }

    for field in schema.fields {
        if counts.get(field.name).copied().unwrap_or(0) > 1 {
            return Err(IndependentCheckerSchemaError {
                path: path.field(field.name),
                reason: IndependentCheckerSchemaErrorReason::DuplicateField {
                    field: field.name.to_owned(),
                },
            });
        }
    }

    let mut duplicate_unknowns = counts
        .iter()
        .filter(|(field, count)| {
            **count > 1 && !schema.fields.iter().any(|spec| spec.name == field.as_str())
        })
        .map(|(field, _)| field.as_str())
        .collect::<Vec<_>>();
    duplicate_unknowns
        .sort_by(|left, right| independent_checker_rfc8785_object_key_cmp(left, right));
    if let Some(field) = duplicate_unknowns.first() {
        return Err(IndependentCheckerSchemaError {
            path: path.clone(),
            reason: IndependentCheckerSchemaErrorReason::DuplicateField {
                field: (*field).to_owned(),
            },
        });
    }

    let mut unknowns = counts
        .keys()
        .filter(|field| !schema.fields.iter().any(|spec| spec.name == field.as_str()))
        .map(String::as_str)
        .collect::<Vec<_>>();
    unknowns.sort_by(|left, right| independent_checker_rfc8785_object_key_cmp(left, right));
    if let Some(field) = unknowns.first() {
        return Err(IndependentCheckerSchemaError {
            path: path.clone(),
            reason: IndependentCheckerSchemaErrorReason::UnknownField {
                field: (*field).to_owned(),
            },
        });
    }

    for field in schema.fields {
        if field.required && !members.iter().any(|member| member.key() == field.name) {
            return Err(IndependentCheckerSchemaError {
                path: path.field(field.name),
                reason: IndependentCheckerSchemaErrorReason::MissingField { field: field.name },
            });
        }
    }

    for field in schema.fields {
        let Some(member) = members.iter().find(|member| member.key() == field.name) else {
            continue;
        };
        validate_independent_checker_field(field, member.value(), &path.field(field.name))?;
    }

    Ok(IndependentCheckerValidatedObject { members })
}

fn write_independent_checker_canonical_json_value(
    value: &JsonValue<'_>,
    path: &IndependentCheckerJsonPath,
    out: &mut Vec<u8>,
) -> Result<(), IndependentCheckerCanonicalJsonError> {
    match value.kind() {
        JsonValueKind::Null => out.extend_from_slice(b"null"),
        JsonValueKind::Bool => {
            if value.bool_value() == Some(true) {
                out.extend_from_slice(b"true");
            } else {
                out.extend_from_slice(b"false");
            }
        }
        JsonValueKind::Number => {
            let raw = value.number_raw().expect("number kind has raw number");
            validate_independent_checker_canonical_integer(raw, path)?;
            out.extend_from_slice(raw.as_bytes());
        }
        JsonValueKind::String => {
            let value = value.string_value().expect("string kind has string value");
            out.extend_from_slice(independent_checker_json_string_literal(value).as_bytes());
        }
        JsonValueKind::Array => {
            out.push(b'[');
            let elements = value.array_elements().expect("array kind has array values");
            for (index, element) in elements.iter().enumerate() {
                if index > 0 {
                    out.push(b',');
                }
                write_independent_checker_canonical_json_value(element, &path.index(index), out)?;
            }
            out.push(b']');
        }
        JsonValueKind::Object => {
            let members = value.object_members().expect("object kind has members");
            write_independent_checker_canonical_json_object_members(members, path, out, None)?;
        }
    }
    Ok(())
}

fn write_independent_checker_canonical_json_object_members(
    members: &[crate::json::JsonMember<'_>],
    path: &IndependentCheckerJsonPath,
    out: &mut Vec<u8>,
    excluded_top_level: Option<&BTreeSet<&str>>,
) -> Result<(), IndependentCheckerCanonicalJsonError> {
    let mut seen = BTreeSet::new();
    for member in members {
        if !seen.insert(member.key()) {
            return Err(IndependentCheckerCanonicalJsonError::DuplicateObjectKey {
                path: path.field(member.key()),
                key: member.key().to_owned(),
            });
        }
    }

    let mut entries = Vec::new();
    for member in members {
        if excluded_top_level
            .map(|excluded| excluded.contains(member.key()))
            .unwrap_or(false)
        {
            continue;
        }
        entries.push((member.key(), member.value()));
    }
    entries
        .sort_by(|(left, _), (right, _)| independent_checker_rfc8785_object_key_cmp(left, right));

    out.push(b'{');
    for (index, (key, value)) in entries.iter().enumerate() {
        if index > 0 {
            out.push(b',');
        }
        out.extend_from_slice(independent_checker_json_string_literal(key).as_bytes());
        out.push(b':');
        write_independent_checker_canonical_json_value(value, &path.field(*key), out)?;
    }
    out.push(b'}');
    Ok(())
}

fn validate_independent_checker_canonical_integer(
    raw: &str,
    path: &IndependentCheckerJsonPath,
) -> Result<(), IndependentCheckerCanonicalJsonError> {
    if raw.contains('.') || raw.contains('e') || raw.contains('E') {
        return Err(IndependentCheckerCanonicalJsonError::FloatNumber {
            path: path.clone(),
            raw: raw.to_owned(),
        });
    }
    if raw == "-0" {
        return Err(IndependentCheckerCanonicalJsonError::NegativeZeroInteger {
            path: path.clone(),
        });
    }
    let digits = raw.strip_prefix('-').unwrap_or(raw);
    if digits.is_empty()
        || (digits.len() > 1 && digits.starts_with('0'))
        || !digits.bytes().all(|byte| byte.is_ascii_digit())
    {
        return Err(IndependentCheckerCanonicalJsonError::InvalidInteger {
            path: path.clone(),
            raw: raw.to_owned(),
        });
    }
    Ok(())
}

fn validate_independent_checker_field(
    field: &IndependentCheckerFieldSpec,
    value: &JsonValue<'_>,
    path: &IndependentCheckerJsonPath,
) -> Result<(), IndependentCheckerSchemaError> {
    if value.kind() == JsonValueKind::Null {
        if field.allow_null {
            return Ok(());
        }
        return Err(IndependentCheckerSchemaError {
            path: path.clone(),
            reason: IndependentCheckerSchemaErrorReason::NullNotAllowed { field: field.name },
        });
    }

    match field.field_type {
        IndependentCheckerJsonFieldType::Object if value.kind() == JsonValueKind::Object => Ok(()),
        IndependentCheckerJsonFieldType::Array if value.kind() == JsonValueKind::Array => Ok(()),
        IndependentCheckerJsonFieldType::String if value.kind() == JsonValueKind::String => Ok(()),
        IndependentCheckerJsonFieldType::Boolean if value.kind() == JsonValueKind::Bool => Ok(()),
        IndependentCheckerJsonFieldType::Integer => {
            let Some(raw) = value.number_raw() else {
                return Err(independent_checker_wrong_type(field, value, path));
            };
            validate_independent_checker_schema_integer(raw).map_err(|()| {
                IndependentCheckerSchemaError {
                    path: path.clone(),
                    reason: IndependentCheckerSchemaErrorReason::InvalidInteger {
                        field: field.name,
                        raw: raw.to_owned(),
                    },
                }
            })
        }
        IndependentCheckerJsonFieldType::HashString => {
            let Some(raw) = value.string_value() else {
                return Err(independent_checker_wrong_type(field, value, path));
            };
            parse_hash_string(raw)
                .map(|_| ())
                .map_err(|_| IndependentCheckerSchemaError {
                    path: path.clone(),
                    reason: IndependentCheckerSchemaErrorReason::InvalidHashFormat {
                        field: field.name,
                    },
                })
        }
        _ => Err(independent_checker_wrong_type(field, value, path)),
    }
}

fn validate_independent_checker_schema_integer(raw: &str) -> Result<(), ()> {
    if raw.contains('.') || raw.contains('e') || raw.contains('E') || raw == "-0" {
        return Err(());
    }
    let digits = raw.strip_prefix('-').unwrap_or(raw);
    if digits.is_empty()
        || (digits.len() > 1 && digits.starts_with('0'))
        || !digits.bytes().all(|byte| byte.is_ascii_digit())
    {
        return Err(());
    }
    Ok(())
}

fn independent_checker_wrong_type(
    field: &IndependentCheckerFieldSpec,
    value: &JsonValue<'_>,
    path: &IndependentCheckerJsonPath,
) -> IndependentCheckerSchemaError {
    IndependentCheckerSchemaError {
        path: path.clone(),
        reason: IndependentCheckerSchemaErrorReason::WrongType {
            field: field.name,
            expected: field.field_type,
            actual: value.kind(),
        },
    }
}

fn independent_checker_json_string_literal(value: &str) -> String {
    let mut out = String::new();
    out.push('"');
    for ch in value.chars() {
        match ch {
            '"' => out.push_str("\\\""),
            '\\' => out.push_str("\\\\"),
            '\u{0008}' => out.push_str("\\b"),
            '\t' => out.push_str("\\t"),
            '\n' => out.push_str("\\n"),
            '\u{000c}' => out.push_str("\\f"),
            '\r' => out.push_str("\\r"),
            '\u{0000}'..='\u{001f}' => {
                out.push_str("\\u00");
                out.push(hex_digit((ch as u8) >> 4));
                out.push(hex_digit((ch as u8) & 0x0f));
            }
            _ => out.push(ch),
        }
    }
    out.push('"');
    out
}

fn independent_checker_hex_bytes(bytes: &[u8]) -> String {
    let mut out = String::with_capacity(bytes.len() * 2);
    for byte in bytes {
        out.push(hex_digit(byte >> 4));
        out.push(hex_digit(byte & 0x0f));
    }
    out
}

fn independent_checker_json_string_array(values: &[String]) -> String {
    let mut out = String::new();
    out.push('[');
    for (index, value) in values.iter().enumerate() {
        if index > 0 {
            out.push(',');
        }
        out.push_str(&independent_checker_json_string_literal(value));
    }
    out.push(']');
    out
}

fn canonical_json_object_from_pairs(mut pairs: Vec<(String, String)>) -> String {
    pairs.sort_by(|(left, _), (right, _)| independent_checker_rfc8785_object_key_cmp(left, right));
    let mut out = String::new();
    out.push('{');
    for (index, (key, value)) in pairs.iter().enumerate() {
        if index > 0 {
            out.push(',');
        }
        out.push_str(&independent_checker_json_string_literal(key));
        out.push(':');
        out.push_str(value);
    }
    out.push('}');
    out
}

fn push_optional_string_pair(pairs: &mut Vec<(String, String)>, key: &str, value: Option<&str>) {
    if let Some(value) = value {
        pairs.push((
            key.to_owned(),
            independent_checker_json_string_literal(value),
        ));
    }
}

fn push_optional_hash_pair(pairs: &mut Vec<(String, String)>, key: &str, value: Option<Hash>) {
    if let Some(value) = value {
        pairs.push((
            key.to_owned(),
            independent_checker_json_string_literal(&format_hash_string(&value)),
        ));
    }
}

fn hex_digit(value: u8) -> char {
    match value {
        0..=9 => char::from(b'0' + value),
        10..=15 => char::from(b'a' + (value - 10)),
        _ => unreachable!("hex digit out of range"),
    }
}

