    #[test]
    fn m3_machine_result_store_uses_run_artifact_hash_not_result_hash() {
        let (request, policy) = m3_request_and_policy();
        let first = independent_checker_machine_check_run(
            &request,
            &policy,
            IndependentCheckerRunObservation {
                result_id: "mchkres_001".to_owned(),
                attempt: 1,
                runner: m3_runner(),
                process: IndependentCheckerMachineCheckProcess::exited(0),
                resource_usage: m3_resource_usage(100),
                stdout: m3_raw_checked("0.8.0").into_bytes(),
                stderr: Vec::new(),
            },
        )
        .unwrap();
        let second = independent_checker_machine_check_run(
            &request,
            &policy,
            IndependentCheckerRunObservation {
                result_id: "mchkres_002".to_owned(),
                attempt: 2,
                runner: m3_runner(),
                process: IndependentCheckerMachineCheckProcess::exited(0),
                resource_usage: m3_resource_usage(101),
                stdout: m3_raw_checked("0.8.0").into_bytes(),
                stderr: Vec::new(),
            },
        )
        .unwrap();
        assert_eq!(first.result_hash(), second.result_hash());
        assert_ne!(first.run_artifact_hash(), second.run_artifact_hash());

        let first_entry = independent_checker_machine_result_store_entry_for_result(
            &first,
            "build/results/first.json",
        )
        .unwrap();
        let second_entry = independent_checker_machine_result_store_entry_for_result(
            &second,
            "build/results/second.json",
        )
        .unwrap();
        let update =
            independent_checker_machine_result_store_with_entry(None, first_entry.clone()).unwrap();
        let update = independent_checker_machine_result_store_with_entry(
            Some(&update.manifest),
            second_entry,
        )
        .unwrap();
        assert_eq!(update.manifest.results.len(), 2);
        assert_eq!(
            parse_independent_checker_machine_result_store_manifest(
                &update.manifest.canonical_json()
            )
            .unwrap(),
            update.manifest
        );

        let mut conflicting_entry = first_entry;
        conflicting_entry.file_hash = test_hash(200);
        let conflict = independent_checker_machine_result_store_with_entry(
            Some(&update.manifest),
            conflicting_entry,
        )
        .unwrap_err();
        assert_eq!(conflict.reason_code.as_ref(), "result_store_entry_conflict");
    }

    #[test]
    fn m3_axiom_report_and_store_hashes_are_deterministic() {
        let report = IndependentCheckerAxiomReport {
            module: "Std.Nat".to_owned(),
            certificate_hash: test_hash(70),
            axioms: vec![
                IndependentCheckerAxiomReportEntry {
                    name: "Aaa.choice".to_owned(),
                },
                IndependentCheckerAxiomReportEntry {
                    name: "Bbb.propExt".to_owned(),
                },
            ],
        };
        let parsed = parse_independent_checker_axiom_report(&report.canonical_json()).unwrap();
        assert_eq!(parsed, report);

        let bad_order = report
            .canonical_json()
            .replace("Aaa.choice", "Zzz.choice")
            .replace("Bbb.propExt", "Aaa.propExt");
        let bad_order = parse_independent_checker_axiom_report(&bad_order).unwrap_err();
        assert_eq!(bad_order.field.as_ref(), "axioms[1]");
        assert_eq!(bad_order.actual_value.as_deref(), Some("order_violation"));

        let entry = IndependentCheckerAxiomReportStoreEntry {
            axiom_report_hash: report.axiom_report_hash(),
            path: "build/axiom-reports/Std.Nat.json".to_owned(),
            file_hash: independent_checker_file_hash(report.canonical_json().as_bytes()),
        };
        let store = IndependentCheckerAxiomReportStoreManifest {
            reports: vec![entry],
        };
        assert_eq!(
            parse_independent_checker_axiom_report_store_manifest(&store.canonical_json()).unwrap(),
            store
        );
    }

