    #[test]
    fn m4_normalized_store_and_write_result_are_deterministic() {
        let (request, policy) = m3_request_and_policy();
        let stored = IndependentCheckerStoredMachineCheckRequest {
            path: "build/check-requests/Std.Nat.reference.json".to_owned(),
            file_hash: independent_checker_file_hash(request.canonical_json().as_bytes()),
            request: request.clone(),
        };
        let request_store = m4_request_store_manifest(std::slice::from_ref(&stored));
        let result = m4_checked_result(&request, &policy, "mchkres_001");
        let normalized = independent_checker_normalize_results(
            "norm_Std.Nat_001",
            "normerr_Std.Nat_001",
            &policy,
            &request_store,
            std::slice::from_ref(&stored),
            std::slice::from_ref(&result),
            None,
        )
        .unwrap();
        let entry = independent_checker_normalized_result_store_entry_for_result(
            &normalized,
            "build/normalized/Std.Nat.json",
        )
        .unwrap();
        let update =
            independent_checker_normalized_result_store_with_entry(None, entry.clone()).unwrap();
        assert_eq!(
            parse_independent_checker_normalized_result_store_manifest(
                &update.manifest.canonical_json()
            )
            .unwrap(),
            update.manifest
        );
        let retry = independent_checker_normalized_result_store_with_entry(
            Some(&update.manifest),
            entry.clone(),
        )
        .unwrap();
        assert!(!retry.rewrite_required);

        let write = independent_checker_normalization_write_result(
            &normalized,
            entry.path.clone(),
            Some(IndependentCheckerNormalizationWriteStore {
                path: "build/normalized/manifest.json".to_owned(),
                manifest_hash: update.manifest.file_hash(),
            }),
        )
        .unwrap();
        let json = write.canonical_json();
        assert!(json.contains(INDEPENDENT_CHECKER_NORMALIZATION_WRITE_RESULT_SCHEMA));
        assert!(!json.contains("\"result_hash\":"));
        assert!(json.contains("\"status\":\"written\""));

        let invalid_store = independent_checker_normalization_write_result(
            &normalized,
            entry.path,
            Some(IndependentCheckerNormalizationWriteStore {
                path: "/tmp/normalized-store.json".to_owned(),
                manifest_hash: update.manifest.file_hash(),
            }),
        )
        .unwrap_err();
        assert_eq!(
            invalid_store.command,
            IndependentCheckerCommandName::NormalizeResults
        );
        assert_eq!(
            invalid_store.field.as_deref(),
            Some("normalized_store.path")
        );
        assert_eq!(invalid_store.actual_value.as_deref(), Some("invalid_path"));
    }

    #[test]
    fn m4_store_references_are_closed_manifest_references() {
        let request_reference = parse_independent_checker_request_store_reference(&format!(
            r#"{{
              "kind":"manifest",
              "path":"build/check-requests/manifest.json",
              "manifest_hash":"{}"
            }}"#,
            hash_wire(44)
        ))
        .unwrap();
        assert_eq!(request_reference.path, "build/check-requests/manifest.json");
        assert!(request_reference
            .canonical_json()
            .contains("\"kind\":\"manifest\""));

        let result_reference = parse_independent_checker_machine_result_store_reference(&format!(
            r#"{{
              "kind":"manifest",
              "path":"build/check-results/manifest.json",
              "manifest_hash":"{}"
            }}"#,
            hash_wire(45)
        ))
        .unwrap();
        assert_eq!(result_reference.path, "build/check-results/manifest.json");

        let invalid = parse_independent_checker_request_store_reference(&format!(
            r#"{{
              "kind":"manifest",
              "path":"/tmp/manifest.json",
              "manifest_hash":"{}"
            }}"#,
            hash_wire(46)
        ))
        .unwrap_err();
        assert_eq!(invalid.field.as_ref(), "request_store.path");
        assert_eq!(invalid.actual_value.as_deref(), Some("invalid_path"));
    }

