    fn m5_failed_result(
        request: &IndependentCheckerMachineCheckRequest,
        policy: &IndependentCheckerRunnerPolicy,
        result_id: &str,
        declaration: &str,
    ) -> IndependentCheckerMachineCheckResult {
        let checker = policy
            .selected_checker_policy(&request.checker_profile)
            .unwrap();
        let raw = format!(
            r#"{{
              "schema":"npa.independent-checker.checker_raw_result.v1",
              "checker_id":"{}",
              "checker_version":"0.8.0",
              "checker_build_hash":"{}",
              "status":"failed",
              "module":"Std.Nat",
              "certificate_hash":"{}",
              "error":{{
                "kind":"type_mismatch",
                "declaration":"{}"
              }}
            }}"#,
            checker.checker_id,
            format_hash_string(&checker.build_hash),
            hash_wire(70),
            declaration
        );
        independent_checker_machine_check_run(
            request,
            policy,
            IndependentCheckerRunObservation {
                result_id: result_id.to_owned(),
                attempt: 1,
                runner: m3_runner(),
                process: IndependentCheckerMachineCheckProcess::exited(1),
                resource_usage: m3_resource_usage(100),
                stdout: raw.into_bytes(),
                stderr: Vec::new(),
            },
        )
        .unwrap()
    }

