    #[test]
    fn independent_checker_disagreement_record_from_normalized_report_is_deterministic() {
        let policy = parse_independent_checker_runner_policy(&m4_runner_policy_json()).unwrap();
        let fast = m4_stored_request(&policy, "fast-kernel", "mchkreq_pua_report_fast");
        let reference = m4_stored_request(&policy, "reference", "mchkreq_pua_report_ref");
        let external = m4_stored_request(&policy, "external", "mchkreq_pua_report_ext");
        let stored_requests = vec![fast.clone(), reference.clone(), external.clone()];
        let request_store = m4_request_store_manifest(&stored_requests);
        let fast_result = m4_checked_result(&fast.request, &policy, "mchkres_pua_report_fast");
        let reference_result = m5_failed_result(
            &reference.request,
            &policy,
            "mchkres_pua_report_ref",
            "Std.Nat.add_zero",
        );
        let external_result =
            m4_checked_result(&external.request, &policy, "mchkres_pua_report_ext");
        let normalized = independent_checker_normalize_results(
            "norm_Std.Nat_pua_report",
            "normerr_Std.Nat_pua_report",
            &policy,
            &request_store,
            &stored_requests,
            &[fast_result, reference_result, external_result],
            None,
        )
        .unwrap();

        let candidate_identity_hash = test_hash(201);
        let record = checker_disagreement_record_from_normalized_result(
            candidate_identity_hash,
            &normalized,
        )
        .unwrap();
        let again = checker_disagreement_record_from_normalized_result(
            candidate_identity_hash,
            &normalized,
        )
        .unwrap();

        assert_eq!(record, again);
        assert_eq!(record.canonical_json(), again.canonical_json());
        assert_eq!(
            record.checker_disagreement_record_hash(),
            independent_checker_sha256(record.hash_input_canonical_json().as_bytes())
        );
        assert_eq!(record.candidate_identity_hash, candidate_identity_hash);
        assert_eq!(record.certificate_hash, test_hash(70));
        assert_eq!(record.policy_hash, normalized.policy.hash);
        assert_eq!(
            record.normalized_result_hash,
            normalized.normalized_result_hash()
        );
        assert_eq!(
            record.comparison_status,
            IndependentCheckerNormalizedComparisonStatus::Disagreement
        );
        assert!(record.cache_invalidation_advisory);
        assert!(record.rerun_required_for_acceptance);

        assert_eq!(record.import_hashes.len(), 1);
        assert_eq!(
            record.import_hashes[0].kind,
            CheckerDisagreementImportHashKind::ImportLock
        );
        assert_eq!(
            record.import_hashes[0].hash,
            normalized.artifact.import_lock_hash
        );

        assert_eq!(
            record
                .checker_identities
                .iter()
                .map(|identity| identity.checker_profile.as_str())
                .collect::<Vec<_>>(),
            vec!["external", "fast-kernel", "reference"]
        );
        assert!(record
            .checker_identities
            .iter()
            .all(|identity| identity.checker_id.is_some()
                && identity.checker_binary_hash.is_some()
                && identity.checker_build_hash.is_some()));

        assert_eq!(record.compared_fields.len(), 1);
        let field = &record.compared_fields[0];
        assert_eq!(field.field, "status");
        assert_eq!(
            field.expected_checker_profile.as_deref(),
            Some("fast-kernel")
        );
        assert_eq!(field.actual_checker_profile, "reference");
        assert_eq!(field.expected_value.as_deref(), Some("checked"));
        assert_eq!(field.actual_value.as_deref(), Some("failed"));

        assert_eq!(
            record
                .frozen_input_artifact_hashes
                .iter()
                .map(|artifact| artifact.kind.as_str())
                .collect::<Vec<_>>(),
            vec![
                "candidate_identity",
                "certificate",
                "certificate_file",
                "import_lock",
                "axiom_policy",
                "runner_policy",
                "normalized_result",
            ]
        );
        assert!(record
            .canonical_json()
            .contains(CHECKER_DISAGREEMENT_RECORD_SCHEMA));
    }

