    #[test]
    fn independent_checker_axiom_unsupported_core_feature_raw_result_is_structured() {
        let policy = parse_independent_checker_runner_policy(
            &pr_runner_policy_with_optional_external_json(),
        )
        .unwrap();
        let imports_json = valid_import_lock_manifest_json();
        let cert_bytes = test_raw_certificate_bytes("Std.Nat", test_hash(70));
        let materialized = independent_checker_request_materialize(
            &policy,
            "Std.Nat",
            "build/certs/Std/Nat.npcert",
            &cert_bytes,
            "build/certs/import-lock.json",
            imports_json.as_bytes(),
            independent_checker_file_hash(imports_json.as_bytes()),
            "external",
            "mchkreq_axiom_unsupported_feature",
            "build/check-requests/Std.Nat.external.json",
            None,
        )
        .unwrap();
        let unsupported_raw = format!(
            r#"{{
              "schema":"npa.independent-checker.checker_raw_result.v1",
              "checker_id":"npa-checker-ext",
              "checker_version":"0.1.0",
              "checker_build_hash":"{}",
              "status":"failed",
              "error":{{
                "kind":"unsupported_core_feature",
                "reason_code":"unsupported_core_feature",
                "section":"core_features",
                "offset":17
              }}
            }}"#,
            hash_wire(15)
        );
        let unsupported = independent_checker_machine_check_run(
            &materialized.request,
            &policy,
            IndependentCheckerRunObservation {
                result_id: "mchkres_axiom_unsupported_feature".to_owned(),
                attempt: 1,
                runner: m3_runner(),
                process: IndependentCheckerMachineCheckProcess::exited(1),
                resource_usage: m3_resource_usage(21),
                stdout: unsupported_raw.into_bytes(),
                stderr: Vec::new(),
            },
        )
        .unwrap();

        let unsupported_error = unsupported.error.as_ref().unwrap();
        assert_eq!(
            unsupported.status,
            IndependentCheckerMachineCheckStatus::Failed
        );
        assert_eq!(unsupported_error.kind, "unsupported_core_feature");
        assert_eq!(
            unsupported_error.reason_code.as_deref(),
            Some("unsupported_core_feature")
        );
        assert_eq!(unsupported_error.section.as_deref(), Some("core_features"));
    }

    #[test]
    fn m7_reproducibility_uses_run_artifact_hash_and_deterministic_equality() {
        let (request, policy) = m3_request_and_policy();
        let baseline = m4_checked_result(&request, &policy, "mchkres_repro_base");
        let mut repeated = baseline.clone();
        repeated.result_id = "mchkres_repro_repeated".to_owned();
        repeated.attempt = 2;
        assert_eq!(baseline.result_hash(), repeated.result_hash());
        assert_ne!(baseline.run_artifact_hash(), repeated.run_artifact_hash());

        let passed = independent_checker_auxiliary_reproducibility_result(
            "aux_repro_001",
            &policy,
            test_hash(201),
            &baseline,
            &repeated,
        )
        .unwrap();
        assert_eq!(passed.status, IndependentCheckerAuxiliaryStatus::Passed);

        repeated.certificate_hash = Some(test_hash(202));
        let failed = independent_checker_auxiliary_reproducibility_result(
            "aux_repro_002",
            &policy,
            test_hash(201),
            &baseline,
            &repeated,
        )
        .unwrap();
        assert_eq!(failed.status, IndependentCheckerAuxiliaryStatus::Failed);
        let error = failed.error.as_ref().unwrap();
        assert_eq!(
            error.reason_code,
            IndependentCheckerAuxiliaryReasonCode::ReproducibilityMismatch
        );
        assert_eq!(error.field.as_deref(), Some("repeated.certificate_hash"));
    }

