    #[test]
    fn m11_final_phase_adopts_exact_existing_output_and_rejects_conflict() {
        let release_policy = m7_release_policy(IndependentCheckerReleaseMode::Release);
        let release_policy_json = release_policy.canonical_json();
        let input = m11_input(
            IndependentCheckerReleaseBundleArtifactKind::ReleasePolicy,
            "policies/release-policy.json",
            &release_policy_json,
            &[("policy_hash", release_policy.policy_hash())],
        );
        let plan = m11_plan(
            IndependentCheckerReleaseBundleStagingPhase::Final,
            vec![input.clone()],
        );
        let plan_json = plan.canonical_json();
        let mut workspace_files = BTreeMap::new();
        workspace_files.insert(input.path.clone(), release_policy_json.clone().into_bytes());
        let target_path =
            independent_checker_release_bundle_artifact_path(input.kind, input.file_hash);
        let mut existing = BTreeMap::new();
        existing.insert(
            target_path.clone(),
            release_policy_json.clone().into_bytes(),
        );
        let staged = independent_checker_release_stage_bundle_inputs(
            IndependentCheckerReleaseBundleStagingPhase::Final,
            "dist/release-bundle",
            "build/staging-plan.json",
            independent_checker_file_hash(plan_json.as_bytes()),
            &plan_json,
            &workspace_files,
            Some(&existing),
        )
        .unwrap();
        assert_eq!(staged.result.staged_artifacts[0].path, target_path);

        existing.insert(target_path, b"different".to_vec());
        let err = independent_checker_release_stage_bundle_inputs(
            IndependentCheckerReleaseBundleStagingPhase::Final,
            "dist/release-bundle",
            "build/staging-plan.json",
            independent_checker_file_hash(plan_json.as_bytes()),
            &plan_json,
            &workspace_files,
            Some(&existing),
        )
        .unwrap_err();
        assert_eq!(err.reason_code.as_ref(), "output_path_conflict");
    }

