    #[test]
    fn p8h12_high_trust_import_certificate_artifacts_follow_import_lock() {
        let import = m12_real_theorem_certificate("Audit.Import", "id_thm");
        let import_lock = IndependentCheckerImportLockManifest {
            imports: vec![IndependentCheckerImportLockEntry {
                module: "Audit.Import".to_owned(),
                export_hash: import.export_hash,
                certificate: IndependentCheckerImportLockCertificate {
                    path: "build/import.npcert".to_owned(),
                    file_hash: import.file_hash,
                    certificate_hash: import.certificate_hash,
                },
            }],
        };
        let mut artifacts = Vec::new();
        let mut files = BTreeMap::new();
        let import_lock_json = import_lock.canonical_json();
        m12_add_artifact(
            IndependentCheckerReleaseBundleArtifactKind::ImportLock,
            import_lock_json.clone(),
            &[(
                "manifest_hash",
                independent_checker_file_hash(import_lock_json.as_bytes()),
            )],
            &mut artifacts,
            &mut files,
        );
        let manifest = IndependentCheckerReleaseAuditBundleManifest::new(
            test_hash(1),
            test_hash(2),
            artifacts.clone(),
        );
        let missing = independent_checker_release_bundle_validate_import_certificate_artifacts(
            &manifest, &files,
        )
        .unwrap_err();
        assert_eq!(missing.field.as_ref(), "artifacts[import_certificate]");

        m12_add_artifact_bytes(
            IndependentCheckerReleaseBundleArtifactKind::ImportCertificate,
            import.bytes.clone(),
            &[
                ("certificate_hash", import.certificate_hash),
                ("export_hash", import.export_hash),
            ],
            &mut artifacts,
            &mut files,
        );
        let mut wrong_lock = import_lock;
        wrong_lock.imports[0].certificate.certificate_hash = test_hash(3);
        let wrong_lock_json = wrong_lock.canonical_json();
        let lock_index = artifacts
            .iter()
            .position(|artifact| {
                artifact.kind == IndependentCheckerReleaseBundleArtifactKind::ImportLock
            })
            .unwrap();
        files.remove(&artifacts[lock_index].path);
        let wrong_lock_hash = independent_checker_file_hash(wrong_lock_json.as_bytes());
        let wrong_lock_path = independent_checker_release_bundle_artifact_path(
            IndependentCheckerReleaseBundleArtifactKind::ImportLock,
            wrong_lock_hash,
        );
        files.insert(wrong_lock_path.clone(), wrong_lock_json.into_bytes());
        artifacts[lock_index] = IndependentCheckerReleaseAuditBundleArtifact {
            kind: IndependentCheckerReleaseBundleArtifactKind::ImportLock,
            path: wrong_lock_path,
            file_hash: wrong_lock_hash,
            hashes: BTreeMap::from([("manifest_hash".to_owned(), wrong_lock_hash)]),
        };
        let manifest = IndependentCheckerReleaseAuditBundleManifest::new(
            test_hash(1),
            test_hash(2),
            artifacts,
        );
        let wrong = independent_checker_release_bundle_validate_import_certificate_artifacts(
            &manifest, &files,
        )
        .unwrap_err();
        assert!(wrong.field.as_ref().ends_with(".hashes.certificate_hash"));
        assert_eq!(wrong.expected_hash, Some(Box::new(test_hash(3))));
        assert_eq!(wrong.actual_hash, Some(Box::new(import.certificate_hash)));
    }

    #[test]
    fn p8h12_audit_bundle_validation_rejects_forbidden_axiom_auxiliary_failure() {
        let mut fixture = m12_fixture(true);
        let axiom_aux_index = fixture
            .artifacts
            .iter()
            .position(|artifact| {
                if artifact.kind != IndependentCheckerReleaseBundleArtifactKind::AuxiliaryResult {
                    return false;
                }
                let source =
                    std::str::from_utf8(fixture.files.get(&artifact.path).unwrap()).unwrap();
                parse_independent_checker_auxiliary_result(source)
                    .map(|result| result.kind == IndependentCheckerAuxiliaryResultKind::AxiomPolicy)
                    .unwrap_or(false)
            })
            .unwrap();
        let old_path = fixture.artifacts[axiom_aux_index].path.clone();
        let old_source = std::str::from_utf8(fixture.files.get(&old_path).unwrap()).unwrap();
        let old = parse_independent_checker_auxiliary_result(old_source).unwrap();
        fixture.files.remove(&old_path);
        fixture.artifacts.remove(axiom_aux_index);
        let failed = IndependentCheckerAuxiliaryResult::failed(
            old.result_id,
            old.kind,
            old.policy_hash,
            old.artifact_hash,
            old.selector,
            IndependentCheckerAuxiliaryError::value(
                IndependentCheckerAuxiliaryReasonCode::AxiomPolicyFailed,
                "axiom_report.axioms[0].name",
                "allowed_axiom",
                "Std.Logic.choice",
            ),
        );
        m12_add_artifact(
            IndependentCheckerReleaseBundleArtifactKind::AuxiliaryResult,
            failed.canonical_json(),
            &[("result_hash", failed.result_hash())],
            &mut fixture.artifacts,
            &mut fixture.files,
        );

        let err = independent_checker_release_bundle(
            "dist/release-bundle",
            "dist/release-bundle/manifest.json",
            fixture.artifact_hash,
            &fixture.artifacts,
            &fixture.files,
            None,
        )
        .unwrap_err();
        assert_eq!(err.reason_code.as_ref(), "release_bundle_generation_failed");
        assert!(err.field.as_deref().unwrap().ends_with(".artifact.status"));
    }

    fn m13_training_stores() -> (
        IndependentCheckerNormalizedCheckResult,
        Vec<IndependentCheckerMachineCheckResult>,
        IndependentCheckerNormalizedResultStoreManifest,
        IndependentCheckerMachineResultStoreManifest,
        BTreeMap<String, Vec<u8>>,
    ) {
        let policy = parse_independent_checker_runner_policy(&m4_runner_policy_json()).unwrap();
        let fast = m4_stored_request(&policy, "fast-kernel", "mchkreq_m13_fast");
        let reference = m4_stored_request(&policy, "reference", "mchkreq_m13_reference");
        let external = m4_stored_request(&policy, "external", "mchkreq_m13_external");
        let stored_requests = vec![fast.clone(), reference.clone(), external.clone()];
        let request_store = m4_request_store_manifest(&stored_requests);
        let machine_results = vec![
            m4_checked_result(&fast.request, &policy, "mchkres_m13_fast"),
            m5_failed_result(
                &reference.request,
                &policy,
                "mchkres_m13_reference",
                "Std.Nat",
            ),
            m4_checked_result(&external.request, &policy, "mchkres_m13_external"),
        ];
        let normalized = independent_checker_normalize_results(
            "norm_Std.Nat_m13",
            "normerr_Std.Nat_m13",
            &policy,
            &request_store,
            &stored_requests,
            &machine_results,
            None,
        )
        .unwrap();
        let normalized_path = "build/normalized/m13-Std.Nat.json";
        let normalized_entry = independent_checker_normalized_result_store_entry_for_result(
            &normalized,
            normalized_path,
        )
        .unwrap();
        let normalized_store = IndependentCheckerNormalizedResultStoreManifest {
            results: vec![normalized_entry],
        };

        let mut files = BTreeMap::from([(
            normalized_path.to_owned(),
            normalized.canonical_json().into_bytes(),
        )]);
        let mut result_entries = Vec::new();
        for result in &machine_results {
            let path = format!("build/check-results/m13-{}.json", result.checker.profile);
            files.insert(path.clone(), result.canonical_json().into_bytes());
            result_entries.push(
                independent_checker_machine_result_store_entry_for_result(result, path).unwrap(),
            );
        }
        result_entries.sort_by_key(|entry| entry.run_artifact_hash);
        let result_store = IndependentCheckerMachineResultStoreManifest {
            results: result_entries,
        };

        (
            normalized,
            machine_results,
            normalized_store,
            result_store,
            files,
        )
    }

    fn m13_expected_training_example(
        normalized: &IndependentCheckerNormalizedCheckResult,
        result: &IndependentCheckerMachineCheckResult,
    ) -> IndependentCheckerTrainingExample {
        IndependentCheckerTrainingExample::new(
            IndependentCheckerTrainingExampleSource {
                result_hash: result.result_hash(),
                request_hash: result.request_hash,
                run_artifact_hash: result.run_artifact_hash(),
            },
            IndependentCheckerTrainingExampleIdentity {
                artifact_input_file_hash: normalized.artifact.input_file_hash,
                artifact_expected_certificate_hash: normalized.artifact.expected_certificate_hash,
                certificate_hash: result.certificate_hash,
                checker_id: result.checker.id.clone(),
                checker_build_hash: result.checker.build_hash,
                checker_profile: result.checker.profile.clone(),
                result_hash: result.result_hash(),
                policy_hash: result.policy.hash,
                policy_version: result.policy.version,
            },
            IndependentCheckerTrainingExampleInput {
                module: normalized.artifact.module.clone(),
                checker_profile: result.checker.profile.clone(),
                policy_id: result.policy.id.clone(),
            },
            IndependentCheckerTrainingExampleLabel {
                status: result.status,
                error_kind: result.error.as_ref().map(|error| error.kind.clone()),
                reason_code: result
                    .error
                    .as_ref()
                    .and_then(|error| error.reason_code.clone()),
            },
        )
    }

    #[test]
    fn m13_training_export_generates_deterministic_jsonl_and_manifest() {
        let (normalized, machine_results, normalized_store, mut result_store, files) =
            m13_training_stores();
        result_store
            .results
            .push(IndependentCheckerMachineResultStoreEntry {
                result_hash: test_hash(210),
                request_hash: test_hash(211),
                run_artifact_hash: test_hash(212),
                checker_profile: "reference".to_owned(),
                path: "build/check-results/m13-unreferenced-extra.json".to_owned(),
                file_hash: test_hash(213),
            });
        result_store
            .results
            .sort_by_key(|entry| entry.run_artifact_hash);
        let normalized_store_json = normalized_store.canonical_json();
        let result_store_json = result_store.canonical_json();

        let export = independent_checker_training_export(
            "build/normalized/manifest.json",
            independent_checker_file_hash(normalized_store_json.as_bytes()),
            &normalized_store_json,
            "build/check-results/manifest.json",
            independent_checker_file_hash(result_store_json.as_bytes()),
            &result_store_json,
            &files,
            "build/training/independent-checker-examples.jsonl",
            "build/training/independent-checker-examples.manifest.json",
            None,
            None,
        )
        .unwrap();

        let mut expected_examples = machine_results
            .iter()
            .map(|result| m13_expected_training_example(&normalized, result))
            .collect::<Vec<_>>();
        expected_examples.sort_by(|left, right| {
            left.source
                .run_artifact_hash
                .cmp(&right.source.run_artifact_hash)
        });
        let mut expected_jsonl = Vec::new();
        for example in &expected_examples {
            expected_jsonl.extend_from_slice(example.canonical_json().as_bytes());
            expected_jsonl.push(b'\n');
        }

        assert_eq!(export.jsonl_bytes, expected_jsonl);
        assert_eq!(
            export.manifest.file_hash,
            independent_checker_file_hash(&expected_jsonl)
        );
        assert_eq!(
            export.manifest.export_id,
            independent_checker_training_export_id(export.manifest.file_hash)
        );
        assert_eq!(export.manifest.record_count, expected_examples.len() as u64);
        assert_eq!(
            export.manifest.sources.normalized_store_manifest_hash,
            independent_checker_file_hash(normalized_store_json.as_bytes())
        );
        assert_eq!(
            export.manifest.sources.result_store_manifest_hash,
            independent_checker_file_hash(result_store_json.as_bytes())
        );
        assert!(std::str::from_utf8(&export.manifest_bytes)
            .unwrap()
            .contains(INDEPENDENT_CHECKER_TRAINING_EXPORT_MANIFEST_SCHEMA));

        let jsonl = std::str::from_utf8(&export.jsonl_bytes).unwrap();
        assert_eq!(jsonl.lines().count(), 3);
        assert!(jsonl.contains(INDEPENDENT_CHECKER_TRAINING_EXAMPLE_SCHEMA));
        assert!(jsonl.contains("\"source\":\"machine_check_result\""));
        assert!(jsonl.contains("\"status\":\"checked\""));
        assert!(jsonl.contains("\"status\":\"failed\""));
        assert!(jsonl.contains("\"error_kind\":\"type_mismatch\""));
        assert!(!jsonl.contains("classification"));
        assert!(!jsonl.contains("confidence"));
        assert!(!jsonl.contains("ai_sidecar"));

        let adopted = independent_checker_training_export(
            "build/normalized/manifest.json",
            independent_checker_file_hash(normalized_store_json.as_bytes()),
            &normalized_store_json,
            "build/check-results/manifest.json",
            independent_checker_file_hash(result_store_json.as_bytes()),
            &result_store_json,
            &files,
            "build/training/independent-checker-examples.jsonl",
            "build/training/independent-checker-examples.manifest.json",
            Some(&export.jsonl_bytes),
            Some(&export.manifest_bytes),
        )
        .unwrap();
        assert!(!adopted.out_rewrite_required);
        assert!(!adopted.manifest_out_rewrite_required);

        let conflict = independent_checker_training_export(
            "build/normalized/manifest.json",
            independent_checker_file_hash(normalized_store_json.as_bytes()),
            &normalized_store_json,
            "build/check-results/manifest.json",
            independent_checker_file_hash(result_store_json.as_bytes()),
            &result_store_json,
            &files,
            "build/training/independent-checker-examples.jsonl",
            "build/training/independent-checker-examples.manifest.json",
            Some(b"{\"schema\":\"not-the-export\"}\n"),
            None,
        )
        .unwrap_err();
        assert_eq!(conflict.reason_code.as_ref(), "output_path_conflict");
        assert_eq!(conflict.field.as_deref(), Some("out.path"));
    }

    #[test]
    fn m13_training_export_rejects_ambiguous_machine_result_candidates() {
        let (_normalized, machine_results, normalized_store, mut result_store, mut files) =
            m13_training_stores();
        let mut retry = machine_results[0].clone();
        retry.result_id = "mchkres_m13_fast_retry".to_owned();
        retry.attempt = 2;
        let retry_path = "build/check-results/m13-fast-kernel-retry.json";
        files.insert(retry_path.to_owned(), retry.canonical_json().into_bytes());
        let retry_entry =
            independent_checker_machine_result_store_entry_for_result(&retry, retry_path).unwrap();
        result_store =
            independent_checker_machine_result_store_with_entry(Some(&result_store), retry_entry)
                .unwrap()
                .manifest;

        let normalized_store_json = normalized_store.canonical_json();
        let result_store_json = result_store.canonical_json();
        let err = independent_checker_training_export(
            "build/normalized/manifest.json",
            independent_checker_file_hash(normalized_store_json.as_bytes()),
            &normalized_store_json,
            "build/check-results/manifest.json",
            independent_checker_file_hash(result_store_json.as_bytes()),
            &result_store_json,
            &files,
            "build/training/independent-checker-examples.jsonl",
            "build/training/independent-checker-examples.manifest.json",
            None,
            None,
        )
        .unwrap_err();

        assert_eq!(
            err.reason_code.as_ref(),
            "training_export_generation_failed"
        );
        assert_eq!(err.field.as_deref(), Some("command"));
    }

    #[test]
    fn m13_no_ai_release_pass_fail_and_challenge_coverage_fixture_are_connected() {
        let (policy, generated, materialized) = m9_generated_challenge();
        let stored_requests = m9_stored_requests(&materialized);
        let failed = m5_failed_result(
            &materialized.requests[0],
            &policy,
            "mchkres_m13_challenge_ref",
            "Std.Nat",
        );
        let result_store = m9_result_store(&failed, "build/results/m13-challenge-ref.json");
        let normalized = independent_checker_normalize_results(
            "norm_challenge_m13",
            "normerr_challenge_m13",
            &policy,
            &materialized.request_store,
            &stored_requests,
            std::slice::from_ref(&failed),
            None,
        )
        .unwrap();
        assert_eq!(
            normalized.comparison.status,
            IndependentCheckerNormalizedComparisonStatus::AllAgreeFailed
        );
        let normalized_store = m9_normalized_store(&normalized);
        let replay = independent_checker_challenge_replay_aggregate(
            "chreplay_m13_pch",
            &generated.manifest,
            generated.manifest.manifest_hash(),
            &policy,
            &materialized.request_store,
            &stored_requests,
            &result_store,
            std::slice::from_ref(&failed),
            Some(&normalized_store),
            std::slice::from_ref(&normalized),
            true,
            "build/challenge-replays/m13-pch.json",
            None,
        )
        .unwrap();
        let target_normalized = m9_target_normalized_result(&policy);
        let coverage = independent_checker_challenge_coverage_summary(
            &policy,
            &target_normalized,
            &generated.challenge_store,
            std::slice::from_ref(&generated.manifest),
            &replay.replay_store,
            std::slice::from_ref(&replay.result),
            &result_store,
            std::slice::from_ref(&failed),
        )
        .unwrap();
        assert_eq!(coverage.total_challenges, 1);
        assert_eq!(coverage.replayed_challenges, 1);
        assert_eq!(coverage.unexpected_acceptances, 0);
        assert!(coverage.passes_release_coverage_condition());

        let pass_fixture = m12_fixture(true);
        let generated_bundle = independent_checker_release_bundle(
            "dist/release-bundle",
            "dist/release-bundle/manifest.json",
            pass_fixture.artifact_hash,
            &pass_fixture.artifacts,
            &pass_fixture.files,
            None,
        )
        .unwrap();
        assert!(generated_bundle
            .manifest
            .artifacts
            .iter()
            .all(|artifact| artifact.kind
                != IndependentCheckerReleaseBundleArtifactKind::AiAuditSidecar));
        let validation = independent_checker_release_validate_bundle(
            "dist/release-bundle/manifest.json",
            independent_checker_file_hash(&generated_bundle.bytes),
            std::str::from_utf8(&generated_bundle.bytes).unwrap(),
            &pass_fixture.files,
            None,
        )
        .unwrap();
        assert_eq!(
            validation.result.status,
            IndependentCheckerAuxiliaryStatus::Passed
        );

        let fail_fixture = m12_fixture(false);
        let fail_manifest = IndependentCheckerReleaseAuditBundleManifest::new(
            fail_fixture.policy_hash,
            fail_fixture.artifact_hash,
            fail_fixture.artifacts,
        );
        let fail_manifest_json = fail_manifest.canonical_json();
        let fail_validation = independent_checker_release_validate_bundle(
            "dist/release-bundle/manifest.json",
            independent_checker_file_hash(fail_manifest_json.as_bytes()),
            &fail_manifest_json,
            &fail_fixture.files,
            None,
        )
        .unwrap();
        assert_eq!(
            fail_validation.result.status,
            IndependentCheckerAuxiliaryStatus::Failed
        );
    }
